-- Poems batch 260
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('9a9de89f-1ecf-430d-939f-e7e4c037c0f9','題陳宗魯東山書塾','方回','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','芳草謂發顛，美石謂發狂。',156,'全唐诗/poet.song.232000.json','["芳草謂發顛，美石謂發狂。", "自賢與自智，豈必草石嘗。", "勿以夫子廟，而欺賜也牆。", "勿以聖人室，而鄙由也堂。", "楛庭有遠孫，美玉深匵藏。", "姓名似元龍，家無上下床。", "收斂河海氣，遁逃聲利場。", "衆謂陟泰嶽，六合視茫茫。", "我之魯東山，亦可小靈光。", "不患見不穹，但患行不强。", "十駕日不已，突過騏驥良。", "美酒無深巷，苦李遺道傍。", "四益視乃叛，蘇合殊糞蜣。"]'),
('b51d197f-89a5-4fcb-be19-0947ccd05d43','唐侯舉摹刊詩卷牟獻之文趙子昂字','方回','宋','宋诗','song-poetry','','[]','金馬文章坡潁氏，玉堂字畫獻羲之。',32,'全唐诗/poet.song.232000.json','["金馬文章坡潁氏，玉堂字畫獻羲之。", "得兼裒施棗此刻，價倍湖州校正詩。"]'),
('04acef9e-95b8-4ea1-a2c5-5d92725a3f6a','孟浩然雪馿圖','方回','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','往年一上岳陽樓，西風倏忽四十秋。',216,'全唐诗/poet.song.232000.json','["往年一上岳陽樓，西風倏忽四十秋。", "詩牌高掛詩兩首，他人有詩誰敢留。", "其一孟浩然，解道氣吞雲夢澤。", "其二杜子美，解道吳楚東南坼。", "浩然詩不多，句句盡堪傳。", "天下詩人推老杜，老杜又專推浩然。", "我亦嘗遨江漢邊，梅花臘月猶年年。", "一句新詩學不得，謾飽槎頭縮項鯿。", "雪天誰寫詩窮狀，凍合吟肩神氣王。", "短褐長夜死不朽，貂蟬何必凌煙上。", "偶隨故人直玉堂，龍鱗不顧嬰君王。", "李太白、賀知章，三郎不識放歸雲水鄉，子美先生餓欲僵。", "浩然先生不直內廄一疋馬，可是蜀棧騎馿山路長。"]'),
('39d77e8f-8bd0-4eb7-ab6d-742d25424042','丁酉生日二首  其一','方回','宋','宋诗','song-poetry','','[]','今年五月冷非常，擁袖無聊一老尪。',64,'全唐诗/poet.song.232000.json','["今年五月冷非常，擁袖無聊一老尪。", "應俗但宜司馬好，全生不必次公狂。", "絳人甲子差相近，皇考庚寅暗自傷。", "病酒客樓聽泥屐，愁邊更用雨淋浪。"]'),
('b0f460c5-f325-4de0-ba16-ee31ca0113e4','丁酉生日二首  其二','方回','宋','宋诗','song-poetry','','[]','未甦殘醉茗頻煨，夙荷諸公載酒來。',64,'全唐诗/poet.song.232000.json','["未甦殘醉茗頻煨，夙荷諸公載酒來。", "照鏡所存唯雪鬢，典衣已盡况銀杯。", "色嬰單豹偶然耳，带索啟期焉怨哉。", "弱水元無三萬里，此心安處是蓬萊。"]'),
('4fff5a67-3762-4ddf-803a-3745b6e5e360','生日又二首  其一','方回','宋','宋诗','song-poetry','','[]','畏途偶許玩餘生，晚節尤難保令名。',64,'全唐诗/poet.song.232000.json','["畏途偶許玩餘生，晚節尤難保令名。", "一禿翁真韓長孺，五男兒可晉淵明。", "凄風開戶綿重著，漏雨濺床酒懶傾。", "俗事沓來敗人意，且須堅坐待天晴。"]'),
('882c895c-b140-4661-88a4-4861840140d9','生日又二首  其二','方回','宋','宋诗','song-poetry','','[]','豈料生逾七十年，孩提脫死瘴鄉煙。',64,'全唐诗/poet.song.232000.json','["豈料生逾七十年，孩提脫死瘴鄉煙。", "未能湯餠觴朋友，祇合爐香拜祖先。", "養性有書知道理，奪胎無藥學神仙。", "天都峰下舊茅屋，消得嚴灘十日船。"]'),
('8ea1ef81-7835-48ba-8452-a5af545a992b','戊戌元日三首  其一','方回','宋','宋诗','song-poetry','','[]','班春踰半月，獻歲換新正。',48,'全唐诗/poet.song.232000.json','["班春踰半月，獻歲換新正。", "馬動人聲喜，星明曉意晴。", "寒袪和氣勝，病愈老身輕。", "七十二年事，沉吟暗自驚。"]'),
('da5e89ca-fc82-49a0-8f59-955291952e4d','戊戌元日三首  其二','方回','宋','宋诗','song-poetry','','[]','爐香禮天地，再過古來稀。',48,'全唐诗/poet.song.232000.json','["爐香禮天地，再過古來稀。", "此日仍逢節，何時定許歸。", "年高還拜怯，客窘久留非。", "遥憶小兒女，新春只故衣。"]'),
('411201ba-a866-422c-927d-edfe8e6c0006','戊戌元日三首  其三','方回','宋','宋诗','song-poetry','','[]','彷彿曉鐘鳴，家家起五更。',48,'全唐诗/poet.song.232000.json','["彷彿曉鐘鳴，家家起五更。", "物宜春後暖，人喜歲初晴。", "衰老猶能飲，虛空誤得名。", "題詩思舊日，無此好新正。"]'),
('5c916c6d-4634-4db2-8388-a1deda1064b2','誰識','方回','宋','宋诗','song-poetry','','[]','梅花香未已，早是杏花時。',48,'全唐诗/poet.song.232000.json','["梅花香未已，早是杏花時。", "身老春遊倦，心恬夜夢知。", "百杯聖俞酒，萬首放翁詩。", "肉眼今誰識，神仙世有之。"]'),
('732ecf1e-99a8-4f62-9a5c-087efc520471','不恨','方回','宋','宋诗','song-poetry','','[]','鼓腹千年有，平心一物無。',48,'全唐诗/poet.song.232000.json','["鼓腹千年有，平心一物無。", "粗能全晚節，不敢恨窮途。", "豈少真君子，何求老腐儒。", "春風香百草，千丈古松枯。"]'),
('ee95c184-cc96-4cf4-a579-f2c832027cdb','題丁適之菊莊','方回','宋','宋诗','song-poetry','','[]','令威舊主芙蓉城，上帝謂此職未清。',144,'全唐诗/poet.song.232000.json','["令威舊主芙蓉城，上帝謂此職未清。", "敕賜別業非菽粟，屈餐陶採餘秋英。", "菊莊先生拜新號，掌管黄花躬播耕。", "莊田莊屋幾頃畝，莊官莊佃無姓名。", "只如天隨自荷鋤，兼味佐以仙犬精。", "乃餱乃糧不過許，春苗夏葉俱可烹。", "木蘭墜露滋上池，亦復樽酒東籬傾。", "人愛熱官我寧冷，粗有菊譜傳諸生。", "南陽月輸三十斛，汝真糞土之朝榮。"]'),
('867d83f2-6255-4fd3-8d34-5e3920069aaa','送林學正愛梅二首  其一','方回','宋','宋诗','song-poetry','','[]','早與梅花歃血盟，歲寒同社保幽貞。',64,'全唐诗/poet.song.232000.json','["早與梅花歃血盟，歲寒同社保幽貞。", "八詩共識林和靖，一賦誰知宋廣平。", "邂逅老夫傳此本，殷勤今日送君行。", "開元宰相和羹事，鐵石心腸待晚成。"]'),
('e564918e-6caf-4816-89d9-aabaae5e74f9','送林學正愛梅二首  其二','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','平生自號愛梅人，家住江南野水濱。',64,'全唐诗/poet.song.232000.json','["平生自號愛梅人，家住江南野水濱。", "屋角暫辭千樹雪，馬頭猶带一枝春。", "馨香事業終須在，酸苦工夫盍少伸。", "莫學君家舊處士，西湖空老太平身。"]'),
('2f3aeb84-0232-4059-a5a1-d8ab3116fa5b','送丘子正以能書入都併呈徐容齋閻靖軒盧處道集賢翰林三學士','方回','宋','宋诗','song-poetry','','[]','君不見古來九關虎豹守，入仕艱難無不有。',387,'全唐诗/poet.song.232000.json','["君不見古來九關虎豹守，入仕艱難無不有。", "興能一札秋槐黄，芒鞋布裙天下走。", "攀援龍鱗萬萬手，咳唾驪珠萬萬口。", "蓬萊無路弱水隔，七上十上空白首。", "邂逅登名豈不偶，選坑沉淪十八九。", "光範三書徒爾忙，子公一紙焉所取。", "書生身體縱著翅，飛聲未辦廷臣右。", "還知氣至天地春，花者必花柳必柳。", "中庸末章八引詩，三詩首言士所爲。", "衣錦尚絅潜雖伏，屋漏不高天聽卑。", "至隠至微至顯見，鬼神森列何可欺。", "斗間有氣射古劍，石上無根生瑞芝。", "快雨乍晴虹霓起，蟄蟲欲振雷霆馳。", "靜中根本動中發，闇處精神明處知。", "禊帖昔秘永禪師，不過紙上王羲之。", "御史蕭翼百計取，公等乃有胸中奇。", "胸中奇者五色筆，可以補天可活國。", "宗彝作繪衮作火，可但能書梵王譯。", "此之所寶玉非石，求而不藏卞和泣。", "良賈韞匵什其襲，藏而不求價倍百。", "公等翰墨今第一，誰云識字不得力。", "借徑文藝以致身，勳名政要無心得。", "九萬里迅扶摇風，今日朝廷貞觀同。", "聯翩房杜肩王魏，試代常何草封事。"]'),
('be8d01a7-0999-4387-806c-1f31f449c990','送趙子昂提調寫金經','方回','宋','宋诗','song-poetry','','["\u592a\u6e56"]','青藜夜照玉堂直，外補已至二千石。',304,'全唐诗/poet.song.232000.json','["青藜夜照玉堂直，外補已至二千石。", "不合自以藝能累，天下善書今第一。", "魏晉力命王略帖，摹臨有過無不及。", "真行草外工篆隸，兼有與可伯時癖。", "小者士庶携卷軸，大者王侯擲縑帛。", "門前踏斷鐵門限，苦向王孫覓真迹。", "有時乘興掃龍蛇，圖畫紙素動成疋。", "有時厭俗三歎息，何乃以此爲人役。", "如池如溝棄殘墨，如冢如陵堆敗筆。", "太湖西畔松雪齋，七弦風清碧山碧。", "桃花水肥釣鱖魚，春雨春風一蓑笠。", "胡爲拾此復塵埃，鳴鞭更上金臺驛。", "白馬四十二章來，一大藏今五千帙。", "訂訛補譌重繕寫，金字琅函較甲乙。", "考工記屬冬官卿，潤文使專宰相職。", "北門學士董此事，一儒迥勝緇輩百。", "精神如玉鬢如漆，天上知己密如櫛。", "省臺要官俱可得，還自管城子中出。", "右軍寫經博白鵝，孰與明時見數多。"]'),
('ca930fba-856e-4ca0-a731-a87174467028','送鄧善之提調寫金經','方回','宋','宋诗','song-poetry','','[]','二三十載鄉閭師，黄紙初除專講帷。',272,'全唐诗/poet.song.232000.json','["二三十載鄉閭師，黄紙初除專講帷。", "溧陽雖小亦新郡，學廩粗足晨昏炊。", "曰事未然缺次遠，槐宮尚需蟬再嘶。", "士食天祿行或使，暗中自有神扶持。", "我昔識君初未髭，犀角雙盈方顙頤。", "飽學武庫富蓄貯，粹行桓璧微瑕疵。", "過市目不視左右，何啻董生園不窺。", "含章晦美抱素藴，修之於家朝廷知。", "一室萬里限戶閾，脚跟不動名四馳。", "譬諸豐城瘞寶劍，紫氣貫斗當有時。", "平生識字乃餘事，倉頡科斗揚雄奇。", "飾翠泥金寫梵夾，凡善書者能辦之。", "至用儒流董厥役，借此進賢培邦基。", "晦翁豈止能詩者，澹庵胡公薦以詩。", "唐柳公權以筆諫，忠鯁隨事堪箴規。", "去去行行勿復遲，未至烹雌炊扊扅。", "白玉之堂鳳凰池，不著君輩當著誰。"]'),
('0d981e22-344a-415f-9d63-dfda7a906dba','送滕玉霄張元樸管押地理書入都','方回','宋','宋诗','song-poetry','','[]','滕侯酒酣宇宙窄，長嘯詩成鬼神泣。',224,'全唐诗/poet.song.232000.json','["滕侯酒酣宇宙窄，長嘯詩成鬼神泣。", "謫仙後身今李白，一錦宮袍猶未得。", "張侯乃翁官鼎軸，芸香家藏百萬牘。", "朝窗夜檠吟不足，政須天下書遍讀。", "四海萬國天一家，東盡蟠木西流沙。", "貢珍未貴貴圖籍，卉服颶風窮島涯。", "玉堂衆雋修國史，搜書北方遣名士。", "若欲講知南地理，亦合南州起才子。", "所以滕侯暨張侯，聯翩同作中原遊。", "夜靜長虹貫明月，春風穩送江天舟。", "張侯富貴素所有，相門會見魯拜後。", "滕侯遭遇夫豈偶，飄然掉臂奮空手。", "金匱石室紬瑶編，大書特書筆如椽。", "成就堯典禹貢篇，不數班固司馬遷。"]'),
('153d728c-9d69-4007-9036-9d1607a5f7b2','爲合密府判題趙子昂大字蘭亭','方回','宋','宋诗','song-poetry','','[]','神奇變化莫若龍，屈蟠可藏螺殻中。',128,'全唐诗/poet.song.232000.json','["神奇變化莫若龍，屈蟠可藏螺殻中。", "一聲霹靂起頭角，金鱗萬丈橫蒼空。", "右軍禊帖不盈咫，善臨摹者子趙子。", "一觴一詠十九之，方如带玉滿疋紙。", "小字古稱黄庭經，大字焦山瘞鶴銘。", "小斂大縱出一手，譬如寫真妙丹青。", "寫真但要寫得似，小纖大濃皆可喜。", "小如眼中見瞳人，大如鏡中見全身。"]'),
('b5915baf-1952-4f19-a521-8a564425031f','題畫盧仝長鬚赤脚','方回','宋','宋诗','song-poetry','','[]','玉川破屋數間洛城中，一時際遇赤尹昌黎公。',114,'全唐诗/poet.song.232000.json','["玉川破屋數間洛城中，一時際遇赤尹昌黎公。", "贈以大篇意甚侈，不數李渤溫造兼石洪。", "買羊沽酒分俸給，時攀綠駬下虛空，月天桃李醺春風。", "豈惟百世之下知盧仝，併使長鬚赤脚名無窮。", "誰其畫者善遊戲，不畫盧仝畫奴婢。", "想見煎茶七碗時，此曹頗亦霑餘味。"]'),
('42a0eabb-d70b-4d79-bd21-1e2106557cb6','平章呂公挽詞二首  其一','方回','宋','宋诗','song-poetry','','[]','難兄捐閫寄，無復救襄人。',48,'全唐诗/poet.song.232000.json','["難兄捐閫寄，無復救襄人。", "半紀嬰孤壘，中朝扼柄臣。", "秦非里奚智，徐爲偃王仁。", "萬事由天命，乾坤歷數新。"]'),
('541cb65a-123b-4441-8559-6d633dea1578','平章呂公挽詞二首  其二','方回','宋','宋诗','song-poetry','','[]','燕頷逢荆鄂，於今四十秋。',48,'全唐诗/poet.song.232000.json','["燕頷逢荆鄂，於今四十秋。", "始聞降鬼國，遄見拔瀘州。", "廟議顓私意，邊圍墮詭謀。", "棄襄不令守，鐵鎖靠江流。"]'),
('9b83934d-d28f-4f50-bed8-105b9234a77a','送金壽之江正寫金字經','方回','宋','宋诗','song-poetry','','[]','碧落金仙躡漢庭，梵書翻寫過東溟。',64,'全唐诗/poet.song.232000.json','["碧落金仙躡漢庭，梵書翻寫過東溟。", "宰官嘗領潤文使，法帖尚傳遺教經。", "子敬比蹤洛神賦，率更媲美醴泉銘。", "夢中五色文章筆，視草鰲扉趁妙齡。"]'),
('9fb4a462-8128-43eb-85a1-591398bdc9bd','題廬山白蓮社十八賢圖','方回','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','六老臞儒十二僧，柴桑醉士肯爲朋。',32,'全唐诗/poet.song.232000.json','["六老臞儒十二僧，柴桑醉士肯爲朋。", "葫蘆自與葫蘆纏，更要閒人纏葛藤。"]'),
('4f153010-25a1-4fc6-904e-ca8d44fcb987','題淵明像','方回','宋','宋诗','song-poetry','','[]','慧遠無此冠，修靜無此巾。',24,'全唐诗/poet.song.232000.json','["慧遠無此冠，修靜無此巾。", "此巾要亦有，無此漉酒人。"]'),
('767fb2f0-d2d6-45af-8162-5bcd12adc74c','題徐仲彬達觀亭','方回','宋','宋诗','song-poetry','','[]','乾涵坤毓萬彙夥，獨得爲人頼鈞播。',384,'全唐诗/poet.song.232000.json','["乾涵坤毓萬彙夥，獨得爲人頼鈞播。", "八尺身爲天地贅，一寸心將天地裹。", "道眼自應非肉眼，以心觀物無不可。", "靈臺光潔日月懸，肯使一絲掛塵堁。", "老壽龜鶴夭蠛蠓，博大鵬鯤小蜾蠃。", "王侯雲霄縱翱翔，奴隸泥塗淹坎軻。", "雷霆起蟄春生兒，霜露斂華秋結果。", "防風九畝霸十圍，痿痹支離蹣跚跛。", "二五之精形相禪，彼胡魁梧此么麽。", "天所賦予各有命，女子豈羨弧矢左。", "螻蟻君臣雁弟兄，道理大處無細瑣。", "洪纖各遂逍遥遊，續鳬之頸爾其叵。", "徐侯讀書得玉匙，聖人門戶啟關鎖。", "用賓屢揚北上鞭，大隠薦鼓南遊柁。", "築室金陵割鍾山，臨川僻學百義墮。", "千古子在川上心，想見解衣盤礴臝。", "梧桐楊柳竹陰間，菱荷疊重花婀娜。", "弄丸一卷經世書，內篇外篇夜燈火。", "靜寂動感來無窮，昭布森列俱帖妥。", "通達居然今賈傅，豈容棲遲老江沱。", "乘流止坎大厥觀，進退久速不預揣。", "熏天富貴臘毒味，涎詎肯流頤敢朵。", "窗前草青鹿共眠，檻外沙白鷗同坐。", "忘機得意茅三間，焉用陶朱西施舸。"]'),
('a21eab85-9065-4a72-b6cc-00c308f72fa0','淳熙甲午東陽郡齋蘭亭','方回','宋','宋诗','song-poetry','','[]','大唐天子紿孤僧，轉瞬人間幾廢興。',32,'全唐诗/poet.song.232000.json','["大唐天子紿孤僧，轉瞬人間幾廢興。", "一幅永和故繭紙，入昭陵又出昭陵。"]'),
('b30dc232-de2a-403d-a35d-c8148c6f9726','淳熙癸卯錢伸東陽本','方回','宋','宋诗','song-poetry','','[]','永和貞觀晉沿唐，奉詔臨摹老遂良。',32,'全唐诗/poet.song.232000.json','["永和貞觀晉沿唐，奉詔臨摹老遂良。", "展轉流傳非一手，虎賁猶得似中郎。"]'),
('ac64436f-b48b-4786-b9a2-a4b6498c0960','淳熙戊申丘壽雋新昌石氏本','方回','宋','宋诗','song-poetry','','[]','頗如畫手善傳神，絕喜他鄉見似人。',32,'全唐诗/poet.song.232000.json','["頗如畫手善傳神，絕喜他鄉見似人。", "俯仰之間已陳迹，如何千載尚如新。"]'),
('dfb84c1b-5fed-4591-b561-9783ddefe596','張椶仲實見惠江陰丘本','方回','宋','宋诗','song-poetry','','[]','絕喜他鄉見似人，頗如畫手善傳神。',32,'全唐诗/poet.song.232000.json','["絕喜他鄉見似人，頗如畫手善傳神。", "忽思今昔無窮事，十五迴經癸丑春。"]'),
('e6bf101d-b872-454e-a1b9-ac9faeb573a5','小本蘭亭二種','方回','宋','宋诗','song-poetry','','[]','子雲可擬易論無，頗似蘭亭細字模。',32,'全唐诗/poet.song.232000.json','["子雲可擬易論無，頗似蘭亭細字模。", "始信聖經非小藝，不羞依樣畫葫蘆。"]'),
('7dfb7bdd-639d-4353-bf94-885f8cd5570c','北本蘭亭','方回','宋','宋诗','song-poetry','','[]','一千年想永和會，十九之傳貞觀摹。',32,'全唐诗/poet.song.232000.json','["一千年想永和會，十九之傳貞觀摹。", "此本中原今第一，真成一字一驪珠。"]'),
('f936dcd6-deab-41f3-a987-df6c249d8497','朱字蘭亭','方回','宋','宋诗','song-poetry','','[]','傾城國色著胭脂，紅字蘭亭又出奇。',32,'全唐诗/poet.song.232000.json','["傾城國色著胭脂，紅字蘭亭又出奇。", "比換鵝書更姿媚，一杯卯酒醉西施。"]'),
('6e18ec64-d630-421d-ac6f-47ae881eea66','題王春陽傚王晉卿山水圖','方回','宋','宋诗','song-poetry','','[]','煙江疊嶂子能學，都尉後身王姓同。',32,'全唐诗/poet.song.232000.json','["煙江疊嶂子能學，都尉後身王姓同。", "詩畫驚逢兩奇麗，賞音吾愧玉堂翁。"]'),
('552b25cf-4876-4f8a-bcf3-c719f80e250c','題李仲賓竹二幅','方回','宋','宋诗','song-poetry','','[]','可是筆端如與可，亦須胸次有東坡。',32,'全唐诗/poet.song.232000.json','["可是筆端如與可，亦須胸次有東坡。", "自從舉世誇崔白，似覺無人識李頗。"]'),
('ccd43809-ffa0-4ef0-a15d-80559b4acd70','次韻受益再題荆浩山水圖當是洪谷子自寫所居','方回','宋','宋诗','song-poetry','','[]','太行荆浩之鄉里，佳處立參仍坐倚。',128,'全唐诗/poet.song.232000.json','["太行荆浩之鄉里，佳處立參仍坐倚。", "崖樹澗石皆寫真，想見含毫吮沁水。", "當年自號洪谷子，畫成署名細如蟻。", "此豈自圖其所居，屋上峰巒插天起。", "柵門雞犬鎖寒林，僮馬盤山暮煙紫。", "高者佛寺平者川，關仝范寬焉得比。", "我少學畫中棄之，時到古齋漫隨喜。", "好古人多識古希，不意永嘉聞正始。"]'),
('ac4ad41e-b819-42eb-87fb-d48fbec3e97d','戊戌端午','方回','宋','宋诗','song-poetry','','[]','退休敢望賜宮衣，破篋重尋舊暑絺。',64,'全唐诗/poet.song.232000.json','["退休敢望賜宮衣，破篋重尋舊暑絺。", "梅子黄時端午又，葵花紅處故園非。", "畫符焉用元無病，標錦休爭但合歸。", "頼有故人餉新煮，一杯草草勒魚肥。"]'),
('98841f3e-73ce-43a8-9124-779b10a564f1','次韻文蔚約梅上人來訪','方回','宋','宋诗','song-poetry','','[]','慚非好客鄭當時，猥荷高人不見遺。',64,'全唐诗/poet.song.232000.json','["慚非好客鄭當時，猥荷高人不見遺。", "頓悟可能參佛理，淡交誰是喜僧詩。", "過從未許泥行數，屬和多因險韻遲。", "彼此緘縢各收拾，他年開卷兩相知。"]'),
('9def8e05-fa19-4cb5-93f9-94c522f5d987','戊戌生日二首  其一','方回','宋','宋诗','song-poetry','','[]','貪得真迷境，持平實悟門。',48,'全唐诗/poet.song.232000.json','["貪得真迷境，持平實悟門。", "未妨人負我，各要子生孫。", "動輒聞誰死，猗嗟幸獨存。", "榮華何足記，衰悴不須論。"]'),
('d96b9b35-9170-4efb-87f9-b52729c8be65','戊戌生日二首  其二','方回','宋','宋诗','song-poetry','','[]','客舍逢生日，鄰家送壽星。',48,'全唐诗/poet.song.232000.json','["客舍逢生日，鄰家送壽星。", "循彝須答禮，恃熟莫忘形。", "把筆遲賡和，開樽共醉醒。", "五兒一隨侍，心竊愧椿庭。"]'),
('85c652c5-d060-4686-800e-999fec137ac8','俞鑑山月歌','方回','宋','宋诗','song-poetry','','["\u6cf0\u5c71", "\u534e\u5c71"]','詩人詩向虛空攫，平地望月不可摸。',192,'全唐诗/poet.song.232000.json','["詩人詩向虛空攫，平地望月不可摸。", "或謂高山去天近，好登東嶽陟西嶽。", "嶽峰峻極未到天，仰面難舐兔臼藥。", "末由手挽月娥衣，詩思肯從天上落。", "不如斟月入杯中，詩酒腸吸杯月空。", "一杯一首百杯百，天送佳句來長風。", "仙人輕舉跨飛鶴，游子歸思隨征鴻。", "扶摇直上九萬里，未辦頂摩丹桂宮。", "所以詩人世難得，倚靠梯凳探月窟。", "山頭拏月月愈遠，塵裏抉詩詩不出。", "大江洶湧波跳金，謫仙捉月淪采石。", "是爲詩人善搜詩，何知君非今李白。"]'),
('5ecd2d5d-707f-4125-ac7d-6607db36284c','送家自昭慈湖山長','方回','宋','宋诗','song-poetry','','[]','我身即此庵，要識一個自。',228,'全唐诗/poet.song.232000.json','["我身即此庵，要識一個自。", "自心爲庵主，太陽了不二。", "太陽本常明，天半隔以地。", "朝紅正晝白，暮夜黄黑異。", "其明未嘗減，西沒復東出。", "此心亦如此，外物爲之累。", "去蔽實在我，豈可自壅閟。", "日能自用力，疾鞭扶桑轡。", "心可自用心，明德永弗墜。", "節飲自少醉，寡欲自少寐。", "自己有此寶，碎璧肯自棄。", "慈湖言本心，似亦無可議。", "未發缺存養，所見恐未粹。", "子往拜其祠，於焉設講肆。", "長短審取舍，予奪謹廢置。", "天日揭義理，慎勿狥私意。", "厚土埋金烏，吾說可一篲。", "大明曉常升，難瞇萬目視。", "老禪駡祖法，不妨略一試。"]'),
('70b7b3ba-da9e-41d6-8938-93bb2280bb77','送天目吳君實館越  其一','方回','宋','宋诗','song-poetry','','[]','天目山人客鑑湖，請言近世兩鴻儒。',64,'全唐诗/poet.song.232000.json','["天目山人客鑑湖，請言近世兩鴻儒。", "洪平齋集親抄否，陸放翁詩背誦無。", "綠芡紫蓴乘月採，黄精白朮入雲鋤。", "土毛未負將軍腹，萬卷撐腸定不枯。"]'),
('fa765e91-fcd1-4f91-8356-446ac546f777','送天目吳君實館越  其二','方回','宋','宋诗','song-poetry','','[]','試問推潮鬼定知，幾吳幾越幾西施。',64,'全唐诗/poet.song.232000.json','["試問推潮鬼定知，幾吳幾越幾西施。", "八千又見陰陵散，十九終存曲水之。", "我輩不當爭外物，如君可用要人詩。", "勉哉往學南山豹，端復深藏霧雨姿。"]'),
('7b31eab5-5132-4a89-a814-ceff31ebf3c3','題布袋和尚豐干禪師寒山拾得畫卷','方回','宋','宋诗','song-poetry','','[]','豐干禪師降猛虎，布袋和尚愚小兒。',32,'全唐诗/poet.song.232000.json','["豐干禪師降猛虎，布袋和尚愚小兒。", "老夫見畫未親見，唯喜寒山拾得詩。"]'),
('330ec1b8-cea5-46cf-8361-c77d6906bcd9','題沈伯雋所藏趙子昂墨蘭','方回','宋','宋诗','song-poetry','','[]','今蘭春秀異秋蘭，世事隨時豈一端。',32,'全唐诗/poet.song.232000.json','["今蘭春秀異秋蘭，世事隨時豈一端。", "別有古人不死處，陶詩晉字要人看。"]'),
('87a8bc7a-25c2-422b-9037-0ec11f5139c6','立秋','方回','宋','宋诗','song-poetry','','[]','暑赦如聞降德音，一凉歡喜萬人心。',64,'全唐诗/poet.song.232000.json','["暑赦如聞降德音，一凉歡喜萬人心。", "雖然未便梧桐落，終是相將蟋蟀吟。", "初夜銀河正牛女，詰朝紅日尾觜參。", "朝廷欲覓玄真子，蟹舍漁蓑煙雨深。"]'),
('fddb6ab3-ef73-4a93-be80-6c63c67fa2af','曉起','方回','宋','宋诗','song-poetry','','[]','夜凉無寐起吟詩，正是秋風欲動時。',64,'全唐诗/poet.song.232000.json','["夜凉無寐起吟詩，正是秋風欲動時。", "百尺樓高蟾獨掛，五更鐘過馬交馳。", "道懷了了元無事，世故紛紛總不知。", "但欠山頭埋骨穴，歸歟分付與諸兒。"]'),
('564eea9e-0c6e-4f82-ae70-ca0b74eb7bf0','瑞雲院大樹林中二首  其一','方回','宋','宋诗','song-poetry','','[]','城中遥望萬重雲，今日蟬聲始一聞。',32,'全唐诗/poet.song.232000.json','["城中遥望萬重雲，今日蟬聲始一聞。", "略計此山松竹數，漢時應比百封君。"]'),
('7c5eb1f5-e1d6-462e-88a0-c85b1fd67ef7','瑞雲院大樹林中二首  其二','方回','宋','宋诗','song-poetry','','[]','萬萬松杉萬竹枝，人間應是少人知。',32,'全唐诗/poet.song.232000.json','["萬萬松杉萬竹枝，人間應是少人知。", "數僧瀟灑相逢處，一鶴昂藏獨立時。"]'),
('28225854-e776-4477-81a5-ab87f5a3635a','三竺道中三首  其一','方回','宋','宋诗','song-poetry','','[]','武林風物異他鄉，三竺山行草亦香。',32,'全唐诗/poet.song.232000.json','["武林風物異他鄉，三竺山行草亦香。", "村落尋常績麻處，隔簾時復見紅粧。"]'),
('ef27d6ad-62a8-4fe7-af65-b464030dce22','三竺道中三首  其二','方回','宋','宋诗','song-poetry','','[]','少人行處路方佳，半著僧鞋半草鞋。',32,'全唐诗/poet.song.232000.json','["少人行處路方佳，半著僧鞋半草鞋。", "直到全無馬糞處，山僮竹箒掃松釵。"]'),
('e0d6e7f7-d0ba-4019-ae4a-7ac5a6853382','三竺道中三首  其三','方回','宋','宋诗','song-poetry','','[]','石溪清淺不容舟，但有常常綠水流。',32,'全唐诗/poet.song.232000.json','["石溪清淺不容舟，但有常常綠水流。", "莫道江湖風浪闊，此中涓滴是源頭。"]'),
('028ad410-4215-4ebd-ad74-6bcef1c40b05','斷橋西人家三首  其一','方回','宋','宋诗','song-poetry','','[]','無數菰蒲間藕花，萬絲垂柳曳風斜。',32,'全唐诗/poet.song.232000.json','["無數菰蒲間藕花，萬絲垂柳曳風斜。", "竹籬茅舍渾如畫，最愛橋西第一家。"]'),
('4382705b-b03b-4e2c-88d7-d3d97da53f69','斷橋西人家三首  其二','方回','宋','宋诗','song-poetry','','[]','主人儻不粗能吟，辜負湖天水竹林。',32,'全唐诗/poet.song.232000.json','["主人儻不粗能吟，辜負湖天水竹林。", "我若移家來此住，詩人無數日相尋。"]'),
('bf4d24ea-9072-4ca3-adef-9ddbc581d273','斷橋西人家三首  其三','方回','宋','宋诗','song-poetry','','[]','望極蘇堤欲盡頭，叢篁老柳水天秋。',32,'全唐诗/poet.song.232000.json','["望極蘇堤欲盡頭，叢篁老柳水天秋。", "船中遥看家家好，却恐君來住亦愁。"]'),
('cdf82334-50e9-49fc-aa72-4f567493babb','聞過','方回','宋','宋诗','song-poetry','','[]','秋來火傘尚高張，心定還能熱處凉。',64,'全唐诗/poet.song.232000.json','["秋來火傘尚高張，心定還能熱處凉。", "自古及今誰不死，寧人負我亦何傷。", "緡錢瑣碎爭多少，杯酒紛紜說短長。", "舊管釣臺時入夢，人間未有兩嚴光。"]'),
('9fa5d5db-998f-479f-93d5-c854ac74fe4f','自覺二首  其一','方回','宋','宋诗','song-poetry','','[]','還將短鬢受秋風，倏忽炎凉事不同。',64,'全唐诗/poet.song.232000.json','["還將短鬢受秋風，倏忽炎凉事不同。", "青史合居人品上，白雲肯到市聲中。", "蕙肴蘭藉何須飽，芰製荷衣未覺窮。", "駟馬高車足憂患，五湖歸作釣魚翁。"]'),
('06e1ccbd-1313-488e-8e04-58176c62cab0','自覺二首  其二','方回','宋','宋诗','song-poetry','','[]','忍垢包羞混世塵，胸中無物只天真。',64,'全唐诗/poet.song.232000.json','["忍垢包羞混世塵，胸中無物只天真。", "平生我亦輕餘子，此日君當恕醉人。", "鍾乳金釵空喪志，鱸魚蓴菜尚知津。", "中行獨復雖差晚，猶與初爻不遠鄰。"]'),
('8ed701d9-d34c-437a-a500-bcd9f3cca466','問西湖','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','誰將西子比西湖，舊日繁華漸欲無。',32,'全唐诗/poet.song.232000.json','["誰將西子比西湖，舊日繁華漸欲無。", "始信坡仙詩是讖，捧心國色解亡吳。"]'),
('a5c2e232-f6e0-4c2b-becd-9c1d89c21a34','西湖答','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','濃粧淡抹比蛾眉，多謝蘇仙內翰詩。',32,'全唐诗/poet.song.232000.json','["濃粧淡抹比蛾眉，多謝蘇仙內翰詩。", "若使朝廷無宰嚭，未妨宮掖有西施。"]'),
('63e68877-31a2-4411-a3fd-6260c210986e','送王宣慰中齋上溫州  其一','方回','宋','宋诗','song-poetry','','[]','兩朝參預慶源長，愧我蒹葭玉樹傍。',64,'全唐诗/poet.song.232000.json','["兩朝參預慶源長，愧我蒹葭玉樹傍。", "先世幸聯龍虎榜，難兄復接鷺鵷行。", "江東連帥迎前纛，浙左侯藩餞去艎。", "每愧淡交無以報，願聞所至有甘棠。"]'),
('373a636f-b0c0-4bb5-b31e-a7aa97c4c350','送王宣慰中齋上溫州  其二','方回','宋','宋诗','song-poetry','','[]','夢草堂邊下榻時，隙駒四十五年馳。',64,'全唐诗/poet.song.232000.json','["夢草堂邊下榻時，隙駒四十五年馳。", "東嘉太守真知己，西里先生共賦詩。", "前輩風流元不遠，故家文獻未全衰。", "留耕相種書元帥，好與儒壇建鼓旗。"]'),
('6ebb0447-1a8e-4216-abb6-f2efad02253c','次韻酬吳僧一山行魁','方回','宋','宋诗','song-poetry','','[]','爲僧應勝我，可惜墮禪林。',48,'全唐诗/poet.song.232000.json','["爲僧應勝我，可惜墮禪林。", "鑄錯剪鬚髪，書癡雕肺心。", "聞名梅止渴，晤語旱逢霖。", "一句詩傳世，猿邊幾夜吟。"]'),
('6b327ff7-fa56-42bf-95d7-dcb65a9acfc8','八月五日病中','方回','宋','宋诗','song-poetry','','[]','於心敢自欺，但恐不精思。',48,'全唐诗/poet.song.232000.json','["於心敢自欺，但恐不精思。", "未覺扶顛易，方驚悔過遲。", "病堪長作客，貧可薦招醫。", "觀井如彭祖，聞諸丱角時。"]'),
('18bcf706-e329-46af-a7ab-41d05f8b0710','送仇仁近持山村圖求屋貲','方回','宋','宋诗','song-poetry','','[]','浪多年二十，是事弗如之。',144,'全唐诗/poet.song.232000.json','["浪多年二十，是事弗如之。", "老我初登第，聞君早解詩。", "風霜懸齒頰，錦繡簇肝脾。", "才是通漫刺，誰非獻屈巵。", "貴人遺世患，寒士扼時危。", "道泰官猶冷，身窮氣未衰。", "雖無間屋妾，已有肯堂兒。", "村擬茅齋卜，山將畫卷隨。", "賀成良匪易，裒益復奚疑。", "歲稔田收倍，秋凉渚汎宜。", "定應爭倒屣，不惜共捐貲。", "千斛歸舟駛，梁文想預爲。"]'),
('366a6331-9924-451a-90b3-4ed0dd8cbeef','八月十二日過湖','方回','宋','宋诗','song-poetry','','[]','荷已無花柳欲陳，秋風颯颯水粼粼。',32,'全唐诗/poet.song.232000.json','["荷已無花柳欲陳，秋風颯颯水粼粼。", "湖山慘淡西施老，細看終於勝醜人。"]'),
('12e8fe28-13a9-4fc4-a676-836672b2cd59','望西太乙宮四聖觀半爲僧寺','方回','宋','宋诗','song-poetry','','[]','紅牆半舊粉牆新，泥塑金塗各有神。',32,'全唐诗/poet.song.232000.json','["紅牆半舊粉牆新，泥塑金塗各有神。", "僧道不須閒計較，等爲和靖守墳人。"]'),
('841c789f-23e5-4d2a-b3ad-84df13a46ada','三天竺道中','方回','宋','宋诗','song-poetry','','[]','三天竺路漸平登，高似雷峰塔幾層。',32,'全唐诗/poet.song.232000.json','["三天竺路漸平登，高似雷峰塔幾層。", "山到無人行處好，松陰萬樹立孤僧。"]'),
('f689d557-7974-4911-96aa-726547b3bef0','登上竺興福寺新閣五首  其一','方回','宋','宋诗','song-poetry','','[]','獅子峰高側見巔，怒飛危欲墮簷前。',32,'全唐诗/poet.song.232000.json','["獅子峰高側見巔，怒飛危欲墮簷前。", "千松萬竹闌干畔，瘦骨秋寒似雪天。"]'),
('8b8c85d9-62fb-4f7d-be6e-79fac7637dc4','登上竺興福寺新閣五首  其二','方回','宋','宋诗','song-poetry','','[]','面面峰巒傑閣新，好山借我倚欄身。',32,'全唐诗/poet.song.232000.json','["面面峰巒傑閣新，好山借我倚欄身。", "商量壁記留名易，未是題詩第一人。"]'),
('f5d26b85-857a-4289-8864-751d3625c29d','登上竺興福寺新閣五首  其三','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','跳過西湖萬萬重，半天蓬鬢洗松風。',32,'全唐诗/poet.song.232000.json','["跳過西湖萬萬重，半天蓬鬢洗松風。", "自慚不得留終日，又向船中入市中。"]'),
('0fd3e507-6687-4852-9ca6-4708b5a4ac55','登上竺興福寺新閣五首  其四','方回','宋','宋诗','song-poetry','','[]','乳竇峰前路不窮，穿林踰嶺浙江通。',32,'全唐诗/poet.song.232000.json','["乳竇峰前路不窮，穿林踰嶺浙江通。", "紫陽山雨釣臺月，消得潮頭幾信風。"]'),
('781b06c3-406a-4d0d-aa3e-2a69a4f2964f','登上竺興福寺新閣五首  其五','方回','宋','宋诗','song-poetry','','[]','燕蟄蜂瘖菊始開，秋凉入骨病堆豗。',32,'全唐诗/poet.song.232000.json','["燕蟄蜂瘖菊始開，秋凉入骨病堆豗。", "吟僧欲約山中宿，後夜須携絮被來。"]'),
('410e0100-25a0-4a86-9f70-5fa80c29b5ad','三天竺還五首  其一','方回','宋','宋诗','song-poetry','','[]','城中决定少新詩，便向湖光也未宜。',32,'全唐诗/poet.song.232000.json','["城中决定少新詩，便向湖光也未宜。", "我有新詩無數處，三天竺路筍輿遲。"]'),
('35ec4bf3-3ba3-45fa-827f-c8904a6c23d9','三天竺還五首  其二','方回','宋','宋诗','song-poetry','','[]','松枝垂地蔭松身，恨不移家此卜鄰。',32,'全唐诗/poet.song.232000.json','["松枝垂地蔭松身，恨不移家此卜鄰。", "石上一根長數丈，似吾細看更無人。"]'),
('bf61b8be-d3df-4bfd-b96a-7b89609f7124','三天竺還五首  其三','方回','宋','宋诗','song-poetry','','[]','澗晴石出水穿沙，萬樹松杉隠數家。',32,'全唐诗/poet.song.232000.json','["澗晴石出水穿沙，萬樹松杉隠數家。", "一鳥不鳴風不動，忽聞林下響繅車。"]'),
('20422338-5281-4148-9d24-7313b5fcf932','三天竺還五首  其四','方回','宋','宋诗','song-poetry','','[]','山中事事勝人間，莫怪山翁喜入山。',32,'全唐诗/poet.song.232000.json','["山中事事勝人間，莫怪山翁喜入山。", "才說出山心不喜，又將身世墮塵寰。"]'),
('eb1a2077-157a-4a71-96bf-53db7a36c7ac','三天竺還五首  其五','方回','宋','宋诗','song-poetry','','[]','七十二翁頭雪白，弱冠初遊鬢如漆。',32,'全唐诗/poet.song.232000.json','["七十二翁頭雪白，弱冠初遊鬢如漆。", "除却一二老山僧，獨來獨往無人識。"]'),
('841c8cde-3ada-4981-8690-a58bb0009a1f','送周漢東入都并呈徐學士子方閻學士子靜盧學士處道','方回','宋','宋诗','song-poetry','','[]','同是黄山採藥人，相逢十載客中身。',64,'全唐诗/poet.song.232000.json','["同是黄山採藥人，相逢十載客中身。", "贅疣天地吾無用，萍梗江湖子亦貧。", "曳組定趨金馬署，揚鞭初闖玉京塵。", "徐閻盧老如相問，向道猶餘漉酒巾。"]'),
('13d51725-b8b4-4fe0-9e4b-9b55a8c5cac6','次韻受益九日','方回','宋','宋诗','song-poetry','','[]','歸歟豈少舊林塘，何用痡瘏陟彼岡。',64,'全唐诗/poet.song.232000.json','["歸歟豈少舊林塘，何用痡瘏陟彼岡。", "白髪轉添吾輩老，黄花不減去年香。", "每嫌佳節多風雨，猶喜炎陬緩雪霜。", "典盡寒衣償酒債，衰翁聊以醉爲鄉。"]'),
('53bcd34c-23f3-45dd-81a3-179123f7ff78','聞謗','方回','宋','宋诗','song-poetry','','[]','脩身可用要人知，暗室孤燈敢自欺。',32,'全唐诗/poet.song.232000.json','["脩身可用要人知，暗室孤燈敢自欺。", "赤口燒城市有虎，熨平寸地聽群兒。"]'),
('c8d28866-b598-484f-b241-ec01643d4b8e','寓意','方回','宋','宋诗','song-poetry','','[]','季路三都不盡隳，城狐尚許脫阽危。',32,'全唐诗/poet.song.232000.json','["季路三都不盡隳，城狐尚許脫阽危。", "一日西家鼠運去，太丘忽有社亡時。"]'),
('95341da4-8e5b-49b6-b35d-500d080d68f6','寄題曹氏居竹','方回','宋','宋诗','song-poetry','','[]','維古修竹鄉，君子世此居。',96,'全唐诗/poet.song.232000.json','["維古修竹鄉，君子世此居。", "厥壤既宜竹，種竹環其廬。", "根不取馬箠，笋不供盤蔬。", "永保歲寒盟，子孫樂只且。", "老夫何當曳長裾，一窺旌節舊門閭。", "華亭豈羨揚州鶴，松江自足馮驩魚。", "田園伏臘頗有餘，竹中明燈夜讀書。"]'),
('37af867b-b79e-4468-977d-a4b3d221f479','送西湖書院趙山長','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','東南大郡莫如杭，其西有湖誇錢唐。',200,'全唐诗/poet.song.232000.json','["東南大郡莫如杭，其西有湖誇錢唐。", "兩賢刺史一隠士，春秋祠祀專蒸嘗。", "芙蓉楊柳鷗鷺傍，四時不絕炷瓣香。", "後來好事者不作，屋摧階圮莓苔荒。", "錢唐城中十萬戶，自古無人興書堂。", "一朝書堂突兀起，鴟吻大殿環脩廊。", "其上高閣觚稜驤，其下豐碑鎸琳琅。", "香山東坡和靖叟，三像野服無金章。", "寓意貴德不貴爵，高風大節遥相望。", "諸生大带冠昂昂，遴選師儒恢典常，文星燁煜教雨滂。", "誰其爲此參預老，百世不朽徐子方。", "趙君牽聯同不朽，首助膏腴五百畝。"]'),
('0b4088b8-f0b1-4a1b-8d7f-0bfda534a854','題王起宗小橫披水墨作工密勢','方回','宋','宋诗','song-poetry','','[]','秋光一片冷於冰，山寺雲深隠幾僧。',32,'全唐诗/poet.song.232000.json','["秋光一片冷於冰，山寺雲深隠幾僧。", "畫出江村太平意，漁樵無事歲豐登。"]'),
('66ad218a-9283-45f2-a6f2-a622bbcbff6f','題王起宗大橫披水墨作遠淡勢','方回','宋','宋诗','song-poetry','','[]','卧龍峰下草廬幽，門外橋橫水自流。',32,'全唐诗/poet.song.232000.json','["卧龍峰下草廬幽，門外橋橫水自流。", "瀟灑王郎只數筆，淡雲疏樹一天秋。"]'),
('f3708f7d-2546-4a62-be50-c3b7c77ceef1','臘月菊','方回','宋','宋诗','song-poetry','','[]','九日侵尋蜡日徂，金鈿尚可泛屠蘇。',64,'全唐诗/poet.song.232000.json','["九日侵尋蜡日徂，金鈿尚可泛屠蘇。", "鑿冰池畔枝尤勁，栽竹林邊蕊不枯。", "同味遲生新枸杞，齊名久謝舊茱萸。", "土龍棄我登高侶，端肯趨時媚我無。"]'),
('e23b2dfa-39cd-42f5-b08b-be49fc0285d5','送宋昶明仲湖州學錄','方回','宋','宋诗','song-poetry','','[]','爲學有本末，根固枝必稠。',240,'全唐诗/poet.song.232000.json','["爲學有本末，根固枝必稠。", "又如水有源，源清無濁流。", "顔子先四勿，韶冕患不優。", "曾子貴者三，豈於籩豆求。", "九經始慎獨，八目正乃脩。", "我嗟半山學，不識濂溪周。", "遠取湖學意，粗迹窮雕鎪。", "邊防與水利，講諸螢案頭。", "是致青苗法，規摹國師劉。", "汲汲淬事功，方寸俱繆悠。", "堯舜不牧羊，羿射奡盪舟。", "農圃有弗如，問陳有弗酬。", "國定一正君，此道軻傳丘。", "茂叔二程張，貛郎疾如仇。", "永樂西事敗，談兵茲可羞。", "陵夷至宣靖，地下噬臍不。", "此心主精一，焉用功利謀。", "所以汗背勃，見嗤戶牖侯。", "君今錄泮事，往遨白蘋洲。", "臆對議湖學，豈無苕溪鷗。"]'),
('568710f4-2bcc-4139-9d20-afc5560ca4f6','寄撫州呂使君索李雁湖注王半山詩','方回','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','一別龍門十五期，湓城日夜夢魂馳。',64,'全唐诗/poet.song.232000.json','["一別龍門十五期，湓城日夜夢魂馳。", "歸裝初解臨川印，注本應多介甫詩。", "定復一鴟能見惠，遥知五馬未相遺。", "鯉魚直下西江水，兼有書來慰我思。"]'),
('557345a7-9313-4e96-bd25-d49c9221dca9','次韻高子明投贈二首  其一','方回','宋','宋诗','song-poetry','','[]','中原從昔信多艱，尚有文才與古班。',64,'全唐诗/poet.song.232000.json','["中原從昔信多艱，尚有文才與古班。", "詩律規隨元好問，樂章雋永蔡蕭閒。", "要知精會神全處，須到聲銷色泯間。", "此話無人膠鳳觜，一蓑煙雨紫陽山。"]'),
('6df1a905-4786-4e5a-8eb2-f23b28de5607','次韻高子明投贈二首  其二','方回','宋','宋诗','song-poetry','','[]','四時天地共成春，千古羲黄寸壤鄰。',64,'全唐诗/poet.song.232000.json','["四時天地共成春，千古羲黄寸壤鄰。", "空復飛車行萬里，本無弱水隔三神。", "大人尺蠖同伸屈，俗物群狙易喜嗔。", "子欲從吾參此妙，倒翻銀漢洗塵巾。"]'),
('9f6c5798-c010-4acf-a814-1b9cf29c6bef','寄贈集虛孟高士','方回','宋','宋诗','song-poetry','','[]','天地春藏凍核中，時來蜂蝶鬨東風。',64,'全唐诗/poet.song.232000.json','["天地春藏凍核中，時來蜂蝶鬨東風。", "萬端變化根無極，一寸靈明裹太空。", "妙處千江分朗月，飄然六合點飛鴻。", "守玄知默交龍虎，肯泥丹爐子午紅。"]'),
('d4d5d140-c5e8-4286-ab87-4199c4049aaa','寄贈介石沈高士  其一','方回','宋','宋诗','song-poetry','','[]','犖確崎嶇峭壁間，險過巫峽更潼關。',32,'全唐诗/poet.song.232000.json','["犖確崎嶇峭壁間，險過巫峽更潼關。", "石頭莫待微相磕，便合收心早早還。"]'),
('5c10698f-1676-4ea3-b510-fde0ba295cb9','寄贈介石沈高士  其二','方回','宋','宋诗','song-poetry','','[]','兩邊巇險我居中，豈可挨西又捺東。',32,'全唐诗/poet.song.232000.json','["兩邊巇險我居中，豈可挨西又捺東。", "冷笑主人忘曲突，泥梁燕燕說春風。"]'),
('d95fb4d1-86f2-48d2-90f7-d171a0f7364a','題東坡先生惠州定惠院海棠詩後','方回','宋','宋诗','song-poetry','','[]','五季乾坤混爲一，艱難得之容易失。',224,'全唐诗/poet.song.232000.json','["五季乾坤混爲一，艱難得之容易失。", "一拳槌碎四百州，新法宰相王安石。", "二蘇中尤惡大蘇，周二程張俱不識。", "紹聖姦臣講紹述，元祐諸賢紛竄斥。", "東坡飽喫惠州飯，心知惇卞乃國賊。", "恍惚他鄉見似人，海棠一株困荆棘。", "海內文章蜀黨魁，蜀第一花世無匹。", "邂逅相逢心相憐，瘴雨蠻烟污玉質。", "憶昔蒟醤筇竹枝，適與張騫遇西域。", "彼徒生事勞遠人，此感與國同休戚。", "屈原放廢郢都喪，箕子囚奴殷錄訖。", "惠州未已更儋州，必欲殺之至此極。", "立黨籍碑封舒王，竟使大梁無社稷。", "此詩此畫繫興亡，可忍細看淚橫臆。"]'),
('b8347323-a11a-45a2-b274-f4be17919a0f','十月二十二夜三更讀清波雜志至五更','方回','宋','宋诗','song-poetry','','[]','遠書答一封，近詩寫數首。',192,'全唐诗/poet.song.232000.json','["遠書答一封，近詩寫數首。", "小雨客不來，我亦厭奔走。", "茗罷午窗倦，草草具杯酒。", "獨酌政自佳，啖茹聊誑口。", "人生一日事，忽已卯至酉。", "就枕不解衣，須臾鼻雷吼。", "起問夜何其，禁鐘云已扣。", "頗欲復謀飲，床下但空缶。", "再卧卧不成，燈膏幸猶有。", "坐至五更轉，讀過一寸厚。", "是書必有益，但當審去取。", "著此者爲誰，未欲斥氏某。", "金陵三不足，奎聚天地剖。", "尊之配孔庭，邪說陰授受。", "後世公論定，馨穢兩不朽。", "未知八寒獄，惇卞果入否。"]'),
('bd4b6eec-6da5-440c-a1bd-e9204d4b5d1a','夜夢呂洞賓仙翁忽憶戊午西遊岳陽樓老木居士祠觀洞賓像與今南谷高士巾裹政如此奇曉起再賦','方回','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','夜來忽夢洞賓仙，四十年前戊午年。',64,'全唐诗/poet.song.232000.json','["夜來忽夢洞賓仙，四十年前戊午年。", "老樹精祠觀畫像，岳陽樓醉誦詩篇。", "喜逢巾裹真相似，獲接杯行豈偶然。", "喚起沅湘舊遊興，洞庭飛過水如天。"]'),
('b3e04842-93ee-48af-8bbe-f2427f5c71a9','題苗經歷耕野','方回','宋','宋诗','song-poetry','','[]','士以仕爲業，野處無所耕。',168,'全唐诗/poet.song.232000.json','["士以仕爲業，野處無所耕。", "近世所大患，苟進頹厥聲。", "蘇子佩六印，相國不爲榮。", "坐乏二頃田，此事誤平生。", "廓然天壤間，一犁早經營。", "春夏刈麻麥，秋冬穫稻粳。", "蓋頭有把茅，餬口有杯羹。", "豈肯拾此去，垂涎公與卿。", "不遇湯先主，伊葛亦何成。", "聘顧不至三，寧爲畎畝氓。", "駟馬高車間，一跌足可驚。", "豈如牛背上，穩卧無欹傾。", "調鼎與荷鋤，心手自權衡。", "我有一飽資，去就萬事輕。"]'),
('e396e872-daf3-4cbd-bd31-71d522d3abbb','十一月二十九日壬子喜雪','方回','宋','宋诗','song-poetry','','[]','撚冰驚起凍髯翁，一色樓臺曉未融。',64,'全唐诗/poet.song.232000.json','["撚冰驚起凍髯翁，一色樓臺曉未融。", "酤肆定應昂酒價，篙工是處打船篷。", "讀書窗上紙偏白，躍馬街頭塵不紅。", "憂國願豐心絕喜，可能兒女絮因風。"]'),
('24465495-5eb7-49fc-94d9-17c9dc62d233','雪後','方回','宋','宋诗','song-poetry','','[]','誰呵凍筆解吾愁，畫到寒天欲盡頭。',64,'全唐诗/poet.song.232000.json','["誰呵凍筆解吾愁，畫到寒天欲盡頭。", "漁子一簑垂野釣，詩翁百尺倚江樓。", "光添幾夜梅窗月，暖望明年麥隴秋。", "却憶半山服坡老，叉魚奇韻費雕鎪。"]'),
('bbba3726-cc0e-4a2a-bef9-6b64e8c0ec19','題醉仙圖','方回','宋','宋诗','song-poetry','','[]','晉七賢歟，唐八仙歟。',162,'全唐诗/poet.song.232000.json','["晉七賢歟，唐八仙歟。", "胸吞萬古，氣高九天。", "糞土軒冕，膏肓林泉。", "造性命之閫奧，眇文章之蹄筌。", "見李耳於樹下，參伏羲於畫前。", "爰養素於黄庭，亦存神於丹田。", "既萬累之盡掃，惟一真之獨全。", "生涯無他，糟丘酒船。", "畫史遊戲，醉態蹁躚。", "或相舁扶，或相攀牽。", "或袒而舞，或跣而眠。", "堂堂八尺，如頹玉山。", "烱烱一寸，如珠在淵。", "老夫一笑知其然，非愚非癡非狂顛。"]'),
('1fdc3229-724d-4973-b74e-02195a4de923','宗陽宮訪葉西莊亨宗飲尋杜南谷道堅不值留詩并呈戴帥初','方回','宋','宋诗','song-poetry','','[]','我不識南谷，亦不識西莊。',48,'全唐诗/poet.song.232000.json','["我不識南谷，亦不識西莊。", "偶然詣仙境，一舉數十觴。", "南谷出何之，童子煎茗忙。", "柏林中有梅，不見惟聞香。"]'),
('2842c87a-30cd-4773-8562-696ad1f4f2be','丹青歌贈王春陽用其神丹歌韻','方回','宋','宋诗','song-poetry','','[]','世上若無鍾子期，破琴勿爲俗子嗤。',360,'全唐诗/poet.song.232000.json','["世上若無鍾子期，破琴勿爲俗子嗤。", "人間亦有王昭君，奈何衆女嫉蛾眉。", "我粗能詩子能畫，筆力豈不山可移。", "希聲絕色識者少，妾婦嗃嗃仍嘻嘻。", "宣和畫史我嘗讀，山水王詵併郭熙。", "儋州禿翁早題品，元祐文章衆首推。", "坡詩一句不收拾，熙豐孽黨遺羣兒。", "大坡小坡俱寫竹，黜不登載無一枝。", "河東顓征領節度，賊貫時實籌兵帷。", "謂此昏椓亦善畫，繆取人主玉色怡。", "畫之是非且不辨，國勢竟隨閹宦痿。", "花光墨梅方盛行，乃坐山谷屏斥爲。", "簡齋五詩動萬乘，此等佳作亦棄之。", "五日十日一水石，王宰見賞杜拾遺。", "如許名手無其名，可謂世衰人才衰。", "筒不肯破菜不潑，朝士閎籍塗粉脂。", "青城北轅五馬渡，正邪稍稍分荼飴。", "萬事盡如畫譜意，焉得炎正不中微。", "雪蘇黄冤尚伊洛，始覺七政齊衡璣。", "錦囊玉軸鎖御府，徑與宗祏同灰飛。", "米元章史論稍公，遺物太倉存一稊。", "子能畫，亦能詩。", "衆人不識不必疑，相逢但當醉如泥。"]'),
('e3915909-9829-4e58-a0a1-c52155624727','次韻受益題荆浩太行山洪谷圖五言','方回','宋','宋诗','song-poetry','','[]','畫聞與畫見，巧拙不同科。',168,'全唐诗/poet.song.232000.json','["畫聞與畫見，巧拙不同科。", "譬如未入蜀，想像圖岷峨。", "可以欺他人，不可欺東坡。", "又如寫神女，瞥然巫山阿。", "宋玉一點筆，眸子橫清波。", "上黨太行山，懷孟踰黄河。", "水落天井關，長劍垂新磨。", "昌黎尋李愿，借車方口過。", "劈斫開崖壁，巨扁侔斧戈。", "荆浩家其間，煙霞恣麾呵。", "親見勝剽聞，胸次所得多。", "天亦寶此畫，易世終無他。", "退之太行詩，幼誦今鬢皤。", "洪谷太行畫，怳兮聊浩歌。"]'),
('bd7c13e9-1662-4150-be0e-b9f2de9940e5','題劉養晦練江并序','方回','宋','宋诗','song-poetry','','[]','朝爲練江吟，暮爲練江吟。',120,'全唐诗/poet.song.232000.json','["朝爲練江吟，暮爲練江吟。", "練江果何在，曰在江之陰。", "練江不在眼，練江常在心。", "譬之古君子，土思操南音。", "褰裳涉其淺，拏舟濟其深。", "練江可以釣，得魚沽酒斟。", "季子佩六印，陶朱賈千金。", "此事决失望，鷗盟難重尋。", "秋落糞本木，春返來賓禽。", "矯首天都峰，吾亦辭武林。"]'),
('0b809aa8-6c32-486f-9e7e-8a2236944398','次韻許瑞石送邵容齋見寄','方回','宋','宋诗','song-poetry','','[]','款段餘生謝伏波，詠歸心事竟云何。',64,'全唐诗/poet.song.232000.json','["款段餘生謝伏波，詠歸心事竟云何。", "藕花又趁榴花發，詩債仍兼酒債多。", "擊壤先生黄色論，賣薪老子翠微歌。", "吾儕胸次元相似，誰道金章勝釣蓑。"]'),
('5d531f2f-a709-4546-94f3-e888a1fa2a9a','嘆士行','方回','宋','宋诗','song-poetry','','[]','學問何難博，文詞亦易工。',48,'全唐诗/poet.song.232000.json','["學問何難博，文詞亦易工。", "自非知道理，更是長姦雄。", "飾首冠章甫，操心竊大弓。", "金椎發冢輩，張竦與陳崇。"]'),
('1f83429d-2890-4632-a4bd-b99d444c016d','老矣','方回','宋','宋诗','song-poetry','','[]','倚樓開戶展青銅，老矣猶能酒面紅。',64,'全唐诗/poet.song.232000.json','["倚樓開戶展青銅，老矣猶能酒面紅。", "浪許滿頭生壽髪，幾堪落葉見秋風。", "每思舊事全如夢，自喜新詩漸不工。", "棺槨衣衾俱未辦，他年何處葬虛翁。"]'),
('fcf077d9-d6a0-4679-987d-099a8d5a5512','送溪堂方先生五世孫觀歸馬金','方回','宋','宋诗','song-poetry','','[]','河南遷漢歙東鄉，遷歙西鄉自有唐。',64,'全唐诗/poet.song.232000.json','["河南遷漢歙東鄉，遷歙西鄉自有唐。", "溪老堂堂首科級，茅田亹亹冠文場。", "考亭郢鄂桑梓友，孝廟乾淳鴛鷺行。", "五世賢孫吾獲識，根源同是洛陽方。"]'),
('a20084e3-3574-4e9e-a831-0ec30fddc0e0','次韻贈吳羽士月湖大椿','方回','宋','宋诗','song-poetry','','[]','萬事平生大道杯，恍然曾過望鄉臺。',64,'全唐诗/poet.song.232000.json','["萬事平生大道杯，恍然曾過望鄉臺。", "榮華外物毛端細，飄忽陽神頂上回。", "羅殿堪思蠻嶠瘴，鬰儀永謝劫池灰。", "何□乞我刀圭劑，同見蟠桃幾度開。"]'),
('33b651d3-426f-47dc-af00-5e0dbca5ce33','醉贈宗陽寓居九江道士胡虛白祈雨感應','方回','宋','宋诗','song-poetry','','[]','欲血蛟螭出太阿，已翻銀漢下天河。',64,'全唐诗/poet.song.232000.json','["欲血蛟螭出太阿，已翻銀漢下天河。", "築場預覺人人飽，賽社應聞處處歌。", "彈指三聲轟霹靂，張頤一噴響滂沱。", "何曾別有神仙術，止是精神感格多。"]'),
('8cedaa0b-2c23-45ce-b7b0-d5e8d455bf09','改白雲庵疏語爲李道大','方回','宋','宋诗','song-poetry','','[]','昔有隠君子，中年洛陽居。',144,'全唐诗/poet.song.232000.json','["昔有隠君子，中年洛陽居。", "擊壤歌太平，洛人爲結廬。", "名曰安樂窩，花間行小車。", "昔有賢宰相，退休寓洛都。", "心乎愛此老，卜鄰同里閭。", "買園廣其宅，至今傳畫圖。", "賢宰富彥國，隠君邵堯夫。", "走也非隠君，賢宰今不無。", "草草白雲庵，隙地日自鋤。", "欲築三兩亭，冠蓋延朋徒。", "勸君可綠蟻，揣己無青蚨。", "解劍肯指廩，芳名宜大書。"]'),
('0f655a84-011a-40d3-9058-d8be9ebd5069','重陽後三日猶熱多病者死者','方回','宋','宋诗','song-poetry','','[]','重陽已過兩三日，真好菊花全未開。',64,'全唐诗/poet.song.232000.json','["重陽已過兩三日，真好菊花全未開。", "合已樓前橫雁字，却於地上洶蚊雷。", "爬搔最苦瘡瘍癢，擗踊時聞哭泣哀。", "南客不堪况北客，生民何罪降天災。"]'),
('b6240f3b-aff8-426c-8449-edb20735d2b7','題錢選木芙蓉','方回','宋','宋诗','song-poetry','','[]','東籬相伴殿西風，我識花神品藻公。',32,'全唐诗/poet.song.232000.json','["東籬相伴殿西風，我識花神品藻公。", "秋老別無第三品，傲霜黄處拒霜紅。"]'),
('f739104d-f82e-4240-a879-cfee3f82a17f','題達磨渡江畫','方回','宋','宋诗','song-poetry','','[]','祖燈傳到老盧奴，解道元來一物無。',32,'全唐诗/poet.song.232000.json','["祖燈傳到老盧奴，解道元來一物無。", "葱嶺笑伊携隻履，渡江更要一枝蘆。"]'),
('ad82f9c7-0165-49f4-9c00-4a13ef9e9e3f','九月二十二日曉倚樓','方回','宋','宋诗','song-poetry','','[]','北斗掛樓北，曉柄正指東。',96,'全唐诗/poet.song.232000.json','["北斗掛樓北，曉柄正指東。", "乃知今夕昏，移以招西風。", "南州霜未降，九月已過中。", "候蟲既無聲，天猶遲過鴻。", "一歲事垂了，吾生將無同。", "春草百種死，夏木千林空。", "依依牆壁間，獨剩殘菊叢。", "日出萬馬動，誰其知此翁。"]'),
('37c80a3b-dbe6-4595-9a9f-dedef9dfdeed','九月二十六日雪予未之見北人云大都是時亦無此寒','方回','宋','宋诗','song-poetry','','[]','立冬猶十日，衣亦未裝綿。',72,'全唐诗/poet.song.232000.json','["立冬猶十日，衣亦未裝綿。", "半夜風翻屋，侵晨雪滿船。", "非時良可怪，吾老最堪憐。", "通袖藏酸指，憑欄聳凍肩。", "枯腸忽蕭索，殘菊尚鮮妍。", "貧苦無衾者，應多疾病纏。"]'),
('705f507a-3ef6-46ae-9900-a324b07a89f4','十月七日早起','方回','宋','宋诗','song-poetry','','[]','己亥十月六，是爲立冬日。',168,'全唐诗/poet.song.232000.json','["己亥十月六，是爲立冬日。", "是日晴頗暄，虛叟偶飲客。", "醉卧二更醒，起視天宇黑。", "三更至四更，大風一何急。", "吼哮甚江潮，十屋九仆壁。", "五更再倚樓，雲掃衆星出。", "我樓正向東，北斗掛東北。", "其杓漸指南，正東起太白。", "日躔氐近房，紅氣卜晴色。", "萬馬漸次動，鐘鳴戍鼓鼜。", "今年未有霜，貧民或絺綌。", "忽念十日前，霰雪已坌集。", "痢瘧死者夥，咎徵復不一。", "所喜浙田登，百姓不憂食。"]'),
('45f06ee9-3a59-4811-8dad-f5d455a0b0c6','次韻吳僧魁一山十絕  其一','方回','宋','宋诗','song-poetry','','[]','百結袈裟破唐帽，子爲何物我爲誰。',32,'全唐诗/poet.song.232000.json','["百結袈裟破唐帽，子爲何物我爲誰。", "孰知各有直鈎釣，解出珊瑚海底枝。"]'),
('ca8222fa-28dd-495a-b2fb-1ba17efccad4','次韻吳僧魁一山十絕  其二','方回','宋','宋诗','song-poetry','','[]','天河瀉水洗心君，瞎眼能觀聵亦聞。',32,'全唐诗/poet.song.232000.json','["天河瀉水洗心君，瞎眼能觀聵亦聞。", "不是唐皇迎佛骨，大顛焉得見韓文。"]'),
('318d1cf1-9893-4268-928b-e4dfb3bd1d0a','次韻吳僧魁一山十絕  其三','方回','宋','宋诗','song-poetry','','[]','潘江陸海一笑唾，暫借禪衣隠此身。',32,'全唐诗/poet.song.232000.json','["潘江陸海一笑唾，暫借禪衣隠此身。", "坡谷兩翁合爲一，座間始可著斯人。"]'),
('8c59b4e9-92b4-4d2a-925a-5d526451a0ef','次韻吳僧魁一山十絕  其四','方回','宋','宋诗','song-poetry','','[]','七十三迴生一陽，子年未半升我堂。',32,'全唐诗/poet.song.232000.json','["七十三迴生一陽，子年未半升我堂。", "筠溪牧潜即汝是，一繫馿橛須耐霜。"]'),
('d7ee4d5e-0735-4610-b8ab-440ffb708d2f','次韻吳僧魁一山十絕  其五','方回','宋','宋诗','song-poetry','','[]','筠溪四十三歲殀，師弟與兄傳夜衣。',32,'全唐诗/poet.song.232000.json','["筠溪四十三歲殀，師弟與兄傳夜衣。", "國手棋高更有著，百年政恐疾於飛。"]'),
('2d155be4-f162-4ccd-b0f9-e734853e9dc6','次韻吳僧魁一山十絕  其六','方回','宋','宋诗','song-poetry','','[]','己學故學天隠說，多因誤剃鏡中頭。',32,'全唐诗/poet.song.232000.json','["己學故學天隠說，多因誤剃鏡中頭。", "戲拈當日顔良案，兩足何堪踏兩舟。"]'),
('9f795004-b591-4ba0-8287-16a0de855d66','次韻吳僧魁一山十絕  其七','方回','宋','宋诗','song-poetry','','[]','長安應制住紅樓，浪惹玄都紫陌愁。',32,'全唐诗/poet.song.232000.json','["長安應制住紅樓，浪惹玄都紫陌愁。", "天目有山無捷徑，落花莫放出溪流。"]'),
('529d8fa0-9688-4c3b-a9fd-c319af14120d','次韻吳僧魁一山十絕  其八','方回','宋','宋诗','song-poetry','','[]','隋朝檜下訪仙真，五十年前夜榻身。',32,'全唐诗/poet.song.232000.json','["隋朝檜下訪仙真，五十年前夜榻身。", "至道宮前天目頂，羨公去作卧雲人。"]'),
('8f0a05a3-b285-4c5c-8633-e21f1b8fe686','次韻吳僧魁一山十絕  其九','方回','宋','宋诗','song-poetry','','[]','東南衲子密如雲，何限參寥與惠勤。',32,'全唐诗/poet.song.232000.json','["東南衲子密如雲，何限參寥與惠勤。", "泉下歐蘇今不作，伽佗祇夜亂紛紛。"]'),
('0c6b928f-3112-4ce2-9e1d-21f01a1a7611','次韻吳僧魁一山十絕  其一○','方回','宋','宋诗','song-poetry','','[]','高安僧寶姚圓至，鹽水誰其成醤冰。',32,'全唐诗/poet.song.232000.json','["高安僧寶姚圓至，鹽水誰其成醤冰。", "莫爲猢猻打筋斗，迴頭不記讀書燈。"]'),
('02bcbac2-be12-461b-900f-746f772d1d30','鄱陽湯仲材以其家息庵存齋東澗三大老鄂州黄龍寺僧惠璋入石詩裝爲一軸求士大夫贊頌紫陽山下方回之先人字元章嘉定甲戌與晦靜先生同年爲下偈言而不及此意可乎仲材能作祇夜回作伽佗可也  其一','方回','宋','宋诗','song-poetry','','[]','黄鶴磯頭百戰塵，黄龍詩刻尚如新。',32,'全唐诗/poet.song.232000.json','["黄鶴磯頭百戰塵，黄龍詩刻尚如新。", "終然峴首碑安在，羊祜元非死朽人。"]'),
('6eeb2d4c-702b-42b7-b12d-3cb7f0b807f1','鄱陽湯仲材以其家息庵存齋東澗三大老鄂州黄龍寺僧惠璋入石詩裝爲一軸求士大夫贊頌紫陽山下方回之先人字元章嘉定甲戌與晦靜先生同年爲下偈言而不及此意可乎仲材能作祇夜回作伽佗可也  其二','方回','宋','宋诗','song-poetry','','[]','息存東澗三湯老，文我平生盡見之。',32,'全唐诗/poet.song.232000.json','["息存東澗三湯老，文我平生盡見之。", "身到黄龍山幾度，却慚欠讀惠璋碑。"]'),
('b81d58d7-11fd-4de9-a21d-52f2ecfc0bbd','鄱陽湯仲材以其家息庵存齋東澗三大老鄂州黄龍寺僧惠璋入石詩裝爲一軸求士大夫贊頌紫陽山下方回之先人字元章嘉定甲戌與晦靜先生同年爲下偈言而不及此意可乎仲材能作祇夜回作伽佗可也  其三','方回','宋','宋诗','song-poetry','','[]','晦靜先生甲戌榜，元章先子幸同年。',32,'全唐诗/poet.song.232000.json','["晦靜先生甲戌榜，元章先子幸同年。", "升沈一付六如夢，休賦青雲紫陌篇。"]'),
('5e55d075-cb1f-402c-815e-4d30b609a7ac','鄱陽湯仲材以其家息庵存齋東澗三大老鄂州黄龍寺僧惠璋入石詩裝爲一軸求士大夫贊頌紫陽山下方回之先人字元章嘉定甲戌與晦靜先生同年爲下偈言而不及此意可乎仲材能作祇夜回作伽佗可也  其四','方回','宋','宋诗','song-poetry','','[]','水繞芝山過紫陽，倒流不解上南昌。',32,'全唐诗/poet.song.232000.json','["水繞芝山過紫陽，倒流不解上南昌。", "兩家俱有傳燈子，始信真源氣脈長。"]'),
('b835c063-2ea4-4167-aa47-aec21f8325a5','送崑山州教劉表姪','方回','宋','宋诗','song-poetry','','[]','紫陽山下世婚姻，幾度家因火後貧。',64,'全唐诗/poet.song.232000.json','["紫陽山下世婚姻，幾度家因火後貧。", "早是前修曾種德，政須後嗣更禔身。", "秋霜白筆辭臺掾，夜雨青燈管士人。", "碩果元來真不食，未妨徐動蟄雷春。"]'),
('c9d5a965-3138-458d-969b-a882aa0f28a3','九月雪十月雷記異','方回','宋','宋诗','song-poetry','','[]','九月二十五夜雪，南天稻粱未全結。',64,'全唐诗/poet.song.232000.json','["九月二十五夜雪，南天稻粱未全結。", "十月二十五夜雷，東風桃李俱誤開。", "七十三翁駭何謂，雷舊慣聞雪則未。", "水旱國家有倉儲，人能寡慾疫癘無。"]'),
('23304e65-2d61-4194-a166-0d33b1d45931','題鄭提學孔明敬齋','方回','宋','宋诗','song-poetry','','[]','恭惟方寸心，表裏無將迎。',240,'全唐诗/poet.song.232000.json','["恭惟方寸心，表裏無將迎。", "妍醜物不逃，宇宙大明鏡。", "時開復時闔，靜定動亦定。", "孰爲磨且奩，塵垢敢吾競。", "徐步衝牙和，儼立章甫正。", "威嚴修德容，戒懼毓景行。", "典謨冠百王，首言欽恭敬。", "慎寅與祗讓，惴惴遠機穽。", "怠慢惟不敢，茲其所以聖。", "三畏四勿傳，孔顔曾思孟。", "洛學至正叔，主一肅正命。", "乾淳朱逮張，銘箴互規詠。", "奧室鬼神臨，寐枕雷霆迸。", "凜若對廟祭，嚴於聽軍令。", "古君子必爾，持身以蒞政。", "保家雲仍長，理國彊以靚。", "繄予幼不學，乃有東家鄭。", "一謹禦萬邪，道涯自孤泳。", "何當躋公堂，幽話聽犀柄。", "師授分所聞，庶盡人己性。"]'),
('9f87921c-b0a8-481d-bac9-626e96d2b4ad','己亥十一月二十一日長至前一旬書','方回','宋','宋诗','song-poetry','','[]','北極地上三十六度出，南極地下三十六度入。',152,'全唐诗/poet.song.232000.json','["北極地上三十六度出，南極地下三十六度入。", "四海之內居中國，不見南極見北極。", "東生西沒一輪日，西沒昏黑東生白。", "春分秋分晝夜中，天上地下度數同。", "地上天少日晷短，子月日南而北返。", "地上天多日晷長，午月日北而南行。", "四時成歲歲如此，日南日北而已矣。", "一百八十度有奇，不過一往一來耳。", "或謂四游升降殆不然，所以景祐新書刪其篇。"]'),
('cef5e27d-2855-4d0e-876d-aef539f5f8c5','信州道士蕭了空坐逝或見其在湘潭總府貳蕭公用之爲作贊亦自號悟空  其一','方回','宋','宋诗','song-poetry','','[]','了了了了，空空空空，心肝不在臭皮袋中。',35,'全唐诗/poet.song.232000.json','["了了了了，空空空空，心肝不在臭皮袋中。", "想見出神似蟬蛻，可能吸露更餐風。"]'),
('7320dc9a-db94-45b9-bce9-6f6499dde8f8','信州道士蕭了空坐逝或見其在湘潭總府貳蕭公用之爲作贊亦自號悟空  其二','方回','宋','宋诗','song-poetry','','[]','可能吸露更餐風，一悟懸知了萬空。',32,'全唐诗/poet.song.232000.json','["可能吸露更餐風，一悟懸知了萬空。", "何似老夫酒肉漢，死時合眼閉棺中。"]'),
('94a31297-0bd9-47dc-a005-aa2d4bdacc4c','送胡仲虎歸婺源并呈江山長雷','方回','宋','宋诗','song-poetry','','[]','大儒疇昔起乾淳，天地星源一脈真。',64,'全唐诗/poet.song.232000.json','["大儒疇昔起乾淳，天地星源一脈真。", "肯使我爲修學記，始知君是讀書人。", "流泉要驗胸中活，死草無拘紙上陳。", "太極初生第一點，尋根細認古今春。"]'),
('6370d07c-ea69-4398-a138-8c171a92e1a5','題東平張智卿梅軒嘗以墨梅一幅自隨','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','大庾嶺頭江南北，生平走遍梅花國。',260,'全唐诗/poet.song.232000.json','["大庾嶺頭江南北，生平走遍梅花國。", "天下梅花詩最難，和靖居士占第一。", "七十四翁詩萬篇，一句梅花吟不得。", "譬如江夏黄鶴樓，既有崔顥無李白。", "何人幻出一橫枝，毛穎陳玄塗側釐。", "不丹不青逞妙手，月窗瘦影吾能移。", "真梅難賦賦寫梅，虛叟大叫尤難之。", "前身相馬九方句，焉能壓倒簡齋詩。", "張侯隨軒梅一幅，什襲珍藏過寶玉。", "南征不取萬戶侯，北歸未即九州督。", "借梅爲題求詩人，中原名士詩滿軸。", "和靖簡齋亦不無，顧慚才盡難貂續。", "張侯今在西湖隈，竹籬茅屋扃蒼苔。", "我亦自有梅世界，紫陽山中歸去來。", "梅花開時看梅開，花未開時看畫梅。", "不用雕肝刻肺被梅惱，但當一杯一杯復一杯。"]'),
('580f8c66-b4c9-4483-b2b4-b4b1b2c642f7','戴帥初賦道人蕭了空坐逝出神事借韻','方回','宋','宋诗','song-poetry','','[]','漆園老子蝶魂飛，緱氏仙人鶴馭歸。',64,'全唐诗/poet.song.232000.json','["漆園老子蝶魂飛，緱氏仙人鶴馭歸。", "往事何憑煙漠漠，餘生幾度雪霏霏。", "早容身厠三千列，偶許年過七十稀。", "籍湜叛韓吾豈敢，平生不慣食言肥。"]'),
('12701260-d0b7-48ea-a25d-1b99aec8c422','臘八日未雪不寒','方回','宋','宋诗','song-poetry','','[]','寒暖違時節，於民有弗堪。',48,'全唐诗/poet.song.232000.json','["寒暖違時節，於民有弗堪。", "豈應今臘八，恰似舊春三。", "夜□蒸膚汗，朝壺溢唾痰。", "渾疑北風雪，不肯到江南。"]'),
('e34f8154-6dff-4479-b656-7bfcd41281e7','十二月大暖雨二十四晝夜二十五日始雪','方回','宋','宋诗','song-poetry','','[]','夜來聞祭竈，猶賣膠牙餳。',96,'全唐诗/poet.song.232000.json','["夜來聞祭竈，猶賣膠牙餳。", "雪欲爲南瑞，風纔作北聲。", "今年全不冷，此月未嘗晴。", "造化難窺測，神奇易變更。", "淫霖過夏澇，槁樹迸春英。", "熱熱如三伏，飛飛忽六霙。", "花瓶梅盡落，虀甕菜尤平。", "欲掘餛飩薺，嫌泥懶出城。"]'),
('e64eee97-375e-4e3f-9cfa-b7950979a0bb','歲除次韻全君玉有懷二首  其一','方回','宋','宋诗','song-poetry','','[]','心事天涯客海涯，自籌何止一毫差。',64,'全唐诗/poet.song.232000.json','["心事天涯客海涯，自籌何止一毫差。", "枕詩夜夜欹簷溜，濁酒朝朝漉井花。", "元日慣曾經百窘，幼男勉爲講三加。", "揚揚喝道樓前過，肥馬輕裘幾子華。"]'),
('74fc4c88-0aa1-4551-b4a3-f15366c97c95','歲除次韻全君玉有懷二首  其二','方回','宋','宋诗','song-poetry','','[]','全老忽貽寒夜句，歲闌吾黨久離羣。',64,'全唐诗/poet.song.232000.json','["全老忽貽寒夜句，歲闌吾黨久離羣。", "一場噩夢三千字，百載頹齡七八分。", "孰與輓前軒此士，端能殿後棟斯文。", "鄉儺禮失求諸野，小鬼應猶畏竈君。"]'),
('cd54c4e4-fdb1-444e-bb53-3f9edab322ea','庚子元日','方回','宋','宋诗','song-poetry','','[]','臘天何故燠於春，恐爲衣單念小民。',64,'全唐诗/poet.song.232000.json','["臘天何故燠於春，恐爲衣單念小民。", "略見雪纔餘一寸，叵堪雨却過三旬。", "野中薺麥不勝旺，市上杏桃無數新。", "白盡此頭浪多事，可憐七十四年人。"]'),
('c20c58f7-af5c-45d7-a623-fe594ee29787','以桐江舊詩十五卷呈范君澤','方回','宋','宋诗','song-poetry','','[]','人品懸知大不同，一絲羞見釣臺風。',64,'全唐诗/poet.song.232000.json','["人品懸知大不同，一絲羞見釣臺風。", "七年假守如虛叟，萬首新詩似放翁。", "貸死偶餘吟鬢白，每生猶想戰塵紅。", "范侯胸次秋天碧，好借寬閒翼斷鴻。"]'),
('6ea18ea6-35e6-47e1-a08d-bd254dc41d08','正月四日大雨不已愈暖不寒','方回','宋','宋诗','song-poetry','','[]','吳山勝概甲杭州，正旦晴明到上頭。',64,'全唐诗/poet.song.232000.json','["吳山勝概甲杭州，正旦晴明到上頭。", "紅袖南人簪翡翠，金鞍北客驟驊騮。", "豐年似覺春尤好，新歲何爲雨不休。", "自笑詩翁百念冷，尚儕癡子說閒愁。"]'),
('51e6cd3b-9310-4fc5-aaca-d6ad2994b4dd','次韻全君玉元日二首  其一','方回','宋','宋诗','song-poetry','','[]','五更皆早起，惟我是閒人。',48,'全唐诗/poet.song.232000.json','["五更皆早起，惟我是閒人。", "展鏡鬚仍雪，添杯臉暫春。", "有終還復始，無舊不成新。", "萬古燒痕意，陳根豈盡陳。"]'),
('ce642e5c-dfb0-4d49-955f-07cb0bb6e89c','次韻全君玉元日二首  其二','方回','宋','宋诗','song-poetry','','[]','春攽諸郡國，漢守喜惟良。',48,'全唐诗/poet.song.232000.json','["春攽諸郡國，漢守喜惟良。", "旦宿重中尾，時花競向陽。", "古今新舊歷，老少後先觴。", "萬事皆如此，無如且醉狂。"]'),
('01705c49-f9d7-4b0e-a91b-c874cec18c42','次韻君澤正月五日早見示','方回','宋','宋诗','song-poetry','','["\u534e\u5c71"]','人人有此珠，萬古天地寶。',240,'全唐诗/poet.song.232000.json','["人人有此珠，萬古天地寶。", "法當潜厥光，蚌殻護其表。", "能使華嶽移，可叱峽流倒。", "未若牀缺足，梓匠不自造。", "脫華培深根，屏翳返內照。", "與辨以興戎，寧訥而出好。", "恭惟羲皇心，豈有夜與曉。", "我眼徹地底，常見日皎皎。", "爰自彖及繫，纂述屢脫稿。", "仙游慕昇飛，佛障怯煩惱。", "九轉與八解，終不擺纏繞。", "彼豈知吾學，往來玩大小。", "艮止體陰負，離明决陽抱。", "平生無所媚，不竈亦不奧。", "突過子雲玄，眇視老氏妙。", "慎察進退間，以爲先師報。", "宜耦長沮耕，遑待方朔詔。", "黑頭氣公旺，黄馘項吾槁。", "一當蟄幽閒，一當翔穹昊。", "何以明其然，□□□衰老。"]'),
('eaf67a5d-568a-448e-8b2a-2e69e5a5a4e9','次韻君澤夜坐示子姪三首  其一','方回','宋','宋诗','song-poetry','','[]','燈影稀疏兩岸樓，市聲已寂睡聲齁。',64,'全唐诗/poet.song.232000.json','["燈影稀疏兩岸樓，市聲已寂睡聲齁。", "幾家夢斷三更過，此老心窮八極游。", "服氣仙人吾不學，坐禪釋子彼何求。", "夜思晝讀諸郎識，俯仰青春鬢忽秋。"]'),
('e946e0a1-dc11-4b63-bff6-e98a6be3588e','次韻君澤夜坐示子姪三首  其二','方回','宋','宋诗','song-poetry','','[]','一樣乾坤幾樣人，甑生塵異襪生塵。',64,'全唐诗/poet.song.232000.json','["一樣乾坤幾樣人，甑生塵異襪生塵。", "寒窗黄卷青燈雨，暖閣金釵玉斝春。", "誰同公子夢方魘，我與先生詩又新。", "□□兒曹供筆墨，爲言不是寫真真。"]'),
('cfc853d8-8d9a-4230-87d4-2eb2c07f1bf2','次韻君澤夜坐示子姪三首  其三','方回','宋','宋诗','song-poetry','','[]','雨脚如麻坐到明，雨樓聽盡五更聲。',64,'全唐诗/poet.song.232000.json','["雨脚如麻坐到明，雨樓聽盡五更聲。", "無人共唱尋尋覓，有子聊教仄仄平。", "凌室不能藏臘凍，稼場或至誤秋成。", "誰知憂世書生意，惟願天階正玉衡。"]'),
('5dc5ad03-869f-4ba7-9db7-cb00be8023d6','人日立春記苦雨無冰','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','三十七日晝夜雨，中間一雪終無冰。',128,'全唐诗/poet.song.232000.json','["三十七日晝夜雨，中間一雪終無冰。", "今日立春遇人日，問天肯晴天不應。", "東南我記前庚子，徽城紙包餽杭米。", "乞人搶奪人食人，旱極西湖乾見底。", "今我七十四歲翁，苟全性命遨春風。", "略雪不冰又庚子，幸而去年秋猶豐。", "西湖莫作癡貓守，紫陽山下可歸否。", "天終不殺好心人，有錢買花仍買酒。"]'),
('bc8d0c72-0023-4dbb-8f64-d4a0746211e6','正月十九日四更起讀朱文公年譜至天大明賦十二首  其一','方回','宋','宋诗','song-poetry','','[]','夜寐若無三斗酒，夙興不待五更鐘。',32,'全唐诗/poet.song.232000.json','["夜寐若無三斗酒，夙興不待五更鐘。", "浩歌閒把鐵如意，□慕先生憶卧龍。"]'),
('9fd264a9-67a1-4a1e-be24-f71c55d241af','正月十九日四更起讀朱文公年譜至天大明賦十二首  其二','方回','宋','宋诗','song-poetry','','[]','顛楊仆墨詆蘇張，推挽時君可帝王。',32,'全唐诗/poet.song.232000.json','["顛楊仆墨詆蘇張，推挽時君可帝王。", "軻死不傳今再見，一時無數起臧倉。"]'),
('f1520d42-6d24-4ed2-84e6-fe678299efb5','正月十九日四更起讀朱文公年譜至天大明賦十二首  其三','方回','宋','宋诗','song-poetry','','[]','獨能有眼識延平，濂洛淵源集大成。',32,'全唐诗/poet.song.232000.json','["獨能有眼識延平，濂洛淵源集大成。", "早負性資專問學，後生豈可少先生。"]'),
('9c60206f-bb49-4e5b-a815-57010cf70c58','正月十九日四更起讀朱文公年譜至天大明賦十二首  其四','方回','宋','宋诗','song-poetry','','[]','鄉國追封初豈意，師垣極品亦何心。',32,'全唐诗/poet.song.232000.json','["鄉國追封初豈意，師垣極品亦何心。", "考功郎議一字□，□相斯文上帝臨。"]'),
('2ea7572a-03b0-4e27-b26b-1502692ecbad','正月十九日四更起讀朱文公年譜至天大明賦十二首  其五','方回','宋','宋诗','song-poetry','','[]','王道浪談行霸說，儒言陰用佐禪機。',32,'全唐诗/poet.song.232000.json','["王道浪談行霸說，儒言陰用佐禪機。", "貪狼弧矢觀星象，天遣吾公闢此非。"]'),
('87803954-087f-400e-ada2-7fe50f8a5889','正月十九日四更起讀朱文公年譜至天大明賦十二首  其六','方回','宋','宋诗','song-poetry','','[]','本無極老謂主靜，不遠復翁言內腴。',32,'全唐诗/poet.song.232000.json','["本無極老謂主靜，不遠復翁言內腴。", "紙上仙方誰解服，尾公羽化上天衢。"]'),
('bca76cd0-43ca-4044-990b-0faf28d0f957','正月十九日四更起讀朱文公年譜至天大明賦十二首  其七','方回','宋','宋诗','song-poetry','','[]','草制無知傅伯壽，問詩不答陳傅良。',32,'全唐诗/poet.song.232000.json','["草制無知傅伯壽，問詩不答陳傅良。", "王淮林栗胡紘輩，仲尼日月曾何傷。"]'),
('98cbc612-1a00-405a-9f52-9c612e4bdc89','正月十九日四更起讀朱文公年譜至天大明賦十二首  其八','方回','宋','宋诗','song-poetry','','[]','孟子告子辨內外，漢王項王爭雌雄。',32,'全唐诗/poet.song.232000.json','["孟子告子辨內外，漢王項王爭雌雄。", "誰歟著定會陔錄，梭象終輸與遯翁。"]'),
('5439fb37-fd5c-4493-9a0f-a078a0e986c3','正月十九日四更起讀朱文公年譜至天大明賦十二首  其九','方回','宋','宋诗','song-poetry','','[]','四世東南保太平，有君無相廟堂輕。',32,'全唐诗/poet.song.232000.json','["四世東南保太平，有君無相廟堂輕。", "具知人眼識朱子，獨趙汝愚陳俊卿。"]'),
('2852bbbc-d83a-44ff-bb21-f03c86819750','正月十九日四更起讀朱文公年譜至天大明賦十二首  其一○','方回','宋','宋诗','song-poetry','','[]','澹庵老薦此詩人，屈道何妨可致身。',32,'全唐诗/poet.song.232000.json','["澹庵老薦此詩人，屈道何妨可致身。", "負鼎干湯公豈肯，本來餘事壓黄陳。"]'),
('7f5ef96a-85e7-41a9-ac1f-c82bee773a90','正月十九日四更起讀朱文公年譜至天大明賦十二首  其一一','方回','宋','宋诗','song-poetry','','[]','考官蔡茲取三策，三奏賞音汪應辰。',32,'全唐诗/poet.song.232000.json','["考官蔡茲取三策，三奏賞音汪應辰。", "天下未嘗無識者，近來識者亦無人。"]'),
('2b11ea20-d37c-4f28-a765-c7832c7e2ae8','正月十九日四更起讀朱文公年譜至天大明賦十二首  其一二','方回','宋','宋诗','song-poetry','','[]','開禧嘉定擅權臣，地下眉頭想更顰。',32,'全唐诗/poet.song.232000.json','["開禧嘉定擅權臣，地下眉頭想更顰。", "侂遠傳衣至亡國，止緣不用讀書人。"]'),
('f87b2b94-845f-41d0-b7dc-de3cd5f2d652','久不作詩非避俗議偶老懶且次范君澤韻','方回','宋','宋诗','song-poetry','','[]','俗坌蝟毛奮，老倦龜殻縮。',96,'全唐诗/poet.song.232000.json','["俗坌蝟毛奮，老倦龜殻縮。", "閉門自著書，此外百無欲。", "試將雙鬢比，我白君尚綠。", "固宜斗百篇，醉不問今昨。", "異端朱翟徒，孟子闢之廓。", "傲睨則有之，未必果落魄。", "焉得百尺樓，與公共盤礴。", "坐令許汜輩，螟蟭仰黄鶴。"]'),
('f26ec881-4c99-41c1-bb0e-36b8166fb9d9','讀魏鶴山先生渠陽集五首  其一','方回','宋','宋诗','song-poetry','','[]','登門四十九年多，細讀公書百遍過。',32,'全唐诗/poet.song.232000.json','["登門四十九年多，細讀公書百遍過。", "今歲摘抄靖州作，遯翁堪配不傳軻。"]'),
('12722116-c867-4228-9efe-29420cd6ad02','讀魏鶴山先生渠陽集五首  其二','方回','宋','宋诗','song-poetry','','[]','濂翁傳到紫陽朱，復見嘉端此大儒。',32,'全唐诗/poet.song.232000.json','["濂翁傳到紫陽朱，復見嘉端此大儒。", "一論道原一原道，他求倫擬漢唐無。"]'),
('525e1109-c499-44b4-84ce-16cd8c900e3e','讀魏鶴山先生渠陽集五首  其三','方回','宋','宋诗','song-poetry','','[]','漢唐臺閣畫功臣，何似宣尼從祀人。',32,'全唐诗/poet.song.232000.json','["漢唐臺閣畫功臣，何似宣尼從祀人。", "欲繪兩賢繼張呂，臨邛魏老建安真。"]'),
('f9b23250-b187-4e35-9579-827d303457d8','讀魏鶴山先生渠陽集五首  其四','方回','宋','宋诗','song-poetry','','[]','投荒彌遠凶徒熾，出督清之狡計行。',32,'全唐诗/poet.song.232000.json','["投荒彌遠凶徒熾，出督清之狡計行。", "得柄欺君例如此，國亡徒剩正人名。"]'),
('adf7723c-e486-4ef5-a91e-f0cc23dad761','讀魏鶴山先生渠陽集五首  其五','方回','宋','宋诗','song-poetry','','[]','瀛登湘渡偶皆同，一了乾坤此兩翁。',32,'全唐诗/poet.song.232000.json','["瀛登湘渡偶皆同，一了乾坤此兩翁。", "前後身吾雖未信，俱遭權孽肆姦凶。"]'),
('1912718f-247c-45a1-ab96-6460033e4fa0','范文正公楷書昌黎伯夷頌平江李使君信之久藏真本以歸文正遠孫族長士貴祠以少牢復其家','方回','宋','宋诗','song-poetry','','[]','班固人表吾嘗疑，第一武王二伯夷。',224,'全唐诗/poet.song.232000.json','["班固人表吾嘗疑，第一武王二伯夷。", "我謂伯夷可第一，武未盡善宜二之。", "退之第一唐文人，希文第一宋輔臣。", "韓爲夷頌范爲寫，三絕誰爲什襲珍。", "星奎運踰三百年，皇祐慶曆諸鉅賢。", "逮至渡江乾淳後，珠題玉跋盈長篇。", "范氏衮衮饒公侯，幽州栝州至蘇州。", "行軍元昊驚破膽，義莊睦族春復秋。", "子子孫孫居吳中，指李後人今黄龔。", "錦囊偶貯此三絕，燕香夜寒吐長虹。", "衮衣繡衣觀且誇，故國喬木興咨嗟。", "大尹不吝歸趙璧，祠以少牢復其家。", "提學翰林索我詩，肯捐此寶真復奇。", "授者良難受者易，即此可刊遺愛碑。"]'),
('fe484b07-3494-4d22-a8a5-7020fedeafe4','送張伯起入都二首  其一','方回','宋','宋诗','song-poetry','','[]','元侯可文學，未壯冠貂蟬。',48,'全唐诗/poet.song.232000.json','["元侯可文學，未壯冠貂蟬。", "之子觀光日，前修致政年。", "芹宮堪注擬，瓜戍尚遲延。", "定有羣公薦，班行綴集賢。"]'),
('5484f156-68ee-4325-8540-d7cd5c6c34d2','送張伯起入都二首  其二','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖風景異，因仕住桐川。',48,'全唐诗/poet.song.232000.json','["西湖風景異，因仕住桐川。", "太守令求宅，諸生爲買田。", "冷官清可喜，遠道老堪憐。", "何似嚴灘守，投簪二十年。"]'),
('04dac716-9153-4bf9-9b78-8291567bc23c','二月朔大雪已五日三首  其一','方回','宋','宋诗','song-poetry','','[]','侵尋半月是花朝，大雪漫天五日飄。',32,'全唐诗/poet.song.232000.json','["侵尋半月是花朝，大雪漫天五日飄。", "臘月如春衆芳吐，繁華時節却蕭條。"]'),
('2c60bf23-e61b-44cc-bf4d-f1d36e955396','二月朔大雪已五日三首  其二','方回','宋','宋诗','song-poetry','','[]','燕山雪花大如席，豈料江南亦見之。',32,'全唐诗/poet.song.232000.json','["燕山雪花大如席，豈料江南亦見之。", "臘前六出知焉往，却在春風二月時。"]'),
('8804ccf6-5c37-4855-969b-a115ba66bb75','二月朔大雪已五日三首  其三','方回','宋','宋诗','song-poetry','','[]','牛馬毛寒縮如蝟，古今此句絕奇奇。',32,'全唐诗/poet.song.232000.json','["牛馬毛寒縮如蝟，古今此句絕奇奇。", "今春大雪亦將爾，鶑死無聲社燕遲。"]'),
('6c9cd5fc-7d72-4903-9e95-fe1697faf517','題趙子昂摹唐人二戲馬駒','方回','宋','宋诗','song-poetry','','[]','我嘗遠過燕山北，樹木已無草一色。',116,'全唐诗/poet.song.232000.json','["我嘗遠過燕山北，樹木已無草一色。", "騏驥驊騮動萬匹，互囓交蹄戲跳躑。", "誰歟畫此雙名駒，似鬬非鬬相嬉娛。", "唐人遺迹趙子摹，善書善畫今代無。", "善書突過元章米，善畫追還伯時李。", "先畫後書此一紙，咫尺之間兼二美。", "元章伯時兩人合一人，愧我一詩難寫兩人真。"]'),
('5739bac0-bdcc-4231-9d5c-ef756f435210','送白廷玉常州教二首  其一','方回','宋','宋诗','song-poetry','','[]','世間可讀不多書，豈但撐腸似蠹魚。',64,'全唐诗/poet.song.232000.json','["世間可讀不多書，豈但撐腸似蠹魚。", "小技僅能攻淺近，大言徒用騁高虛。", "道心切戒偏忘助，義事毋先計毀譽。", "我學暮年方見此，毗陵博士比何如。"]'),
('1b30caf6-b000-45a0-af6b-f27f89648d48','送白廷玉常州教二首  其二','方回','宋','宋诗','song-poetry','','[]','詩酒論交幾歲寒，更無我輩甕虀酸。',64,'全唐诗/poet.song.232000.json','["詩酒論交幾歲寒，更無我輩甕虀酸。", "劇談公每掀髯笑，偉幹人皆仰面看。", "縱使未前乙夜席，何妨暫作甲科官。", "祖風雅肖香山白，白玉堂登未是難。"]'),
('1cc6d79e-5e03-492c-85d0-df1e178be347','送男存心如燕二月二十五日夜走筆古體  其一','方回','宋','宋诗','song-poetry','','[]','我年三十四，鄂漢脫戰場。',288,'全唐诗/poet.song.232000.json','["我年三十四，鄂漢脫戰場。", "四月扁舟東，生汝於建康。", "九載鶴山門，靜翁還鵷行。", "實爲舊主人，別意殊徊徨。", "爾時京湖閫，開府羅才良。", "呂氏賢父子，欲我高騰驤。", "補以□□爵，江岸司征航。", "既而今左轄，千騎如池陽。", "携我一家往，郡齋代表章。", "汝姊始四歲，同爾歸南堂。", "明年辛酉秋，浙漕鶚薦翔。", "道山此大恩，給我鬻爵郎。", "別省第一人，見知梧與杭。", "不學執國柄，似道貪如狼。", "其客福建子，瑩中狼如羊。", "厥子偶不第，乃獨憾老方。", "讒之於似道，陰幽弩機張。", "廷試復第一，考官文趙常。", "易置乙科首，爾豈識臭香。", "蕭艾壓蘭蕙，我心亦不忙。", "仕宦天有命，豈由人低昂。", "不意毒愈盛，廖真嬖人倉。", "五百彼何知，四遭白簡霜。", "故嘗忤林秴，何至嗾郭閶。"]'),
('7604dae6-f0de-4661-8b7f-d119e493f199','送男存心如燕二月二十五日夜走筆古體  其二','方回','宋','宋诗','song-poetry','','[]','大物既歸周，裸士來殷商。',288,'全唐诗/poet.song.232000.json','["大物既歸周，裸士來殷商。", "夷齊與箕微，均爲識三綱。", "我所領小壘，可容久徜徉。", "亦欲拾之去，羣盜紛寇攘。", "勉强不得已，芟惡完善良。", "完國非我責，完郡亦何傷。", "幸保千里民，不爲劍戟戕。", "姦鬼伏肘腋，兩賊程與黄。", "門生訐座主，婿不顧糟糠。", "妄告無反坐，官吏飽賄贓。", "一朝擲笏綬，僅有書幾囊。", "辛巳至庚子，闔門饑欲僵。", "二十年不仕，愚意誰揣量。", "苟生內自愧，一思汗如漿。", "焉得掛海席，萬里窮扶桑。", "茅屋蔭松菊，槿籬畦芋薑。", "讀書粗知道，晦遯攀餘芳。", "詩文亦不俗，千篇垂琳琅。", "今汝往筮仕，已踰四十强。", "蕭然乏行李，艱甚謀聚糧。", "此皆我之過，棄官畏禍殃。", "以致兒女輩，無不羸以尫。", "行行燕山下，悠悠易水傍。", "北風無時無，南人少裘裳。"]'),
('c2808990-3107-422c-b74b-31a728754fca','送方復大宣城學錄  其一','方回','宋','宋诗','song-poetry','','[]','莆田鄣郡本同宗，更著深衣臭味同。',64,'全唐诗/poet.song.232000.json','["莆田鄣郡本同宗，更著深衣臭味同。", "禿筆有天猶易補，孤燈無地可能容。", "不趨宰相翹材館，寧糾諸侯泮水宮。", "十載鳳池科尚在，已應一舉首登龍。"]'),
('88086fab-8e29-4291-a2d2-4b8d13b31d8e','送方復大宣城學錄  其二','方回','宋','宋诗','song-poetry','','[]','方氏來南漢閏時，蒸嘗所在富孫枝。',64,'全唐诗/poet.song.232000.json','["方氏來南漢閏時，蒸嘗所在富孫枝。", "歙溪真應仙翁墓，嚴瀨玄英處士祠。", "邂逅弟兄元共祖，殷勤子我總能詩。", "因風不要花瓜顆，梅老遺篇幸寄之。"]'),
('5e0d2efc-df4a-438a-a840-e01e19a0d025','再送羅雲叔','方回','宋','宋诗','song-poetry','','[]','欲共君歸未有緣，春風奪我紫陽天。',64,'全唐诗/poet.song.232000.json','["欲共君歸未有緣，春風奪我紫陽天。", "牡丹富豔花如洛，煮白香濃酒似燕。", "細看貌非寒士相，隨宜班亞冷官員。", "人間第一好山處，賦幾篇詩醉幾筵。"]'),
('55cba8d4-37f0-4ccc-b9cb-40628e909685','題龍虎山高士毛和叔愚泉詩稿','方回','宋','宋诗','song-poetry','','[]','暫住身如鶴在松，忽然飛去又無蹤。',32,'全唐诗/poet.song.232000.json','["暫住身如鶴在松，忽然飛去又無蹤。", "閤皂山頭曾不睡，夜寒看月到晨鐘。"]'),
('da157606-76e4-4532-ae31-83e048bd5424','宗兄端叟年七十六來訪二首  其一','方回','宋','宋诗','song-poetry','','[]','年才踰壯早相知，北騎南船幾別離。',64,'全唐诗/poet.song.232000.json','["年才踰壯早相知，北騎南船幾別離。", "二老皆鄰八旬壽，一生誰賦萬篇詩。", "特承枉顧元無說，獲侍同行識者誰。", "流水桃花別天地，碧山許到果何時。"]'),
('c3ff5fc8-7f38-4aca-9d4e-bbfeecb18f2f','宗兄端叟年七十六來訪二首  其二','方回','宋','宋诗','song-poetry','','[]','遼廣歸來二紀强，脫身煙瘴遠沙場。',64,'全唐诗/poet.song.232000.json','["遼廣歸來二紀强，脫身煙瘴遠沙場。", "僧多吟友詩常淡，家見玄孫壽且康。", "殘月夜潮渡漁浦，飛花春雨客錢塘。", "西山後會何妨數，管趁年年早茗香。"]'),
('850e529f-c90a-49fc-aa3a-80fee757af5f','三月八日百五節林敬輿携酒約盛元仁戴帥初方萬里訪趙仲實宣慰於西湖第五橋之曲港南山書院五首  其一','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','第五橋通曲港船，直摇春水到門前。',64,'全唐诗/poet.song.232000.json','["第五橋通曲港船，直摇春水到門前。", "休官久作漁竿客，扶老來尋鶴氅仙。", "疇曩歡娛如昨日，今吾衰颯最高年。", "舊墳新冢石羊馬，且舉殘杯莫愴然。"]'),
('9ebc77d4-af79-4c56-a61a-19b2db9bf40e','三月八日百五節林敬輿携酒約盛元仁戴帥初方萬里訪趙仲實宣慰於西湖第五橋之曲港南山書院五首  其二','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖山春色已如斯，城市原來了不知。',64,'全唐诗/poet.song.232000.json','["湖山春色已如斯，城市原來了不知。", "百五韶華全似畫，二三名勝總能詩。", "忽驚我輩相携處，誰識吾人始到時。", "五十四年前弱冠，設盆猶憶唱閩詞。"]'),
('2b5be5a8-d7f2-4e16-9805-b91083266a26','三月八日百五節林敬輿携酒約盛元仁戴帥初方萬里訪趙仲實宣慰於西湖第五橋之曲港南山書院五首  其三','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','暮年無不與心違，節物過從事總非。',64,'全唐诗/poet.song.232000.json','["暮年無不與心違，節物過從事總非。", "何處青梅嘗煮酒，誰家紅藥試單衣。", "半酣便合拏舟去，驟熱猶容借扇歸。", "忽憶向來獨立處，雪天閒看白鷗飛。"]'),
('53753e7c-4f6a-4c8f-9b01-891a22976c9c','三月八日百五節林敬輿携酒約盛元仁戴帥初方萬里訪趙仲實宣慰於西湖第五橋之曲港南山書院五首  其四','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','生長西湖死葬湖，興言舟子與農夫。',64,'全唐诗/poet.song.232000.json','["生長西湖死葬湖，興言舟子與農夫。", "全家衣食憑摇艣，歷世兒孫學荷鋤。", "布衲劣兼蓑笠有，虀湯恐併醤醯無。", "金盤玉筯環歌舞，午鬨昏空一任渠。"]'),
('be988620-28ba-4e7d-98d9-6f02b1b9d47f','三月八日百五節林敬輿携酒約盛元仁戴帥初方萬里訪趙仲實宣慰於西湖第五橋之曲港南山書院五首  其五','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','後生誰識舊西湖，除却山僧樹總無。',64,'全唐诗/poet.song.232000.json','["後生誰識舊西湖，除却山僧樹總無。", "何至梅仙墳亦掘，惟應葛嶺鬼當誅。", "紅裙鞭鐙追游女，白首端章笑腐儒。", "兩盞三杯更多感，不如爛醉眼模糊。"]'),
('152b5845-75d0-4c49-8382-4a78f9f7bb07','送徐君奇入燕','方回','宋','宋诗','song-poetry','','[]','貌寢如孫叔，貲單未計然。',48,'全唐诗/poet.song.232000.json','["貌寢如孫叔，貲單未計然。", "曾微方朔辯，已過買臣年。", "插翅能踰海，乘槎可上天。", "問君何所恃，珠玉富千篇。"]'),
('47b6d7ed-e1b0-42db-a065-3200ff9a4e67','贈筆工楊日新','方回','宋','宋诗','song-poetry','','[]','黄鐘九寸裁爲律，六呂六律相配匹。',240,'全唐诗/poet.song.232000.json','["黄鐘九寸裁爲律，六呂六律相配匹。", "嶰谷參差十二筩，猗管城子從此出。", "上古蒼頡初制字，後人蒙恬始造筆。", "吳云不律燕云弗，韻書又以律爲聿。", "曰方曰冊刀削之，削之筆之作以述。", "析竹蘸墨絲其端，龍圖龜書就篇帙。", "秋兔拔毛號毛穎，愈奇愈巧愈精密。", "脩管執之以爲柄，短管竅之以爲室。", "其實不過一毫端，良工於此有神術。", "鋒但欲齊忌太尖，翠羽鼠鬚俱不必。", "老夫平生學歐顔，晚脫場屋塗注乙。", "著書棄筆如丘山，使年將及三萬日。", "眼花尚能寫蠅頭，筆不如意輒怒叱。", "江淮筆工千百家，孰甲孰乙我所悉。", "鷄距散卓楊日新，不落第二亦第一。"]'),
('0af00bd4-e941-458a-bff9-7a1014b118a0','次韻謝嚴養晦酒邊說易','方回','宋','宋诗','song-poetry','','[]','四正爲奇偶四隅，舊窺七七古河圖。',64,'全唐诗/poet.song.232000.json','["四正爲奇偶四隅，舊窺七七古河圖。", "易雖未畫元知有，極果何形孰識無。", "方寸天開通造化，半生夜坐下工夫。", "老衰多學精專少，病體摳趨但要扶。"]'),
('0af9928e-5068-47e6-ac09-a8c44b603371','送紫陽趙山長治台叟三首  其一','方回','宋','宋诗','song-poetry','','[]','昭代英髦盛，文儒氣數還。',48,'全唐诗/poet.song.232000.json','["昭代英髦盛，文儒氣數還。", "天明黄道日，地重紫陽山。", "斗食三年內，孤燈午夜間。", "晦翁元不死，鑽仰定睎顔。"]'),
('b126ee72-bf8c-4f21-8652-d8224f947089','送紫陽趙山長治台叟三首  其二','方回','宋','宋诗','song-poetry','','[]','山好鄰書塾，溪翁割釣磯。',48,'全唐诗/poet.song.232000.json','["山好鄰書塾，溪翁割釣磯。", "許時爲客久，長是送人歸。", "子去青衿喜，吾衰白髪稀。", "會須桐蔭底，酬唱羽觴飛。"]'),
('2dcfa026-e00c-4509-a6fe-48b6ca073b82','送紫陽趙山長治台叟三首  其三','方回','宋','宋诗','song-poetry','','[]','昔年初弱冠，丙午創書堂。',48,'全唐诗/poet.song.232000.json','["昔年初弱冠，丙午創書堂。", "四海仰朱子，萬山環紫陽。", "工夫誰久大，邃密要商量。", "舊日鵝湖語，端能子細詳。"]'),
('fb32f00d-0454-4556-812a-085d26500efb','怪夢十首  其一','方回','宋','宋诗','song-poetry','','[]','高枕非難就，深杯未易謀。',48,'全唐诗/poet.song.232000.json','["高枕非難就，深杯未易謀。", "可須疑噩夢，久已慣窮愁。", "老矣何嫌死，歸歟豈願留。", "曉梁數聲燕，搔首倚吾樓。"]'),
('54c5b823-3ea9-4c2b-a5bb-72a3266ae3ee','怪夢十首  其二','方回','宋','宋诗','song-poetry','','[]','倜儻千金盡，艱難斗酒謀。',48,'全唐诗/poet.song.232000.json','["倜儻千金盡，艱難斗酒謀。", "有生誰不死，惟醉暫無愁。", "彭澤先生去，周南太史留。", "誰家錦步障，還墜綠珠樓。"]'),
('af328cb5-1eca-481f-98ba-6eb4dcbbb1ce','怪夢十首  其三','方回','宋','宋诗','song-poetry','','[]','休官二十載，絲髪不身謀。',48,'全唐诗/poet.song.232000.json','["休官二十載，絲髪不身謀。", "肯顧江淹恨，焉知庾信愁。", "但當思反魯，何必望封留。", "閉目常危坐，胸中百尺樓。"]'),
('460eed40-915b-49a3-af94-0ec696923d34','怪夢十首  其四','方回','宋','宋诗','song-poetry','','[]','身謀曾不暇，何况子孫謀。',48,'全唐诗/poet.song.232000.json','["身謀曾不暇，何况子孫謀。", "我老宜多病，癡人豈識愁。", "管窺天謂小，繩挽日難留。", "將騎言何猥，蒼茫下白樓。"]'),
('626fec69-602a-4a63-a02f-29f5ab9ec943','怪夢十首  其五','方回','宋','宋诗','song-poetry','','[]','勤能將拙補，命輒與仇謀。',48,'全唐诗/poet.song.232000.json','["勤能將拙補，命輒與仇謀。", "尚有江湖債，終無世俗愁。", "已衰猶未死，欲去又還留。", "萬事鵝兒酒，諸公燕子樓。"]'),
('f86453a5-6e07-469a-8d4d-0d6540fb36fb','怪夢十首  其六','方回','宋','宋诗','song-poetry','','[]','文宗韓吏部，詩學杜參謀。',48,'全唐诗/poet.song.232000.json','["文宗韓吏部，詩學杜參謀。", "餘子焉能凂，吾徒別有愁。", "潮陽寧遠謫，補闕肯中留。", "往事驚棋局，餘生付酒樓。"]'),
('5781b745-762c-46a0-9e7d-cf7ee6a64ce4','怪夢十首  其七','方回','宋','宋诗','song-poetry','','[]','子午參同契，春秋類是謀。',48,'全唐诗/poet.song.232000.json','["子午參同契，春秋類是謀。", "生前焉用學，死外別無愁。", "豈料猶窮健，胡爲此滯留。", "客懷誰可比，王粲賦登樓。"]'),
('1e40b259-ed7f-4c61-a1d7-3b2927f94188','怪夢十首  其八','方回','宋','宋诗','song-poetry','','[]','三朝前穀雨，寒甚過時謀。',48,'全唐诗/poet.song.232000.json','["三朝前穀雨，寒甚過時謀。", "夜短雞聲早，春闌燕語愁。", "獨行仍獨坐，難去又難留。", "粗守持身法，堅城護百樓。"]'),
('cd7d34d9-32f7-4915-b22f-8de390cf74fe','怪夢十首  其九','方回','宋','宋诗','song-poetry','','[]','萬變觀時事，誰其肉食謀。',48,'全唐诗/poet.song.232000.json','["萬變觀時事，誰其肉食謀。", "乾坤一儒腐，今古兩眉愁。", "白首生何益，青春逝不留。", "孤燈夜夜坐，曉角動軍樓。"]'),
('7abfdb0e-c608-4279-b7cf-9793f1b28f03','怪夢十首  其一○','方回','宋','宋诗','song-poetry','','[]','昔日顓朝柄，何人誤廟謀。',48,'全唐诗/poet.song.232000.json','["昔日顓朝柄，何人誤廟謀。", "漸驚吾輩盡，誰識向來愁。", "忠鯁芳香在，姦邪臭穢留。", "一時窮富貴，蜃氣結成樓。"]'),
('61902eca-2c7c-41c6-86f7-073104f745cb','三月二十九夜二更杭火焚花巷壽安坊至四月一日寅卯止','方回','宋','宋诗','song-poetry','','[]','傾國傾城誇美色，千金萬金供首飾。',227,'全唐诗/poet.song.232000.json','["傾國傾城誇美色，千金萬金供首飾。", "武林城中花巷名，紹興年前人未識。", "亮死瓜洲再講和，巷名不爲栽花窠。", "象珠翠玳玉笄外，紫紫紅紅裁綺羅。", "是時永嘉有佳士，歎嗟花巷名太侈。", "繁華漸盛古朴衰，書謂鄉人非美事。", "誰知驁集一朝非，婦鬟女髻彌芳菲。", "冠梳簪珥向曉賣，百僞一真無關譏。", "戊戌年冬十月十，爇此闤闠成瓦礫。", "豈料鬰攸再作祟，庚子春殘小盡日。", "一十六度蓂莢新，兩見焦頭花巷人。", "買賣假花牟厚利，坐此得罪於神明。", "君不見九重一言軒輊易，頭白紛紛無忌諱。", "人人一朵牡丹春，四海太平呼萬歲。"]'),
('8b37cbf9-186f-4386-b51b-9222ba014cf3','次韻王起宗勉爲高子明繪松巖圖','方回','宋','宋诗','song-poetry','','[]','松下客携琴，巖中人讀書。',72,'全唐诗/poet.song.232000.json','["松下客携琴，巖中人讀書。", "聲氣相應求，妙寫入畫圖。", "灑落真意趣，冷淡閒工夫。", "體中脫不佳，明窗時自娛。", "誰方策龍驤，萬里籋雲衢。", "卿自用卿法，未用輕賢愚。"]'),
('9198eb3e-71af-4933-87e3-7e72e77f6e18','鉛山虞華甫往謝疊山枋得君直爲書耕隠二字今年八十一其子舜臣字舜民來見嘗師君直年四十九求賦耕隠詩','方回','宋','宋诗','song-poetry','','[]','君直不可見，見此長虹吐。',120,'全唐诗/poet.song.232000.json','["君直不可見，見此長虹吐。", "使其尚未死，年始七十五。", "當時書此字，贈我老華甫。", "今年八十一，仍卧舊處所。", "謝公名太盛，殺身甘荼苦。", "虞公不競名，躬耕隠村塢。", "有名無名間，俯仰隔今古。", "直木先剪拜，明膏自煎煮。", "何如牛背上，一蓑弄煙雨。", "所以馬少游，伏波非所取。"]'),
('6b74c898-6399-4029-a378-70a3d4a4f7b7','跋郝仲雨游梁百韻','方回','宋','宋诗','song-poetry','','[]','讀君百詠魏中梁，始僭諸侯又僭王。',32,'全唐诗/poet.song.232000.json','["讀君百詠魏中梁，始僭諸侯又僭王。", "孟子兩言無識者，六王亡更七王亡。"]'),
('ace943cf-c2d9-4bf1-bf94-b64ea59fa9d8','偶書','方回','宋','宋诗','song-poetry','','[]','忽明詩眼一螢飛，夜讀樓頭暑暫微。',64,'全唐诗/poet.song.232000.json','["忽明詩眼一螢飛，夜讀樓頭暑暫微。", "多醉少醒忘世故，易消難長察天機。", "郭中令考書廛隠，公冶長篇過古稀。", "正爾山林可投老，果何所戀不思歸。"]'),
('ef2ce837-73ea-4c22-87e0-5ac750f3d9ff','讀方處士墓誌挽詩題其後閻集賢承旨文趙翰直書傅學士序','方回','宋','宋诗','song-poetry','','[]','瑰文寶翰勒堅珉，薤露諸篇序更新。',64,'全唐诗/poet.song.232000.json','["瑰文寶翰勒堅珉，薤露諸篇序更新。", "鳳閣鸞臺三學士，羊裘魚釣一詩人。", "登金競奮凌雲筆，埋玉如瞻墊雨巾。", "逢掖的過二千石，九原不死氣如神。"]'),
('fd67f43a-38a9-4fb8-a5f9-186954592c4d','題程氏麟嘉壽域','方回','宋','宋诗','song-poetry','','[]','當年此地瑞麒麟，預卜佳城壽檟春。',64,'全唐诗/poet.song.232000.json','["當年此地瑞麒麟，預卜佳城壽檟春。", "早把一官爲長物，永期千歲作全人。", "盈消虛息知時命，戰履兢臨保性真。", "馬革裹屍空志大，寧騎款段了閒身。"]'),
('dccee0d8-6504-4d9f-b8c7-a393b49f40fe','送趙無己之臨川','方回','宋','宋诗','song-poetry','','[]','古之諸侯公侯伯，今之諸侯二千石。',281,'全唐诗/poet.song.232000.json','["古之諸侯公侯伯，今之諸侯二千石。", "建邦作郡事不同，後車皆當載賓客。", "釣魚呂望朝棄竿，飯牛甯越夜辭軛。", "雲龍風虎機會偶，赫奕功名垂竹帛。", "原嘗春陵四公子，珠履三千分鼎食。", "馮讙市義薄聚斂，毛遂歃盟却强敵。", "梁王兔園禮詞人，相如之賦枚乘七。", "平津更有翹材館，大開東閣英彥集。", "徒步常何起馬周，落河房琯任劉秩。", "嚴鄭公延杜子美，郭汾陽遇李太白。", "朱門若止藏歌舞，無一措大研文墨。", "不知稼穡友朋闕，儻非癡物亦俗物。", "臨川太守千騎行，誰董琴瑟護書冊。", "吾子從之大江西，訓誘諸郎據師席。", "王介甫之學誤人國家，陸子靜之學雜彼禪佛。", "四海公論有如此，讀書豈可無揀擇。", "若夫擬峴臺登臨而賦詩，不妨寄我清江紙一疋。"]'),
('2c5152c7-df33-4d92-9d0e-778b9be5a2ca','次韻象山書院山長汪德載垂訪','方回','宋','宋诗','song-poetry','','[]','古學非如進士場，淵乎深處海難量。',64,'全唐诗/poet.song.232000.json','["古學非如進士場，淵乎深處海難量。", "善藏未用爭飴利，中立懸知異狷狂。", "度遠出寒公案在，漸修頓悟話頭長。", "公□與我評茲事，一洗人間粉黛粧。"]'),
('733651fc-35e3-412d-b789-06c44e2729f7','吾鄉朋友比多詩人宜進一步大則文公小亦龍溪可也於汪德載楊復之歸賦此意并寄劉元煇黄仲宣','方回','宋','宋诗','song-poetry','','[]','吾鄉南渡有儒真，二百年來兩絕倫。',64,'全唐诗/poet.song.232000.json','["吾鄉南渡有儒真，二百年來兩絕倫。", "繼聖乾淳綿道統，代言炎紹冠詞臣。", "紫陽山可搜遺老，白玉堂堪踵後塵。", "□□苕溪漁隠學，單傳詩話作詩人。"]'),
('cf1c0737-69c2-431f-b3f1-862ea459e921','六月二十四日秋夜書','方回','宋','宋诗','song-poetry','','[]','昨朝交末伏，今日立新秋。',48,'全唐诗/poet.song.232000.json','["昨朝交末伏，今日立新秋。", "故是凉猶未，終須熱漸休。", "酒醒興午夜，月上倚西樓。", "暍死端能免，江天問去舟。"]'),
('25538b9a-463e-46da-8633-d580b9bc531d','連夜書  其一','方回','宋','宋诗','song-poetry','','[]','獨倚西樓夜漸深，下弦月欲近觜參。',32,'全唐诗/poet.song.232000.json','["獨倚西樓夜漸深，下弦月欲近觜參。", "立秋是日微微雨，病暑衰翁稍慰心。"]'),
('61e3efcb-a308-4f87-bfac-e69a0e41e927','連夜書  其二','方回','宋','宋诗','song-poetry','','[]','斜向西南月半彎，五更正值畢叉間。',32,'全唐诗/poet.song.232000.json','["斜向西南月半彎，五更正值畢叉間。", "朝來驟有風兼雨，紅暈饒添一大環。"]'),
('cc39e03d-2462-495b-a4cd-cf3210b61f8c','連夜書  其三','方回','宋','宋诗','song-poetry','','[]','秋凉斷是合還家，三伏今年暑倍加。',32,'全唐诗/poet.song.232000.json','["秋凉斷是合還家，三伏今年暑倍加。", "病痛百般營藥草，精神一半減菱花。"]'),
('bd85ba60-8de5-40e5-80d9-17f0a5134993','連夜書  其四','方回','宋','宋诗','song-poetry','','[]','腐儒休致懶彈冠，樓倚新秋午夜闌。',32,'全唐诗/poet.song.232000.json','["腐儒休致懶彈冠，樓倚新秋午夜闌。", "木德臨參照南斗，江湖一稔百憂寬。"]'),
('de7814cd-7441-41a2-8856-843a697f10e8','再題通政院王榮之八月杏花  其一','方回','宋','宋诗','song-poetry','','[]','紅閙枝頭二月寒，中秋還許兩迴看。',32,'全唐诗/poet.song.232000.json','["紅閙枝頭二月寒，中秋還許兩迴看。", "君家泮水宮牆畔，吾道重春孔子壇。"]'),
('a71915d9-f782-4c9e-b467-6d1b225d460a','再題通政院王榮之八月杏花  其二','方回','宋','宋诗','song-poetry','','[]','半秋凉意轉春寒，似曲江頭紫陌看。',32,'全唐诗/poet.song.232000.json','["半秋凉意轉春寒，似曲江頭紫陌看。", "霜近核中仁再結，多調餳酪奉新歡。"]'),
('6cdc681f-d2a5-4f39-a07e-e0ac07e2700e','再題通政院王榮之八月杏花  其三','方回','宋','宋诗','song-poetry','','[]','早開菖葉勸耕辰，八月繁華又一新。',32,'全唐诗/poet.song.232000.json','["早開菖葉勸耕辰，八月繁華又一新。", "舊日舉人應最喜，桂闈秋報杏園春。"]'),
('33bdc3f0-a1ec-4be5-8a3e-a41d543aa6a9','再題通政院王榮之八月杏花  其四','方回','宋','宋诗','song-poetry','','[]','簡齋詩老不重生，流月無聲句絕清。',32,'全唐诗/poet.song.232000.json','["簡齋詩老不重生，流月無聲句絕清。", "好個杏花疏影裏，秋空吹笛到天明。"]'),
('8d46edf9-393e-4cdd-91b1-6a0e3db9b59a','再題通政院王榮之八月杏花  其五','方回','宋','宋诗','song-poetry','','[]','種傳董奉術韓湘，頃刻能開錦繡香。',32,'全唐诗/poet.song.232000.json','["種傳董奉術韓湘，頃刻能開錦繡香。", "好畫團圓明月夜，中秋天色變春光。"]'),
('ba2c5ae1-e318-4e74-a6ee-56d777f3bf22','七月初一日淮浙大潮巨風亙古所無二首  其一','方回','宋','宋诗','song-poetry','','[]','等是耕王土，誰令住海濱。',72,'全唐诗/poet.song.232000.json','["等是耕王土，誰令住海濱。", "死沈凡幾屋，生哭併無人。", "可痛淮連浙，兼憂廣及閩。", "鯨鯢容此物，螻蟻視吾民。", "浪祭推潮鬼，虛祈主地神。", "懷襄吾未見，七十五年身。"]'),
('b0688726-31f9-4eb5-8ac6-16f9ab2ec029','七月初一日淮浙大潮巨風亙古所無二首  其二','方回','宋','宋诗','song-poetry','','[]','江海諸州縣，新秋捲颶風。',72,'全唐诗/poet.song.232000.json','["江海諸州縣，新秋捲颶風。", "樓臺漂燕厦，城市化龍宮。", "舶寶千艘覆，亭鹽萬竈空。", "直令無片瓦，更許有孤篷。", "徹底沙洲掃，連根樹木童。", "骨骸誰與殯，腐爛出屍蟲。"]'),
('b6a7b746-8ba9-4128-b2b7-6f2ea2a4ac57','送趙揭陽北上  其一','方回','宋','宋诗','song-poetry','','[]','去歲別新正，今秋尚未行。',48,'全唐诗/poet.song.232000.json','["去歲別新正，今秋尚未行。", "求書何太數，問選竟無成。", "鱷海真曾到，龍沙果欲征。", "恐如吾所料，姑用此爲名。"]'),
('116c4343-5f8e-410c-bc09-43a168815f0c','送趙揭陽北上  其二','方回','宋','宋诗','song-poetry','','[]','先世聯龍榜，難兄接鷺班。',48,'全唐诗/poet.song.232000.json','["先世聯龍榜，難兄接鷺班。", "時移誰念舊，身老各投閒。", "吾已謀周翣，君猶戀漢綸。", "與其奔赤日，何似卧青山。"]'),
('3a7624b8-e9cc-4aff-8b63-64ffea52ba70','七月十五日書','方回','宋','宋诗','song-poetry','','[]','家貧難辦素食，事忙不及草書。',28,'全唐诗/poet.song.232000.json','["家貧難辦素食，事忙不及草書。", "今日果然如此，古人可信非歟。"]'),
('b945d8d9-4ba6-45f0-9608-8095d80f5be3','偶書  其一','方回','宋','宋诗','song-poetry','','[]','一日無酒飲，一日意不樂。',72,'全唐诗/poet.song.232000.json','["一日無酒飲，一日意不樂。", "一夜無酒飲，一夜睡不著。", "後生殊未知，老人今始覺。", "萬卷漫讀書，千金空服藥。", "我有一盃酒，大勝凌煙閣。", "酣歌脫頭巾，毛髪動褒鄂。"]'),
('85866e58-c9f1-486f-a129-2925d37742d4','偶書  其二','方回','宋','宋诗','song-poetry','','[]','一夕五七起，起輒搔我頭。',72,'全唐诗/poet.song.232000.json','["一夕五七起，起輒搔我頭。", "明月掛簷前，獨飲憑危樓。", "清曉上參井，黄昏移斗牛。", "殘暑未云退，幸已臻新秋。", "天上有銀河，化酒還肯不。", "大醉更無夢，小醉亦無愁。"]'),
('7689f0f9-1bb6-419d-8d53-c8a1250be7e2','寄題張受益會清堂','方回','宋','宋诗','song-poetry','','[]','伏生年九十，腹貯秦坑書。',240,'全唐诗/poet.song.232000.json','["伏生年九十，腹貯秦坑書。", "終童年十八，手擲漢關繻。", "一老一妙年，智勇夫何如。", "兩皆濟南人，稟受風氣殊。", "乾坤妙融結，山水清有餘。", "鍾賢代不乏，一變可魯儒。", "吾友子張子，世於此焉居。", "烏哺奉甘旨，鵷行贊都俞。", "將指許假道，榮哉兼熊魚。", "甲此一都會，築堂冠蓋趨。", "萬象納戶牖，八荒來庭除。", "陽丘古邑南，均是宅一區。", "粗中必有精，所見獨異諸。", "人見花與竹，我見皆道腴。", "彝鼎日玩弄，簡冊日卷舒。", "拔出形器上，漉水月本無。", "譬若椰子腹，中有萬卷儲。", "何必西域賈，剖股藏明珠。", "矢詩說解悟，指天撮空虛。", "何如登君堂，嘯傲傾觴壺。"]'),
('45e0cbe8-f04e-41aa-9e64-4224967a8bd4','七十五翁吟','方回','宋','宋诗','song-poetry','','[]','衰翁七十五，猶有身世憂。',252,'全唐诗/poet.song.232000.json','["衰翁七十五，猶有身世憂。", "暑不辦寒計，朝始爲夕謀。", "海若挾風伯，掃蕩數十州。", "錢塘幸而免，湖已入城流。", "吾雖偶不死，生涯殊苟偷。", "米價不少減，錢刀何所求。", "長女亡六載，次女病未瘳。", "假使即勿藥，嫁奩將焉籌。", "五男喪其幼，餘皆隠林丘。", "憶昔年十五，七月辛丑秋。", "郡治及祖居，一夜灰鬰攸。", "倏忽六十載，將無墜箕裘。", "僥倖登一第，患難何其稠。", "濱死者累矣，尚存鏡中頭。", "行善叢謗議，施德招冤讎。", "久已致其仕，此生行且休。", "半飽半饑間，陳粟虀一甌。", "鼎食拚鼎烹，吾非斯人儔。", "萬事不如意，自取何怨尤。", "折腰復仰面，舐痔而封侯。", "何如醉茅柴，霞外鼾鼻齁。"]'),
('6a5a3499-2e08-4791-b81b-e90f7b2af274','偶書二首  其一','方回','宋','宋诗','song-poetry','','[]','磊落終休矣，艱難晚見之。',24,'全唐诗/poet.song.232000.json','["磊落終休矣，艱難晚見之。", "罔知當世事，殊悔少年時。"]'),
('c1044680-1678-495e-b487-7290388edae6','偶書二首  其二','方回','宋','宋诗','song-poetry','','[]','一昨懸車後，蹉跎又五年。',24,'全唐诗/poet.song.232000.json','["一昨懸車後，蹉跎又五年。", "常書乞米帖，猶費買花錢。"]'),
('e5b7a22e-a893-4239-ada8-4d41c06b39b6','故王氏安人挽辭','方回','宋','宋诗','song-poetry','','[]','淑配生同邑，錢王錦繡鄉。',48,'全唐诗/poet.song.232000.json','["淑配生同邑，錢王錦繡鄉。", "甫登重卦壽，遽掩若堂喪。", "桑梓推真節，芝蘭篤義方。", "冥冥資佛力，長子作緇郎。"]'),
('35ca1a21-b580-4c63-bd17-7e0a79d88142','次韻沈茂實小園偶書  其一','方回','宋','宋诗','song-poetry','','[]','人因雅俗分高下，同是園林興不同。',64,'全唐诗/poet.song.232000.json','["人因雅俗分高下，同是園林興不同。", "時覺燕鶑相爾汝，焉知蜂蝶有雌雄。", "豈惟酒可兼詩可，常在花中與竹中。", "秋老紗窗猶未換，要令深夜月華通。"]'),
('e6d82051-404f-440a-98e3-ff1e60933747','次韻沈茂實小園偶書  其二','方回','宋','宋诗','song-poetry','','[]','秋風稉稻又嘗新，續食年年肯濟貧。',64,'全唐诗/poet.song.232000.json','["秋風稉稻又嘗新，續食年年肯濟貧。", "遠學佺期響□□，近同東老致仙人。", "貴公勳業一杯水，俗子面顔三斛塵。", "流火授衣誦豳什，戒寒深恐雁來賓。"]'),
('d4b35cdd-430c-4620-8ee5-562a676ec81a','題淵明采菊圖','方回','宋','宋诗','song-poetry','','[]','東籬東籬所至有，南山南山古至今。',144,'全唐诗/poet.song.232000.json','["東籬東籬所至有，南山南山古至今。", "東籬之西拄我杖，秋菊千叢開黄金。", "南山之北送我目，鴻飛山陽我山陰。", "今是昨非栗里宅，三徑就荒猶可尋。", "畫工可寫淵明面，政恐難寫淵明心。", "淵明面匪宣明面，誰歟障我西風扇。", "翁醉欲眠遣客去，淵明此心我常見。", "歸去來兮歸去來，淵明方寸焉在哉。", "寧入東鄰白蓮社，不上徐州戲馬臺。"]'),
('1892e22f-f399-4c06-bf50-84e7bd027475','秋風歌','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','君不見七月一日海上風，浙水西東淮水東。',285,'全唐诗/poet.song.232000.json','["君不見七月一日海上風，浙水西東淮水東。", "鹽亭網戶十萬許，潮頭三丈一掃空。", "高門大屋聳金碧，瞬息浮入龍王宮。", "官吏軍民不知幾，肉無肥瘦魚腹中。", "縱屍橫骨互撐拄，蠅蚋姑嘬鷹鸇同。", "人家婦女金纏臂，惡少斫之殘血紅。", "富商大賈浮巨舶，犀象珠璣誇豪雄。", "三五百艘□□□，□□紙船紙梢工。", "善登高樹毒蛇滿，善泅有蛇纏其躬。", "□□□家無一口，甚寇屠戮兵戰攻。", "我憶淳熙前辛丑，赤地□□飛蝗蟲。", "江南人才殊未少，南康救荒頼文公。", "我憶嘉熙□辛丑，西湖涸底舟不通。", "人肉饅頭市肆賣，艮山門潮堯水洪。", "水旱厄運古來有，皇天得不憐民窮。", "辛丑定數不可免，願言少殺神怨恫。", "七十有五衰病翁，未即就木猶轉蓬，僥倖米價不長年歲豐。"]'),
('a0335678-d8a1-4929-b524-d3735add8767','五湖空濛圖','方回','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','五湖之水何冥冥，五湖之山何青青。',214,'全唐诗/poet.song.232000.json','["五湖之水何冥冥，五湖之山何青青。", "煙雨空濛寄絹素，吾聞善畫不畫形。", "畫山畫水畫煙雨，界畫點綴分秤星。", "寓意托興有所主，人品高絕名芳馨。", "斗牛分野古彭蠡，橘柚包貢今洞庭。", "史傳同異不可考，青草丹陽兼宮亭。", "諸老英魂可招否，亡吳霸越携娉婷。", "三致千金變名姓，橐裝恐带戰血腥。", "陸龜蒙，張季鷹，無功可上彝鼎銘。", "江湖粗有蓴可羹，何必石崇虀韭萍。", "滿身花影醉歸夜，何必涯訓居朝廷。", "三高之中去一高，似於人物太渭涇。", "鴟夷子者非我侶，焉得張陸二高復起與我共揚舲。"]'),
('5d9b5d37-54d6-429d-bc21-3d0284044b85','送秘書監丞張受益還都傚山谷體','方回','宋','宋诗','song-poetry','','[]','君家所有吾弗如，價估萬金猶有餘。',64,'全唐诗/poet.song.232000.json','["君家所有吾弗如，價估萬金猶有餘。", "科斗字前古彝器，椰子腹中行秘書。", "楚吳閩粵吏狼虎，淮浙海江民鱉魚。", "歸闕一言動天聽，生靈百萬免淪胥。"]'),
('a4e9c658-1778-4f10-8c51-e86e07e38201','送鄧善之翰林應奉并呈交代汪親家','方回','宋','宋诗','song-poetry','','[]','海內師儒四十强，臯比一撤即鵷行。',64,'全唐诗/poet.song.232000.json','["海內師儒四十强，臯比一撤即鵷行。", "聲名久動黄金闕，相貌宜登白玉堂。", "真學士當專翰墨，寡言人定鎮巖廊。", "交承正是吾姻婭，爲謝魚龍老子汪。"]'),
('782ee9c2-ece9-4174-8efe-948c34b0e433','辛丑中秋曲阜橋倚樓','方回','宋','宋诗','song-poetry','','[]','月漸高雖小，星全隠不明。',48,'全唐诗/poet.song.232000.json','["月漸高雖小，星全隠不明。", "老夫偶有酒，獨酌過三更。", "世間千萬戶，誰是倚樓人。", "今夜中秋月，危欄一病身。"]'),
('fcbd0cbd-f56f-49aa-860d-8e0a0e95522a','送福州謝學正無疑歸南劍州','方回','宋','宋诗','song-poetry','','[]','問知桑梓處，師祖李延平。',48,'全唐诗/poet.song.232000.json','["問知桑梓處，師祖李延平。", "往正三山學，看馳四海聲。", "新吟嚴更典，老貌古兼清。", "上水過衢信，閩溪却順行。"]'),
('bfae7d2f-bfe2-4384-994e-ec3f23b85f73','秋思七言八首  其一','方回','宋','宋诗','song-poetry','','[]','久不作詩詩律廢，時須飲酒酒皆慳。',32,'全唐诗/poet.song.232000.json','["久不作詩詩律廢，時須飲酒酒皆慳。", "翠微雲外宣平宅，一棹歸歟隠此山。"]'),
('a1dbec91-6087-4d54-9284-e4c34dd2212e','秋思七言八首  其二','方回','宋','宋诗','song-poetry','','[]','重陽時節黄花近，老子情懷白髪新。',32,'全唐诗/poet.song.232000.json','["重陽時節黄花近，老子情懷白髪新。", "點檢客囊無一物，江湖七十五年身。"]'),
('2ebc3f15-91ac-4fff-be9a-f3b25d7d8c35','秋思七言八首  其三','方回','宋','宋诗','song-poetry','','[]','大庾嶺頭梅掛月，居庸關外草連天。',32,'全唐诗/poet.song.232000.json','["大庾嶺頭梅掛月，居庸關外草連天。", "馬牛風古不相及，障霧饕風一夢然。"]'),
('282f1a75-cfa1-4e1c-bd0e-c7152b6b9f55','秋思七言八首  其四','方回','宋','宋诗','song-poetry','','[]','將相共扶黄道日，神仙獨隠紫陽山。',32,'全唐诗/poet.song.232000.json','["將相共扶黄道日，神仙獨隠紫陽山。", "雲深夜註參同契，身在虛無縹緲間。"]'),
('d0835a5d-0ff2-43e6-9c40-2598b49962e1','秋思七言八首  其五','方回','宋','宋诗','song-poetry','','[]','郎官己未老秋崖，丞相庚申老訥齋。',32,'全唐诗/poet.song.232000.json','["郎官己未老秋崖，丞相庚申老訥齋。", "己亥□螭竹坡老，吾鄉三老掛予懷。"]'),
('8240867c-7b71-4863-aed7-d142ee16536f','秋思七言八首  其六','方回','宋','宋诗','song-poetry','','[]','早遇鶴山先生子，晚登和義郡王門。',32,'全唐诗/poet.song.232000.json','["早遇鶴山先生子，晚登和義郡王門。", "靜翁道翁兩知己，慟哭新墳接舊墳。"]'),
('972de6fe-52a7-4b0c-9847-bdffd38fd69f','秋思七言八首  其七','方回','宋','宋诗','song-poetry','','[]','七旬有二傳凶問，九月初三記誕辰。',32,'全唐诗/poet.song.232000.json','["七旬有二傳凶問，九月初三記誕辰。", "客裏偶然逢此日，淮思江望淚痕新。"]'),
('b217099a-7046-4eba-86fb-58fb7843d617','秋思七言八首  其八','方回','宋','宋诗','song-poetry','','[]','菊殿百花梅第一，重陽節過小春來。',32,'全唐诗/poet.song.232000.json','["菊殿百花梅第一，重陽節過小春來。", "年年歲歲身長健，擺去窮愁醉幾杯。"]'),
('a575a3c6-2328-4f96-a72c-085df778e27b','後秋思五言五首  其一','方回','宋','宋诗','song-poetry','','[]','多病全然懶，微凉尚未寒。',24,'全唐诗/poet.song.232000.json','["多病全然懶，微凉尚未寒。", "偶然無一事，蛛網雨中看。"]'),
('5a9cfd9d-fbb6-4baf-8fa7-6a8d8d99a08d','後秋思五言五首  其二','方回','宋','宋诗','song-poetry','','[]','詩老吾衰矣，秋風又颯然。',24,'全唐诗/poet.song.232000.json','["詩老吾衰矣，秋風又颯然。", "黄花香五度，八十太公年。"]'),
('810cf9b4-9c69-4aa6-8695-d647b940712e','後秋思五言五首  其三','方回','宋','宋诗','song-poetry','','[]','黄陳今不作，天地少詩人。',24,'全唐诗/poet.song.232000.json','["黄陳今不作，天地少詩人。", "不是詩人少，詩人未必真。"]'),
('132f54ad-6066-4021-85eb-125f55d2e10f','後秋思五言五首  其四','方回','宋','宋诗','song-poetry','','[]','詩與風騷迫，文兼史漢長。',24,'全唐诗/poet.song.232000.json','["詩與風騷迫，文兼史漢長。", "半山非不爾，僻學汴梁亡。"]'),
('9ed532d7-d5c1-4b1a-aa90-7cde0d327fdb','後秋思五言五首  其五','方回','宋','宋诗','song-poetry','','[]','五房十昆仲，獨許一身存。',24,'全唐诗/poet.song.232000.json','["五房十昆仲，獨許一身存。", "今日重陽日，登樓欲斷魂。"]'),
('f6f7e538-47b4-4c68-b123-e7499a59affb','辛丑九日五首  其一','方回','宋','宋诗','song-poetry','','[]','政恐登高枉斷腸，今年恰值雨重陽。',32,'全唐诗/poet.song.232000.json','["政恐登高枉斷腸，今年恰值雨重陽。", "晨興中酒情懷懶，滿眼黄花滿屋香。"]'),
('0b5f9aff-d5c8-4ef8-bad6-25862a67c17a','辛丑九日五首  其二','方回','宋','宋诗','song-poetry','','[]','世間何事不空無，萬古年年九日徂。',32,'全唐诗/poet.song.232000.json','["世間何事不空無，萬古年年九日徂。", "最憶吾家先叔父，塘頭一樹紫茱萸。"]'),
('430ff67a-49d6-46b4-8cb4-bfafc37016fc','辛丑九日五首  其三','方回','宋','宋诗','song-poetry','','[]','五度秋光過古希，節名良是嘆人非。',32,'全唐诗/poet.song.232000.json','["五度秋光過古希，節名良是嘆人非。", "吾州大火前辛丑，問政山頭伐木歸。"]'),
('4518b472-9994-4919-a2c5-38b173c5a47c','辛丑九日五首  其四','方回','宋','宋诗','song-poetry','','[]','何事清秋已衣綿，微寒最怯倚樓天。',32,'全唐诗/poet.song.232000.json','["何事清秋已衣綿，微寒最怯倚樓天。", "江南今歲黄花早，醉嚼重陽半月前。"]'),
('4af4506b-c88d-4bfc-a75c-9b6853b299a9','辛丑九日五首  其五','方回','宋','宋诗','song-poetry','','[]','往歲金臺屢據鞍，居庸雁字仰天看。',32,'全唐诗/poet.song.232000.json','["往歲金臺屢據鞍，居庸雁字仰天看。", "中秋蟹斷□花絕，紅葉西山九日寒。"]'),
('d4d674c5-b764-4595-b39b-e98fc020e10b','爲孫同簽瓚題趙子昂馬','方回','宋','宋诗','song-poetry','','[]','畫馬當年李伯時，長懷魯直子瞻詩。',32,'全唐诗/poet.song.232000.json','["畫馬當年李伯時，長懷魯直子瞻詩。", "朝廷□道人才盛，元祐風流再見之。"]'),
('b4adaa6a-e244-40a4-8249-a8dac5febeeb','爲張都目益題爪哇王后將相圖','方回','宋','宋诗','song-poetry','','[]','闍婆之國古來有，其人裸體蓬厥首。',352,'全唐诗/poet.song.232000.json','["闍婆之國古來有，其人裸體蓬厥首。", "後來改號作爪哇，君僭稱王妻僭后。", "跣足露乳布纏腰，往往自妍不知醜。", "千島萬島南海南，謂遠無虞險可守。", "成周通道八蠻朝，旅獒越裳孰敢後。", "真臘彭亨皆入貢，巴尚答洽爾獨否。", "壬辰臘月明日望，三平章往命招誘。", "泉州出門七州洋，飛檣舞帆朔風吼。", "五旬有餘至其境，驚禽駭獸破膽走。", "前主初喪後主立，國亂未定內掣肘。", "生擒瞎直吃當王，癸巳三月之十九。", "先降土漢必者牙，水陸引道分左右。", "繼獲昔剌小大子，□□留屯豈容久。", "所俘病亡或逋逃，窮則反噬如野□。", "□秋班師會占城，諸國降表肯相受。", "梢工滿載檳榔果，征夫爛醉椰子酒。", "生金銅錢暨百寶，搜山討擄恣意取。", "蝤蛑蝦蟹玳瑁螺，芭蕉豆蔻皆可口。", "風俗可怪亦可憐，食無匕筯但用手。", "生年月日都不記，淫亂混雜忘牝牡。", "得此詩料告者誰，滕良伯父乃吾友。", "我賦長篇當凱歌，甘誓胤征同不朽。"]'),
('918dd201-5f5a-44ce-bcb1-9d25c033edfb','九月一日稍佳演作五十六字終不及少陵牧之','方回','宋','宋诗','song-poetry','','[]','少陵哦後牧之□，□□篇章可謂過。',64,'全唐诗/poet.song.232000.json','["少陵哦後牧之□，□□篇章可謂過。", "真是能專詩筆否，似應無奈菊花何。", "雁來秋老江湖落，病感風寒涕唾多。", "自古死生元有命，滿斟且復醉顔酡。"]'),
('8f38fba1-7a5e-4a5c-ad1c-ff5597fd4f66','重陽後秋感','方回','宋','宋诗','song-poetry','','[]','盛夏關防少，深秋證候知。',48,'全唐诗/poet.song.232000.json','["盛夏關防少，深秋證候知。", "脂寒饒涕唾，膚癢困瘡痍。", "故國山千疊，重陽菊一枝。", "醉鄉差可可，歸路尚遲遲。"]'),
('2df280ee-d665-4ddd-a8c3-37f2b9abb738','送胡雲峰炳文錄廣信二首  其一','方回','宋','宋诗','song-poetry','','[]','蓋輿上下立乾坤，眼底無人可與論。',64,'全唐诗/poet.song.232000.json','["蓋輿上下立乾坤，眼底無人可與論。", "分數不難升地位，絲毫未易見天原。", "因重文字窮羲畫，速肖生徒半孔門。", "斗食泮池何足凂，晦庵異姓要雲孫。"]'),
('cf76ab18-cfcc-44ef-8bab-22eea3145e39','送胡雲峰炳文錄廣信二首  其二','方回','宋','宋诗','song-poetry','','[]','近沿關洛至乾淳，遠探羲圖未畫真。',64,'全唐诗/poet.song.232000.json','["近沿關洛至乾淳，遠探羲圖未畫真。", "自古斯文元有種，即今所學不無人。", "轉移鴞泮希聲起，判斷鵝湖正論□。", "□□諸生仕鄰國，變齊同囿杏壇春。"]'),
('df561a57-b73a-43c3-b050-21ef8a7e0a78','題楊仲謙走馬牽犬圖鄭某畫','方回','宋','宋诗','song-poetry','','[]','渥生漢馬真龍種，旅獻周獒敵虎威。',32,'全唐诗/poet.song.232000.json','["渥生漢馬真龍種，旅獻周獒敵虎威。", "時節太平鬨花柳，平川牽鞚走如飛。"]'),
('18b8fe51-0e0b-4845-a031-832acc52aa08','題錢舜舉著色山水','方回','宋','宋诗','song-poetry','','[]','堆青積翠聳□□，□□崢嶸古寺深。',32,'全唐诗/poet.song.232000.json','["堆青積翠聳□□，□□崢嶸古寺深。", "此畫老錢暮年筆，真成一紙直千金。"]'),
('ced4cfe7-c985-4a20-ae65-6752c1e4ad1f','次韻郝元隠浙西山','方回','宋','宋诗','song-poetry','','[]','疏處溫凉密處寒，未須向背問支干。',64,'全唐诗/poet.song.232000.json','["疏處溫凉密處寒，未須向背問支干。", "猿閑配偶雙嬉戲，樹古根枝萬屈盤。", "何限樓臺荒宿草，幾年歌舞罷鳴鑾。", "頼天獨肯扶僧剎，佛大泥多許共看。"]'),
('0c082325-7968-4fe5-bffd-ec1b1e70654e','挽艮岩梅府卿  其一','方回','宋','宋诗','song-poetry','','[]','庚午昔同朝，權臣狠且驕。',48,'全唐诗/poet.song.232000.json','["庚午昔同朝，權臣狠且驕。", "至尊俱芥視，大物遽冰消。", "密勿毗廊肆，艱難駕使軺。", "絲毫心有愧，壽肯到今朝。"]'),
('5f56dcdc-6af5-4bba-885a-2c8f18ecad05','挽艮岩梅府卿  其二','方回','宋','宋诗','song-poetry','','[]','往事括囊坤，元魁罪忍論。',48,'全唐诗/poet.song.232000.json','["往事括囊坤，元魁罪忍論。", "咸淳君蔑有，德祐國能存。", "委曲都司筆，侵尋亞從門。", "惟公獨不肯，手板倒桓溫。"]'),
('367258f7-a461-43b5-9691-de39a3f1b81c','挽艮岩梅府卿  其三','方回','宋','宋诗','song-poetry','','[]','改卜龜圖後，閒居二十年。',48,'全唐诗/poet.song.232000.json','["改卜龜圖後，閒居二十年。", "商顔才聘幣，剡曲竟回船。", "□□無虛日，粢盛有薄田。", "何須似裴李，綠野及平泉。"]'),
('5c944c25-b90b-4116-98a9-4d95cd56368f','寄董總管文卿精春秋連爲太平姑蘇二大郡','方回','宋','宋诗','song-poetry','','[]','春秋家學漢醇儒，纔尹當塗又尹蘇。',64,'全唐诗/poet.song.232000.json','["春秋家學漢醇儒，纔尹當塗又尹蘇。", "光價九霄懸日月，愛思兩郡甲江湖。", "蛾眉采石風前笛，橘里長橋□後鱸。", "太白季鷹俱不及，□□□□擁菟符。"]'),
('275d21fa-82d9-4cc2-a5a6-f095ecc0fd9d','送方巖夫四首  其一','方回','宋','宋诗','song-poetry','','[]','河南徙歙徙浮光，逮徙莆田派愈長。',32,'全唐诗/poet.song.232000.json','["河南徙歙徙浮光，逮徙莆田派愈長。", "六出長官刺史百，端平最數鐵庵方。"]'),
('072b6f56-1591-46cb-9a11-a9c38ce4d4e7','送方巖夫四首  其二','方回','宋','宋诗','song-poetry','','[]','同姓同年綰左符，嶺南萬里送孀孤。',32,'全唐诗/poet.song.232000.json','["同姓同年綰左符，嶺南萬里送孀孤。", "先君遺墨今猶在，爲問封州有後無。"]'),
('a936b215-80b7-4169-801b-7153f303615b','送方巖夫四首  其三','方回','宋','宋诗','song-poetry','','[]','巨山蒙仲昔同官，對峙詩家兩將壇。',32,'全唐诗/poet.song.232000.json','["巨山蒙仲昔同官，對峙詩家兩將壇。", "昭武即今聞有子，文星高照七閩寒。"]'),
('22712542-ace4-437a-a67b-06da45f4ca15','送方巖夫四首  其四','方回','宋','宋诗','song-poetry','','[]','紫陽山下一燈寒，曾守桐廬七里灘。',32,'全唐诗/poet.song.232000.json','["紫陽山下一燈寒，曾守桐廬七里灘。", "空手去官□一物，詩名聊得繼方干。"]'),
('f7ff8d62-165e-465d-a017-b3bc178ab654','送李君佐游浙東','方回','宋','宋诗','song-poetry','','[]','鑑湖北棹迓征鴻，昭代乾坤靡不容。',64,'全唐诗/poet.song.232000.json','["鑑湖北棹迓征鴻，昭代乾坤靡不容。", "運際包荒連茹泰，時當養正出泉蒙。", "暫爲掾史司刀筆，遄許勳名上鼎鐘。", "看取漢家有故事，趙堯猶得拜三公。"]'),
('ddc8a023-f5a9-4a8d-aa62-57da254c1f87','贈李得甫寄拙軒','方回','宋','宋诗','song-poetry','','[]','吾嘗鄙文賦，陸機自衒鬻。',180,'全唐诗/poet.song.232000.json','["吾嘗鄙文賦，陸機自衒鬻。", "濬發誇巧心，見唾憾拙目。", "□□淵明詩，莫若黄山谷。", "或者巧斧斤，疑謂拙不足。", "詩文較巧拙，議論黄勝陸。", "人才亦復爾，世事可類觸。", "善宦司馬安，四食九卿祿。", "百世名不馨，史筆有餘戮。", "大匠公輸子，繩墨萬厦屋。", "規矩方圓外，何必續土木。", "李子寄此軒，一□夜檠獨。", "未入巖野夢，□□□□卜。", "焉知千駟馬，豈慕萬鍾□。", "□□蠹書魚，惄如饑亦讀。", "掛簷飽飛蟲，彼哉蛛網腹。"]'),
('0d7bdae6-92af-4adb-b796-d7e05adcb3ac','用韻謝湖州總管李才甫附周漢東寄聲','方回','宋','宋诗','song-poetry','','[]','文章太守與誰游，山水江南第一州。',64,'全唐诗/poet.song.232000.json','["文章太守與誰游，山水江南第一州。", "試向清風明月內，得非與可子瞻不。", "生徒時喜高軒過，英俊多蒙□□□。", "冷掾能言修學事，殿堂新葺更書樓。"]'),
('003fccfd-1581-45bd-89a4-f2bef5a07a91','重贈王相士','方回','宋','宋诗','song-poetry','','[]','是人家有些兒屋，何處山無這個雲。',32,'全唐诗/poet.song.232000.json','["是人家有些兒屋，何處山無這個雲。", "浪走江湖□□□，□邊雲肯强隨君。"]'),
('55fd87bb-8ebc-403e-9b20-cfc840cb6fb2','偶題五言絕句五首  其一','方回','宋','宋诗','song-poetry','','[]','不寐常欹枕，無言獨倚樓。',24,'全唐诗/poet.song.232000.json','["不寐常欹枕，無言獨倚樓。", "江淹猶匪恨，庾信始爲愁。"]'),
('6826254f-ee2c-4a91-a1c6-88f012209174','偶題五言絕句五首  其二','方回','宋','宋诗','song-poetry','','[]','落木包生意，來鴻定去期。',24,'全唐诗/poet.song.232000.json','["落木包生意，來鴻定去期。", "如何蕭瑟氣，有許楚臣悲。"]'),
('12de21ef-97d8-4626-a8ab-4c1f0e60908f','偶題五言絕句五首  其三','方回','宋','宋诗','song-poetry','','[]','春秋踰致仕，南北粗知名。',24,'全唐诗/poet.song.232000.json','["春秋踰致仕，南北粗知名。", "有客來相問，如何不治生。"]'),
('2ddf44c9-ad5d-4990-970a-cd477e6c90c5','偶題五言絕句五首  其四','方回','宋','宋诗','song-poetry','','[]','爲客彈長鋏，□□□短衣。',24,'全唐诗/poet.song.232000.json','["爲客彈長鋏，□□□短衣。", "奈何年不肯，五過古來希。"]'),
('f7fb11ca-df50-4c06-a2ae-d4e6cb8b5526','偶題五言絕句五首  其五','方回','宋','宋诗','song-poetry','','[]','自古有治亂，誰家無是非。',24,'全唐诗/poet.song.232000.json','["自古有治亂，誰家無是非。", "曉牀聽鄰語，瑣瑣訴寒饑。"]'),
('6b502190-44f1-461a-a3fe-de53135626fa','客况六言五首  其一','方回','宋','宋诗','song-poetry','','[]','狐白裘玉作带，汗血馬金爲鞭。',28,'全唐诗/poet.song.232000.json','["狐白裘玉作带，汗血馬金爲鞭。", "雪髪河中老叟，霜天裸體撐船。"]'),
('6c33aacb-8072-4df0-9604-05c228e1912b','客况六言五首  其二','方回','宋','宋诗','song-poetry','','[]','一瓣香陳無己，萬首詩陸放翁。',28,'全唐诗/poet.song.232000.json','["一瓣香陳無己，萬首詩陸放翁。", "借問老夫年紀，五屈指姜太公。"]'),
