('712b5003-0e8a-4fca-a8b9-00921aa708c9','猴牛尾貍圖','方回','宋','宋诗','song-poetry','','[]','宣城牛尾雪天貍，梅老饞涎爲賦詩。',32,'全唐诗/poet.song.232000.json','["宣城牛尾雪天貍，梅老饞涎爲賦詩。", "曾與沐猴戲相得，脂膏爭奈獵人知。"]'),
('83fc7e75-3400-4184-8ffd-9ba048ce8173','東坡真迹','方回','宋','宋诗','song-poetry','','[]','歐蘇一代兩文忠，頼是滁陽起醉翁。',32,'全唐诗/poet.song.232000.json','["歐蘇一代兩文忠，頼是滁陽起醉翁。", "誰欲儋州殺坡老，靖康戰血鼓腥風。"]'),
('a294585b-3687-451a-a571-c14438e8f75f','錢舜舉瓜畫','方回','宋','宋诗','song-poetry','','[]','老錢工作趙昌花，殘綠依稀姤五瓜。',32,'全唐诗/poet.song.232000.json','["老錢工作趙昌花，殘綠依稀姤五瓜。", "正叔晦翁凡六說，始知輔嗣大爭差。"]'),
('1726826d-f3f7-4e4d-b638-870b9ca7cdf3','送廣信山長趙然明','方回','宋','宋诗','song-poetry','','[]','宅本詞人傑，祠今學者宗。',48,'全唐诗/poet.song.232000.json','["宅本詞人傑，祠今學者宗。", "才華明斧藻，師範服章縫。", "竭力鑽書蠹，乘時補衮龍。", "勉旃企鄉達，徽國荷堯封。"]'),
('fe2542fd-93be-48dc-a79c-1e1ea378fd90','擬古五首  其一','方回','宋','宋诗','song-poetry','','[]','達人安天命，養器以待時。',72,'全唐诗/poet.song.232000.json','["達人安天命，養器以待時。", "匪謂閉其門，端坐無所爲。", "東家田中苗，既種且溉之。", "西家不復爾，秋至或忍饑。", "一得異一失，非天有偏私。", "口實云自求，曷不觀諸頤。"]'),
('6b7d46a3-71e2-48a1-b118-8ba203f62ff1','擬古五首  其二','方回','宋','宋诗','song-poetry','','[]','高臺垂釣竿，不過一漁翁。',60,'全唐诗/poet.song.232000.json','["高臺垂釣竿，不過一漁翁。", "三徑連東籬，略與寒士同。", "何獨嚴與陶，百代流清風。", "文叔本僥倖，寄奴非英雄。", "我評夷與齊，大勝營丘公。"]'),
('9389fec0-b4b7-4fe5-8f1c-0ea24a62f2c5','擬古五首  其三','方回','宋','宋诗','song-poetry','','[]','江南九月後，無日非重陽。',60,'全唐诗/poet.song.232000.json','["江南九月後，無日非重陽。", "十月十一月，豈不雪且霜。", "嚴凍殺百草，菊花彌更黄。", "於茲偶有酒，十觴至百觴。", "□□□□了，復醉梅花傍。"]'),
('c8a3be50-e817-4b51-bb3b-c41c43077bdf','擬古五首  其四','方回','宋','宋诗','song-poetry','','[]','騷人稱屈宋，宋豈敵子平。',48,'全唐诗/poet.song.232000.json','["騷人稱屈宋，宋豈敵子平。", "詩家推陶謝，謝豈肩淵明。", "魯直愛水仙，以梅爲其兄。", "梅似可祖父，吾今改茲評。"]'),
('578a1a99-d266-432d-b059-e5e87187128a','擬古五首  其五','方回','宋','宋诗','song-poetry','','[]','知十與知二，回賜同補哲。',48,'全唐诗/poet.song.232000.json','["知十與知二，回賜同補哲。", "所以孟堅表，九品較優劣。", "人貌無明鏡，妍醜孰分別。", "物無權與衡，輕重亦不决。"]'),
('8ec3cab1-1cef-4a3d-8f99-c3b4afb17c12','題禊帖圖','方回','宋','宋诗','song-poetry','','[]','永和九年晉癸丑，禊帖至今家家有。',192,'全唐诗/poet.song.232000.json','["永和九年晉癸丑，禊帖至今家家有。", "遺墨一紙出昭陵，摹本宇宙同不朽。", "甲子循環十六周，甫近千歲未爲久。", "之字二十我諦觀，誰繪此圖誇妙手。", "晉人之學吾能□，□以莊子爲六經。", "大同小異立議論，漆園遺意入蘭亭。", "七情靜動應萬事，一氣聚散鍾千形。", "樂極必悲生必死，倏開忽闔風天螢。", "豈不痛哉逸少語，畏怖生老病死苦。", "掇拾釋氏之緒餘，惴惴其慄有如許。", "顔瓢致樂悲安在，曾簀臨死生焉□。", "短中求長斷斯文，翰墨高名萬萬古。"]'),
('1274bc8e-c3e2-4ff1-b0ec-c25a08b49923','離騷九歌圖','方回','宋','宋诗','song-poetry','','[]','正則靈均皇揆余，屈子文章古所無。',272,'全唐诗/poet.song.232000.json','["正則靈均皇揆余，屈子文章古所無。", "我嘗痛飲讀□□，□乃復覽九歌圖。", "九歌根源何所自，羲文周孔易□□。", "□□坤馬中孚鶴，鼎虎革豹未濟狐。", "載鬼一車豕負塗，先張之弧後說弧。", "奇奇怪怪浩以博，湘纍取以爲範模。", "東皇太一九霄下，百靈護駕飛龍趨。", "雲中之君儼帝服，眇視四海翔天衢。", "堯女舜妃兩嬋娟，想見當年泣蒼梧。", "大少司命尾東君，倏來忽逝紛馳驅。", "河伯白黿弭英輔，山鬼赤□□□□。", "桂酒椒漿奠瑶玉，鼓迎簫送鸞鳳輿。", "佳人在望□□□，□君不見心躊躇。", "采芳馨兮日將暮，有所思兮甘糜軀。", "吾王不寤蛾眉嫉，知心惟有寡女媭。", "一士葬魚亡楚國，而况他日秦坑儒。", "我詩頗似賈誼賦，敬弔先生空嗟吁。"]'),
('45cb25b6-c5ec-402c-8e51-1408cff493ee','題淵明歸來圖','方回','宋','宋诗','song-poetry','','[]','人以心役形，方寸有所主。',144,'全唐诗/poet.song.232000.json','["人以心役形，方寸有所主。", "陋巷足簞瓢，外物肯妄取。", "心或爲形役，饑腸內煎煮。", "未必得鼎食，湯鑊已烹汝。", "淵明歸去來，妙甚第三語。", "自形役自心，何乃浪自苦。", "此理一以悟，公相亦糞土。", "而况折我腰，不過米斗五。", "昨非謝督郵，今是睇衡宇。", "易有不遠復，艮曰止其所。", "聖之清若和，高風夷惠伍。", "懦立薄夫敦，仰止邁終古。"]'),
('8acaa205-3bb8-4e0f-9538-7c3278dd4d2c','題家慶圖','方回','宋','宋诗','song-poetry','','[]','昔在成周與唐虞，比屋可封人歡娛。',64,'全唐诗/poet.song.232000.json','["昔在成周與唐虞，比屋可封人歡娛。", "臯夔稷契贊帝俞，周有閎顛弘廟謨。", "太平之世與同符，四海朝車同軌□。", "□□有慶萬姓蘇，天下家家家慶圖。"]'),
('284f289c-6e31-4b8d-8128-df69bbcb032f','題唐人按樂圖','方回','宋','宋诗','song-poetry','','[]','鼓笛笙簫鬨舞茵，伶官和尚雜宮人。',32,'全唐诗/poet.song.232000.json','["鼓笛笙簫鬨舞茵，伶官和尚雜宮人。", "黄番綽共唐三藏，彷彿相傳未必真。"]'),
('52a41a32-77c3-4f94-91c0-b89f47aaab55','哭方碧山前惠州同知  其一','方回','宋','宋诗','song-poetry','','[]','同宗多兩歲，官學幸同門。',48,'全唐诗/poet.song.232000.json','["同宗多兩歲，官學幸同門。", "去夏才相別，踰旬遽□□。", "□□淹逆旅，公已見曾孫。", "二子言將葬，驚嗟欲斷魂。"]'),
('55ffaac2-c530-41f8-9dea-0237cc4d088c','哭方碧山前惠州同知  其二','方回','宋','宋诗','song-poetry','','[]','四年登八十，壽過古來稀。',48,'全唐诗/poet.song.232000.json','["四年登八十，壽過古來稀。", "辭郡非關瘴，思親自合歸。", "千詩存老筆，二紀掩閒扉。", "雞絮臨筵几，隨潮夜夢飛。"]'),
('68db04e1-a8e7-4329-995d-85f313d60b42','送葉茂叔淮安教','方回','宋','宋诗','song-poetry','','[]','爲儒元匪易，入仕似無難。',48,'全唐诗/poet.song.232000.json','["爲儒元匪易，入仕似無難。", "捷疾非科第，飛騰即教官。", "梁城依汴古，楚郡號淮安。", "臺省多知己，書燈莫遣寒。"]'),
('66ef6589-9262-4b4e-976b-49620cb6c971','送凌應蘭玉傳詩序  其一','方回','宋','宋诗','song-poetry','','[]','壬戌同先祖，登名四十年。',48,'全唐诗/poet.song.232000.json','["壬戌同先祖，登名四十年。", "吾衰逃世網，子學紹家傳。", "好作聲名計，姑隨仕宦緣。", "王奇有故事，即見旅朝賢。"]'),
('9268b785-a021-4bc1-bf16-7203c1c2b867','送凌應蘭玉傳詩序  其二','方回','宋','宋诗','song-poetry','','[]','保舉甘年進，何妨緩致身。',48,'全唐诗/poet.song.232000.json','["保舉甘年進，何妨緩致身。", "暫時刀筆吏，他日腹心臣。", "□□全相似，唐詩更逼真。", "多能乃畏謹，誰不與斯人。"]'),
('06497d01-b97c-41f0-a206-66be0fee3780','送李伯英','方回','宋','宋诗','song-poetry','','[]','八十三歲李鶴田，我兄事之後八年。',232,'全唐诗/poet.song.232000.json','["八十三歲李鶴田，我兄事之後八年。", "有弟有弟來見我，我亦待之如弟然。", "鶴田鶴田真神仙，讀萬卷書忘蹄筌。", "鈎銀畫鐵筆下字，咳珠唾玉胸中篇。", "維伯英甫父深齋，我未識之人稱賢。", "相觀骨骼聽議論，九臯之鳴紹家傳。", "□□□□我所敬，論宋勿論唐以前。", "文名第一歐永叔，詩名第一黄庭堅。", "節義第一文丞相，三士鼎峙撐青天。", "隠逸第一□□人，拾吾鶴田其誰旃。", "君不見西漢四皓起商顔，羽□□□劉氏綿。", "又不見東漢子陵卧嚴灘，足加帝腹摇星躔。", "鶴田爲嚴之處則九鼎重，鶴田爲皓之出則九鼎安，吾將以子伯英之行卜之焉。"]'),
('d5cce308-d59c-4b6f-b954-f7441ce189f9','寄閻承旨靖軒','方回','宋','宋诗','song-poetry','','[]','相逢偶值寄梅人，今歲江南暖未勻。',32,'全唐诗/poet.song.232000.json','["相逢偶值寄梅人，今歲江南暖未勻。", "報與玉堂真學士，小詩聊當一枝春。"]'),
('e12fe2e0-33d3-4cd1-93bb-d1c5446021b2','題三蘇先生族譜後','方回','宋','宋诗','song-poetry','','[]','眉山萬古老蘇仙，坡潁兒孫世世賢。',64,'全唐诗/poet.song.232000.json','["眉山萬古老蘇仙，坡潁兒孫世世賢。", "尚想九關排虎豹，□須七葉珥貂蟬。", "何人不作無窮地，今日才知已定□。", "紹述姦朋市朝撻，剡源學士筆如椽。"]'),
('058d3562-48a7-41d9-a9c4-6e6478fe9573','至前偶書','方回','宋','宋诗','song-poetry','','[]','江南子月已春迴，一日堪傾一百杯。',64,'全唐诗/poet.song.232000.json','["江南子月已春迴，一日堪傾一百杯。", "朝飯太牢□□□，□窗西子月中梅。", "閒心自得無窮趣，老氣猶誇未盡才。", "我近八旬經萬變，傍觀嬉戲小嬰孩。"]'),
('a9b5bb2b-ca94-4b1c-8084-0b01bfba7a7f','湖州推官史彥明碎妖石','方回','宋','宋诗','song-poetry','','[]','君不見杜子美，搜詩益州城。',190,'全唐诗/poet.song.232000.json','["君不見杜子美，搜詩益州城。", "西門所見石筍雙高蹲，欲募壯士擲天外，使人不疑見本根。", "又不見韓退之，□□□□憐愚民，枯株朽木事爲神。", "偶然題作木居士，便有□□□福人。", "安吉古廟李衛公，有一怪石左廡中。", "不知始初孰舁致，矯誣妄誕欺吳儂。", "諸欲殺人劫盜者，牲酒奠祭駢羣凶。", "狂魂滯魄詫憑附，乞靈徼福撐虛空。", "忽值湖州推官史，□如明月清如水。", "集衆搥之百雜碎，棄置溝渠同糞矢。", "南方淫祠百且千，焉得一一皆若此。"]'),
('8b5073f1-ff90-45c2-90e7-267f22195f03','次韻送郝同知還閩二首  其一','方回','宋','宋诗','song-poetry','','[]','平生奔走遍區中，老尚流離作寓公。',64,'全唐诗/poet.song.232000.json','["平生奔走遍區中，老尚流離作寓公。", "合坐黄堂稱太守，願求丹劑學仙翁。", "繄誰虎豹占文變，何限貂蟬出武功。", "可似有心隨李耳，流沙西邁過崆峒。"]'),
('94512f3e-d099-478f-b2cc-fdc7baaf4d05','次韻送郝同知還閩二首  其二','方回','宋','宋诗','song-poetry','','[]','字畫多年逼獻之，高材天賦豈人爲。',64,'全唐诗/poet.song.232000.json','["字畫多年逼獻之，高材天賦豈人爲。", "一枝禿筆無能敵，百尺名樓有所思。", "磧馬塞鴻忘舊夢，建茶閩荔富新詩。", "皇天具眼終徼福，多病從來喜讓夷。"]'),
('a1667925-0a4f-4865-8091-c855b4c40860','十四日至節','方回','宋','宋诗','song-poetry','','[]','錢塘多少富豪家，酒肉如山賞物華。',32,'全唐诗/poet.song.232000.json','["錢塘多少富豪家，酒肉如山賞物華。", "野老入城□□□，□蘿蔔菜臘梅花。"]'),
('e76aea0c-2500-45df-a165-20bb6409b543','十六日大雪','方回','宋','宋诗','song-poetry','','[]','長至前踰一月晴，忽然細細雨無聲。',32,'全唐诗/poet.song.232000.json','["長至前踰一月晴，忽然細細雨無聲。", "中宵變作今□□，□得樓頭鼓角清。"]'),
('37051494-ef53-4944-96fe-05fb46c04339','十七日大雪','方回','宋','宋诗','song-poetry','','[]','扁舟未覺出城難，訪舊情知老畏寒。',32,'全唐诗/poet.song.232000.json','["扁舟未覺出城難，訪舊情知老畏寒。", "七十五翁無□□，□樓聊且隔簾看。"]'),
('ce60275d-331a-48a7-8dd8-fd08d437109a','寄題朱信州自閑堂','方回','宋','宋诗','song-poetry','','[]','吾師魏華父，庵以自爲名。',120,'全唐诗/poet.song.232000.json','["吾師魏華父，庵以自爲名。", "自庵有類稿，其文世盛行。", "吾友陳壽夫，堂以自爲號。", "謂予可言詩，玉成有大造。", "上饒朱使君，燕居題自閑。", "此自指何處，專指方寸間。", "閑眠與閑防，暇字匪二義。", "自防乃自暇，只是一箇自。", "子思慎其獨，使君資之深。", "自身閑不難，先當閑自心。"]'),
('961e0a9b-6173-4568-8818-3d8593782d35','贈學易耕心','方回','宋','宋诗','song-poetry','','[]','佛書曾畫牛犁舌，以易耕心却不然。',32,'全唐诗/poet.song.232000.json','["佛書曾畫牛犁舌，以易耕心却不然。", "一寸地中栽□□，□將三寸舌談天。"]'),
('24877aae-7472-43e6-9a77-e4f961839ad1','和李鶴田乙未贈李个庵','方回','宋','宋诗','song-poetry','','[]','這个庵中這个人，莫將兩个認心身。',32,'全唐诗/poet.song.232000.json','["這个庵中這个人，莫將兩个認心身。", "一个亦無羲□□，□於此處玩天真。"]'),
('d9bf8cc8-084d-4bab-a12f-43f0703d18ea','全真教隨喜','方回','宋','宋诗','song-poetry','','[]','全真遺教契清寧，蕭散無爲養性靈。',64,'全唐诗/poet.song.232000.json','["全真遺教契清寧，蕭散無爲養性靈。", "百歲萍蓬無定跡，一身土木已忘形。", "陳言不用參同契，祕法何須急律令。", "中有異人殊未測，倏然輕舉上青冥。"]'),
('c5c77a03-80cb-4fab-a9af-99fb05427e5a','雪中汎舟','方回','宋','宋诗','song-poetry','','[]','詩翁汎雪船，動趣兩三篇。',48,'全唐诗/poet.song.232000.json','["詩翁汎雪船，動趣兩三篇。", "未快看梅眼，空流憶酒涎。", "□□衝凍凌，饑雁起荒田。", "兒女牽衣處，新春入暮年。"]'),
('d1150a00-66bc-469e-ad19-5d00b47f8128','去姑蘇','方回','宋','宋诗','song-poetry','','[]','雙臉殷紅捧玉尊，陽臺彷彿見香魂。',32,'全唐诗/poet.song.232000.json','["雙臉殷紅捧玉尊，陽臺彷彿見香魂。", "一生心道蘇州好，何事摇船出葑門。"]'),
('ecf4635d-c361-4093-bae6-7932a0db499e','過臨平二首  其一','方回','宋','宋诗','song-poetry','','[]','臨平山下汎歸船，何必荷花五月天。',32,'全唐诗/poet.song.232000.json','["臨平山下汎歸船，何必荷花五月天。", "記取五更霜□□，□芳橋買小魚鮮。"]'),
('3b6b11ec-f9ed-4566-8c0b-a4259874da04','過臨平二首  其二','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','行在名存一夢惺，西湖路近六長亭。',32,'全唐诗/poet.song.232000.json','["行在名存一夢惺，西湖路近六長亭。", "陳橋驛與臨平鎮，興廢何人了汗青。"]'),
('34d5aa02-54e1-44e2-96d4-faa8d74f7295','寄魏珍卿','方回','宋','宋诗','song-poetry','','[]','五十年登靜老門，八男今見九曾孫。',64,'全唐诗/poet.song.232000.json','["五十年登靜老門，八男今見九曾孫。", "浮生變幻□□□，□事艱危詎忍論。", "三級浪知龍有種，九臯聲喜鶴猶□。", "□□舟畔書帷舊，酒醒燈前欲斷魂。"]'),
('c0f8733e-4968-446b-974b-be41ccbf0850','寄魏鶴臺並呈虛舟','方回','宋','宋诗','song-poetry','','[]','損益相因俯仰間，人才世事頗相關。',64,'全唐诗/poet.song.232000.json','["損益相因俯仰間，人才世事頗相關。", "熙豐消息黄龍府，濂洛源流白鶴山。", "此道不隨高岸改，吾徒寧作野雲閒。", "世家但保書燈在，莫羨雲霄玉笋班。"]'),
('f85e55f6-bc98-452d-ad6e-f238668d799f','寄魏景山','方回','宋','宋诗','song-poetry','','[]','長橋身作長城夢，南五湖天北濟淮。',64,'全唐诗/poet.song.232000.json','["長橋身作長城夢，南五湖天北濟淮。", "重聽吳歈憐我老，憶騎塞馬與君偕。", "田園粗有何須侈，子婿俱賢豈不佳。", "七十六翁如未死，便郵一紙更忘懷。"]'),
('4eae111f-dd23-4fef-a050-e7f2a5bce454','壬寅立春在辛丑十二月二十九日歸□□□三宿','方回','宋','宋诗','song-poetry','','[]','隔日春先立，崇朝歲始除。',48,'全唐诗/poet.song.232000.json','["隔日春先立，崇朝歲始除。", "去來身不定，好惡夢皆□。", "□□千山外，舟車一月餘。", "豈真休客擔，猶□□家書。"]'),
('2fc36724-708d-4041-9b15-6468941a88be','予丁亥生壬寅年七十六留杭十二年','方回','宋','宋诗','song-poetry','','[]','吾生已是三分過，此地胡爲一紀留。',32,'全唐诗/poet.song.232000.json','["吾生已是三分過，此地胡爲一紀留。", "萬事無心偶然耳，久將身世付浮休。"]'),
('52fbe944-72fa-4230-9aa8-01e43d11d896','送鮑子壽寶慶教授','方回','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','吾聞陳后山，兩爲彭城教。',276,'全唐诗/poet.song.232000.json','["吾聞陳后山，兩爲彭城教。", "先生新安人，歷歲董卿□。", "□□晚潁州，日與坡老樂。", "君今實似之，往食邵陽稍。", "□□□□□，□□□□□。", "吾聞徐孝節，教授家山陽。", "其名聞于朝，其行高□□。", "□□大書之，特褒宣德郎。", "君今詎止此，即日鵷鷺行。", "□□□□□，□□□□□。", "戊午秋七月，予泛洞庭湖。", "君山朝欲曙，武口日未□。", "□□怒蛟龍，忠信堪支吾。", "君胸有所挾，浮湘弔蒼梧。", "□□□□□，□□□□□。", "長沙十二縣，東西湘江夾。", "君才嶽麓高，君心洞庭□。", "□□古邵州，青燈萃儒帢。", "循循善誘人，不必劍□□。", "君往隸邵學，近接濂翁州。", "君居長徽學，晦翁之故丘。", "顔曾思生魯，孟子生於鄒。", "君其鄒魯人，天畀鄒魯遊。"]'),
('776cb94c-01f1-40e2-947d-29394d528d08','六言四首  其一','方回','宋','宋诗','song-poetry','','[]','馬文園消渴病，嵇中散絕交書。',28,'全唐诗/poet.song.232000.json','["馬文園消渴病，嵇中散絕交書。", "未害子虛烏有，可□□□才疏。"]'),
('ba61be3c-fd03-4600-be5f-cee3c2cc751b','六言四首  其二','方回','宋','宋诗','song-poetry','','[]','樓中老子無事，座上梅花盛開。',28,'全唐诗/poet.song.232000.json','["樓中老子無事，座上梅花盛開。", "閉目不閉鼻孔，暗□□□自來。"]'),
('5654559f-62f7-4261-9a0c-7be5453059e0','六言四首  其三','方回','宋','宋诗','song-poetry','','[]','讀萬卷行萬里，酌一杯題一詩。',28,'全唐诗/poet.song.232000.json','["讀萬卷行萬里，酌一杯題一詩。", "頹齡如此如此，豪氣已而已而。"]'),
('6fed47c6-9b93-43b7-9b40-ad5a71711472','六言四首  其四','方回','宋','宋诗','song-poetry','','[]','傳燈錄第一卷，我佛世尊如來。',28,'全唐诗/poet.song.232000.json','["傳燈錄第一卷，我佛世尊如來。", "自謂寂滅樂已，誰不嗚呼哀哉。"]'),
('b83958ef-2a88-473e-b333-cd7e676801f4','題王起宗畫雪扇六言','方回','宋','宋诗','song-poetry','','[]','何必見戴安道，月圓夜雪晴時。',29,'全唐诗/poet.song.232000.json','["何必見戴安道，月圓夜雪晴時。", "烏府王起宗畫，□□□□虛谷詩。"]'),
('1501bc1a-2ddf-4bee-9488-49cf55a4b2c6','送郝同知','方回','宋','宋诗','song-poetry','','[]','僕昔塵忝歲壬戌，甲科爲首降爲乙。',336,'全唐诗/poet.song.232000.json','["僕昔塵忝歲壬戌，甲科爲首降爲乙。", "宰相謂己□□□，□實見怒出私臆。", "漢東掌教大洪山，寄名帥幕隸□□。", "□陵還鄂艤安陸，燃火高岸夜伐荻。", "是時約近一二□，□書有來遞鈴急。", "閫公拆觀衆太息，郢州新喪二千石。", "□□蓋代真人豪，養士萬數馬千疋。", "邊頭失此老□□，□□以致襄陽失。", "世事輪雲勿嘆嗟，郢州諸子吾皆識。", "伯仲□□落鵰手，舞騎彎弓轟霹靂。", "黄金鎖甲青油幕，黄卷青燈從此出。", "能爲橫槊建安詩，不減修禊永和筆。", "難弟兄中屈指三，漳州半刺今第一。", "黄閤紫樞烏臺官，有求可以唾手得。", "邂逅一閒二十年，髭雪鬢霜慵不摘。", "我老我窮甚於公，公獨枉駕顧此客。", "既觴我酒俎豆之，又厪珠玉□□什。", "一別千門換桃符，梅初未白柳遄碧。", "人生有若鴻□□，銜蘆一枝食數粒。", "往來去就無定所，寒避江湖暖沙磧。", "此心與彼獨不同，睡裏有情夢相憶。"]'),
('0e565f58-48ce-4587-afa0-2c6093a753b6','次韻趙朴翁赴衍聖公嶧山書院之招','方回','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','鄒魯相望擊柝間，亦顔誰許獨晞顔。',64,'全唐诗/poet.song.232000.json','["鄒魯相望擊柝間，亦顔誰許獨晞顔。", "同源泗水別沂水，接壤嶧山連泰山。", "萬世元勳闢楊墨，一時浮論主雍環。", "七篇事業君能講，男子臨岐淚肯潸。"]'),
('6a3f79d3-7f9d-470e-a5e8-9a32356fb7e7','正月二十一日偶題','方回','宋','宋诗','song-poetry','','[]','樓頭日日倚危欄，來往人忙許靜看。',64,'全唐诗/poet.song.232000.json','["樓頭日日倚危欄，來往人忙許靜看。", "老子無聊常□□，杏花欲動更春寒。", "虛名疇昔三千字，險路平生百八盤。", "揮翰玉堂有公相，閒人贏得把漁竿。"]'),
('41afa0dd-aa3d-4077-9b2c-4c5bfda6edb6','題王瓛王珪母郭氏義節記','方回','宋','宋诗','song-poetry','','[]','老儒致聘女師儒，二十言歸四十夫。',64,'全唐诗/poet.song.232000.json','["老儒致聘女師儒，二十言歸四十夫。", "令弟階庭駢兩玉，賢郎門戶儼雙珠。", "摽梅迨吉年雖淺，汎柏維儀志不踰。", "冠帔笏袍相照映，稱觴真可畫成圖。"]'),
('0268590d-a675-4716-9af0-672543630c40','題郎川紀勝圖','方回','宋','宋诗','song-poetry','','[]','維汝明父起宗父，古潤嘗僚佐農扈。',304,'全唐诗/poet.song.232000.json','["維汝明父起宗父，古潤嘗僚佐農扈。", "釃酒金山焦山寺，□馬昇州揚州府。", "歌詩千百南北傳，一別十年散還聚。", "駸致五袠知天命，雙鬢更無絲一縷。", "昔賢相思即命駕，車而不笠莫敢侮。", "汝明家在軍都山，田十五頃清潁灣。", "母及子孫六百指，仰事俯育身久閒。", "大江之南雁北向，故人聞綴行臺班。", "合眼有時得相見，不過夢中空往還。", "起宗籍籍□□史，□□易退仕如止。", "桐川大邑當孔道，弦歌聲□□□□。", "斷橋流水來者誰，兩轡相逢各驚喜。", "丹青慘澹繪爲圖，邃□幽穿知幾里。", "右軍蘭亭未足誇，摩詰輞川焉可擬。", "紫陽洞天虛谷春，亦荷老筆爲寫真。", "踰七望八盍早往，滄浪日濯冠纓塵。", "二公妙齡挾才藝，往往見知今宰臣。", "省□□□夕有命，再使堯舜風俗醇。", "錦囊此軸且捲起，未可□□□鱠蓴。"]'),
('425f7f21-f6a5-4bb8-b6ed-55606ae5a86d','春半久雨走筆五首  其一','方回','宋','宋诗','song-poetry','','[]','月餘不浴不梳頭，垢服埃巾獨倚樓。',64,'全唐诗/poet.song.232000.json','["月餘不浴不梳頭，垢服埃巾獨倚樓。", "萬古事銷閒裏醉，一年春向雨中休。", "天時纔暖又還冷，人世少歡多是愁。", "治亂無窮如糾纏，華山高卧最爲優。"]'),
('ebe84157-3330-4a7c-8222-50b7974cd332','春半久雨走筆五首  其二','方回','宋','宋诗','song-poetry','','[]','早從師讀易乾元，晚乃微探性命源。',64,'全唐诗/poet.song.232000.json','["早從師讀易乾元，晚乃微探性命源。", "道在一前包宇宙，心無二處契羲軒。", "行將死矣依先塚，即合歸歟理故園。", "二十餘年復韋布，人生焉用兩朱轓。"]'),
('8d6ca1e3-b7cf-4e6a-82c3-4c9aeefb2306','春半久雨走筆五首  其三','方回','宋','宋诗','song-poetry','','[]','纔喜晴明又雨陰，尋春未了早春深。',64,'全唐诗/poet.song.232000.json','["纔喜晴明又雨陰，尋春未了早春深。", "牡丹芍藥□□□，寒食清明上塚心。", "詩癖已應吟萬首，酒狂何止費千金。", "□□百歲三分過，屢死焉知活到今。"]'),
('4e9ea91f-b72e-4a22-b02b-29c9b8a093d0','春半久雨走筆五首  其四','方回','宋','宋诗','song-poetry','','[]','萬事心空口亦箝，如何感事氣猶炎。',64,'全唐诗/poet.song.232000.json','["萬事心空口亦箝，如何感事氣猶炎。", "落花滿硯慵磨墨，乳燕歸梁急捲簾。", "詩句妄希敲月賈，郡符深愧釣灘嚴。", "千愁萬恨都消處，笑指鄰樓一酒帘。"]'),
('ef7db408-2520-45f6-be99-63fbc51305b3','春半久雨走筆五首  其五','方回','宋','宋诗','song-poetry','','[]','耳焦髪禿四肢枯，年近非熊異壯圖。',64,'全唐诗/poet.song.232000.json','["耳焦髪禿四肢枯，年近非熊異壯圖。", "見識漸高詩□□，精神常好酒相扶。", "地輿茂育元非有，天宇空虛不是無。", "自笑太倉中一粒，夢魂夜夜侍都俞。"]'),
('aa2e2eb3-da2c-4572-a2ac-eb4f1312546d','醉題二首  其一','方回','宋','宋诗','song-poetry','','[]','倏忽侵尋八十翁，平生學問見詩中。',64,'全唐诗/poet.song.232000.json','["倏忽侵尋八十翁，平生學問見詩中。", "可因道術仙能到，何用禪言佛不同。", "是是非非雙鬢白，鶑鶑燕燕百花紅。", "太歲壬寅題此句，小樓買酒酹東風。"]'),
('fe56a832-0043-4a90-8d54-221fb362cbe5','醉題二首  其二','方回','宋','宋诗','song-poetry','','[]','賣花人憩小樓前，買幾枝看日典錢。',64,'全唐诗/poet.song.232000.json','["賣花人憩小樓前，買幾枝看日典錢。", "詩向夢中頻□□，□才醉後便如仙。", "貧閒略比陶元亮，老壽將過白樂天。", "□□定爲林下計，嚴灘西向練溪船。"]'),
('e2513e53-5c1d-4116-8284-b8b285026e06','道山座主先生平章呂公挽歌辭五首  其一','方回','宋','宋诗','song-poetry','','[]','一門真將相，天地間生之。',48,'全唐诗/poet.song.232000.json','["一門真將相，天地間生之。", "表海太公望，封王郭子儀。", "□□堪襲閫，跨竈早持麾。", "福壽完終始，人□□□□。"]'),
('b11fe4e3-325e-482b-afd0-9a9b88dbd736','道山座主先生平章呂公挽歌辭五首  其二','方回','宋','宋诗','song-poetry','','[]','乃翁同此老，兩柱共擎天。',48,'全唐诗/poet.song.232000.json','["乃翁同此老，兩柱共擎天。", "初作二千石，才生十九年。", "漢陽□最大，嶺外帥何緣。", "極恨湖濱相，姦臣喜弄權。"]'),
('04e3ba90-2fda-4eea-ab03-458dc09bb867','道山座主先生平章呂公挽歌辭五首  其三','方回','宋','宋诗','song-poetry','','[]','□公三十歲，死守漢陽城。',48,'全唐诗/poet.song.232000.json','["□公三十歲，死守漢陽城。", "焉得江陵閫，能支鄂渚兵。", "椿庭纔不起，槐府已無情。", "最恨木綿鬼，乾坤一擲輕。"]'),
('4cfbbcae-9333-4835-9bd5-77a55868d572','道山座主先生平章呂公挽歌辭五首  其四','方回','宋','宋诗','song-poetry','','[]','昔僕叨名第，繄誰極作成。',48,'全唐诗/poet.song.232000.json','["昔僕叨名第，繄誰極作成。", "首捐登仕誥，誤掇別闈□。", "□□人皆喜，權臣獨不平。", "可憐身欲死，無以報平生。"]'),
('d08afd91-cf2f-43dc-af3c-4875fc4de9ad','道山座主先生平章呂公挽歌辭五首  其五','方回','宋','宋诗','song-poetry','','[]','大別登秋興，南樓望戰塵。',48,'全唐诗/poet.song.232000.json','["大別登秋興，南樓望戰塵。", "興亡元有數，生死不無神。", "將相名千古，兒孫近百人。", "生靈活億萬，報豈止公身。"]'),
('f6c15dac-d536-4361-96c4-a50a866e92d2','次韻謝周兄見訪','方回','宋','宋诗','song-poetry','','[]','弱壯之間幾輩流，不凡已與老成侔。',64,'全唐诗/poet.song.232000.json','["弱壯之間幾輩流，不凡已與老成侔。", "筆端可挽千鈞弩，胸次如登百尺樓。", "良木政須資長養，芳蘭未厭□□□。", "□□衰晚不聞道，幸早專心似奕秋。"]'),
('dcd29b29-b138-4ccb-9fac-88766c3a45a7','贈俞碧巖體仁刊圖書','方回','宋','宋诗','song-poetry','','[]','上古包羲卦初畫，五行之金刀爲革。',272,'全唐诗/poet.song.232000.json','["上古包羲卦初畫，五行之金刀爲革。", "兩儀四象生□□，□初一圈爲太極。", "八卦之上六十四，右乾左坤名曰易。", "因重□定科斗書，削木爲方竹爲冊。", "擣紙束毫寫今字，世降俗□動山積。", "何如簡徑却艱難，篠簜梓桐事雕刻。", "所以近人刊圖書，篆籀依稀規鳥迹。", "博雅君子具老眼，爾□生者□不識。", "紫陽山西星源州，遥見長虹貫白日。", "伊人□□□□間，雲氣開晴碧巖碧。", "一旦飄然□□湖，硎刃如□□□□。", "誰嘗石鼓玩陳倉，忽似野碑揭鄒嶧。", "贈我三印紅屈蟠，細□游絲疏復密。", "侯王黄金橐駝紐，韓彭何曾得渠力。", "如我□綠綬亦無，不過小匣藏寸物。", "閒詩倡和外謹封，家書時用報兒姪。", "佩之如寶漢剛卯，不懼取將轟霹靂。"]'),
('89d44503-c5cc-4cdc-804b-22ffe363cbae','清明大雪三日','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','半月雕梁燕子歸，怯寒著盡舊綿衣。',32,'全唐诗/poet.song.232000.json','["半月雕梁燕子歸，怯寒著盡舊綿衣。", "何人醉眼西湖路，錯認楊花作雪飛。"]'),
('00a97b15-f7b4-4fa8-8037-7dae46fd6e30','跋高舍人錢舜舉君選著色山水','方回','宋','宋诗','song-poetry','','[]','堆青仍積翠，山與水俱奇。',48,'全唐诗/poet.song.232000.json','["堆青仍積翠，山與水俱奇。", "毫髪漁船遠，尋常草舍卑。", "喜君真好學，索我細題詩。", "卷軸頻舒卷，明窗肯見思。"]'),
('d817521c-b000-41dd-8df6-88edceb2ed90','送戴帥初信州教授','方回','宋','宋诗','song-poetry','','[]','伏羲之後幾萬年，堯舜八聖孟一賢。',240,'全唐诗/poet.song.232000.json','["伏羲之後幾萬年，堯舜八聖孟一賢。", "誰學其學傳其傳，□明間氣生戴先。", "上庠文聲撐青天，高揭蘭闈十名前。", "□□隻字宮商宣，豈但場屋著祖鞭。", "早合玉堂照金蓮，□□□衣常退然。", "擢第三十二載間，昔日朱顔今蒼顔。", "踰冠□□□□班，垂迫耳順猶在閒。", "一任金陵絳帳還，近始再調□□山。", "得非世道多間關，乍可不仕避險艱。", "四男二女膝□環，束脩餬口萊衣斑。", "我宿冒忝博士官，稠衆中□□□□。", "□□直上秋天寒，得公老筆不厭看。", "雄文兩魁□□□，□□柄國韜禍端。", "老夫尋遭霜簡彈，白首相逢徒□□。", "□□□給甕虀酸，人生出處如此難。"]'),
('60efb452-ecea-4f08-b7c7-43e6df247966','畫觀世音贊','方回','宋','宋诗','song-poetry','','[]','□見呻吟，我砭我針。',20,'全唐诗/poet.song.232000.json','["□見呻吟，我砭我針。", "人有此心，即觀世音。"]'),
('30feff02-52d6-45f4-b878-af00f88a04f2','題曹舍人文龍墨竹扇仲賓息齋寫','方回','宋','宋诗','song-poetry','','[]','文湖州筆欠坡詩，便面瀟瀟雨一枝。',32,'全唐诗/poet.song.232000.json','["文湖州筆欠坡詩，便面瀟瀟雨一枝。", "暑汗輕摇骨□□，□間誰識庾元規。"]'),
('75f4eef5-a54f-43d8-bcf8-7911028795b4','題陳仲良宅觀古物及徐熙來禽卷','方回','宋','宋诗','song-poetry','','[]','車書一統混乾坤，福地錢塘戶口蕃。',64,'全唐诗/poet.song.232000.json','["車書一統混乾坤，福地錢塘戶口蕃。", "治世故□□巨室，吉人宜爾保名門。", "金玉印章文物古，丹青圖畫典刑存。", "來禽幾顆徐熙筆，欲摘紅鮮薦酒樽。"]'),
('fbc22050-c9e3-48c9-b37a-460b9a0f1bfc','送吳僧慶閒上人','方回','宋','宋诗','song-poetry','','[]','唐僧窮島可，應是筆能追。',48,'全唐诗/poet.song.232000.json','["唐僧窮島可，應是筆能追。", "投卷初來此，迴船忽去之。", "味□工會合，情淡慣分離。", "許讀紅樓集，昌黎亦贈詩。"]'),
('2ba52918-1b43-49dd-8c37-602f6ee49c0c','觀世音像贊','方回','宋','宋诗','song-poetry','','[]','觀見世間，苦痛之心。',42,'全唐诗/poet.song.232000.json','["觀見世間，苦痛之心。", "而往救之，脫彼呻吟。", "咄，千□□□，□□隻眼。", "曰何以故，以心觀心。"]'),
('0bec5735-9eb0-4af2-a0ed-be919c38eb57','五月二夜聞雨大□□日至杭','方回','宋','宋诗','song-poetry','','[]','□凉喚起酒醒人，聽雨更闌得句新。',32,'全唐诗/poet.song.232000.json','["□凉喚起酒醒人，聽雨更闌得句新。", "兒子遠來作生□，□□□十六年身。"]'),
('d3c2d4b9-6933-46fa-a8b4-351fd68d7663','送汪復心饒州教','方回','宋','宋诗','song-poetry','','[]','派出魚龍氏，聲摇虎豹關。',48,'全唐诗/poet.song.232000.json','["派出魚龍氏，聲摇虎豹關。", "兩司千里泮，一退四年閒。", "學孔誰如孔，晞顔我亦顔。", "不應但携酒，日日看芝山。"]'),
('19bad28e-3005-4f61-8947-597f4ff96b83','送畢用虎談星命','方回','宋','宋诗','song-poetry','','[]','知君家世擅儒風，不與江湖術士同。',64,'全唐诗/poet.song.232000.json','["知君家世擅儒風，不與江湖術士同。", "季主市占排賈誼，□平肆卜服揚雄。", "言談簡淡非長古，揖讓雍□□鞠躬。", "甲子支干五星說，源流本出六經中。"]'),
('22b90cd3-b1ee-4dde-bb38-bc371b3dfb1b','題凍雀著色梅花','方回','宋','宋诗','song-poetry','','[]','一枝玉蕊艷□□，□雀雙跧凍翼香。',32,'全唐诗/poet.song.233000.json','["一枝玉蕊艷□□，□雀雙跧凍翼香。", "誰識綠毛掛么鳳，坡仙詩眼醉南□。"]'),
('c7716a22-4be7-41b6-8ca9-4e776ec60e22','壬寅生日楊廣文携示壬辰生日詩次韻','方回','宋','宋诗','song-poetry','','[]','方寸天知地亦知，昂藏胸次了無奇。',64,'全唐诗/poet.song.233000.json','["方寸天知地亦知，昂藏胸次了無奇。", "山林獨樂休官早，□縣徒勞見事遲。", "一影浪行千萬里，十年未朽兩三詩。", "故□□□驚陳迹，旅次傳抄付小兒。"]'),
('26db9deb-a341-4a23-a8b6-b138d6403768','壬寅生日別賦','方回','宋','宋诗','song-poetry','','[]','南踰梅嶺北冰天，跋涉艱危□□憐。',64,'全唐诗/poet.song.233000.json','["南踰梅嶺北冰天，跋涉艱危□□憐。", "頗頼青州從事力，□過絳縣老人年。", "稍同氣臭能□□，□□□□□□□。", "□□八旬苦多病，且須爛醉海榴前。"]'),
('a0b16b50-bdf9-4c67-b6df-784193caeb51','生日後三朝又書','方回','宋','宋诗','song-poetry','','[]','□□七十六年春，湖海飄零一病身。',64,'全唐诗/poet.song.233000.json','["□□七十六年春，湖海飄零一病身。", "相愛故人誇壽相，遠□兒子作生辰。", "齒浮聲嗄調凉劑，髪少頭瘡爪破巾。", "只合歸歟辦棺塚，斷無華表石麒麟。"]'),
('59cb9a85-c7e0-47f0-8333-c29b5412cc51','送丘正之海鹽州教授二首  其一','方回','宋','宋诗','song-poetry','','[]','而立年前髭未長，金臺早已擅名場。',64,'全唐诗/poet.song.233000.json','["而立年前髭未長，金臺早已擅名場。", "法書筆下蛟龍□，□句胸中錦繡腸。", "斧藻一州專學校，枌榆卜舍近家鄉。", "□□講道相傳授，不在槐花舉子忙。"]'),
('456b8ab6-dd6d-47a7-b8c8-dfaa4a62f8fa','送丘正之海鹽州教授二首  其二','方回','宋','宋诗','song-poetry','','[]','去年七月朔風潮，倒海排山蜃鱷驕。',64,'全唐诗/poet.song.233000.json','["去年七月朔風潮，倒海排山蜃鱷驕。", "亭□□□□□□，□宮未必盡飄颻。", "隨宜補葺燈窗破，循序扶持粟廩□。", "□友一心研義理，浙鄉風俗未蕭條。"]'),
('7f039aa5-60c1-4b83-b453-2625f38dbbf7','送張仲實宜興州教授','方回','宋','宋诗','song-poetry','','[]','天未喪斯文，遯翁續思孟。',252,'全唐诗/poet.song.233000.json','["天未喪斯文，遯翁續思孟。", "戒慎恐懼傳，源流獨也正。", "□□中節情，未發爲善性。", "人己不睹聞，了無一可偵。", "上璧□□朗，下譬深淵靚。", "尚復有形迹，兩物相照映。", "人心統性情，本□垢可淨。", "鬼神不能知，匣中未開鏡。", "所以古君子，一恬□□□。", "學者當此時，養之惟以敬。", "述者於茲明，作者於茲聖。", "三畏孰爲首，戰兢保天命。", "武林子張子，早執文□□。", "□□將相家，炎紹四大姓。", "未應釣渭□，□□□□□。", "□□□□□，□見退之病。", "中年有省悟，坐覺浮華屏。", "宜興□□□，□□聞且榜。", "諸生望絳帳，□以慰郊迎。", "朱子所著書，率□□□□。", "當於謹獨上，有法更究竟。"]'),
('3105084b-bf83-4f3f-931a-dc28085fa837','題孫廷玉藏李仲賓墨竹','方回','宋','宋诗','song-poetry','','[]','仲賓筆底招君子，廷玉胸中敬正人。',32,'全唐诗/poet.song.233000.json','["仲賓筆底招君子，廷玉胸中敬正人。", "更著紫陽虛叟句，兩公烱烱見精神。"]'),
('539bd96d-c2c5-48d2-a1fd-7b33a5b4e8d4','寄題感應夫人廟','方回','宋','宋诗','song-poetry','','[]','觀世音化馬郎婦，西王母嘲方朔兒。',32,'全唐诗/poet.song.233000.json','["觀世音化馬郎婦，西王母嘲方朔兒。", "乾坤大幻萬千變，□我敬之而遠之。"]'),
('4b6c87f5-c518-4bef-86f9-2bf89b673675','五月二十三日懷歸二首  其一','方回','宋','宋诗','song-poetry','','[]','拔茅猶在盍歸休，何事清河日倚樓。',64,'全唐诗/poet.song.233000.json','["拔茅猶在盍歸休，何事清河日倚樓。", "百歲四分三已過，十朝九醉一無愁。", "獨遺蕙帳容逋客，誰向瓜田識故侯。", "定是紫陽山下路，西風仙袂揖浮丘。"]'),
('8a053cd0-fac3-4478-9255-f983dbf9669e','五月二十三日懷歸二首  其二','方回','宋','宋诗','song-poetry','','[]','生紅一簇海榴枝，慚愧虛翁兩鬢絲。',64,'全唐诗/poet.song.233000.json','["生紅一簇海榴枝，慚愧虛翁兩鬢絲。", "久客湖山何足戀，□□父子自相知。", "江南江北千鍾酒，身後身前萬首詩。", "連□□霖忽開朗，人生亦有晚晴時。"]'),
('cc1e367b-bc35-4932-b385-417859cbfbfa','題答祿章瑞淨香亭','方回','宋','宋诗','song-poetry','','[]','□□成都府治元帥堂，綠竹含籜新出牆。',178,'全唐诗/poet.song.233000.json','["□□成都府治元帥堂，綠竹含籜新出牆。", "今古詩人第一□，幕屬工部員外郎。", "□□□酒樽，主賓遨晚凉。", "上句雨洗娟娟淨，一掃人間塵土黄。", "下句嚇破嚴武膽，解道風吹細細香。", "竹淨易見香難說，此□撩天鼻孔長。", "我知橫溪□□□，□□少陵先生鼻。", "不徒□此君之佳色，又能識此君至清之□。", "然則是又不徒識此君之清氣，而能識此君之真味，識此君之深意者歟。", "下一轉語參此禪，敢問竹香云何細而細。"]'),
('20b0fa66-95c5-48f3-b498-2db176366c54','題范陽祖澤士榮松齋','方回','宋','宋诗','song-poetry','','[]','九天風雨歲寒頻，十八公邊夜讀身。',64,'全唐诗/poet.song.233000.json','["九天風雨歲寒頻，十八公邊夜讀身。", "氣味菟□□□□，□朋梅竹可三人。", "秦皇愛護加封爵，夏后栽培作社□。", "可以書燈照吟榻，落毛掃石當茶薪。"]'),
('cf1b2774-80ec-4fb1-acc2-1e83c69285b6','六月八日遷寓侍郎橋','方回','宋','宋诗','song-poetry','','[]','梧桐樓外雨蕭蕭，客裏遷居意不聊。',64,'全唐诗/poet.song.233000.json','["梧桐樓外雨蕭蕭，客裏遷居意不聊。", "凈土偶鄰羅漢洞，閒人肯羨侍郎橋。", "蠹魚書少家何窘，行李船輕路匪遥。", "此□十翁肯相送，典錢沽酒了今朝。"]'),
('a35d1cf9-438f-438a-ba04-a04a9ba59ece','苦雨半年','方回','宋','宋诗','song-poetry','','[]','□海蛟龍睡不鼾，半年晝夜雨漫漫。',64,'全唐诗/poet.song.233000.json','["□海蛟龍睡不鼾，半年晝夜雨漫漫。", "何曾略識三春暖，更□難禁六月寒。", "孰感神明迴叶氣，忍聞生聚落深湍。", "鼇□□擲將期矣，不許□□□日安。"]'),
('c305dda2-84cc-4262-bd5b-02f8fa8aad54','六月十二日侍郎橋感事','方回','宋','宋诗','song-poetry','','[]','□大歷歷七南朝，幾□□潮夜復潮。',64,'全唐诗/poet.song.233000.json','["□大歷歷七南朝，幾□□潮夜復潮。", "湖上已無□□□，□□□有侍郎橋。", "官同謝傅慚高潔，位過周公肆吝驕。", "□□□心木綿鬼，穢聲不與骨俱銷。"]'),
('c5702bc4-07c5-4485-ab61-f8e30eb968d6','題郭元德寓意齋藁後','方回','宋','宋诗','song-poetry','','[]','一硯隨身一棹輕，斗南斗北仰詩名。',64,'全唐诗/poet.song.233000.json','["一硯隨身一棹輕，斗南斗北仰詩名。", "豈真寓意不留意，□恐無情還有情。", "瘦島獨敲逢尹詰，癖陵寧死要人驚。", "□□自號異商隠，妥律平平仄仄平。"]'),
('cec38906-f934-4dbe-a433-785844b80080','題施好古示龔學古瘦馬六言','方回','宋','宋诗','song-poetry','','[]','畫馬不學韓幹，我知八十翁心。',28,'全唐诗/poet.song.233000.json','["畫馬不學韓幹，我知八十翁心。", "使皆肥□□□，□□□□可斟。"]'),
('b72c86d1-595b-4b42-86e0-81637ce0198b','送江泰發晦庵書院小學教諭','方回','宋','宋诗','song-poetry','','[]','翩然歸去兩芒鞋，朱子書堂小學齋。',64,'全唐诗/poet.song.233000.json','["翩然歸去兩芒鞋，朱子書堂小學齋。", "好向四書尋骨髓，敢辭五嶺役筋骸。", "晦傳可是終無愧，遯筮誰知晚□佳。", "前哲持身但如此，知時豈不有吾儕。"]'),
('5e935160-d141-4517-9e63-c3f93054ec40','次韻曹清父營生墳追和范石湖韻四首  其一','方回','宋','宋诗','song-poetry','','[]','桑榆未迫尚東隅，諸子盈前返哺烏。',64,'全唐诗/poet.song.233000.json','["桑榆未迫尚東隅，諸子盈前返哺烏。", "早檢青囊營□□，□□丹竈著工夫。", "無生話可忘言了，自祭文能信手摸。", "□□□年未遑辦，一抔□□□良圖。"]'),
('8029282f-3c4e-46bb-b213-545a132f2181','次韻曹清父營生墳追和范石湖韻四首  其二','方回','宋','宋诗','song-poetry','','[]','古來奕世保松楸，八百姬周四百劉。',64,'全唐诗/poet.song.233000.json','["古來奕世保松楸，八百姬周四百劉。", "今代未聞□□□，□時尚想引魌頭。", "干戈蒿里無完穴，□□蘭亭有□□。", "□□□□誰可免，一杯聊□祝千秋。"]'),
('e300dd6e-8e07-44d5-8223-fbb6b27ad4fc','次韻曹清父營生墳追和范石湖韻四首  其三','方回','宋','宋诗','song-poetry','','[]','□□如斯舉一隅，誰非長夜閟金烏。',64,'全唐诗/poet.song.233000.json','["□□如斯舉一隅，誰非長夜閟金烏。", "裹屍馬革真□□，□□□山淺丈夫。", "羽化苦無仙伎倆，茶毗別是佛規模。", "□□彭祖終須爾，匪悟浮休肯豫圖。"]'),
('e5ee10e6-db41-4605-8a58-8e7aa8237059','次韻曹清父營生墳追和范石湖韻四首  其四','方回','宋','宋诗','song-poetry','','[]','殺心奕局響紋楸，鷄肋何如酒德劉。',64,'全唐诗/poet.song.233000.json','["殺心奕局響紋楸，鷄肋何如酒德劉。", "世事但堪常袖手，人生政要早迴頭。", "誰能卒辦魚千里，自笑終成貉一丘。", "□□明年纔七十，商山剩飫紫芝秋。"]'),
('9cca948a-71e8-4a15-862a-d88ef78e1f47','贈胡端本顯伯教諭二首  其一','方回','宋','宋诗','song-poetry','','[]','星□□□□諸胡，鄉里人人仰範模。',64,'全唐诗/poet.song.233000.json','["星□□□□諸胡，鄉里人人仰範模。", "韜養沉潜求大□，□揮□□號通□。", "□生不出跧吟屋，垂老□□□□□。", "□□舊坑硯中覓，浮溪汪氏遯翁朱。"]'),
('791be8e2-73ce-49cb-a3e0-b1c8e0e1343a','贈胡端本顯伯教諭二首  其二','方回','宋','宋诗','song-poetry','','[]','芙蓉嶺外矮窗開，夜讀燈從祖父來。',64,'全唐诗/poet.song.233000.json','["芙蓉嶺外矮窗開，夜讀燈從祖父來。", "四海八荒□□□，□山一壑絕塵埃。", "生涯晚節香黄菊，世德清陰映綠槐。", "□□仲車教鄉里，何時除目下行臺。"]'),
('34272c9e-757b-4477-945a-da44463db717','送劉仲鼎瀏陽教四首  其一','方回','宋','宋诗','song-poetry','','[]','□□今名郡，劉公昔碩師。',48,'全唐诗/poet.song.233000.json','["□□今名郡，劉公昔碩師。", "山留黄帝蹕，水遶紫陽祠。", "遣□□□足，陳言講說疲。", "□曾參到否，未有四書時。"]'),
('cc6332fa-24ca-4056-942a-4f8926b0e1fa','送劉仲鼎瀏陽教四首  其二','方回','宋','宋诗','song-poetry','','[]','□向湖南去，衡湘剩□□。',48,'全唐诗/poet.song.233000.json','["□向湖南去，衡湘剩□□。", "淚凝斑竹恨，骨冷葬魚悲。", "學□循常式，師生整舊現。", "□軒何故道，無所爲而爲。"]'),
('d56fc14f-426f-482b-b5c5-efda4362d907','送劉仲鼎瀏陽教四首  其三','方回','宋','宋诗','song-poetry','','[]','瀏陽吾未到，疇昔到長沙。',48,'全唐诗/poet.song.233000.json','["瀏陽吾未到，疇昔到長沙。", "文定諸胡子，宣公故相□。", "□□□已化，心皎月無瑕。", "□□尋方冊，燈昏眼易花。"]'),
('9278ac47-b36d-4d9a-a5ac-d02f396f0d70','送劉仲鼎瀏陽教四首  其四','方回','宋','宋诗','song-poetry','','[]','□□湘江潔，名應嶽麓齊。',48,'全唐诗/poet.song.233000.json','["□□湘江潔，名應嶽麓齊。", "扁舟先浙左，匹馬次江西。", "眼可□今大，詩須到處題。", "世人無陸學，一笑過金谿。"]'),
('e781b278-07f1-4ef0-b796-e80e6ebc09c0','贈秋蓬王相士','方回','宋','宋诗','song-poetry','','[]','人生兮若蓬，摇落兮秋風。',80,'全唐诗/poet.song.233000.json','["人生兮若蓬，摇落兮秋風。", "或南兮或北，忽西兮忽東。", "□□兮潦水，高之兮太空。", "天翔兮征鴻，地泄兮鳴蛬。", "皆一氣□所使兮，曾不由夫我躬。", "焉得三萬六千日，無盡無藏兮惟杯中。"]'),
('44570844-ba30-49ab-9037-73ce3e812f62','贈范君用筆工五首  其一','方回','宋','宋诗','song-poetry','','[]','漢庭上方斬馬劍，子製毛錐端似之。',32,'全唐诗/poet.song.233000.json','["漢庭上方斬馬劍，子製毛錐端似之。", "未辦朱雲請此物，筆誅市撻佞臣誰。"]'),
('717b8375-c49b-44ba-876b-fb7f9ca8215b','贈范君用筆工五首  其二','方回','宋','宋诗','song-poetry','','[]','世上豈無千里馬，能騎千里馬何人。',32,'全唐诗/poet.song.233000.json','["世上豈無千里馬，能騎千里馬何人。", "直須讀書破萬卷，始用子筆如有神。"]'),
('e1b8c7b8-daa9-44d9-b043-fe58851067a7','贈范君用筆工五首  其三','方回','宋','宋诗','song-poetry','','[]','畫工如山赤墀下，調子之筆丹青勻。',32,'全唐诗/poet.song.233000.json','["畫工如山赤墀下，調子之筆丹青勻。", "一洗萬古空凡馬，曹將軍外更無人。"]'),
('6b407939-530e-4b34-a86b-5c950cc45d1e','贈范君用筆工五首  其四','方回','宋','宋诗','song-poetry','','[]','未誇長管入手便，政須短管護銛鋒。',32,'全唐诗/poet.song.233000.json','["未誇長管入手便，政須短管護銛鋒。", "未染濡時常著帽，忽□脫帽走蛟龍。"]'),
('b8ed5219-c067-41e2-9830-efeb4d705593','贈范君用筆工五首  其五','方回','宋','宋诗','song-poetry','','[]','善舞吾聞霓裳曲，□□音有陶朱公。',32,'全唐诗/poet.song.233000.json','["善舞吾聞霓裳曲，□□音有陶朱公。", "長袖多錢世豈少，鐵鞭難得尉遲恭。"]'),
('bb365867-2954-4b40-b149-4b26942e6ed4','贈馬唐卿數學環中吟','方回','宋','宋诗','song-poetry','','[]','揚子雲易爲太玄，邵堯夫易爲皇極。',192,'全唐诗/poet.song.233000.json','["揚子雲易爲太玄，邵堯夫易爲皇極。", "溫公之易曰潜虛，觀物行成有七易。", "環圓其形刳其中，圓則能轉中則容。", "譬如門牡必有牝，環中居士心與同。", "車各雙輪三十輻，與之運行謂之轂。", "轂之兩端鑿竅穴，良工於此膏其軸。", "老子教人舉一隅，莊子推廣言戶樞。", "圓而能容無滯礙，大德若容百川輸。", "居士易應有師授，言人咎休頃刻究。", "厥祖三世登巍科，乃翁八旬享高壽。", "環外人賦環中篇，何時吳門吾過船。", "携酒與汝談此事，月窟天根玄又玄。"]'),
('15dc3bda-8c52-43eb-90c6-7f3ffa88b88c','蘭亭','方回','宋','宋诗','song-poetry','','[]','細看僧字永和碑，誰見山陰落筆時。',32,'全唐诗/poet.song.233000.json','["細看僧字永和碑，誰見山陰落筆時。", "想像捧心□□□，□間幾本話西施。"]'),
('83260b64-a77c-439a-ac04-7416e92a881d','中秋夜喜晴','方回','宋','宋诗','song-poetry','','[]','秋來剩賦倚樓吟，天慰衰翁此夜心。',64,'全唐诗/poet.song.233000.json','["秋來剩賦倚樓吟，天慰衰翁此夜心。", "霽色一輪升白玉，歡聲萬鎰價黄金。", "酒纔半醉吾忘我，詩最難題古到今。", "日□西流聊困卧，不知更淺與更深。"]'),
('3b1e87e4-7702-498c-88ff-cc2e3cccdc54','八月十八日天曉二首  其一','方回','宋','宋诗','song-poetry','','[]','木犀花正盛，吹入滿樓香。',48,'全唐诗/poet.song.233000.json','["木犀花正盛，吹入滿樓香。", "不是人無寐，焉知夜已長。", "樹鳴秋雨急，潮過海天凉。", "自覺衣裘少，侵尋近肅霜。"]'),
('b1edd14a-d73b-4302-9c04-3c1d5c8a27a4','八月十八日天曉二首  其二','方回','宋','宋诗','song-poetry','','[]','河中船已動，岸亦有人行。',48,'全唐诗/poet.song.233000.json','["河中船已動，岸亦有人行。", "城北鐘聲斷，樓東鬼宿明。", "倚□□酒醒，搔首小詩成。", "□□中秋熱，今朝始漸清。"]'),
('de886772-299e-49b4-9c3f-b38ba1e9794c','寄題陳公輔聽雨軒','方回','宋','宋诗','song-poetry','','[]','知時潤物最關心，不作珠簾暮捲吟。',32,'全唐诗/poet.song.233000.json','["知時潤物最關心，不作珠簾暮捲吟。", "龍過驚迴欹枕夢，簷聲點點是商霖。"]'),
('fd69cf76-90c2-4ad6-b5a5-c9ea39128e68','八月二十日天曉','方回','宋','宋诗','song-poetry','','[]','清曉潮初過，西風獵弊裘。',48,'全唐诗/poet.song.233000.json','["清曉潮初過，西風獵弊裘。", "肯爲貧士地，偏覺老人愁。", "蟋蟀聲彌急，梧桐色漸愁。", "殘星餘幾點，吾獨倚吾樓。"]'),
('139b1b3c-3bdd-43ca-bee7-ae973ead614b','八月二十日趙西湖携酒夜醒二更記事  其一','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','社襖初穿暑氣收，今朝五日過中秋。',64,'全唐诗/poet.song.233000.json','["社襖初穿暑氣收，今朝五日過中秋。", "隔湖我每思□□，□市公能顧小樓。", "斗酒隻鷄承厚意，扁舟匹馬約閒遊。", "吾儕不與人間事，肯掛眉頭一點愁。"]'),
('b947b7dd-53c2-4fc4-a5dc-47f9e583b3ae','八月二十日趙西湖携酒夜醒二更記事  其二','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','酒醒更深獨倚樓，天清地靜俯河流。',64,'全唐诗/poet.song.233000.json','["酒醒更深獨倚樓，天清地靜俯河流。", "梧桐影轉三更月，蟋蟀聲催萬象秋。", "自古有生皆有死，即今無喜亦無憂。", "更著四年當八十，我於人世復何求。"]'),
('e4aa54c1-036d-4434-8dec-f87f97eb8470','八月二十三日早起','方回','宋','宋诗','song-poetry','','[]','不寐緣何事，無言試自思。',96,'全唐诗/poet.song.233000.json','["不寐緣何事，無言試自思。", "百年欹枕裏，五夜倚樓時。", "天下奇才少，人中間氣誰。", "洗心方見易，知道始能詩。", "可用黄庭演，何勞素問醫。", "儻來縻爾爵，小事惄如饑。", "栗里淵明菊，商山綺里芝。", "乾坤萬萬古，達者姓名垂。"]'),
('6eaf86dd-b370-4afd-abd0-c74253b07f59','贈存古楊茂盛卿','方回','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','卷軸年深碎破時，我能補苴以完之。',64,'全唐诗/poet.song.233000.json','["卷軸年深碎破時，我能補苴以完之。", "驚逢大桁重華典，喜見由庚束皙詩。", "王會周篇汲郡冢，儒生秦頌泰山碑。", "裝潢作手今無敵，消得朝天馹騎馳。"]'),
('d036d7c0-62d1-4286-a3ec-18316c5fb5c9','贈葉宗貴一山','方回','宋','宋诗','song-poetry','','[]','一山葉翁七十二，齒牙禿缺面不媚。',396,'全唐诗/poet.song.233000.json','["一山葉翁七十二，齒牙禿缺面不媚。", "忽然袖詩叩我門，偏貝疇能辦茲事。", "才德豈關貌妍醜，西子□□孟光膩。", "三十年許舊相識，翁攝官霅我半刺。", "兵銷甲解各不死，我嘗作郡翁弗至。", "鴻翔燕蟄蓬飄風，會合良難別離易。", "往不可追來叵測，人生恍惚如夢寐。", "邂逅尚肯匡解頤，當爲酒樓謀一醉。", "雙臺方叟七十六，二十七霜絕俸祿。", "幸與陵陽牟先生，丁亥同生共星宿。", "先生擘箋介翁來，筆勢雲烟字珠玉。", "翁索我詩紙七尺，見示諸公詩一軸。", "孟能靜吟我所畏，趙子昂寫我所服。", "我詩初學張文潜，晚悟后山拜山谷。", "頗通大道合自然，拙朴有餘巧不足。", "近世後生宗許渾，可謂諺云狗尾續。", "至當之論天地中，不可違異必合同。", "詩自明良賡歌起，以至孔刪雅頌風。", "蘇李曹陶唐甫白，慶曆元祐乾淳宗。", "是爲四始大正派，姓名太陽燭天紅。", "軻死不傳忽復傳，道學一燈垂天窮。", "二程張子之所得，南渡前有濂溪翁。", "何人實編道命錄，南渡後有張宣公，南渡後有朱文公。", "學詩本是一小藝，彼哉自謂晚唐夜雨鳴秋蛬。"]'),
('a18d2aec-f0f2-4b97-b8b1-822f925ce0fc','留錢塘十二年','方回','宋','宋诗','song-poetry','','[]','一紀錢塘去未能，寒梅凉菊暑天冰。',64,'全唐诗/poet.song.233000.json','["一紀錢塘去未能，寒梅凉菊暑天冰。", "春風七寶山頭寺，夜雨三茅閣上燈。", "和靖不生無隠士，道潜如在可詩僧。", "大船相聚惟歌舞，小舫漁翁采芡菱。"]'),
('6fef8173-ee9d-46d7-a735-a38c1b3365e6','題立上舍草意','方回','宋','宋诗','song-poetry','','[]','萬派江河盡向東，秋風摇落又春風。',64,'全唐诗/poet.song.233000.json','["萬派江河盡向東，秋風摇落又春風。", "性靈根本元相似，軀殻胚胎偶不同。", "螻蟻階前藏窟穴，蜘蛛簷外掛虛空。", "家中子女兼雞犬，爾我無非樂意中。"]'),
('bae09ead-ba5b-4c20-abdc-e8fbba686fce','九月初八日','方回','宋','宋诗','song-poetry','','[]','今年未見菊花枝，老恐登高亦不宜。',64,'全唐诗/poet.song.233000.json','["今年未見菊花枝，老恐登高亦不宜。", "但得明朝須有酒，可能我輩更無詩。", "身閒天下朋遊少，秋暑江南雁到遲。", "宗武宗文佐觴詠，幾家伯道嘆無兒。"]'),
('e4ece097-e789-4eda-8dbd-95d4fabaafe1','九日早起','方回','宋','宋诗','song-poetry','','[]','今日真當爛醉時，丁牀搔首便吟詩。',64,'全唐诗/poet.song.233000.json','["今日真當爛醉時，丁牀搔首便吟詩。", "擬斟白蟻元來少，旋典青蚨亦未遲。", "萬事茫茫先卯飲，一家草草僅晨炊。", "紙窗日上微風冷，斜倚危樓有所思。"]'),
('8f4db5ed-982f-4669-a60c-f6265f88b3d2','九日即事','方回','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','閒居九日意何窮，落木長江感舊同。',64,'全唐诗/poet.song.233000.json','["閒居九日意何窮，落木長江感舊同。", "佳句致多惟杜老，良辰專美只陶翁。", "爲問從人游戲馬，何如對物詠來鴻。", "無萸無菊無螃蟹，亦可隨宜酒一中。"]'),
('9bca97fb-78aa-41e2-b36a-bdcf3196f5b1','次韻靈鷲清長老二首  其一','方回','宋','宋诗','song-poetry','','[]','粗讀書難盡信書，世誰鯁直但阿諛。',64,'全唐诗/poet.song.233000.json','["粗讀書難盡信書，世誰鯁直但阿諛。", "平生湖海悲遊子，晚歲乾坤老腐儒。", "知己尚堪擡醉眼，從僧似欲剃吟鬚。", "何當靈鷲兼三竺，日伴猿饑侶鶴臞。"]'),
('37cfdfda-fb50-4e2c-9f43-d9fe245c6db5','次韻靈鷲清長老二首  其二','方回','宋','宋诗','song-poetry','','[]','得句無僧字不清，公來一日兩詩成。',64,'全唐诗/poet.song.233000.json','["得句無僧字不清，公來一日兩詩成。", "龍雷珠浦東坡和，海日江潮老宋驚。", "魯直尚能推大國，長卿誰可詫長城。", "二桃三士抱吟膝，我所師兮葛孔明。"]'),
('1e5adc2a-6327-4a0d-be88-c1415e72a16d','重陽後絕句五首  其一','方回','宋','宋诗','song-poetry','','[]','梧桐疏葉間微黄，年例江南未肯凉。',32,'全唐诗/poet.song.233000.json','["梧桐疏葉間微黄，年例江南未肯凉。", "菊自此花三兩月，樽前日日是重陽。"]'),
('e845b2e1-527d-4f8d-b6cc-9ce704aa05f6','重陽後絕句五首  其二','方回','宋','宋诗','song-poetry','','[]','昨朝卯酒醉至酉，不記滿斟凡幾巡。',32,'全唐诗/poet.song.233000.json','["昨朝卯酒醉至酉，不記滿斟凡幾巡。", "莫問擔頭青蕊菊，且迎座上白衣人。"]'),
('54a7706d-4018-4ebb-a2aa-9f31af7a8d6b','重陽後絕句五首  其三','方回','宋','宋诗','song-poetry','','[]','九日若無詩與酒，人生如此定凡人。',32,'全唐诗/poet.song.233000.json','["九日若無詩與酒，人生如此定凡人。", "我師子美牧之者，郪縣齊山句尚新。"]'),
('09b8de11-10d5-49ba-886f-b81ee7c51423','重陽後絕句五首  其四','方回','宋','宋诗','song-poetry','','[]','難開笑口憶小杜，今歲江湖雁未飛。',32,'全唐诗/poet.song.233000.json','["難開笑口憶小杜，今歲江湖雁未飛。", "政使菊花無可□，□當爛醉更忘歸。"]'),
('4ab1b559-9987-4046-aaf4-744df5c7054d','重陽後絕句五首  其五','方回','宋','宋诗','song-poetry','','[]','九月重陽菊未開，十月小春梅又來。',32,'全唐诗/poet.song.233000.json','["九月重陽菊未開，十月小春梅又來。", "賞過日長添一線，一瓶菊伴一瓶梅。"]'),
('748fe8e1-4212-41e0-968b-a6b1f684e9ba','乙巳三月十五日監察御史王東溪節宿戒方回萬里飲靈隠冷泉亭趙宣慰君實趙提舉子昂靈隠寺知事晦壇治具西方僧四人兩提領北人放泉噴雪觀猿擲果予醉先退賦詩五首記之  其一','方回','宋','宋诗','song-poetry','','[]','年年時節美春三，誰識湖山綠似藍。',64,'全唐诗/poet.song.233000.json','["年年時節美春三，誰識湖山綠似藍。", "萬戶棟梁雙語燕，千村桑柘兩眠蠶。", "鼓鐘下竺寺連上，香火北高峰勝南。", "除却咸平處士外，何人更此築吟庵。"]'),
('9e201497-76a1-48e6-9086-367ac24faa66','乙巳三月十五日監察御史王東溪節宿戒方回萬里飲靈隠冷泉亭趙宣慰君實趙提舉子昂靈隠寺知事晦壇治具西方僧四人兩提領北人放泉噴雪觀猿擲果予醉先退賦詩五首記之  其二','方回','宋','宋诗','song-poetry','','[]','淵靜濤飛亦壯哉，冷泉亭右閘初開。',64,'全唐诗/poet.song.233000.json','["淵靜濤飛亦壯哉，冷泉亭右閘初開。", "一時變作跳空雪，萬衆驚聞噴壑雷。", "老鶴遠過彭祖壽，巨杉何啻盛唐栽。", "吾生八十重遊此，身健猶堪酒一杯。"]'),
('1c6b43ea-d44b-4754-9e2b-bc985f1cc8d9','乙巳三月十五日監察御史王東溪節宿戒方回萬里飲靈隠冷泉亭趙宣慰君實趙提舉子昂靈隠寺知事晦壇治具西方僧四人兩提領北人放泉噴雪觀猿擲果予醉先退賦詩五首記之  其三','方回','宋','宋诗','song-poetry','','[]','世間春暖此間寒，萬樹陰陰萬竹攢。',64,'全唐诗/poet.song.233000.json','["世間春暖此間寒，萬樹陰陰萬竹攢。", "驄馬來遊人不避，畫龍誰寫我頻看。", "餘生久已忘三黜，高會猶容預四難。", "閒賞孤山梅五絕，樽前剩愛一枝酸。"]'),
('a2f1f8d8-2897-408e-adcf-bb2757159ef1','乙巳三月十五日監察御史王東溪節宿戒方回萬里飲靈隠冷泉亭趙宣慰君實趙提舉子昂靈隠寺知事晦壇治具西方僧四人兩提領北人放泉噴雪觀猿擲果予醉先退賦詩五首記之  其四','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','休兵三十有餘齡，鐵馬曾來似不曾。',64,'全唐诗/poet.song.233000.json','["休兵三十有餘齡，鐵馬曾來似不曾。", "寒士喜從賢御史，閒人許識老名僧。", "畫船處處歌春雪，厦屋遥遥貯臘冰。", "保得西湖如此好，心知明首遇良肱。"]'),
('9e9663e3-5bdb-41f6-9533-2a3b32977663','乙巳三月十五日監察御史王東溪節宿戒方回萬里飲靈隠冷泉亭趙宣慰君實趙提舉子昂靈隠寺知事晦壇治具西方僧四人兩提領北人放泉噴雪觀猿擲果予醉先退賦詩五首記之  其五','方回','宋','宋诗','song-poetry','','[]','三月晴過半月春，真成好景與良辰。',64,'全唐诗/poet.song.233000.json','["三月晴過半月春，真成好景與良辰。", "簪花騎馬多遊女，擲果呼猿不畏人。", "湖山行樂有心賞，天地太平無戰塵。", "兩紀逃名作閒客，樂哉七十九年身。"]'),
('a1c19513-5824-441a-8c97-c5571675f6f5','三月十八日甲子晴','方回','宋','宋诗','song-poetry','','[]','夜夜春寒漸覺輕，桐花十日過清明。',64,'全唐诗/poet.song.233000.json','["夜夜春寒漸覺輕，桐花十日過清明。", "去年稔更今年稔，壬子晴兼甲子晴。", "樓閣相望饒客醉，干戈不用保農耕。", "老儒八十心無事，依舊吟窗剔短檠。"]'),
('493d0fe4-9e11-41a8-8f87-14c7419bbaf0','寄題畢氏鯉潭壽藏','方回','宋','宋诗','song-poetry','','[]','陰德蒙泉日夜流，使君鄉社號千秋。',64,'全唐诗/poet.song.233000.json','["陰德蒙泉日夜流，使君鄉社號千秋。", "方聞壽倒三松詠，遽作身隨一鍤謀。", "誰謂滕公居此室，何云文子樂斯丘。", "穴中得石如金槊，定有人封萬戶侯。"]'),
('31c25724-bc8b-4cfa-8c56-ba20524bd77d','讀太原王氏家記二首  其一','方回','宋','宋诗','song-poetry','','[]','卧冰公相舊家聲，紀載鏗鏘樂九成。',64,'全唐诗/poet.song.233000.json','["卧冰公相舊家聲，紀載鏗鏘樂九成。", "大姓江山同久遠，雄文日月競光明。", "雙親强健躋高壽，兩紀休閒致盛名。", "冠豸澄清聊一出，萬鍾千駟未爲榮。"]'),
('c00f76d7-a76d-47e9-b018-96408f8cf82e','讀太原王氏家記二首  其二','方回','宋','宋诗','song-poetry','','[]','中原表表日星垂，積善傳家泗水湄。',64,'全唐诗/poet.song.233000.json','["中原表表日星垂，積善傳家泗水湄。", "一瓣心香鄒國廟，八分手筆嶧山碑。", "檢身粹行言相應，報國精忠孝可移。", "千萬人中無一二，庭闈偕老及期頤。"]'),
('1a739992-6f9f-4418-b254-50ed623a7a36','三月二十九日飲杭州路耿同知花園','方回','宋','宋诗','song-poetry','','[]','巢燕春泥久已融，虞弦節近鼓薰風。',64,'全唐诗/poet.song.233000.json','["巢燕春泥久已融，虞弦節近鼓薰風。", "枝枝爛熟櫻桃紫，朵朵爭妍芍藥紅。", "冠豸霽威賢御史，雕蟲得雋老詩翁。", "十分蠶麥今年稔，我輩何妨酒一中。"]'),
('0815eb34-f41f-438d-b7e2-a835ece3b8b9','立夏五首  其一','方回','宋','宋诗','song-poetry','','[]','吾家正對紫陽山，南向宜添屋數間。',32,'全唐诗/poet.song.233000.json','["吾家正對紫陽山，南向宜添屋數間。", "百歲十分已過八，只消無事守窮閒。"]'),
('cafb544d-921d-4350-9d68-4365cbff9530','立夏五首  其二','方回','宋','宋诗','song-poetry','','[]','齊侯北海楚南海，匹馬扁舟我過之。',32,'全唐诗/poet.song.233000.json','["齊侯北海楚南海，匹馬扁舟我過之。", "一事略如陸務觀，囊中真有萬篇詩。"]'),
('12f3b4c3-4f2d-41cf-93fe-57709343ceea','立夏五首  其三','方回','宋','宋诗','song-poetry','','[]','說與江湖故舊知，不曾得句未爲詩。',32,'全唐诗/poet.song.233000.json','["說與江湖故舊知，不曾得句未爲詩。", "一更一至五更五，半是搔頭不寐時。"]'),
('891c9f4e-75ad-4e33-8174-d69f98a659af','立夏五首  其四','方回','宋','宋诗','song-poetry','','[]','路過偏嶺暑風凉，草色連天七寸長。',32,'全唐诗/poet.song.233000.json','["路過偏嶺暑風凉，草色連天七寸長。", "無限牛羊無樹木，青青六月地椒香。"]'),
('153c2398-c54b-4f45-b3f0-dc31f6844153','立夏五首  其五','方回','宋','宋诗','song-poetry','','[]','南華六祖老盧能，宇宙千燈復萬燈。',32,'全唐诗/poet.song.233000.json','["南華六祖老盧能，宇宙千燈復萬燈。", "佛法平生吾不信，神交一二老詩僧。"]'),
('e007b865-2902-44e6-8da2-f99a9a50e9f1','李仲賓墨竹四首  其一','方回','宋','宋诗','song-poetry','','[]','乾坤各各變三爻，坎兌相依似泰交。',32,'全唐诗/poet.song.233000.json','["乾坤各各變三爻，坎兌相依似泰交。", "認得易中甘節卦，籜龍貞幹寫煙梢。"]'),
('333345bd-3459-4094-bb89-fab4377857ae','李仲賓墨竹四首  其二','方回','宋','宋诗','song-poetry','','[]','春生夏長出牆頭，含籜新梢玉版抽。',32,'全唐诗/poet.song.233000.json','["春生夏長出牆頭，含籜新梢玉版抽。", "宜雪宜霜無不可，如椽且與貌宜秋。"]'),
('985e071b-0332-4497-91d2-7ebaea224314','李仲賓墨竹四首  其三','方回','宋','宋诗','song-poetry','','[]','心空節勁翠筠濃，冷笑凡花誨冶容。',32,'全唐诗/poet.song.233000.json','["心空節勁翠筠濃，冷笑凡花誨冶容。", "可是人間秋水碧，東方七宿應蒼龍。"]'),
('848b0814-07ac-4ff6-a3cd-420075143288','李仲賓墨竹四首  其四','方回','宋','宋诗','song-poetry','','[]','渭川千畝入毫端，子美臨風野色寒。',32,'全唐诗/poet.song.233000.json','["渭川千畝入毫端，子美臨風野色寒。", "不是畫師即詩客，可能收拾與人看。"]'),
('456a8209-8647-4b3a-b955-75d2c8a8edd3','送方仲和信州學正二首  其一','方回','宋','宋诗','song-poetry','','[]','公論乾坤萬古留，秋崖秋壑兩般秋。',64,'全唐诗/poet.song.233000.json','["公論乾坤萬古留，秋崖秋壑兩般秋。", "尚思下惠甘三黜，肯向新都羨五侯。", "籍甚故家佳玉樹，彼哉亡國阽金甌。", "同鄉同姓仍同榜，喜見煙中跨竈樓。"]'),
('e681b021-f477-451f-b188-a42162030598','送方仲和信州學正二首  其二','方回','宋','宋诗','song-poetry','','[]','科第官資異昔年，束書聊憩玉山前。',64,'全唐诗/poet.song.233000.json','["科第官資異昔年，束書聊憩玉山前。", "師生講暇臯比地，兄弟吟高雁字天。", "虛谷宗生雙鬢禿，秋崖家學一燈傳。", "向來晦靜相逢處，諸老猶應有斷編。"]'),
('12f8ea80-6ee8-4c98-86d1-2c331b61ddad','送柴廷玉靜得','方回','宋','宋诗','song-poetry','','[]','爛柯峰下碧溪雲，元自龜山一派分。',64,'全唐诗/poet.song.233000.json','["爛柯峰下碧溪雲，元自龜山一派分。", "羅仲素初同此脈，朱元晦始張吾軍。", "儻知柴氏潜心學，未數徐魁徑畈文。", "近喜識荆靜得老，名家知道更多聞。"]'),
('5783abdd-7166-4048-8ee0-1519e01b40bf','義犬行','方回','宋','宋诗','song-poetry','','[]','君不見周興西旅貢厥獒，今日天下新建櫜。',234,'全唐诗/poet.song.233000.json','["君不見周興西旅貢厥獒，今日天下新建櫜。", "遠方不許進異物，閒却三略兼六韜。", "又不見王孫昔歎走狗烹，今日天下永太平。", "保全功臣决無此，花村夜不爭雉鳴。", "陸平原家養黄耳，繫書不隔江淮水。", "金陵音問還洛陽，往來何啻萬餘里。", "杜少陵寓鄜州居，舊物低徊入衣裾。", "宗文宗武共入蜀，愛憐想亦如相如。", "古滕東溪王御史，先公豈弟世無比。", "一犬育之十五年，送葬至墓不食死。", "一飯糟糠何足論，恒飽不饑謝乾坤。", "垂深井韁馬救主，銜明月珠蛇報恩。", "世上紛紛輕薄子，翻雲覆雨喪廉恥。", "動輒反噬不識人，可似韓盧烏喙之徒知義理。"]'),
('e509a789-c518-4340-977d-50d610bc63e0','送程桂軒子方還蜀治先墓','方回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','周宣中興常武雅，程伯休父爲司馬。',288,'全唐诗/poet.song.233000.json','["周宣中興常武雅，程伯休父爲司馬。", "其先重黎掌天地，此佐尹氏征伐者。", "顔曾思復有七篇，孰云軻死道不傳。", "洛中二程忽突起，乃有明道與伊川。", "西蜀名士古相繼，東坡外家亦程氏。", "吾州紫陽此姓多，宰相訥翁顯近世。", "猗哉古渝程子方，年高七十彌健强。", "子公禮甫侍入峽，灑掃松楸脩墓藏。", "孝思祖考安遺體，何惜往來萬餘里。", "曳裾岷峨山上雲，鼓棹灧澦堆前水。", "儒流不與常人同，何况此郎娛此翁。", "自古搜詩得句處，往往車中與舟中。", "夔州十歌劉賓客，百花潭北子美宅。", "二老遺蹤可訪尋，飛龍舞蛟轟霹靂。", "五月重午離西湖，九月重九趨成都。", "盍簪之別澆菖蒲，若堂之封酹茱萸。", "小春早梅仲春柳，蜀地吳天兩俱有。", "古渝何必卜故廬，不如再飲西湖酒。"]'),
('d60477dc-809a-4e26-973a-b535bc3f9554','走筆送吳僧慶間遊明越','方回','宋','宋诗','song-poetry','','[]','挑包前日過垂虹，明旦乘潮向浙東。',64,'全唐诗/poet.song.233000.json','["挑包前日過垂虹，明旦乘潮向浙東。", "兩袖虎丘山上月，一竿漁浦渡頭風。", "乾坤佛法元來盛，湖海詩僧到處雄。", "而立妙齡廣長舌，肯參八十紫陽翁。"]'),
('d477020f-26ac-48fa-85cb-0d148915f5ad','送康彥博文夫吉州教長句二十韻','方回','宋','宋诗','song-poetry','','[]','廟廊謁賢飯吐哺，留子翰林不肯住。',304,'全唐诗/poet.song.233000.json','["廟廊謁賢飯吐哺，留子翰林不肯住。", "閻公大學今儒宗，邀子同宿玉堂霧。", "曰我天南有嚴親，滫瀡旨甘奉朝暮。", "得一泮水廣文官，匹馬扁舟遂南渡。", "未愛紅藥當階翻，但憶芝山携酒句。", "江東自鄱泝江西，郡曰青原洲白鷺。", "歐陽文逮周益公，誠齋詩傳楊長孺。", "比戶弦誦家書燈，子往爲師異瓜戍。", "人才爐冶入老手，鏌鋣干將由我鑄。", "即今場屋已無用，五言省題八韻賦。", "人心天理不可磨，秉彝物則常如故。", "五天竺國身出神，三蓬萊山臂生羽。", "緇黄引之入迷途，殘魄零魂應悔誤。", "昌黎原道孟七篇，除蚘剗蟯剔魚蠹。", "子當以此據臯比，正正邪邪明舉錯。", "本根樹立謹心術，節目設張行法度。", "子曾精讀萬卷書，子又遠遊萬里路。", "諸生北面孰不服，窮理盡性擺傳註。", "天民先覺敢自許，作成後進定無數。"]'),
('103ad06c-454d-4295-b2f6-e177abf58f10','學詩吟十首  其一','方回','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','我陟匡廬山，想像淵明廬。',108,'全唐诗/poet.song.233000.json','["我陟匡廬山，想像淵明廬。", "我遊永嘉郡，康樂茲佩魚。", "學詩六十載，鑽仰二老且。", "白首恐無成，嗟哉腹空虛。", "邇來擺百務，糲飯幾無蔬。", "朝吟極摹倣，夜詠加勤渠。", "不必一字工，意味但舒徐。", "比陶似不足，方謝尚有餘。", "舉世無人識，歸歟吾歸歟。"]'),
('c4d403d8-0a58-4f1a-a03f-d2a19c403cf3','學詩吟十首  其二','方回','宋','宋诗','song-poetry','','[]','三百篇既絕，孔聖作春秋。',96,'全唐诗/poet.song.233000.json','["三百篇既絕，孔聖作春秋。", "榮辱繫褒貶，與詩美刺侔。", "楚騷降一等，尚可風雅儔。", "漢盛出蘇李，魏興起曹劉。", "歷覽逮六朝，仰止茲爲優。", "獨一陶元亮，龍鳳翔九州。", "韓柳繼李杜，黄陳紹蘇歐。", "江湖近一種，禽蟲鳴啁啾。"]'),
('7ec86156-4f98-47ab-b607-5990ea4d730f','學詩吟十首  其三','方回','宋','宋诗','song-poetry','','[]','我讀淵明詩，不忍復去手。',96,'全唐诗/poet.song.233000.json','["我讀淵明詩，不忍復去手。", "休官四十一，不肯戀五斗。", "二十三霜秋，籬下作重九。", "朝亦一杯酒，暮亦一杯酒。", "南北幾蛙紫，能爾一醉否。", "義熙所以立，寄奴幸而偶。", "牧野誅獨夫，夷齊尚弗取。", "竊評首陽山，乃後有五柳。"]'),
('00421320-40c4-453c-a881-1e37dae95691','學詩吟十首  其四','方回','宋','宋诗','song-poetry','','[]','我愛真西山，讀書有甲記。',96,'全唐诗/poet.song.233000.json','["我愛真西山，讀書有甲記。", "首論天命性，豈可不論氣。", "我愛魏鶴山，周易輯集義。", "濂洛十七家，一貫六十四。", "有寂即有感，槁死笑釋氏。", "無氣欲爲人，瓦礫棄骸胔。", "復見天地心，有處起生意。", "王弼獨云無，此語决非是。"]'),
('9444be6f-2b45-4d4f-9322-1ac6cf59279b','學詩吟十首  其五','方回','宋','宋诗','song-poetry','','[]','楊氏昔爲我，老子實似之。',96,'全唐诗/poet.song.233000.json','["楊氏昔爲我，老子實似之。", "墨氏昔兼愛，釋迦亦如之。", "孟子闢楊墨，有功此一時。", "似仁與似義，暗傳匪明垂。", "梵語東漢譯，玄門西晉師。", "迄爲萬世害，三教乃並馳。", "獨一韓文公，張我正正旗。", "濂洛有諸老，此盛彼遂衰。"]'),
('01792b93-245f-4bf8-9198-b0d27e8a364e','學詩吟十首  其六','方回','宋','宋诗','song-poetry','','[]','離騷謂絕響，此道傳人心。',96,'全唐诗/poet.song.233000.json','["離騷謂絕響，此道傳人心。", "外物有鼎革，能言無古今。", "曹劉與陶謝，五柳擅正音。", "李杜與韓柳，一字直萬金。", "歐蘇與黄陳，孰淺而孰深。", "尤蕭楊陸范，乾淳鶴在陰。", "二澗可繼之，章泉亦駸駸。", "奈何近百載，種火灰中深。"]'),
('836e9cc1-c2fa-4885-8d72-4bd7760e08a1','學詩吟十首  其七','方回','宋','宋诗','song-poetry','','[]','宋詩孰第一，吾賞梅聖俞。',96,'全唐诗/poet.song.233000.json','["宋詩孰第一，吾賞梅聖俞。", "綽有盛唐風，晚唐其劣諸。", "牛尾狸無敵，馬蹄鱉與俱。", "龍溪奏思陵，此産臣鄉閭。", "宣城二十詠，歙浦俗亦如。", "春洲生荻芽，寄興河豚魚。", "真言寫實事，組刻全屏除。", "黄陳吟格高，此事分兩途。"]'),
('76267785-b52f-4fee-87fa-aafd572c48b6','學詩吟十首  其八','方回','宋','宋诗','song-poetry','','[]','我寓侍郎橋，夜枕聞五德。',84,'全唐诗/poet.song.233000.json','["我寓侍郎橋，夜枕聞五德。", "四更即不眠，東望逆曙色。", "南睨三茅閣，千燈破暗黑。", "百八仙林鐘，鼉龍吼其北。", "繄此倚闌人，四海誰我識。", "未能朱晦翁，鄉邦續道脈。", "猶當陸放翁，桐江刻詩集。"]'),
('501ce7d1-04f6-4658-ba19-21257440eb5c','學詩吟十首  其九','方回','宋','宋诗','song-poetry','','[]','承天寺一碑，宜州萬里走。',96,'全唐诗/poet.song.233000.json','["承天寺一碑，宜州萬里走。", "後山與簡齋，各年四十九。", "李杜俱有厄，郊島終不偶。", "今人好作詩，曾不鑒茲否。", "我如陸務觀，平生詩萬首。", "明年當八十，不可日無酒。", "四男異甑釜，二女欠箕箒。", "曉問床頭甕，僅有酒一斗。"]'),
('0b431af1-0e3a-4796-a976-dcd79b201d89','學詩吟十首  其一○','方回','宋','宋诗','song-poetry','','[]','吾性能忍窮，所以不仕宦。',96,'全唐诗/poet.song.233000.json','["吾性能忍窮，所以不仕宦。", "兩紀加一載，考槃歌在澗。", "當車穩杖屨，當肉飽藜莧。", "雖然鮮歡娛，終不墮憂患。", "憶昔四十九，奏書似臺諫。", "請劍斬佞臣，此賊罪惡貫。", "倏忽三十秋，往事如夢幻。", "不死踰八旬，幾度見賓雁。"]'),
('9c19f071-d868-402d-a3e2-98aa33ae6edc','再送王聖俞戴溪','方回','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','宇宙喜一統，於今三十年。',240,'全唐诗/poet.song.233000.json','["宇宙喜一統，於今三十年。", "江南諸將相，北上揚其鞭。", "書生亦覓官，裹糧趨幽燕。", "青原有王老，歷世羲獻賢。", "自浙而江淮，北理彭城船。", "不上郭隗臺，不飲盧溝泉。", "問之果何往，往陟泰山巔。", "觀古封禪碑，討究秦漢鎸。", "森森楷木林，上香先聖前。", "滕州孟子廟，鄒縣有墓田。", "我亦嘗過之，如親聞七篇。", "羨君今勇往，插翅如登仙。", "嗚呼古先哲，何以百世傳。", "我等生後世，倏忽銷如煙。", "嗟嗟此何故，男子若婦然。", "少游勝伏波，此論何其偏。", "七戰歿牖下，畢萬自有天。", "誓死或不死，求全終罕全。", "吾聞溪中禽，有曰信天緣。", "魚過得飽食，終不流饑涎。"]'),
('10c5e398-f067-42de-ba12-161823929c8c','獨立','方回','宋','宋诗','song-poetry','','[]','午窗睡起懶衣裳，獨立樓頭數過航。',64,'全唐诗/poet.song.233000.json','["午窗睡起懶衣裳，獨立樓頭數過航。", "苔蘚瓦連蒼暈古，梧桐簷覆綠陰凉。", "北來話舊玉堂雨，西望懷人白筆霜。", "自覺多思尚多事，不如樽酒見羲皇。"]'),
('dc6f5a05-86a5-4284-a43b-9351d9d4ecb9','思家五首  其一','方回','宋','宋诗','song-poetry','','[]','憶昔年垂五十時，紫陽山下結茅茨。',64,'全唐诗/poet.song.233000.json','["憶昔年垂五十時，紫陽山下結茅茨。", "閒花野竹三間屋，皓月清風萬首詩。", "得罪權臣常自笑，逃名市隠復奚疑。", "壽登釣渭真慚愧，不學空令有四兒。"]'),
('7e06b771-537b-4e8d-bb8f-b728f1e39850','思家五首  其二','方回','宋','宋诗','song-poetry','','[]','湖海今非昔妙齡，未容許汜識陳登。',64,'全唐诗/poet.song.233000.json','["湖海今非昔妙齡，未容許汜識陳登。", "歸心七里灘頭棹，客思三茅閣上燈。", "雪裏梅香尋酒媼，雨前茶好待詩僧。", "近來衰老嗟何似，怕啖杭州六月冰。"]'),
('719a318b-a1f7-4eb4-83df-dbdeda6198be','思家五首  其三','方回','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','世道駸駸似可咍，多年吾已似銜枚。',64,'全唐诗/poet.song.233000.json','["世道駸駸似可咍，多年吾已似銜枚。", "品題已定門人叛，議論方公敵國來。", "瓦礫敢侔珠玉價，茅茨誰辦棟梁材。", "淵明歸去廬山下，未少黄花酒一杯。"]'),
('4a896b49-202d-4d44-b491-5e74588fbf49','思家五首  其四','方回','宋','宋诗','song-poetry','','[]','弱冠吟詩六十年，自然熟處有肥仙。',64,'全唐诗/poet.song.233000.json','["弱冠吟詩六十年，自然熟處有肥仙。", "坡翁追和陶元亮，谷老深慚白樂天。", "苦李道傍人不採，蟠桃海上事空傳。", "平心定氣求中道，佳句無窮在眼前。"]'),
('f36ff832-a604-4b58-b735-4f218f28d8b4','思家五首  其五','方回','宋','宋诗','song-poetry','','[]','黄山三十六峰豪，南照城樓百里高。',64,'全唐诗/poet.song.233000.json','["黄山三十六峰豪，南照城樓百里高。", "五嶺舊坑金作硯，雙橋新釀玉爲醪。", "浙鄉巨艦供魚鮝，淮郡駢肩致蟹螯。", "牛尾狸兼馬蹄鱉，消得坡仙賦老饕。"]'),
('b1b41d43-554e-4eb4-b86a-533daa60d0ee','詩思十首  其一','方回','宋','宋诗','song-poetry','','[]','大雅嗟麟筆，離騷嘆鳳弦。',48,'全唐诗/poet.song.233000.json','["大雅嗟麟筆，離騷嘆鳳弦。", "猗那誰與敵，羌蹇尚堪傳。", "步仰曹劉獨，名歆李杜專。", "無時吾不夢，携酒訪斜川。"]'),
('223ae6f8-5fab-4591-8c8d-43d75068cfeb','詩思十首  其二','方回','宋','宋诗','song-poetry','','[]','老子持公論，評詩衆勿驚。',48,'全唐诗/poet.song.233000.json','["老子持公論，評詩衆勿驚。", "更無雙子美，止有一淵明。", "響接東坡和，肩隨太白名。", "吾嘗圖畫像，釋菜四先生。"]'),
('9b81950c-be05-4574-b7c7-9bea45d6d209','詩思十首  其三','方回','宋','宋诗','song-poetry','','[]','萬古陶兼杜，誰堪配饗之。',48,'全唐诗/poet.song.233000.json','["萬古陶兼杜，誰堪配饗之。", "赦還儋耳海，謫死瘴城宜。", "無己玉堂凍，去非榕嶺馳。", "更添韓與柳，欲築八賢祠。"]'),
('f963a52b-a822-4eba-af3c-b95f607dfa20','詩思十首  其四','方回','宋','宋诗','song-poetry','','[]','滿眼詩無數，斯須忽失之。',48,'全唐诗/poet.song.233000.json','["滿眼詩無數，斯須忽失之。", "精深元要熟，玄妙不因思。", "默契如神助，冥搜有鬼知。", "平生天相我，得句匪人爲。"]'),
('91636b1d-861d-42fc-8f65-62e117d25ee7','詩思十首  其五','方回','宋','宋诗','song-poetry','','["\u8861\u5c71", "\u957f\u6c5f"]','素甚鄙南嶽，幸嘗忝雪窗。',48,'全唐诗/poet.song.233000.json','["素甚鄙南嶽，幸嘗忝雪窗。", "格高爲第一，意到自無雙。", "倏忽千軍陣，雍容九鼎扛。", "僧敲作手勢，吾可賈長江。"]'),
('66c37db9-c7e9-4444-9805-3242bd22cfea','詩思十首  其六','方回','宋','宋诗','song-poetry','','[]','楊劉崑體變，誰實擅元功。',48,'全唐诗/poet.song.233000.json','["楊劉崑體變，誰實擅元功。", "萬古推梅老，三辰仰醉翁。", "穆脩先漢筆，魏野盛唐風。", "今日何人悟，江湖慟阮窮。"]'),
('9eb8b038-f0d4-4f66-a28a-6a92b34c0757','詩思十首  其七','方回','宋','宋诗','song-poetry','','[]','俗子欺詩客，詩成未易工。',48,'全唐诗/poet.song.233000.json','["俗子欺詩客，詩成未易工。", "虛聲難忝竊，生理早窮空。", "謠諑無庸聽，諄譫爾未通。", "阮公青白眼，留取送飛鴻。"]'),
('8bfe0fd6-b139-447e-82bb-026290ed1acd','詩思十首  其八','方回','宋','宋诗','song-poetry','','[]','忝竊嚴陵郡，依稀陸放翁。',48,'全唐诗/poet.song.233000.json','["忝竊嚴陵郡，依稀陸放翁。", "作詩踰萬首，浪仕只千窮。", "醉卧三更後，閒吟兩紀中。", "時時落幽夢，漁笛鑑湖東。"]'),
('6d873942-bb0b-46f2-9e91-188215e52bef','詩思十首  其九','方回','宋','宋诗','song-poetry','','[]','苕溪漁隠老，家在績溪東。',48,'全唐诗/poet.song.233000.json','["苕溪漁隠老，家在績溪東。", "苦學多前輩，評詩出此翁。", "生年同孔氏，傳道仰文公。", "爛却沙頭月，誰參到此中。"]'),
('8469a5a0-d374-4a8e-b58d-4e38bba40642','詩思十首  其一○','方回','宋','宋诗','song-poetry','','[]','蛇起新州荻，溫玄業不成。',48,'全唐诗/poet.song.233000.json','["蛇起新州荻，溫玄業不成。", "已無司馬氏，猶有石頭城。", "北伐中原捷，南歸大物更。", "菊花籬下酒，萬古一淵明。"]'),
('f305b404-cf1c-443e-a0ed-606e000d6b83','題十六羅漢畫像','方回','宋','宋诗','song-poetry','','[]','一釋迦佛起天竺，羅漢五百又十六。',121,'全唐诗/poet.song.233000.json','["一釋迦佛起天竺，羅漢五百又十六。", "中華止繪十六僧，貫休十八老筆續。", "千無萬無無更無，芥子須彌一掃俱。", "阿字義門總深入，畫圖豈止伐顓臾。", "咄，伏虎降龍兩尊者，此卷寫一犬如獅一仙鶴，精妙絲毫無苟且。", "筆墨游戲真，古今劫火燃。", "捲起短軸且飲酒，西窗萬里開青天。"]'),
('5ac25d44-5be8-49ad-9fd8-726c38827056','題寒山拾得畫像','方回','宋','宋诗','song-poetry','','[]','我讀寒山拾得詩，唐初武德貞觀時。',128,'全唐诗/poet.song.233000.json','["我讀寒山拾得詩，唐初武德貞觀時。", "此必前朝老進士，開皇大業不仕隋。", "長歌短舞芙蓉句，開元元和尚無之。", "一箒天台國清寺，掃滅人世貪嗔癡。", "文殊師利復現世，僧俗未妨疑傳疑。", "或題松下讀黄老，臆辨二叟果爲誰。", "諺云橘皮錯認皮，九方臯馬遺黄驪。", "嗚呼甚矣吾衰矣，郁郁都都焉雄雌。"]'),
('52b33022-875f-41d6-be96-81b398dda035','武寧茶提舉相臺鄭君思恭之萱堂太夫人馮氏大德乙巳年八十六紫陽山方回萬里年七十九賦長句','方回','宋','宋诗','song-poetry','','[]','孝子不願爲高官，履危未必親心安。',165,'全唐诗/poet.song.233000.json','["孝子不願爲高官，履危未必親心安。", "孝子不願食厚祿，移此祿爲親之福。", "親家堂上太夫人，九九之算饒五春。", "令郎江西三十載，董提茗事職不改。", "他人公台天上飛，我不衮衣但萊衣。", "誰其總戎動百萬，我寧不作麒麟楦。", "夫人愈老愈優游，髪白返黑此之由。", "夫人內丹保堅固，齒落更生此之故。", "君不見莊椿一歲秋八千，彭祖十分之一焉。", "夫人壽骨比彭祖，尚餘七百一十有四年。"]'),
('c6d3b3b1-d49d-4ce3-a78e-79e13d9f93c9','題米元暉寒林','方回','宋','宋诗','song-poetry','','[]','善書善畫古來希，前輩風流日漸微。',32,'全唐诗/poet.song.233000.json','["善書善畫古來希，前輩風流日漸微。", "開卷令人憶羲獻，米元章更米元暉。"]'),
('f7c49c81-fa16-4dc4-a7a2-edbd6a686fda','九日','方回','宋','宋诗','song-poetry','','[]','樓前樓後獨徘徊，便當登高百尺臺。',64,'全唐诗/poet.song.233000.json','["樓前樓後獨徘徊，便當登高百尺臺。", "海內共知吾輩老，江南未見菊花開。", "細思去歲人誰健，遥想中原雁已來。", "我似少陵亦賒酒，不妨剩舉兩三杯。"]'),
('93a85509-6e95-467d-a290-fad71c4e8d76','次韻前住中竺希鑑上人五言','方回','宋','宋诗','song-poetry','','[]','中興今佛法，百倍勝儒紳。',48,'全唐诗/poet.song.233000.json','["中興今佛法，百倍勝儒紳。", "達磨重初祖，觀音再化身。", "此心元是道，何物不爲塵。", "轂觫齊王眼，焉知一角麟。"]'),
('bfca2fae-75c4-4a17-9b3a-045e37ffbab5','送岳德裕如大都','方回','宋','宋诗','song-poetry','','[]','岳忠武王炎興中，才跨光世俊世忠。',400,'全唐诗/poet.song.233000.json','["岳忠武王炎興中，才跨光世俊世忠。", "人見百戰百勝功，孰知洙泗儲心胸。", "姦檜忮忍摧英雄，秦賊之臭傳無窮。", "忠武馨香逈不同，鬼神呵護垂箕弓。", "子子孫孫有祖風，允文允武足臨容。", "敦以閲樂詩書崇，維德裕甫明且聰。", "昭文大學其宗公，招之使來有秋鴻。", "賢父賢兄笑顔紅，酌酒贐別浮金鍾。", "有馬有車舟有篷，脯臘湩酪羊豕熊。", "藕蓮梨棗蘋蕰葑，罍之俎之籩豆豐。", "文賓詩客罔不從，軷祀而行氣如虹。", "浙之西而淮之東，中原廣大堯民雍。", "鄒魯齊趙森儒宮，默會寸心豁雙瞳。", "盧溝之水何溶溶，五門佳氣瞻鬰葱，殿上日月朝衮龍。", "馬億萬萬休戰攻，獵圍發蹤無豜豵。", "海東青上天無穹，天鵝腦碎飄虛空。", "書生匪我求童蒙，橋門冠带新辟廱。", "六藝一經或一通，加之官爵與磨礱。", "千里虎符百里銅，君遨王京登丹楓。", "即霑一命壽乃翁，歸歟不見橘霜濃。", "近在新年桃李穠，鶑鶑燕燕飛蝶蜂。", "滿斟環坐繡芙蓉，春滿一家和氣融。", "我有一言如藥石，後生仕宦非所急。", "明時用人略梯級，况乃要路薦引密，集賢翰林真可得。"]'),
('e66c7458-7942-4f25-b254-b2e23551fca9','寄題暢上人文溪別業詩','方回','宋','宋诗','song-poetry','','[]','愛僧予尤愛詩僧，千偈萬頌傳五燈。',336,'全唐诗/poet.song.233000.json','["愛僧予尤愛詩僧，千偈萬頌傳五燈。", "寒山拾得兩奇絕，妙壓神秀盧慧能。", "四明北郭四十里，文溪之名四海稱。", "文溪上人貌古怪，吟壇突兀高千層。", "我雖未到燕坐處，想見蘚薜樅行藤。", "上之所陟聳樓閣，星辰日月危欄凭。", "下之所種足鋤耒，芋菔黍粱滿甑蒸。", "有時挑包大都會，省臺貴顯皆其朋。", "紫陽山叟年八十，吟號夜蛬書秋蠅。", "厥今流俗所不齒，獨肯惠顧談上乘。", "門前車馬熱如火，兀坐相對森寒冰。", "氣臭吻合風味似，萬里可並橫坐肱。", "文溪文溪有別業，松陰百穀禾千塍。", "何當插翅渡潮海，月門吾敲堂吾陞。", "春華櫻李杏桃藥，夏果榛椇蓮藕菱。", "西風九日東籬菊，十月早梅霜霰凝。", "短才題詠匪騷雅，有愧蹇羌慚觀興。", "公詩自是第一等，紙上龍變青雲蒸。", "文溪有集定脫稿，庶越韓門島可澄。", "老夫所作豈敢並，鵰鶚風前跧凍鷹。", "誰歟作記已六載，敢不服膺今戴憑。"]'),
('ef4d1cb1-936b-43b9-9a92-9d7e5ed67d02','題葉蘭坡居士蘭','方回','宋','宋诗','song-poetry','','[]','一花一幹秀春風，此論黄家太史公。',32,'全唐诗/poet.song.233000.json','["一花一幹秀春風，此論黄家太史公。", "若問靈均舊紉佩，零陵香出古湘中。"]'),
('d0393734-f4b4-4264-a9bd-9d7eaee1232b','題畫龍首','方回','宋','宋诗','song-poetry','','[]','掛龍西作但見尾，舜服龍章臨斧扆。',48,'全唐诗/poet.song.233000.json','["掛龍西作但見尾，舜服龍章臨斧扆。", "昌黎石鼎囷蠢吟，此詩真可泣神鬼。", "得非永嘉陳畫龍，此紙錢塘葉蘭翁。"]'),
('f248ce88-5e60-4096-9e07-0ada14da47c6','走筆送僧宣無言歸泉南','方回','宋','宋诗','song-poetry','','[]','杭泉三千二百里，一瓶一鉢走桑梓。',224,'全唐诗/poet.song.233000.json','["杭泉三千二百里，一瓶一鉢走桑梓。", "此僧胸中有詩腸，一口吸盡四海水。", "自從北海至南海，搜詩直至珊瑚底。", "歸哉非爲戀鄉味，橄欖檳榔紅荔子。", "隻身家世無眷屬，亦不尋訪囝郎罷。", "一欲追還李太白，二欲中興杜子美。", "三欲扶起黄魯直，四欲再作陳無己。", "若島若可若貫休，直下視之眇糠粃。", "名僧詩話六十卷，我葺偈頌如野史。", "西天七祖南六祖，略如志傳與表紀。", "尋復悔之泯其稿，間存一二笑狂斐。", "幼讀紫陽先生書，豈可拾之從釋氏。", "爛却沙頭月一船，不妨文公漫隨喜。", "可與言詩宜與言，不可與言姑止止。"]'),
('d0d709e8-2ed7-427b-b419-10d7366a3d6d','寄題松江下砂唐氏竹友','方回','宋','宋诗','song-poetry','','[]','趙子昂書今第一，竹友二字大踰尺。',144,'全唐诗/poet.song.233000.json','["趙子昂書今第一，竹友二字大踰尺。", "結交此君者爲誰，松江其家吾未識。", "想見彷彿如渭川，千畝比封環乃宅。", "根竹可曾掘作鞭，笋出不忍煮爲食。", "青琅玕棲紫鳳凰，可待九成擊夔石。", "老夫客居杭州城，一葦可航不三日。", "不問主人即直造，誰知亦復有此癖。", "夢到霜松雪梅邊，龜殻踞兮蛤蜊食。", "取此三友并友之，月明半夜吹長笛。"]'),
('7b52fdf6-5a29-4416-867b-e60f082a3caf','題羅觀光藏陳所翁墨竹','方回','宋','宋诗','song-poetry','','[]','陳其姓，名曰容。',114,'全唐诗/poet.song.233000.json','["陳其姓，名曰容。", "稱所翁，善畫龍。", "葛嶺翹材酒杯客，不分虎，不憑熊。", "晚節寫此籜龍兒，真是老筆善藏鋒。", "我嘗遥望識其貌，古面無髯雙鬢蓬。", "畫龍撇竹匪二技，造化雖異機軸同。", "竹即是龍龍即竹，鬼施神設非人工。", "龍耶竹耶勿惱我，拓樓長嘯萬里天宇空。"]'),
('3a73b748-b751-4a8d-82de-278c4f800231','題羅觀光所藏李仲賓墨竹','方回','宋','宋诗','song-poetry','','[]','以筆寫竹如寫字，何獨鍾王擅能事。',128,'全唐诗/poet.song.233000.json','["以筆寫竹如寫字，何獨鍾王擅能事。", "同是蒙恬一管筆，老手變化自然異。", "胸中渭川有千畝，咄嗟辦此籜龍易。", "竹葉竹枝竹本根，方寸中藏竹天地。", "幼年癖好此亦頗，萬卷書右竹圖左。", "妄希眉山蘇謫仙，擬學湖州文與可。", "眉山一枝或兩枝，湖州千朵復萬朵。", "李侯有之以似之，袖手獨觀誰識我。"]'),
('cf4d0177-6257-4464-88ab-8814923d80ce','追和東坡先生親筆陳季常見過三首  其一','方回','宋','宋诗','song-poetry','','[]','坡仙果何辜，黄州七年客。',48,'全唐诗/poet.song.233000.json','["坡仙果何辜，黄州七年客。", "價高日月低，名大天地窄。", "嗟彼舒亶輩，豈不辨菽麥。", "阿黨更妬忌，一視皂與白。"]'),
('075ff5eb-2d79-41df-9619-df2bb46f8a6a','追和東坡先生親筆陳季常見過三首  其二','方回','宋','宋诗','song-poetry','','[]','前後赤壁賦，悲歌慘江風。',48,'全唐诗/poet.song.233000.json','["前後赤壁賦，悲歌慘江風。", "江山元不改，在公神遊中。", "三經及字說，胎禍垂無窮。", "想如季常輩，對寤三嘆同。"]'),
('93a42913-bb29-4c9d-b0cc-3cb972395072','追和東坡先生親筆陳季常見過三首  其三','方回','宋','宋诗','song-poetry','','[]','我嘗過黄州，故國聳喬木。',48,'全唐诗/poet.song.233000.json','["我嘗過黄州，故國聳喬木。", "半山歌元豐，此老蝸角縮。", "及至紹聖初，嶺海謫坡谷。", "人生歸去來，破鐺煮黄獨。"]'),
('a327ec3c-9f12-44a7-8d70-7bc14dbd1530','題文文山天祥遺墨','方回','宋','宋诗','song-poetry','','[]','年踰弱冠唱楓宸，海內文章第一人。',64,'全唐诗/poet.song.233000.json','["年踰弱冠唱楓宸，海內文章第一人。", "孰謂國家無厄運，從來天地有忠臣。", "此聲不朽垂千古，今歲猶存僅七旬。", "二十五年九原底，剛風夜夜薄星辰。"]'),
('8922400f-d2df-4f60-be54-fa34d3b09986','寄題沈可久雪村','方回','宋','宋诗','song-poetry','','[]','吾聞昔人善賦梅，嘗是夢中見春來。',128,'全唐诗/poet.song.233000.json','["吾聞昔人善賦梅，嘗是夢中見春來。", "前村深雪天未曉，焉知昨夜一枝開。", "江村一雪復一雪，三白豐年與玉屑。", "多事詩人要閒管，想像高唐寫奇絕。", "真曾質明杖屨無，前隨牧童後樵夫。", "暗香何處費摸索，寒生吟癖浩然馿。", "平生我有脊梁鐵，明年八十凍不折。", "卿用卿法自雪村，橫斜獨玩書窗月。"]'),
('c0550d3c-1cf0-4217-b0d6-d334daa9ab8c','題楊叔雅水墨百花圖','方回','宋','宋诗','song-poetry','','[]','梅梢前後兩枝春，百世中間各寫真。',32,'全唐诗/poet.song.233000.json','["梅梢前後兩枝春，百世中間各寫真。", "忽見花王大如斗，始知天地有君臣。"]'),
('4fbc4eb6-3fbd-43a2-b852-e76f894262e0','題坡仙求心齋三字','方回','宋','宋诗','song-poetry','','[]','千聖相傳止一機，常惺惺法免危微。',32,'全唐诗/poet.song.233000.json','["千聖相傳止一機，常惺惺法免危微。", "但於方寸求吾事，莫問坡書是與非。"]'),
('37d7c1cb-dcf2-457f-bfb8-6d68e631a6da','次韻芝田上人子虛二首  其一','方回','宋','宋诗','song-poetry','','[]','年長山僧五十秋，每携詩卷過吾樓。',32,'全唐诗/poet.song.233000.json','["年長山僧五十秋，每携詩卷過吾樓。", "老衰英妙心相似，靈隠亭前水不流。"]'),
('c8925b4b-d48f-4ea2-a801-2b1883018433','次韻芝田上人子虛二首  其二','方回','宋','宋诗','song-poetry','','[]','爲問葛藤禪律論，口箝舌結更無言。',32,'全唐诗/poet.song.233000.json','["爲問葛藤禪律論，口箝舌結更無言。", "何如了辦眼前事，且說詩家不二門。"]'),
('fad6830b-b34d-4cf4-8962-a4466e0c9a96','劉子華儒吏','方回','宋','宋诗','song-poetry','','[]','短檠徹曉一燈寒，椰腹中藏萬卷寬。',64,'全唐诗/poet.song.233000.json','["短檠徹曉一燈寒，椰腹中藏萬卷寬。", "了事足爲良吏易，讀書真作大儒難。", "隠身雁鶩雖常調，致位貂蟬可顯官。", "褒鄂功臣不須此，長槍挽出進賢冠。"]'),
('941711a2-3aa3-4eee-827a-b90d780a1262','寄題婺源戴氏蒼山歌','方回','宋','宋诗','song-poetry','','[]','大蒼山，小蒼山，有若醉翁亭外滁山環。',288,'全唐诗/poet.song.233000.json','["大蒼山，小蒼山，有若醉翁亭外滁山環。", "萬梅萬竹萬松柏，萬巖萬壑超人寰。", "河洛以來萬萬卷，上至姚姒下孔顔。", "蠅頭細字藏數世，晁張韓柳筆追還。", "三道八韻果何用，時文之學久已刪。", "星源幸有此一老，妙齡早悟向上關。", "明年古希滿七十，不知京洛有塵闤。", "花間自與鶑蝶賞，果熟朝共猿猱攀。", "文人才士過從每樽酒，樵夫牧子亦許荆同班。", "海內一統三十載，書文車軌過荆蠻。", "捐軒棄冕考槃磵，清朝乃容此士閒。", "神仙窟宅何可到，蓬萊弱水隔險艱。", "安得插翅一飛往，穿深憩密弄潺湲。", "王摩詰心似可擬，陶淵明徑焉能扳。", "既而思之各有分，命所當得天不慳。", "大蒼山，小蒼山，此非百頃之家不能辦，遊人未易窺豹斑。", "題詩寄往聊想像，我有把茅獨蝸跧。"]'),
('20bb7529-5467-48ae-8575-0aa4885e2755','題王義之雲隠','方回','宋','宋诗','song-poetry','','[]','心天界限絕塵氛，廛市雖喧耳不聞。',32,'全唐诗/poet.song.233000.json','["心天界限絕塵氛，廛市雖喧耳不聞。", "大隠從來非小隠，可須深入萬重雲。"]'),
('84c8c61c-72b7-48ea-b089-c6d2454073bc','送呂主簿還任永豐','方回','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u6d1e\u5ead\u6e56"]','吾友陸太初，擢第歲丙辰。',264,'全唐诗/poet.song.233000.json','["吾友陸太初，擢第歲丙辰。", "同舟下歙灘，羣英對楓宸。", "於時程訥相，中書秉洪鈞。", "拔我魏靜翁，丞郎厠朝紳。", "明年去其位，出使洞庭濱。", "回也實同行，兩見桃源春。", "己未入江險，鄂城飛戰塵。", "近歲亡國相，再造誇庚申。", "金陵留舉子，始獲識偉人。", "公年二十三，太初之館賓。", "回年三十四，太初之鄉鄰。", "四十六載別，世事難具陳。", "後歲公七袠，明年我八旬。", "雪髯對舉酒，談詩如有神。", "健筆涸湖海，便腹羅星辰。", "匪玉亦匪珠，自有席上珍。", "近世澆薄俗，百僞無一真。", "二老舉措間，復還天地淳。", "醉鄉闢坦途，永無荆與榛。", "傍觀果孰識，無懷葛天民。", "一邑主簿領，內省忘屈伸。", "歸隠匡廬峰，寄雁或可頻。"]'),
('1164a128-9d30-492a-a678-61a213ea89e0','以讀書破萬卷下筆如有神爲韻賦十詩送趙然然如大都  其一','方回','宋','宋诗','song-poetry','','[]','博學果何謂，書不可不讀。',48,'全唐诗/poet.song.233000.json','["博學果何謂，書不可不讀。", "子思繼以審，子夏繼以篤。", "是皆返諸心，夫豈泥簡牘。", "試一凭危樓，萬里送鴻鵠。"]'),
('6c139b66-31e4-4625-88bb-5fc9013f59f3','以讀書破萬卷下筆如有神爲韻賦十詩送趙然然如大都  其二','方回','宋','宋诗','song-poetry','','[]','羲皇卦未畫，世間有何書。',48,'全唐诗/poet.song.233000.json','["羲皇卦未畫，世間有何書。", "今人所校者，惟亥豕魯魚。", "曷不洗肺腸，求諸天地初。", "此理儻有得，萬卷皆空虛。"]'),
('baa0d380-a727-4b14-8e64-19f1665721db','以讀書破萬卷下筆如有神爲韻賦十詩送趙然然如大都  其三','方回','宋','宋诗','song-poetry','','[]','所謂先天易，諸人識不破。',48,'全唐诗/poet.song.233000.json','["所謂先天易，諸人識不破。", "獨一觀物翁，入手不放過。", "太極是生兩，然後品物播。", "參以邵子言，佛老義自墮。"]'),
('1ac4fb60-5a35-4dad-9f39-d77e2f12fa68','以讀書破萬卷下筆如有神爲韻賦十詩送趙然然如大都  其四','方回','宋','宋诗','song-poetry','','[]','誤訓若稽古，字至於三萬。',48,'全唐诗/poet.song.233000.json','["誤訓若稽古，字至於三萬。", "一言思無邪，可以了羣怨。", "世人爾所有，夜光珠徑寸。", "吾儕道固窮，君子兼山艮。"]'),
('27e19513-f16d-418f-9e6a-3e3fa71e1c36','以讀書破萬卷下筆如有神爲韻賦十詩送趙然然如大都  其五','方回','宋','宋诗','song-poetry','','[]','揚雄論立師，始於書一卷。',48,'全唐诗/poet.song.233000.json','["揚雄論立師，始於書一卷。", "曾子貫忠恕，本無書可傳。", "趙子足著述，古今妙貫穿。", "考諸領袖間，深衣有表撰。"]'),
('734b6bda-7461-4b65-badc-9a208643abd6','以讀書破萬卷下筆如有神爲韻賦十詩送趙然然如大都  其六','方回','宋','宋诗','song-poetry','','[]','朱先之桑梓，如我二人者。',48,'全唐诗/poet.song.233000.json','["朱先之桑梓，如我二人者。", "趙子於吟詩，一字不妄下。", "虛叟明八十，硉矹老病馬。", "年齡已衰頹，文字亦苟且。"]'),
('754706f2-72bb-418b-8392-4091f289d43c','以讀書破萬卷下筆如有神爲韻賦十詩送趙然然如大都  其七','方回','宋','宋诗','song-poetry','','[]','妙年嘗自負，韓子補天筆。',48,'全唐诗/poet.song.233000.json','["妙年嘗自負，韓子補天筆。", "年及渭濱人，今也老無力。", "送君如燕都，誰門可長揖。", "蘇舉黄自代，靖翁獨我識。"]'),
('8ed9f592-aef9-4504-856d-cc4a2fdd5573','以讀書破萬卷下筆如有神爲韻賦十詩送趙然然如大都  其八','方回','宋','宋诗','song-poetry','','[]','言詩卜子夏，作賦馬相如。',48,'全唐诗/poet.song.233000.json','["言詩卜子夏，作賦馬相如。", "三十六字母，文公之四書。", "知君便便中，自有一石渠。", "以貌失子羽，諸公其慎諸。"]'),
('c662c347-707c-44d7-aa35-40f7655878bf','以讀書破萬卷下筆如有神爲韻賦十詩送趙然然如大都  其九','方回','宋','宋诗','song-poetry','','[]','魯語第一篇，子曰即次有。',48,'全唐诗/poet.song.233000.json','["魯語第一篇，子曰即次有。", "有子與曾子，專美孔聖後。", "乃知古學者，尊師復重友。", "君之師友何，殆不止韓柳。"]'),
('be1cd1c7-c299-40fd-a913-70f0f6eb66b5','以讀書破萬卷下筆如有神爲韻賦十詩送趙然然如大都  其一○','方回','宋','宋诗','song-poetry','','[]','後生信可畏，君年未四旬。',48,'全唐诗/poet.song.233000.json','["後生信可畏，君年未四旬。", "我老長空倍，閒將三十春。", "學行各有見，出處何必均。", "寧將詩泣鬼，肯與錢稱神。"]'),
('66e258fa-ce58-461c-b132-6bd4de03e699','至節前二日','方回','宋','宋诗','song-poetry','','[]','梅花買到滿樓香，但笑吾家節是常。',64,'全唐诗/poet.song.233000.json','["梅花買到滿樓香，但笑吾家節是常。", "雨凍不應無雪凍，肩瘡更復有頭瘡。", "桃符爆竹年將近，繡線書帷日漸長。", "三歲嶺南江左路，豈知八十客錢塘。"]'),
('52802856-215b-422b-bd43-4729efb56aca','至節後一日十月二十九日','方回','宋','宋诗','song-poetry','','[]','倚欄閒玩老梧桐，萬變真如一夢中。',64,'全唐诗/poet.song.233000.json','["倚欄閒玩老梧桐，萬變真如一夢中。", "竹葉滿斟今古了，楊枝早放是非空。", "幼孤嶺海三千里，衰病江湖八十翁。", "舊雨來人竟安在，邇來朋友馬牛風。"]'),
('c5415c3d-2cdf-4b17-a2ab-90476929b85d','至節前一日六首  其一','方回','宋','宋诗','song-poetry','','[]','少陵早是滄浪客，馬援真成矍鑠翁。',32,'全唐诗/poet.song.233000.json','["少陵早是滄浪客，馬援真成矍鑠翁。", "四十五年忝科第，一生心與布衣同。"]'),
('13ae0ec7-7145-4bf9-bdd5-fe2d7288170e','至節前一日六首  其二','方回','宋','宋诗','song-poetry','','[]','征羌漢將趙充國，賜履齊侯周太公。',32,'全唐诗/poet.song.233000.json','["征羌漢將趙充國，賜履齊侯周太公。", "虛叟紀年亦云爾，五湖四海一詩窮。"]'),
('5653f281-acd4-4764-8722-8cede8f85cb9','至節前一日六首  其三','方回','宋','宋诗','song-poetry','','[]','燈前一影客中身，雞未鳴時起已頻。',32,'全唐诗/poet.song.233000.json','["燈前一影客中身，雞未鳴時起已頻。", "每日盆梅千百擔，倚樓閒作看花人。"]'),
('1b33a26c-942c-46ba-a990-acca96ec1eab','至節前一日六首  其四','方回','宋','宋诗','song-poetry','','[]','蓴羹鱸鱠鑑湖風，想像依稀老放翁。',32,'全唐诗/poet.song.233000.json','["蓴羹鱸鱠鑑湖風，想像依稀老放翁。", "惜爲平原多一出，詩名元已擅無窮。"]'),
('d1192c7d-f15c-4456-8300-278c4ee3c766','至節前一日六首  其五','方回','宋','宋诗','song-poetry','','[]','客子光陰詩卷裏，杏花消息雨聲中。',32,'全唐诗/poet.song.233000.json','["客子光陰詩卷裏，杏花消息雨聲中。", "我謂簡齋此奇句，元來出自后山翁。"]'),
('fb9589b2-e32a-4d8e-8131-76a70ae974ba','至節前一日六首  其六','方回','宋','宋诗','song-poetry','','[]','心情詩卷無佳句，時節梅花有好枝。',32,'全唐诗/poet.song.233000.json','["心情詩卷無佳句，時節梅花有好枝。", "較似后山更平澹，一生愛誦石湖詩。"]'),
('3b11328b-9f17-4c2a-9fff-a62813cbcca1','贈魯至道','方回','宋','宋诗','song-poetry','','[]','種薰不生蕕，種蕕不生薰。',240,'全唐诗/poet.song.233000.json','["種薰不生蕕，種蕕不生薰。", "人力異培植，草木各有根。", "或不然此說，宜以變化論。", "蛟魚無頭角，作龍行雨雲。", "麴糵釀成酒，醒者皆醺醺。", "不見昔諸子，摳衣孔聖門。", "仲由氣暴虎，不使行三軍。", "欲俾賜也訥，故曰天何言。", "不見孺悲子，取瑟使之聞。", "色黄而在裳，深取六五坤。", "志學及從心，非變尚何云。", "南山隠霧豹，養其所變文。", "明明德新民，此書洙泗孫。", "所謂新者何，拾舊新是勤。", "服可古衣冠，耕須故田園。", "世惟有舊染，不可留一痕。", "變人先變己，毋我求道原。", "下愚彼不移，烏喙無蘭蓀。", "昏昏與曉曉，火蟄仍復蟠。", "人生悟此理，寸丹還一元。"]'),
('6f26edea-b4f0-40d0-ba5b-3f05a6c24f3f','寄題汪稱隠海陽船亭','方回','宋','宋诗','song-poetry','','[]','望之有若船，其實止一亭。',144,'全唐诗/poet.song.233000.json','["望之有若船，其實止一亭。", "世情作風濤，平地有滄溟。", "中裁宮室製，外肖舳艫形。", "片帆可萬里，眇視蛟龍腥。", "吾友汪定翁，積世家海寧。", "海寧亦海陽，難考山海經。", "季子棟此宇，世皆稱寧馨。", "乘桴否運革，作楫良辰丁。", "漳饒兩分教，奕葉家氈青。", "記者弘齋老，文辭摇斗星。", "不慕蓬萊島，不求楚江萍。", "野水無人渡，何時一揚舲。"]'),
('9336495c-4af8-4a1e-a3bc-0a7fca655c7c','武林感舊又二首  其一','方回','宋','宋诗','song-poetry','','[]','錢塘多少少年人，孰識迴頭迹已陳。',64,'全唐诗/poet.song.233000.json','["錢塘多少少年人，孰識迴頭迹已陳。", "綠草地元無綠草，紅塵天更不紅塵。", "三茅觀頂燈猶在，六部橋南塔頓新。", "試問衆生詩得意，袈裟底下自由身。"]'),
('779a936f-aacd-444b-b81f-b5965faa3afc','武林感舊又二首  其二','方回','宋','宋诗','song-poetry','','[]','吳儂青蓋已云何，郎罷猶能欸乃歌。',64,'全唐诗/poet.song.233000.json','["吳儂青蓋已云何，郎罷猶能欸乃歌。", "湖上船稀西子老，城中馬響北人多。", "珍烹富戶金千埒，負販貧民雨一蓑。", "倏忽虛盈三十載，世間春夏幾南柯。"]'),
('6565a10a-b92a-40a5-b997-75833226b12d','松鶴詞','方回','宋','宋诗','song-poetry','','[]','千桃李之穠華兮不如我之孤松，彼眩三春之朝露兮我專一丘壑之風，聽此以洗耳兮又何有乎牛鬬之聰。',133,'全唐诗/poet.song.233000.json','["千桃李之穠華兮不如我之孤松，彼眩三春之朝露兮我專一丘壑之風，聽此以洗耳兮又何有乎牛鬬之聰。", "百鶑啼兮萬蝶舞，不如我獨鶴兮褵褷其羽，顧月池之在地兮各以影而自侶。", "九轉砂成兮鶴頂同丹，我鬢不凋兮松鬣長青，何十八公之爲夢兮胎仙夜鳴醉魂醒。", "亦貞其心兮亦癯其形，與我作朋兮俱千齡。"]'),
('e8daa08f-c8b8-4e1b-acb3-256c475d8d27','西齋','方回','宋','宋诗','song-poetry','','[]','偶得西齋字，向西開此齋。',24,'全唐诗/poet.song.233000.json','["偶得西齋字，向西開此齋。", "人間詩眼少，天下夕陽佳。"]'),
('a67fb2d8-c1df-4349-95b3-0b1fe430fb75','題納甲圖','方回','宋','宋诗','song-poetry','','[]','朝有讀書客，過我携酒壺。',144,'全唐诗/poet.song.233000.json','["朝有讀書客，過我携酒壺。", "問我參同契，汝亦嘗讀諸。", "虞翻納甲法，即是先天圖。", "伯陽竊其秘，靜夜觀蟾蜍。", "初八二十三，艮兌丙丁殊。", "上弦進火候，下弦退陰符。", "望盈仰乾蓋，晦滅俯坤輿。", "震巽庚辛對，坎離戊己俱。", "朔旦之日中，交媾水火爐。", "彭曉彼何人，嘵嘵爭魯魚。", "可惜非易學，欲飛血肉軀。", "借易弄丹術，鄒訢曷不誅。"]'),
('1ee81e1f-95ec-49fe-8d28-641bdbbfe93d','題雲泉題詠','方回','宋','宋诗','song-poetry','','[]','天一生水，坎卦象旃。',240,'全唐诗/poet.song.233000.json','["天一生水，坎卦象旃。", "二陰一陽，坤之中淵。", "天而非此，必爲旱年。", "澤自空降，其雲油然。", "地而非此，民何以田。", "曰有畎澮，泉出于山。", "六坎之卦，次坤次乾。", "在屯爲雲，在蒙爲泉。", "至於需卦，復以雲言。", "既亨既養，需厥成焉。", "萬物始生，孰爲之元。", "水爲物母，乳之而蕃。", "雲爲水胎，泉爲水源。", "雲初一縷，霶霈八埏。", "泉初一滴，洶湧滔天。", "君子心學，攸體攸研。", "觀象於坎，奚水之專。", "中剛內實，處險常安。", "於雲於泉，復究厥觀。", "水之始初，未波未瀾。", "心之始初，萬善俱完。", "如雲欲雨，如泉欲川。", "發而中節，養蒙亨屯。", "無爲而成，地平天全。"]'),
('8b685ec6-b306-4cad-870f-cef68828bbf3','皇甫巨川父年八十八母年八十四歌','方回','宋','宋诗','song-poetry','','[]','屈二指兮郎罷九秩，雖則九秩兮髯猶如漆。',157,'全唐诗/poet.song.233000.json','["屈二指兮郎罷九秩，雖則九秩兮髯猶如漆。", "梁之郊兮黍稷櫛櫛，父曰兒歸兮吾督汝銍。", "加六算兮聖善九旬，雖則九旬兮髪猶未銀。", "汴之水兮魴鯉鱗鱗，母曰兒歸兮我甘汝珍。", "夫婦偕老兮古無此比，父母俱存兮今誰其擬。", "祿養于南兮云胡不善，汴梁言還兮晝錦樂只。", "二老有子兮又有孫，壽且康兮施及後昆。", "逮老及彭兮永貞厥根，澤詩薰書兮益大寧齋翁之門。"]'),
('bf4e4533-e4e6-4f25-8285-b661306f458d','王御史野塘圖歌','方回','宋','宋诗','song-poetry','','[]','野塘之水兮其色油油，以畜以泄兮灌我良疇。',147,'全唐诗/poet.song.233000.json','["野塘之水兮其色油油，以畜以泄兮灌我良疇。", "弋有鳬雁兮盟有鷗，我出而仕兮可則進，脫如不可兮還我鋤耰。", "水之上兮山之下，稷黍棗栗兮野塘之塢。", "秋收其實兮於粲滿筥，車既膏兮馬不前，退而家食兮孰予敢侮。", "我思野塘兮繄古之沂，有懷其人兮瑟聲希。", "可由求赤兮賢寧不希，登之廊肆兮佩玉黼黻，否則豈無春服兮詠雩風而與歸。"]'),
('32af66fd-baae-4174-9883-2780a282597f','輔德廟碑歌','方回','宋','宋诗','song-poetry','','[]','綠之渚兮浣侯衣，青厥蟾兮神所依。',173,'全唐诗/poet.song.233000.json','["綠之渚兮浣侯衣，青厥蟾兮神所依。", "未壯而逝兮匪夭，白首者拜兮莫之敢非。", "潮來兮潮往，侯朝出遊兮夜歸。", "侯昔家兮今廟，奠椒醑兮神其我釂。", "渺渺兮綠之渚，子陵在上兮子胥下。", "羊裘孔樂兮鴟夷猶怒，勾吳炎漢兮俯仰今古。", "侯之願兮天不違，保我民兮靡兵靡饑。", "水無蛟蜮兮山無貙豹，有蘋有芷兮歲其報。", "彭殤共盡兮孰盡而神，不死者心兮幻者身。", "雨八荒兮先我桑梓，刊此石兮百世之史。"]'),
('46aec784-4878-4c92-9d8e-0940e4266f0e','宿包山楊明府宅  其一','方回','宋','宋诗','song-poetry','','[]','十年共艱難，老友楊明府。',120,'全唐诗/poet.song.233000.json','["十年共艱難，老友楊明府。", "賢令實所頼，拙守何足數。", "尚憶紛紜初，天地沸鼙鼓。", "窮山古未見，倏忽集萬馬。", "家財吝不捐，寧保殺與擄。", "公一無所愛，什器亦遭斧。", "我書寄歙山，萬卷棄草莽。", "即令兩禿翁，衣破缺紉補。", "獨有浩然氣，依舊塞□□。", "□□白雲村，連榻曉共語。"]'),
('231abae4-e0b4-43a6-a96e-c04013794aca','宿包山楊明府宅  其二','方回','宋','宋诗','song-poetry','','[]','今日到桐廬，登堂拜壽母。',60,'全唐诗/poet.song.233000.json','["今日到桐廬，登堂拜壽母。", "□□□□□，□□□□□。", "人間富豪兒，吾事弗如汝。", "汝縱□□□，□□□□□。", "□□□□□，□□□□□。"]'),
('db9cca49-c3c7-4753-b411-c7af489b8784','宿包山楊明府宅  其三','方回','宋','宋诗','song-poetry','','[]','誰實生成之，諺謂慈父母。',60,'全唐诗/poet.song.233000.json','["誰實生成之，諺謂慈父母。", "彼錦衣玉食，及朱弦鏤簋。", "公但寶一硯，百倍似勝汝。", "我眠公浩唱，猶有半夜許。", "可親未易別，依依睇烟雨。"]'),
('240b9254-7ed7-4944-b386-c664cb7db174','次韻趙賓暘見寄長句','方回','宋','宋诗','song-poetry','','[]','百憂攻心成白首，不少自寬死已久。',32,'全唐诗/poet.song.233000.json','["百憂攻心成白首，不少自寬死已久。", "我初作郡猶未貧，□□比□□□□。"]'),
('4e30cae9-0379-40b2-bef0-fc705a80912a','萬山堂呈史察使  其一','方回','宋','宋诗','song-poetry','','[]','□□□□□□□，□□□□□□□。',64,'全唐诗/poet.song.233000.json','["□□□□□□□，□□□□□□□。", "□□□□□□□，□予年事雪盈頭。", "藥巖夏冷水泉潤，茗屋午香窗戶幽。", "相過端能坐終日，微吟清嘯兩無求。"]'),
('42fc6a64-18c7-4980-830a-fc617d7e3a5c','萬山堂呈史察使  其二','方回','宋','宋诗','song-poetry','','[]','質肅英聲蓋九州，名孫吾獲與之遊。',64,'全唐诗/poet.song.233000.json','["質肅英聲蓋九州，名孫吾獲與之遊。", "胸中所學萬青簡，堂上有親雙黑頭。", "買硯新添行橐重，抄書勤過野廬幽。", "雕鞍長劍紛紛是，人物如斯豈易求。"]'),
('aa801b5b-7d77-432b-a35a-8b3ce75968ac','贈管氏三昆仲羅漢保大閭官孫','方回','宋','宋诗','song-poetry','','[]','顆顆圓珠掌上珍，更如玉樹皎無塵。',64,'全唐诗/poet.song.233000.json','["顆顆圓珠掌上珍，更如玉樹皎無塵。", "公侯富貴元常事，兄弟聰明各過人。", "著意學吟須刻苦，立談屬對已清新。", "老夫不誤青雙眼，會見他年筆有神。"]'),
('c1529a41-e2ab-4f43-9f65-3a8e4ceba720','次韻酬趙無己','方回','宋','宋诗','song-poetry','','[]','文才因學進，名譽待時隆。',48,'全唐诗/poet.song.233000.json','["文才因學進，名譽待時隆。", "定有仙能遇，元無鬼可窮。", "剛貞侔鐵石，猥瑣笑蒿蓬。", "百尺樓頭目，時時沒去鴻。"]'),
('5ed4308a-0e78-4ee2-887b-d517f245a95a','謝客二首  其一','方回','宋','宋诗','song-poetry','','[]','夢到紅雲玉殿來，骨凡無路住蓬萊。',32,'全唐诗/poet.song.233000.json','["夢到紅雲玉殿來，骨凡無路住蓬萊。", "鶴身欲向仙官舞，病翅褵褷展不開。"]'),
('818b1c76-9e00-4ed8-b4fd-7f35d07a1d99','謝客二首  其二','方回','宋','宋诗','song-poetry','','[]','時脫蓑衣當酒錢，江天身世一漁船。',32,'全唐诗/poet.song.233000.json','["時脫蓑衣當酒錢，江天身世一漁船。", "七旬衰老人無識，林下休官十五年。"]'),
('879d01a4-2faf-40ae-abeb-a9b3abc5f32b','次韻邵君以容名齋二首  其一','方回','宋','宋诗','song-poetry','','[]','細讀來詩窺所學，忘機忍事用功深。',64,'全唐诗/poet.song.233000.json','["細讀來詩窺所學，忘機忍事用功深。", "遠同隨筆洪公號，妙得吟窩邵子心。", "懷抱春濃重醖酒，語言淵嘿絕弦琴。", "我能容物天容我，無是無非鎮似今。"]'),
('cde7d545-0fb3-4494-8f15-9de7b5e0fa15','次韻邵君以容名齋二首  其二','方回','宋','宋诗','song-poetry','','[]','我能容物天容我，容足元消地幾多。',64,'全唐诗/poet.song.233000.json','["我能容物天容我，容足元消地幾多。", "結莫逆交聊爾汝，聞無義語勿誰何。", "飄零蹤跡因循慣，冷淡光陰苟且過。", "人世政如蠶食葉，百年誰辦繭成窩。"]'),
('93f6911d-31bc-4532-a006-4fa72f9074d1','詩二首  其一','方回','宋','宋诗','song-poetry','','[]','鸚鵡籠開綵索寬，一宵飛去爲誰歡。',64,'全唐诗/poet.song.233000.json','["鸚鵡籠開綵索寬，一宵飛去爲誰歡。", "早知黠賊心腸別，肯作佳人面目看。", "忍著衣裳辜舊主，便塗脂粉事新官。", "丈夫能舉登科甲，可得妖雛膽不寒。"]'),
('993ad0cc-03c8-4094-8011-0b9b66871b59','詩二首  其二','方回','宋','宋诗','song-poetry','','[]','一牝猶嫌將兩雄，趨新背舊片時中。',64,'全唐诗/poet.song.233000.json','["一牝猶嫌將兩雄，趨新背舊片時中。", "陡忘前主能爲叛，乍事他人更不忠。", "玉碗空亡無易馬，絳桃猶在未隨風。", "何須苦問沙吒利，自是紅顔薄老翁。"]'),
('cc3f1dc7-883a-4f9e-8092-b2efe37819a8','挽呂襄陽','方回','宋','宋诗','song-poetry','','[]','將軍報國寸心丹，滿眼兒孫盡好官。',64,'全唐诗/poet.song.233000.json','["將軍報國寸心丹，滿眼兒孫盡好官。", "一品已頒新印綬，九重猶許舊衣冠。", "碑存峴首懷羊祜，箭著浮圖恨賀蘭。", "公論百年應自定，且留忠節後人看。"]'),
('a572b3f9-e708-4018-b650-d26801f3fb26','浙西園苑','方回','宋','宋诗','song-poetry','','[]','壁間墨客掃龍蛇，所寫詩佳字亦佳。',32,'全唐诗/poet.song.233000.json','["壁間墨客掃龍蛇，所寫詩佳字亦佳。", "忽見一詩增感慨，吾家宗伯老秋崖。"]'),
('cda7ac3e-f535-40b4-ad5e-42542dd5f381','久雨','方回','宋','宋诗','song-poetry','','[]','云胡不出，積雨予尼。',120,'全唐诗/poet.song.233000.json','["云胡不出，積雨予尼。", "意彌八紘，膝此一席。", "誰具蒸徒，假予楫航。", "一往滄海，觀彼茫洋。", "掩關晝眠，胡寧不暇。", "魯叟攸戒，敢視爲夜。", "寂寂疏簾，幽幽空階。", "鳥下碎蘚，傷予之懷。", "悠悠古道，溢溢行潦。", "豈無岑樓，送目遥草。", "心之憂矣，莫或予知。", "彼其之子，謂予寒饑。"]'),
('17c23b3b-e4a0-41dc-a34c-2383a9ba8ef9','築城謠','方回','宋','宋诗','song-poetry','','[]','從軍去築城，不如困長征。',91,'全唐诗/poet.song.233000.json','["從軍去築城，不如困長征。", "從軍去掘塹，不如鏖血戰。", "古今征戰立奇功，貂蟬多出兜鍪中。", "徒教力盡鍤與杵，主將策勳士卒苦。", "君不見每調一軍役百室，一日十人戕六七。", "草間髑髏飼螻蟻，主將言逃不言死。"]'),
('c1a0f6f3-6bf3-4917-895e-c17e41860317','遊石頭城','方回','宋','宋诗','song-poetry','','[]','卧龍起草廬，扶漢有餘忠。',180,'全唐诗/poet.song.233000.json','["卧龍起草廬，扶漢有餘忠。", "欲結紫髯客，共追黄星公。", "一言根本定，萬里氛翳空。", "指此爲虎踞，長嘯吞西風。", "夫豈樊吾圃，以虞他人攻。", "烏林逸元惡，入蜀愴途窮。", "汝亦趙佗輩，區區帝江東。", "吾意本謂何，劍佩殊不同。", "後來矯虔人，藉口欺盲聾。", "九折劍閣棧，一泥函關封。", "盜賊柄干將，姦雄非英雄。", "老我弔古癖，徘徊梵王宮。", "城壞遺甃泯，江徙孤岸穹。", "中原芳草外，戰塵春濛濛。", "酒盡欲下山，目極斜陽紅。"]'),
('9e83b781-6d93-4671-be0f-e5734a102115','人生如流丸','方回','宋','宋诗','song-poetry','','[]','人生如流丸，冉冉不肯住。',96,'全唐诗/poet.song.233000.json','["人生如流丸，冉冉不肯住。", "草變鶗鴂鳴，花零蝴蝶去。", "去去無奈何，一飯三起步。", "鬢綠密已稀，紅顔新忽故。", "往悔杳莫追，前瞻冥未悟。", "破鏡忽偶圓，墮甑寧足顧。", "方池疏雨餘，歷歷見鳥度。", "沉吟高樹間，聊用寫心素。"]'),
('2d58bff8-3f6d-4b3c-8942-1971c204565b','韓蘄王湖上騎馿圖爲王孫葉葉賦','方回','宋','宋诗','song-poetry','','[]','取日虞淵戰臨平，鼓起金山麾伏兵。',204,'全唐诗/poet.song.233000.json','["取日虞淵戰臨平，鼓起金山麾伏兵。", "既不畫此背嵬軍陣形，國容貂蟬佩葱珩，軍容金甲馬朱纓。", "又不畫此生面真儀刑，昔王不肯專樞庭。", "清凉居士以自名，散遣萬騎還屯營。", "獨控長耳遊林坰，林間坐石樵叟爭。", "不無醉尉呵夜行，孰識朱門抗旄旌。", "王孫妙年萬事輕，欲蹈箕潁遺浮榮。", "龔侯淡墨勝丹青，作此灞橋風雪征。", "龍變不測人中英，諦觀豈是寒書生。", "丈夫出處吾能評，不可長劍即短檠。", "得時用世身名亨，否哉履道幽人貞。", "葉葉用意何崢嶸，大司馬侃孫淵明。"]'),
('c5c7fc4b-f7f7-4b66-803c-1d90b63bd94b','陸君實哀挽','方回','宋','宋诗','song-poetry','','[]','亙古無斯事，于今有若人。',48,'全唐诗/poet.song.233000.json','["亙古無斯事，于今有若人。", "龍綃同把手，鮫室共沉身。", "蹈海言能踐，憂天志不伸。", "曾微一坏土，魚腹瘞君臣。"]'),
('465899d1-b86a-413f-b7dc-6729bb2a7d39','晚望滸墅','方回','宋','宋诗','song-poetry','','["\u592a\u6e56"]','太湖晚山雨，白鳥去冥冥。',48,'全唐诗/poet.song.233000.json','["太湖晚山雨，白鳥去冥冥。", "古冢多無後，荒祠或有靈。", "異峰攙石骨，遠樹聳人形。", "兵革已蘇息，廢田蒲稗青。"]'),
('568ab423-17ab-4d5d-a9f1-5ce5aac019a7','江漲','方回','宋','宋诗','song-poetry','','[]','暑雪西南下，愁霖日夜傾。',48,'全唐诗/poet.song.233000.json','["暑雪西南下，愁霖日夜傾。", "高城人避水，古廟吏祈晴。", "沙鳥依庭宿，漁船入市行。", "老夫隠几意，可但憫吾生。"]'),
('2523988f-0802-46e9-bd25-23a29ff3047c','讀四明尊堯集','方回','宋','宋诗','song-poetry','','[]','大道行天如日月，羣兒簸弄竟何如。',64,'全唐诗/poet.song.233000.json','["大道行天如日月，羣兒簸弄竟何如。", "自悲責沈曾爲學，安得尊堯更有書。", "義膽輪囷千古在，神州攻戰百年餘。", "誣辭逆像今俱已，猶恐忠賢恨未祛。"]'),
('355bb810-bccf-4b5d-ac57-871ed555cbac','重遊鳳凰臺','方回','宋','宋诗','song-poetry','','[]','重扶瘦影上荒臺，萬里秋陰凝不開。',64,'全唐诗/poet.song.233000.json','["重扶瘦影上荒臺，萬里秋陰凝不開。", "天地未休貔虎戰，江山敢望鳳凰來。", "是非易判元嘉事，今古難逢太白才。", "尊酒闌珊詩思亂，夕陽吹角不勝哀。"]'),
('10865b75-6677-4ed6-a864-edbb6f0f918a','溪閣呈陸太初','方回','宋','宋诗','song-poetry','','[]','臨水看山日百迴，等閒收拾有詩才。',64,'全唐诗/poet.song.233000.json','["臨水看山日百迴，等閒收拾有詩才。", "老松於我幾年長，啼鳥無名何處來。", "病髪漸應彫翠葆，衰蹤那復夢金臺。", "鷫鸘未敝猶堪典，聊挽秋花薦酒杯。"]'),
('6ea55d41-5bde-47b4-ad7b-3858dfa44b9d','贈郭澹溪','方回','宋','宋诗','song-poetry','','[]','赫日燒空暍欲死，詩來如向雪中看。',64,'全唐诗/poet.song.233000.json','["赫日燒空暍欲死，詩來如向雪中看。", "古罍出土銅聲盡，明月浮空貝影寒。", "江海豈無鷗作社，頭顱安得鶡爲冠。", "會須棄置人間事，同向秋風覓釣竿。"]'),
('5f543f5b-a0b4-46b9-8859-d280ba4b453a','初夏書事','方回','宋','宋诗','song-poetry','','[]','平生萬事鳥飛空，綠鬢蒼顔俯仰中。',64,'全唐诗/poet.song.233000.json','["平生萬事鳥飛空，綠鬢蒼顔俯仰中。", "醉若山頹無舊侶，坐如泥塑有新功。", "詩成不覺窗移日，心定何煩扇引風。", "結網小蛛恣來往，忘機應亦識衰翁。"]'),
('b7e20622-b137-4abd-a425-140a35a93f1e','次韻休寧程君圉來訪','方回','宋','宋诗','song-poetry','','[]','秋崖勁筆敵黄陳，贄卷當年許望塵。',64,'全唐诗/poet.song.233000.json','["秋崖勁筆敵黄陳，贄卷當年許望塵。", "十載江湖春雁斷，萬山煙雨石羊新。", "餘生敢忘尊前話，先正曾同席上賓。", "今日相逢兩家子，可無努力繼前人。"]'),
('5941e994-265c-422e-b919-7e6739b9f5d1','贈雲屋瑞上人','方回','宋','宋诗','song-poetry','','[]','名緇今已絕，見汝忽驚神。',168,'全唐诗/poet.song.233000.json','["名緇今已絕，見汝忽驚神。", "昔日陪三衛，多年護九宸。", "漫從雞幘報，長與蠹編親。", "漢幄垂前箸，秦關痛隻輪。", "驟驚淪寶玉，何惜褫冠巾。", "往事憐蝸國，餘生脫雁臣。", "片雲聊作屋，死樹自觀身。", "空鉢寧無食，枵囊別有珍。", "跣行千里近，凍卧八寒春。", "像喜圖佳士，名虛徹貴人。", "論詩色涇渭，遠俗意參辰。", "餘子一時盡，高流百世新。", "公能追慧遠，吾或可遺民。", "剃櫛雖殊相，澄江月共真。"]'),
('19f5cd73-eeb7-4b5a-8e5c-ac1405422be9','出城','方回','宋','宋诗','song-poetry','','[]','久病欣初愈，長忙愛暫閒。',24,'全唐诗/poet.song.233000.json','["久病欣初愈，長忙愛暫閒。", "出城因送客，沿路得看山。"]'),
('1086ef40-cb25-47e7-86ab-638176492946','湖堤雨中夜歸','方回','宋','宋诗','song-poetry','','[]','夜雨昏昏欲雪天，數家燈火北山前。',32,'全唐诗/poet.song.233000.json','["夜雨昏昏欲雪天，數家燈火北山前。", "鄉心認作桑麻路，忽有湖船奏管絃。"]'),
('9274b58c-38a2-4c89-ac3d-6ccdc0f6de4e','行宮西門','方回','宋','宋诗','song-poetry','','[]','翠華東幸締和盟，從此君王罷北征。',32,'全唐诗/poet.song.233000.json','["翠華東幸締和盟，從此君王罷北征。", "宿衛周廬無處所，野人畦菜傍宮城。"]'),
('260b2890-12c9-4969-87c0-f76d93b619d5','題許宣平南山故居','方回','宋','宋诗','song-poetry','','[]','一庵依舊翠微中，身在蓬萊第幾宮。',32,'全唐诗/poet.song.233000.json','["一庵依舊翠微中，身在蓬萊第幾宮。", "羽衛夜歸人不識，滿山松檜響清風。"]'),
('16116b16-eee5-4dd3-a908-d70443d654c3','秀山霜晴晚眺與趙賓暘黄惟月聯句','方回','宋','宋诗','song-poetry','','[]','一峰何崢嶸，萬象悉匍匐。',288,'全唐诗/poet.song.233000.json','["一峰何崢嶸，萬象悉匍匐。", "心包元氣并，影立太空獨。", "遥瞻極乾端，俯瞰際坤軸。", "飄飄凌雲身，杳杳送鴻目。", "揮袖裨八風，開襟吞百瀆。", "醒脾嚥醇清，滌髓盪痼俗。", "斗摘紫垣杓，日攀黄道轂。", "川令夷若奔，林訶魍魈伏。", "螺蚌視三神，盃盎閲四隩。", "參旗摩右肩，崑苑踏左足。", "營營蟻磨旋，戢戢蜂房簇。", "羶俎饜前臑，詩瓢慳半菽。", "歷測尊盧年，桴窮沃焦谷。", "疇非浮點漚，吾亦寄粒粟。", "氣形孰融結，高深誰濬矗。", "媧皇不能補，共工多事觸。", "飛思騰虛遨，殫精馳逈矚。", "浩浩蔑垠涯，渾渾曷邊幅。", "百刻倏汐潮，九行遞朏朒。", "達觀等鵬鷦，殊趨殽燕蝠。", "仙馭鞭虬螭，神駕軌驪騄。", "寰中無遁照，象外有玄燭。", "推尋製字蒼，究考畫卦宓。", "萬變既日滋，百靈遂宵哭。"]'),
('0ecaa532-40a8-4a92-8ccd-0d8e8d0b7639','冷泉亭','方回','宋','宋诗','song-poetry','','[]','金鞍驟紫陌，詎識林下勝。',96,'全唐诗/poet.song.233000.json','["金鞍驟紫陌，詎識林下勝。", "石苔爲誰碧，我輩坐乃稱。", "絲毫無愧容，照此冷泉鏡。", "竹樹亦如我，不與春色競。", "匏尊未用酌，一見百慮醒。", "土囊發饕風，無波此終定。", "革履漢臣心，恐未敵茲瑩。", "木杪夜月孤，庶其許相映。"]'),
('4ee04d6c-4474-467d-91e9-1e2e7efd76fe','次容齋喜雪禁體二十四韻','方回','宋','宋诗','song-poetry','','[]','燠寒節若無嗟若，不寒而燠疫癘作。',368,'全唐诗/poet.song.233000.json','["燠寒節若無嗟若，不寒而燠疫癘作。", "叵堪窮臘陽氣泄，况乃炎方土風惡。", "大塊積蓄久醖釀，元造斡回驟飄落。", "朝曦掩翳九烏死，夜吹呼號萬騎掠。", "餞歲纔轟爆竹聲，鞭春初截土牛角。", "芳芽脆甲縮芹薺，饑喙枵腸訴烏鵲。", "小遲尚可詫祥瑞，大快一舉洗汙濁。", "蟄蟲且當伏深穴，貞松决不仆幽壑。", "孤舟獨釣柳何奇，衡門空宇陶如昨。", "凍手三噢復三咻，泥屐一前仍一却。", "未妨獵騎濕鞍韉，政恐征車埋軫較。", "誰方輕暖擁文貂，我欲豪飲欠金錯。", "雀窺囷廩絕粃糠，蛛軃簷榱收網絡。", "老人畏怯小兒喜，富翁驕傲寒士虐。", "蜚蜮定復掃蠻蜑，歸雁未敢度幽朔。", "銜枚猛將死不懼，煨芋野僧貧亦樂。", "九頭鬼車悉逃遁，三足畢方能距躩。", "眼生燈暈蝶栩栩，膚澀衾稜雞喔喔。", "預占麥餌堆村場，絕喜米價減郛郭。", "忽得膚使奇麗句，韻未易賡筆屢閣。", "潁陰故事聚星堂，汶叟先生元祐脚。", "禁體物語繼醉翁，即今再見蘇龍學。", "幸公憂國僕無與，煎水烹茶聊一酌。"]'),
('06736d78-3968-4134-a925-9c3ccb0354fd','喜雨','方回','宋','宋诗','song-poetry','','[]','驟漲階前可泛舟，天低近屋火雲收。',64,'全唐诗/poet.song.233000.json','["驟漲階前可泛舟，天低近屋火雲收。", "竹戶紙窗清灑灑，葛衫紗帳冷脩脩。", "秋館梧桐羈客恨，春郊楊柳少年愁。", "移得此聲來六月，人人喜色上眉頭。"]'),
('085b5949-f371-402b-820a-a80dae77c735','謁東坡祠','方回','宋','宋诗','song-poetry','','[]','至和嘉祐政途開，老鳳將雛出蜀來。',64,'全唐诗/poet.song.233000.json','["至和嘉祐政途開，老鳳將雛出蜀來。", "父子聲名天宇小，弟兄筆陣海潮回。", "岷峨一氣鍾三傑，杜富諸賢得異材。", "二百年來拜遺像，堂堂直氣尚崔嵬。"]'),
('9a772632-8aa6-4d5d-a41f-f8b387244194','烟雨樓','方回','宋','宋诗','song-poetry','','[]','樓壓重湖實壯哉，樓前圖畫若天開。',66,'全唐诗/poet.song.233000.json','["樓壓重湖實壯哉，樓前圖畫若天開。", "鷗從沙際衝烟去，燕向花邊捲雨來。", "傍柳一橋相掩映，隔林雙塔共崔嵬。", "欄干倚盡催詩處，晴日須來三四回。", "八。"]'),
('95bfe8b8-d9e5-484d-baec-027bfaff3182','龔侯玉豹圖','方回','宋','宋诗','song-poetry','','[]','龔侯之先楚兩龔，遠孫挺挺有祖風。',256,'全唐诗/poet.song.233000.json','["龔侯之先楚兩龔，遠孫挺挺有祖風。", "五鼎食肉不掛意，萬卷讀書曾用功。", "草字隸字各神妙，古詩律詩俱豪雄。", "雖有一癖好畫馬，不比人間凡畫工。", "颯爽脩髯雪三尺，長安市上無人識。", "等閒幅紙寫驊騮，或者終身求不得。", "我未嘗求忽得之，袖出玉花驄一疋。", "開卷如聞嘶風聲，蹴踏青天砲霹靂。", "曹霸昔遇唐明皇，畫出此馬真龍驤。", "黄金拜賜南薰殿，赫奕門戶生輝光。", "昇平難保金易散，晚歲奔波逃戰場。", "却得少陵詩一首，名撐宇宙相悠長。", "龔侯不干萬乘主，但欲追尋窮杜甫。", "老筆一洗韓幹肉，天閑至寶落環堵。", "詩非杜甫畫勝曹，無乃心神漫勞苦。", "龔侯此筆游戲耳，別有文章垂萬古。"]'),
('fdb7dbed-f9c8-46e9-bce7-81f8871b4c6f','聽孫鍊師琴','方回','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','名畫元不出畫工，善書决不屬書史。',344,'全唐诗/poet.song.233000.json','["名畫元不出畫工，善書决不屬書史。", "子春伯牙非伶官，古能琴者必君子。", "枕流漱石今孫郎，電眸冰齒霜髯張。", "灑埽書室焚古香，信手爲吾調宮商。", "琮琮琤琤泉落澗，嗈嗈喈喈鴻度漢。", "從容整暇未肯忙，小俟吟猱觀抑按。", "急如快劍斫蛇分兩截，琉璃瓶碎玉簪折。", "似有鸞膠再補完，細視冰弦元不絕。", "又如電走雹飛驅霹靂，老樹百丈龍爪入。", "得非獺髓滅瘢痕，依舊烏桐淨如拭。", "睥睨黠鼠伏狸奴，殺機一動與之俱。", "鷹揚頗類師尚父，牧野秉鉞行天誅。", "臨河而聞殺鳴犢，曳輪不往反乎覆。", "許由不受堯天下，一瓢雖無吾亦足。", "聖門此意傳不傳，耿耿精靈月在天。", "孫郎何處得授受，長江秋霽印嬋娟。", "五音本無根舌齒，六律發揮憑手指。", "音律之外求七情，萬變悉從心上起。", "孫郎胸次夫何如，貯儲古今萬卷餘。", "孰謂七弦軫上之神聖，不本二尺檠邊之功夫。", "少年學琴欲學渠，勿但彈琴當讀書。"]'),
('a9d50302-3da9-4857-9340-ce0e0db1edd1','句  其一','方回','宋','宋诗','song-poetry','','[]','舊業三元賦，新功百中經。',12,'全唐诗/poet.song.233000.json','["舊業三元賦，新功百中經。"]'),
('2547706f-3eae-4107-9316-8cb7b99c9e98','句  其二','方回','宋','宋诗','song-poetry','','[]','屈使守鄉國，護保□□□。',24,'全唐诗/poet.song.233000.json','["屈使守鄉國，護保□□□。", "□□□比屋，燕雀語□□。"]'),
('553176e2-bf96-4aa1-9b77-7b8cf6631a74','句  其三','方回','宋','宋诗','song-poetry','','[]','菊花與汝作生日，螃蟹喚吾入醉鄉。',16,'全唐诗/poet.song.233000.json','["菊花與汝作生日，螃蟹喚吾入醉鄉。"]'),
('9d1363b7-56a2-43b4-8ee1-bcbadb54d7b2','句  其四','方回','宋','宋诗','song-poetry','','[]','諸公未許子爲政，萬事無如髯絕倫。',16,'全唐诗/poet.song.233000.json','["諸公未許子爲政，萬事無如髯絕倫。"]'),
('24160ed5-8181-48c7-93a7-febb73b344b6','句  其五','方回','宋','宋诗','song-poetry','','[]','糟薑三盞酒，桕燭一甌茶。',12,'全唐诗/poet.song.233000.json','["糟薑三盞酒，桕燭一甌茶。"]'),
('23b0ca75-3111-411d-9137-6669d68e1111','句  其六','方回','宋','宋诗','song-poetry','','[]','把酒從來不可期，吾降今日少人知。',16,'全唐诗/poet.song.233000.json','["把酒從來不可期，吾降今日少人知。"]'),
('194f655b-2ef2-4277-8272-de8c347ceb08','句','鮮于樞','宋','宋诗','song-poetry','','[]','一官屢厄黄楊閏。',8,'全唐诗/poet.song.233000.json','["一官屢厄黄楊閏。"]'),
('6733b79e-1706-4d2d-be04-97d8663ae31f','句','吳覺','宋','宋诗','song-poetry','','[]','燕頷英姿宜食肉，羊腸險韻宜剪茶。',16,'全唐诗/poet.song.233000.json','["燕頷英姿宜食肉，羊腸險韻宜剪茶。"]'),
('38f5041b-7b28-4904-84bf-9063e36b1cd1','句','金漢臣','宋','宋诗','song-poetry','','[]','故鄉萬里思親遠，客館孤身度日長。',16,'全唐诗/poet.song.233000.json','["故鄉萬里思親遠，客館孤身度日長。"]'),
('1a243026-fbf9-4ccf-92fa-484ed06cc082','題王氏小園','唐從龍','宋','宋诗','song-poetry','','[]','山脈鍾雲氣，新晴散紫霞。',48,'全唐诗/poet.song.233000.json','["山脈鍾雲氣，新晴散紫霞。", "玉藏雲裏石，金落水中沙。", "瘦鶴依疏竹，饑蜂戀落花。", "臨池看洗硯，知是右軍家。"]'),
('30ae259a-82e2-41b6-8ff9-5de4d8234857','句','徐遜綿','宋','宋诗','song-poetry','','[]','士死惟留姓與名。',8,'全唐诗/poet.song.233000.json','["士死惟留姓與名。"]'),
('4c761474-2da0-49ad-8689-4ce966706d35','句','張鵬飛','宋','宋诗','song-poetry','','[]','蒼天定俾期頤壽，會看芸書聘五更。',16,'全唐诗/poet.song.233000.json','["蒼天定俾期頤壽，會看芸書聘五更。"]'),
('f3feff33-40a3-4db2-b2ab-47174b111666','句','謝中','宋','宋诗','song-poetry','','[]','十年太守桐江郡，萬首新詩陸放翁。',16,'全唐诗/poet.song.233000.json','["十年太守桐江郡，萬首新詩陸放翁。"]'),
('baff8bad-22da-4a9f-a0a7-9f05916438eb','句','孫內翰','宋','宋诗','song-poetry','','[]','那更廉織雨，謾道玉爲堂。',12,'全唐诗/poet.song.233000.json','["那更廉織雨，謾道玉爲堂。"]'),
('5dc9aaf3-7ef6-401d-b6b1-8c80760b9187','句','無名氏','宋','宋诗','song-poetry','','[]','但看建德安民榜，即是虛翁德政碑。',16,'全唐诗/poet.song.233000.json','["但看建德安民榜，即是虛翁德政碑。"]'),
('41ad91d6-0914-4249-845d-649bf37235ce','東野平陵圖','牟巘','宋','宋诗','song-poetry','','[]','鞅掌不可耐，壯士縛申卯。',132,'全唐诗/poet.song.233000.json','["鞅掌不可耐，壯士縛申卯。", "驅馿古平陵，水木樂幽茂。", "苦吟到斜日，危坐類持釣。", "俗情見擺落，鵝雁極衆口。", "兩曹第忍之，適滿百乃報。", "吾終不以此，而易彼升斗。", "小裁鶴料案，官事竟未了。", "斯人坐詩窮，咎在虧天巧。", "有如發其羃，爲謔豈不暴。", "理宜得嫌憎，枵腹鎮雷吼。", "區區尤李氏，此頗天意不。"]'),
('64c0c25e-4c07-4238-888b-8ea1ed31ad3f','趙春谷約游北山次陳本齋韻','牟巘','宋','宋诗','song-poetry','','[]','病士痼於懶，舉世少匹亞。',192,'全唐诗/poet.song.233000.json','["病士痼於懶，舉世少匹亞。", "未省讀道書，低頭蒙絳帕。", "夢想北山北，戶限久不跨。", "折簡許我游，籃輿暫相借。", "腹鳴肩自舉，悠然謝銜靶。", "邂逅得水竹，神明湛吾舍。", "山亦紫翠橫，了不費要迓。", "平生赤兩脚，城市所深怕。", "何妨巖石間，共永一日暇。", "高情偉卓犖，不在古人下。", "喜客見眉宇，煮茗掃風榭。", "老山澹一癯，龜息聞靜夜。", "攝衣倒凌景，回首憐俗駕。", "吾儕偶會弁，小語輒雷咤。", "風雨萬慮清，詎肯隨物化。", "商山尚局促，而况彼畦夏。"]'),
('fbbdf211-6de8-4ca9-86e6-6b7162c7f0dc','東坡九日尊俎蕭然有懷宜興高安諸子姪和淵明貧士七首余今歲重九有酒無餚而長兒在宜興諸兒蘇杭溧陽因輒繼和  其一','牟巘','宋','宋诗','song-poetry','','[]','吾翁始落南，土思尚依依。',72,'全唐诗/poet.song.233000.json','["吾翁始落南，土思尚依依。", "築堂扁岷峨，目斷落日暉。", "憶昔丙申歲，錦里烟塵飛。", "甲子已一週，而我猶未歸。", "孤蓬失本叢，旅雁抱長饑。", "百年直寄爾，曠然勿徒悲。"]'),
('d20c3718-e74f-4bc3-9b64-a9fe0bb2802a','東坡九日尊俎蕭然有懷宜興高安諸子姪和淵明貧士七首余今歲重九有酒無餚而長兒在宜興諸兒蘇杭溧陽因輒繼和  其二','牟巘','宋','宋诗','song-poetry','','[]','驚飆舉落葉，意氣何軒軒。',72,'全唐诗/poet.song.233000.json','["驚飆舉落葉，意氣何軒軒。", "秋高百卉盡，寂寞但空園。", "何異富與貴，變滅隨雲烟。", "緬懷陶彭澤，平生極幾研。", "朗詠貧士詩，相對如晤言。", "今人之所耻，古人以爲賢。"]'),
('266278a3-9322-4797-8b90-ef3293478640','東坡九日尊俎蕭然有懷宜興高安諸子姪和淵明貧士七首余今歲重九有酒無餚而長兒在宜興諸兒蘇杭溧陽因輒繼和  其三','牟巘','宋','宋诗','song-poetry','','[]','我殆勝彭澤，無酒亦無琴。',72,'全唐诗/poet.song.233000.json','["我殆勝彭澤，無酒亦無琴。", "湖外來遠餉，屋角囀好音。", "吹帽節已迫，醉鄉路可尋。", "勿違故人意，洗盞起自斟。", "甜酒乏風骨，谷永與杜欽。", "而此清且勁，良足慰我心。"]'),
('ee19d6b3-2245-4061-94ba-dfa8541cd15b','東坡九日尊俎蕭然有懷宜興高安諸子姪和淵明貧士七首余今歲重九有酒無餚而長兒在宜興諸兒蘇杭溧陽因輒繼和  其四','牟巘','宋','宋诗','song-poetry','','[]','人生徒自苦，與世爲卷婁。',72,'全唐诗/poet.song.233000.json','["人生徒自苦，與世爲卷婁。", "何如有美酒，自獻還自酬。", "貧雖不若富，用寡庶易周。", "婚嫁願已畢，此外復何憂。", "况無下潠田，得與彭澤儔。", "年豐米長賤，一飽或可求。"]'),
('549a4bac-bc96-4a59-9355-dc2ac36ca534','東坡九日尊俎蕭然有懷宜興高安諸子姪和淵明貧士七首余今歲重九有酒無餚而長兒在宜興諸兒蘇杭溧陽因輒繼和  其五','牟巘','宋','宋诗','song-poetry','','[]','翁媼老白髮，蕭然老江干。',72,'全唐诗/poet.song.233000.json','["翁媼老白髮，蕭然老江干。", "大兒荆溪遊，折腰豈爲官。", "諸兒走異縣，亦各營一餐。", "別多會面少，端復坐饑寒。", "諸幼且眼前，笑語開我顔。", "勿問賢與愚，懷抱俱相關。"]'),
('37c9d127-9567-45d0-915f-1bdd7074ee4e','東坡九日尊俎蕭然有懷宜興高安諸子姪和淵明貧士七首余今歲重九有酒無餚而長兒在宜興諸兒蘇杭溧陽因輒繼和  其六','牟巘','宋','宋诗','song-poetry','','[]','好惡豈不察，鑿垣植蒿蓬。',72,'全唐诗/poet.song.233000.json','["好惡豈不察，鑿垣植蒿蓬。", "而此庭前菊，鋤灌少人工。", "此物抱至潔，有似楚兩龔。", "留香待嚴凜，意與烈士同。", "糞土笑伯始，金錢鄙鄧通。", "千載一元亮，舍此將安從。"]'),
('3af23994-39f8-4cb3-8575-5b28bc79536e','東坡九日尊俎蕭然有懷宜興高安諸子姪和淵明貧士七首余今歲重九有酒無餚而長兒在宜興諸兒蘇杭溧陽因輒繼和  其七','牟巘','宋','宋诗','song-poetry','','[]','兩山南北峙，四水貫此州。',72,'全唐诗/poet.song.233000.json','["兩山南北峙，四水貫此州。", "登臨豈不嘉，出門自寡儔。", "客鄉幾重九，歲月如奔流。", "蕭然具果飲，聊以散百憂。", "平生和陶集，韻高乃敢酬。", "乃復咏歌之，歲晚葆姱修。"]'),
('039be39d-6dba-4c69-a562-13b207fb734b','和程漁莊救燕','牟巘','宋','宋诗','song-poetry','','[]','燕巢屹高壘，蛇行危折罄。',180,'全唐诗/poet.song.233000.json','["燕巢屹高壘，蛇行危折罄。", "不虞猝見侵，怪事發軒屏。", "黄口養漸大，紫翮翻相映。", "雌雄力難護，吞噬氣方盛。", "豈不避戊己，天意特未定。", "主人勇赴救，爲惠固當竟。", "蜿蜒墮尺箠，折首甘所迎。", "古人致陰類，嗜好用其性。", "此族遭炮燔，往往多夭橫。", "人固異於物，縱暴胡忍聽。", "試看自古來，善者終必勝。", "羿殞莽亦屠，曾莫保軀命。", "報應各以類，豈不信可證。", "驅而放之菹，是乃三代政。", "姑用柳子言，鋤吾草萊徑。"]'),
('3bb9df3e-d357-4ef5-a0d0-bec9854f85ef','題淵明圖','牟巘','宋','宋诗','song-poetry','','[]','平生抱耿介，四海寡朋交。',96,'全唐诗/poet.song.233000.json','["平生抱耿介，四海寡朋交。", "凄其九日至，頗感顔髮凋。", "無酒醒對菊，風味乃更高。", "誰識此時情，白雲行遠霄。", "地主有佳餉，得之良已勞。", "而我適邂逅，赴飲如沃焦。", "永言大化內，朽質非所陶。", "惟有飲美酒，一醉可千朝。"]'),
('ac5f0807-17d9-4e67-8f27-7bfde6df46e0','九日','牟巘','宋','宋诗','song-poetry','','[]','秋風颯以至，今日重陽日。',228,'全唐诗/poet.song.233000.json','["秋風颯以至，今日重陽日。", "明明對南山，尚想陶彭澤。", "向來建威幕，頗見有此客。", "驅車不少留，駕言公田秫。", "如何又棄去，此意誰能識。", "寄奴趣殊禮，風旨來自北。", "只今王江州，建白功第一。", "故是僧彌孫，舉動殊足惜。", "飲媿望柴桑，稍欲自湔滌。", "殷勤白衣餉，猶恐不我即。", "中路候籃輿，要致已甚迫。", "葛巾赤兩脚，頹然向州宅。", "此翁本坦蕩，焉能苦違物。", "一時可計取，中實未易屈。", "華軒有何羨，自載返蓬蓽。", "終身書甲子，凜凜義形色。", "如使磷且緇，安得爲玉雪。", "籬邊有佳菊，弄黄正堪摘。", "我方持空觴，千載高風激。"]'),
('17a4517b-31a2-4089-a322-87aa38dad4f5','簡趙子昂','牟巘','宋','宋诗','song-poetry','','[]','君維大雅姿，被服藹蘭蓀。',204,'全唐诗/poet.song.233000.json','["君維大雅姿，被服藹蘭蓀。", "胸次綜流略，本本又元元。", "手追七子作，凌厲氣所吞。", "餘事到翰墨，藉甚聲價喧。", "居然難自藏，珠玉走中原。", "四年郎省戶，小滯當高鶱。", "肯來爲多士，復除布春溫。", "力爭吾道回，中流收崩奔。", "眷言維桑舊，從容駐輶軒。", "我亦喜再見，一笑略寒暄。", "首誦新詩章，兩耳爲君尊。", "高情殊磊落，俗子何足論。", "顧我寂寞地，無物當贈言。", "乃復携尺紙，看君醉墨翻。", "霜木石共老，野竹翠不蕃。", "落筆頻申頃，歲晚古色存。", "思君時一把，此意期勿諼。"]'),
('59aa68ac-38d3-4e2c-b64c-8055a716362f','和趙子俊閒居十首  其一','牟巘','宋','宋诗','song-poetry','','[]','俯仰一室內，我興尚無爲。',96,'全唐诗/poet.song.233000.json','["俯仰一室內，我興尚無爲。", "凝塵澹素几，乍見閒居詩。", "吐詞甚高簡，觀者未必知。", "士固各有志，肯爲富貴移。", "汲多羸其瓶，居然井在湄。", "何似鴟夷全，張弛隨所宜。", "楊子不違物，趙子不干時。", "此意諒所同，相與三復之。"]'),
('6501cca0-b675-4f58-a59e-4710490868fe','和趙子俊閒居十首  其二','牟巘','宋','宋诗','song-poetry','','[]','窘步殊蹣跚，戶限久不踰。',84,'全唐诗/poet.song.233000.json','["窘步殊蹣跚，戶限久不踰。", "若或縶維之，媿彼空谷駒。", "俯焉念平生，我亦酷信書。", "所得不償失，每與憂患俱。", "飲水飯脫粟，此意豈願餘。", "貧實爲我累，舍貧將焉如。", "堪嗟嗜利者，死甘謚爲愚。"]'),
('ab363647-74d4-494e-93c4-cef27a9c0ad5','和趙子俊閒居十首  其三','牟巘','宋','宋诗','song-poetry','','[]','維昔陶元亮，早歲尚隠淪。',96,'全唐诗/poet.song.233000.json','["維昔陶元亮，早歲尚隠淪。", "從事建威幕，奔走戎馬塵。", "宵征亦良苦，我豈戀軒茵。", "時運不可回，物態日以新。", "悠然彭澤去，漸與鄉里親。", "公田半稅秫，亦足慰我貧。", "有人企高躅，漫仕求所伸。", "閩嶠雖云遠，絃歌遂其真。"]'),
('8108874a-730d-4e01-8412-b36320b1ae96','和趙子俊閒居十首  其四','牟巘','宋','宋诗','song-poetry','','[]','九日忽已過，霜薄陽光晞。',84,'全唐诗/poet.song.233000.json','["九日忽已過，霜薄陽光晞。", "未漉頭上巾，先典篋中衣。", "時物尚有菊，採掇頻爾稀。", "對酒胡不飲，坐看白日飛。", "五勝更囚旺，萬事誰是非。", "且復進一觴，酒盡情依依。", "晚蝶抱孤蕊，無乃昧先幾。"]'),
('7f8d23bc-d2cf-4acb-9b30-e5daf6066aa6','和趙子俊閒居十首  其五','牟巘','宋','宋诗','song-poetry','','[]','勢利苦炎炎，名節貴皜皜。',72,'全唐诗/poet.song.233000.json','["勢利苦炎炎，名節貴皜皜。", "河縣開桃李，家園熟梨棗。", "當年歸騎省，名譽豈不早。", "一染金谷塵，蕭艾沒芳草。", "胡爲閒居賦，乃誚任安巧。", "所以惟慕陶，固窮而守道。"]'),
('82d0063f-a738-4087-9b05-7f9389b1f136','和趙子俊閒居十首  其六','牟巘','宋','宋诗','song-poetry','','[]','我亦愛閒居，好山環屋青。',48,'全唐诗/poet.song.233000.json','["我亦愛閒居，好山環屋青。", "拄頰坐來久，冉冉白雲生。", "山中有三秀，誰爲采其榮。", "散我腰脚頑，使我神觀清。"]'),
('7cf1a961-d119-4d58-a79e-0cb56098fc84','和趙子俊閒居十首  其七','牟巘','宋','宋诗','song-poetry','','[]','我居殊偪仄，東西鑿兩牖。',72,'全唐诗/poet.song.233000.json','["我居殊偪仄，東西鑿兩牖。", "卧起於其間，不知歲年久。", "秋菜上牆生，廢圃一何有。", "只應溪上人，笑我已白首。", "橘柚非所種，勸我且種柳。", "也莫種牡丹，與物爭妍醜。"]'),
('aadf498a-3ade-466b-bb94-14161ef2d2ae','和趙子俊閒居十首  其八','牟巘','宋','宋诗','song-poetry','','[]','閒居維弄翰，窗明庭戶寂。',72,'全唐诗/poet.song.233000.json','["閒居維弄翰，窗明庭戶寂。", "硬黄力追古，旁觀共歎息。", "當由結習深，亹亹向晨夕。", "持用自怡悅，而不爲物役。", "但恐好事者，逸少混鐵石。", "我能別真贋，一紙百金直。"]'),
('8b25619e-c120-4d10-92a7-e117d40c4bfe','和趙子俊閒居十首  其九','牟巘','宋','宋诗','song-poetry','','[]','衣短不及骭，髮短不滿梳。',72,'全唐诗/poet.song.233000.json','["衣短不及骭，髮短不滿梳。", "惟有憂世心，皇皇此生俱。", "鮒魚呼轍中，微濕以相濡。", "斗水旦夕急，豈與人意殊。", "試誦反招隠，願無懷故居。", "墨突何曾黔，行矣勿踟躕。"]'),
('3e990338-1056-4ca1-84f2-0f17d55815a5','和趙子俊閒居十首  其一○','牟巘','宋','宋诗','song-poetry','','[]','人生與出處，要不失其正。',60,'全唐诗/poet.song.233000.json','["人生與出處，要不失其正。", "手捧毛義檄，以爲庭闈慶。", "祿養有甘旨，東西惟所命。", "賀客來何多，踏破蒼苔徑。", "再拜稱壽觴，閭里生新敬。"]'),
('cbade923-8a14-4390-a884-25db777b883c','米元暉山水','牟巘','宋','宋诗','song-poetry','','[]','鶻突烟樹外，水遠山更長。',84,'全唐诗/poet.song.233000.json','["鶻突烟樹外，水遠山更長。", "天地有如許，扁舟何處藏。", "如何短篷底，結習猶未忘。", "是時水月繁，不見此夜光。", "於今尚無恙，懷袖行可將。", "我亦流落者，此味慣所嘗。", "誰能畫峨堂，坐我於其旁。"]'),
('3bc3409f-92f1-4389-ba8e-8925e123811b','十月既望能靜飲客海棠花下即席索詩走筆一笑','牟巘','宋','宋诗','song-poetry','','[]','久聞使君歸，扁舟欲自載。',216,'全唐诗/poet.song.233000.json','["久聞使君歸，扁舟欲自載。", "竟負九日約，吾意良有待。", "今朝得得來，適與佳辰會。", "名園盛衆卉，摇落不少愛。", "爲語玉林神，無乃風景殺。", "春葩發霜枝，一夜作奇怪。", "此花紅濕處，無如錦城最。", "銜來定鴻鵠，萬里從雪外。", "高情相暖熱，置酒出花背。", "固知是鄉人，豈不在我輩。", "西莊見西産，一笑心領解。", "主人獨妙年，有花正宜戴。", "胡爲亦見分，無乃嘲老大。", "誰令開非時，故遣白髮對。", "君勿輕白髮，髮白老更耐。", "洛陽劉伯壽，耆英典型在。", "醉帽仍插花，豈是兒女態。", "還以壽主人，風流更耆艾。"]'),
('be3b35fe-22fc-4e67-9e93-37752a89a0bb','羅漢臣拄笏亭','牟巘','宋','宋诗','song-poetry','','[]','爽氣鍾於西，峨眉橫太白。',264,'全唐诗/poet.song.233000.json','["爽氣鍾於西，峨眉橫太白。", "春風吹不暖，暑路有積雪。", "月照平羌冷，雲頂七頂濕。", "游戲兩謫仙，銀河洒醉墨。", "遂令漢嘉郡，千古占一色。", "一從殊方走，江山頗蕭瑟。", "流落各天涯，相逢未相識。", "微聞莊舄吟，握手話疇昔。", "乃知此邦秀，終不斷地脈。", "權門車如霧，衆甘炙手熱。", "而君獨幾先，惟恐涴我笏。", "偉哉百尺樓，西望即鄉國。", "爽氣今已回，何妨高拄頰。", "里中表聖公，千載推汲直。", "當年幾諫紙，扣笏良鯁切。", "意欲摧百士，死職非所惜。", "此笏豈其遺，正自峭風骨。", "願君善藏之，擊邪看他日。", "也無羨堆牀，富貴竟何益。", "長鑱白木柄，乃我手中物。", "惟有故鄉夢，與君共愁絕。", "何當駕雙鵠，萬里遡寥碧。"]'),
('8a7d9b66-fd8f-4df0-8800-f77ecdf5009c','文本心參政約游西山分韻得頂字','牟巘','宋','宋诗','song-poetry','','[]','僕僕事行役，度盡千峰頂。',168,'全唐诗/poet.song.233000.json','["僕僕事行役，度盡千峰頂。", "恣覽亦云倦，困卧殊未醒。", "西爽俄見要，前約欲重訂。", "結習若猶在，寧復計兩脛。", "天際豁輕陰，溪頭橫短艇。", "挳手謝籃輿，信步蹋荒徑。", "適意自忘遠，迷途誰爲詗。", "此翁平生意，故自略畦町。", "何妨一笑回，呼僮催煮茗。", "兩年已三至，我如飫黿鼎。", "無乃太屬厭，徒欲逃酩酊。", "老筆忽先倡，高標誰與並。", "尚記去載游，金碧光炯炯。", "何處非吾鄉，一氣相滓溟。"]'),
('54483fbe-359a-48d6-8ff0-a0ba9e7251d7','送姚子敬','牟巘','宋','宋诗','song-poetry','','[]','方聞興秀孝，久矣無令舉。',216,'全唐诗/poet.song.233000.json','["方聞興秀孝，久矣無令舉。", "公車冷於冰，吾已棄如土。", "提書向孔牆，萬代禮樂主。", "而與先簿正，厥有聖法寓。", "士也得所歸，至窮亦云遇。", "於惟京頖舊，幸不生蒿穭。", "斯文諒在茲，天意豈輕付。", "之子抱淵靜，蕭然守環堵。", "光彩難自閟，珠玉滿囊楮。", "一從鶚表飛，諸公共稱許。", "如何但熟睨，引鼎力不武。", "棲遲冷掾間，無乃太廉取。", "相縻共升斗，端欲重黌宇。", "勿嫌屋打頭，硉兀氣未吐。", "六月取一息，千里始跬步。", "期君在遠業，看君即軒翥。", "風雨忽道別，悢悢寡悰緒。", "從今閉柴荆，何以慰衰暮。"]'),
('e395519c-7703-48cd-bee0-18d9a5179530','題張老山從好堂','牟巘','宋','宋诗','song-poetry','','[]','世有嗜土炭，恣啖等粱稻。',264,'全唐诗/poet.song.233000.json','["世有嗜土炭，恣啖等粱稻。", "海上逐臭夫，自謂姣且好。", "好惡一失正，萬境眩顛倒。", "亦有欲富者，蠅營無不到。", "洗削誇鼎食，執鞭甘隸皂。", "於此還有人，深耻貨賂冒。", "一笑視千駟，貧賤守以道。", "厥好豈爾殊，吾自有至寶。", "但恐好不真，回奪諒難保。", "老山殊絕塵，褰裳衣欲縞。", "區區名與利，何曾挂懷抱。", "世人定不愛，昌歜與羊棗。", "吾意各有在，端未恨枯槁。", "從好以名堂，一室聊笑傲。", "心惟有所好，乃能無所好。", "好仁者夫子，不知歲年老。", "益晚而好易，易編窮所好。", "彼富如浮雲，非義是所悼。", "諒茲得其從，聖言極探討。", "孰重復孰輕，辨之亦既早。", "而我方忍饑，四壁浄如掃。", "舍魚取熊掌，因用儆衰耄。"]'),
('1acd14db-717e-48fe-9743-e8585a6b2190','十日菊爲子昂壽','牟巘','宋','宋诗','song-poetry','','[]','風露浩如洗，漸覺霜氣滋。',96,'全唐诗/poet.song.233000.json','["風露浩如洗，漸覺霜氣滋。", "九日已成旬，黄花爛盈枝。", "誰云清香減，清香在詩脾。", "詩人亦未老，皎皎冰雪姿。", "爲我掇繁英，和露三嚥之。", "此物是壽耐，千載以爲期。", "一點綴鬚髮，真是麒麟兒。", "長大著膝上，綵衣相娛嬉。"]'),
('a53c057c-4a14-4301-9614-f32b5cb2bb81','戚子雲袖詩見過且篤敘先祭酒與先人同朝之雅意甚古用韻爲謝','牟巘','宋','宋诗','song-poetry','','[]','白髮祭酒公，儀刑古君子。',120,'全唐诗/poet.song.233000.json','["白髮祭酒公，儀刑古君子。", "多士所共敬，豈獨桑與梓。", "吾翁幸同朝，輦路時並轡。", "流風日以邈，追慨徒倚徙。", "子雲篤世誼，朅來自槜李。", "念我一破廬，落落荒城址。", "遺以五朵雲，置之五雲裏。", "我是老祠官，未忘鏡湖水。", "握手更細論，書味淵以旨。", "嘉問有青衿，十載詩千紙。"]'),
('243f1735-379c-4b98-a958-08a1fcadd277','西巖使君上冢過霅首訪敝廬又會能靜話舊感慨情見於辭所以道別','牟巘','宋','宋诗','song-poetry','','[]','自爲旴江行，最聲日飛馳。',252,'全唐诗/poet.song.233000.json','["自爲旴江行，最聲日飛馳。", "赤子問襦袴，白雲滿鬢髭。", "苕邊重會晤，握手慰所思。", "舊有瀧岡表，三讀起懦衰。", "乃翁平生志，正在造膝時。", "曾擊戚畹悍，曾疏公田欺。", "曾陳峴山急，或訝話太危。", "移疾逃相印，何忍張悌爲。", "全歸干戈際，一致視險夷。", "象賢有令子，紀實無溢辭。", "刻之並纂疏，自足永久垂。", "憶昔姑孰守，欲碎脫鞾碑。", "博士何偉哉，奮身力護持。", "粗沙與大石，彼計竟莫施。", "遂令兩圖在，留作千載奇。", "此事關世道，磯激我匪私。", "他時記先友，要當附見之。", "顧我窮未死，僅存骨裹皮。", "殷勤綈衣貺，古道其在斯。", "無物當贈策，遠大以爲期。", "願勿忘吾州，歲晚託茅茨。"]'),
('2bea6107-eff4-4c1c-bb40-873bedb81d39','和德清曹魯郊七十一吟','牟巘','宋','宋诗','song-poetry','','[]','元日書甲子，曉槃問五辛。',288,'全唐诗/poet.song.233000.json','["元日書甲子，曉槃問五辛。", "頗記絳縣老，宜有善頌陳。", "君乎生是歲，早晚戰伐塵。", "明年七十二，舊諜無糾紛。", "斜飛滯棲枳，旁觀歎積薪。", "欵乃來澤國，比屋多嚬呻。", "何由躋壽域，君勿開荒榛。", "遺以大有年，在在鼓腹人。", "非徒事勾稽，耄稚情日親。", "溪流甚清泚，鵞山亦嶙峋。", "胡爲動鄉思，便欲乞其身。", "駕言登東山，遐眺窮崖垠。", "有時於沂浴，庶幾遠俗氛。", "平生布衣舊，方今鼎鉉巨。", "挽留不聽去，好語溫如春。", "悠然復少住，終惠此邑民。", "九十以珍重，八十起渭濱。", "如君老益壯，眼明無眵昏。", "精力殊未衰，齒宿意自新。", "盍陪英俊游，可是枯槁倫。", "而况二三子，左右參魚鱗。", "從翁取青紫，且姑置垂綸。", "憶昨初相識，氣象清以淳。", "而我已索如，髮短不可耘。"]'),
('82d3bda2-c5da-4e12-afe3-9de0977f116f','餞潛岡南提舉','牟巘','宋','宋诗','song-poetry','','[]','君前郡文學，端自吾州始。',192,'全唐诗/poet.song.233000.json','["君前郡文學，端自吾州始。", "壇坫日以高，到處執牛耳。", "平生灑落胸，作事故奇偉。", "飛上南樓去，坐得數千里。", "全楚带五嶺，古俗甚豐美。", "一昨干戈後，或未識瑚簋。", "禾穭生黌宮，學士氣如洗。", "此行纍佩印，良爲吾黨喜。", "三閭屈大夫，四海習鑿齒。", "堂堂始興公，亦從韶石起。", "何地不生賢，幸勿遐陋視。", "著意絢荒餘，文物中州比。", "况復多蜀客，誰其顧瑣尾。", "相與噢休之，我頗念桑梓。", "垂老猶惜別，何以當馬箠。", "願君爲廣厦，大庇天下士。"]'),
('95f63d12-3daf-4101-a4da-68e90ad07cfe','柏生兩石間千歲終不大韓子則欲移之平地以遂其生柏生兩石間天命本如此蘇子則欲安之石間以全其生二說若異然韓子愛惜人物以有用者也故又曰傷根柏不死千丈不難至蘇子愛惜名節以自保者也故曰雖云生之艱與石相終始愛柏一也雖然處險難而出險尤難金華倪君老儒也以柏山自號因取二公意賦詩寄之','牟巘','宋','宋诗','song-poetry','','[]','柏生兩石間，平地盍移置。',144,'全唐诗/poet.song.233000.json','["柏生兩石間，平地盍移置。", "平地豈不好，又恐傷生意。", "兩翁爲柏謀，其慮各已至。", "受命獨也正，固與凡木異。", "夷險猶爾殊，而我本一致。", "但能全其天，所擇不在地。", "我聞柏山名，抱藝久不試。", "自種秋柏實，離離滿山翠。", "石礙曾不傷，地平亦不肆。", "歲月漸婉娩，冰雪幾凌厲。", "此柏初不知，老大見根柢。", "一笑謝兩翁，何省爲榮悴。"]'),
('a69580b8-e1ae-40da-962b-2e851df5c89c','送洪竹堂','牟巘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','家住西湖西，愛吟仍愛竹。',192,'全唐诗/poet.song.233000.json','["家住西湖西，愛吟仍愛竹。", "富貴豈不好，變滅如轉燭。", "一昨流落後，破垣竹猶綠。", "往事何用訪，得此良自足。", "胡爲被書誤，彈冠向苕曲。", "三年飯脫粟，不飽而况肉。", "頗有青衿子，對之尋舊讀。", "時復吐佳句，家山如在目。", "不知竹是伴，誰護蒼玉束。", "官滿還滯留，欲歸未可卜。", "無錢買扁舟，遷居更勿促。", "悠然謝此君，行止任遲速。", "新年雨雪深，忽已歸期告。", "天公似有意，爲爾開晴旭。", "士固不可料，窮久理當復。", "東風吹浩蕩，萬里奔鴻鵠。"]'),
('8278ab5d-aa52-4385-b4c3-970ad89fe22a','贈姜醫','牟巘','宋','宋诗','song-poetry','','[]','越人嘗遊齊，後世多名醫。',48,'全唐诗/poet.song.233000.json','["越人嘗遊齊，後世多名醫。", "漢時太倉長，亦復出臨淄。", "子實同鄉里，兩翁諒所師。", "從今霅川水，飲者不厲疵。"]'),
('05551d08-fa32-40ff-9e2d-2876c02418d7','贈日者薛東湖','牟巘','宋','宋诗','song-poetry','','[]','抱疴蓬廬下，白日背我馳。',48,'全唐诗/poet.song.233000.json','["抱疴蓬廬下，白日背我馳。", "我生已如此，天命復奚疑。", "悠哉東湖水，不迎亦不隨。", "相對澹無語，可以樂我饑。"]'),
('9de59474-2438-42b1-913c-67b4553873ce','和德問弟苦雨','牟巘','宋','宋诗','song-poetry','','[]','鵓鳩朝喚晴，竹鷄莫催雨。',264,'全唐诗/poet.song.233000.json','["鵓鳩朝喚晴，竹鷄莫催雨。", "翛翛晴雨間，平生睡足處。", "剝啄忽以詩，使我浪愁苦。", "此事屬天公，底用强如許。", "淋漓不得休，土偶復於土。", "君何見之晚，三歎詠集栩。", "不如兩忘言，危坐擁敗絮。", "向來夏畦勞，抱甕漢陰圃。", "旱澇相乘除，天地只此數。", "爲我語老農，未用輕喜怒。", "使有二頃田，亦欲荷鋤去。", "我評昔遜世，幼安勝根矩。", "毋爲苦近名，江湖多數罟。", "但看采榮者，隠約殆終古。", "彼以膏自煎，謝去非吾侶。", "無已則沮溺，躬耕諒所取。", "吾儕固長貧，正坐力不武。", "所營薄少耳，摶沙尚難聚。", "却笑杜陵翁，欲把漏天補。", "胡不歸自謀，颼颼破茅宇。", "天邊金老鴉，已放晴曜吐。", "馬嘶群動起，吾惟守環堵。"]'),
('d0361de4-6078-4740-8012-a045e3c4b0ae','和無逸子敬獨姥山','牟巘','宋','宋诗','song-poetry','','[]','維址呀洞戶，雲氣一縷烟。',168,'全唐诗/poet.song.233000.json','["維址呀洞戶，雲氣一縷烟。", "老龍蓄精祐，萬石護其巔。", "從此叩林屋，倒翻水中天。", "金庭漫隔凡，窮探未擬旋。", "轟豗四面動，兀坐孤寂然。", "頗疑北山脈，跨湖潛屬聯。", "歸來夢所歷，跳波撼晝眠。", "種橘化爲枳，我髮日已宣。", "何時崦邊路，去伴毛公仙。", "獨姥舊聞名，俚俗訛已傳。", "一朝得妙語，塗抹乃更妍。", "天姥似失色，葉姥休語年。", "而我復自笑，槁乾非葉鮮。", "聊以調二士，鼓棹還延緣。"]'),
('538198ad-8759-4e58-9d3a-678def8a20c4','和善之遊龜溪乾元寺','牟巘','宋','宋诗','song-poetry','','[]','疇昔侍吾翁，尚記入霅年。',168,'全唐诗/poet.song.233000.json','["疇昔侍吾翁，尚記入霅年。", "米麯家家釀，蒲荷處處田。", "龜溪見鶴林，欲去遭挽牽。", "借屋度長夏，對牀時醉眠。", "或登左顧亭，風物清且妍。", "回顧一甲子，往事隨奔川。", "翰林左綿秀，宮錦不上船。", "肯尋兩翁遊，來弄明月泉。", "弄泉珠麗袖，吟詩箭脫弦。", "是誰修月斧，斲地成空穿。", "猶有半泓碧，奈此筆如椽。", "乃知宇宙內，小大常相懸。", "惟堪供我輩，古瓦生茶烟。", "雲乳聊一啜，松風灑禿顛。"]'),
('ffc71394-1a41-44ac-af20-23c3a253dcff','和善之遊法華','牟巘','宋','宋诗','song-poetry','','[]','勝游得勝士，欲濟得健艣。',276,'全唐诗/poet.song.233000.json','["勝游得勝士，欲濟得健艣。", "如此正自佳，寧論晴復雨。", "徐行看前山，雲氣互吞吐。", "借我烏藤枝，急奔青蓮宇。", "跋疐良亦疲，籧篨可能俯。", "呼酒酹此脚，一笑失枝拄。", "吾懷已曠然，阿香殷餘怒。", "牀敷相對睡，不暇參佛祖。", "晨光報新霽，生色浮宿莽。", "諸峰忽自獻，頗自作眉嫵。", "絕頂瞰具區，勇往不可戶。", "而我跛躄者，遲鈍誰比數。", "窘步竟難陪，內熱生心腑。", "龐通遠相要，淵明喜欲舞。", "籃輿叩隠廬，趺坐直香縷。", "四士苦未還，踏破辛夷塢。", "俱是青雲客，那得薄圭組。", "新笋甜如蜜，新茗白勝乳。", "山靈倘見容，吾欲老茲土。", "預愁下山去，塵事紛旁午。", "試問白木鑱，何如長柄麈。", "他日蒙菜把，終當作地主。", "此翁無乃癡，紞如已五鼓。"]'),
('d0e100f6-3756-47e2-85b7-c7ff070a39e0','真隠詩','牟巘','宋','宋诗','song-poetry','','[]','招隠費招呼，習隠聊習步。',264,'全唐诗/poet.song.233000.json','["招隠費招呼，習隠聊習步。", "素隠爲素餐，充隠似充數。", "悠悠千載內，罕與真隠遇。", "少小慕真隠，每誦坡老句。", "朅來法華遊，正在題詩處。", "真境忽在前，更慕坡所慕。", "真則思慮泯，不真精爽騖。", "真則光塵合，不真圭角露。", "真書無欹仄，真味無反惡。", "真樂無安排，真逸無疲苦。", "所以要任真，從其訝箕踞。", "所以貴葆真，從他笑椎魯。", "但看真隠廬，蕭然只環堵。", "青山以爲屏，白雲常在戶。", "隨宜種花藥，快意掃庭宇。", "可作真率會，可說真實語。", "可飲真一酒，何者非天趣。", "玄真乃詩流，季真是仙侶。", "拉之相與俱，巾屨此容與。", "坐聞雛鶴鳴，時看蒼虬舞。", "疏散略邊幅，誰客復誰主。", "吾亦忘吾真，酣歌下山去。"]'),
('234f9c76-a1e2-4e39-9033-15080a463a78','俞好客又號菊莊爲賦數語','牟巘','宋','宋诗','song-poetry','','[]','人生自作計，北屋連南莊。',288,'全唐诗/poet.song.233000.json','["人生自作計，北屋連南莊。", "其間復何有，積粟埋屋梁。", "敢村有退士，用意獨異常。", "種菊一萬株，規作歲晚糧。", "老農與老圃，工勤略相當。", "春雨茁陳根，柔荑綠於秧。", "剪翳披厥穎，葉盛在本昌。", "啜之付茗椀，聊誑藜莧腸。", "秋高飽風露，粲粲枝間黄。", "使天而雨金，不可以爲糧。", "此賜何敢慢，再拜然後嘗。", "挼挲不勞咀，迸入牙頰香。", "三嚥下丹田，字之曰黄粱。", "其情性具烈，毋以他饋傷。", "爲爾制頹齡，使爾壽而康。", "彭澤有公田，秫種半頃强。", "正使及秋成，所得亦已凉。", "奈何不少忍，决去驚鴻翔。", "百匝繞東籬，采采不盈筐。", "高吟發清餓，持此送一觴。", "珠玉實其腹，千載有耿光。", "子亦慕陶者，閉戶歌慨慷。", "但得三徑存，何慮一莊荒。", "老我饑不死，誰與辟穀方。"]'),
('dd579e17-226c-42ff-a203-2b85a65baa77','鄉曲諸名宿不鄙老朽移樽見過風誼甚古語笑甚歡輒借昌黎人日城南詩韻少見謝意','牟巘','宋','宋诗','song-poetry','','[]','人生貴合併，造物忌嘲弄。',120,'全唐诗/poet.song.233000.json','["人生貴合併，造物忌嘲弄。", "頗與同社闊，正坐兩骭凍。", "南城七日遊，前事諸賢用。", "但愁茅屋陋，不足置賓從。", "此會豈偶然，歲月日時共。", "四癸義可取，三壬老堪送。", "况有蹇東陽，初不減潘葑。", "渴吻久已燥，樂飲宜一縱。", "笑談更溫克，容與非倥傯。", "永言戢厚意，拜嘉敢不重。"]'),
('800d9c3f-ce2f-4ed1-8906-557dab72a1a0','李千秋訪數語代謝','牟巘','宋','宋诗','song-poetry','','[]','昔有孟萬年，脫帽狂不休。',120,'全唐诗/poet.song.233000.json','["昔有孟萬年，脫帽狂不休。", "今有李千秋，吟詩醉愈遒。", "我久聞佳句，一面苦未酬。", "殷勤忽過我，意氣殊相投。", "能道太白語，便可太白浮。", "清論或抵掌，烏紗猶在頭。", "而我已頹然，頗有此樂不。", "偉抱自卓犖，下國難淹留。", "同來玉雪郎，外家乃名流。", "好歌鳳將雛，飛上丹極遊。"]'),
('a8bcacb5-926d-47fa-8934-fb3362629065','宣和御畫紫芥','牟巘','宋','宋诗','song-poetry','','[]','荒園老蔓菁，空見根葉大。',36,'全唐诗/poet.song.233000.json','["荒園老蔓菁，空見根葉大。", "苦硬螫人口，棄去何足頼。", "穰穰來萬蟻，微醒有餘嘬。"]'),
('abf3397c-0d16-4836-8a99-fae06079606f','岳君舉用東陽法釀酒味頗藴藉長兒携歸偶得數語','牟巘','宋','宋诗','song-poetry','','[]','昔屢飲東陽，往往錯認水。',156,'全唐诗/poet.song.233000.json','["昔屢飲東陽，往往錯認水。", "次公似少猛，汲生終戇耳。", "知我野心性，雅不便軟美。", "契闊二十年，那復此風味。", "飲酒真飲蜜，直欲嘔心胃。", "兒從南塘歸，殷勤有佳遺。", "公等久要在，相看猶故意。", "曲江加藴藉，鄭公殊嫵媚。", "一見極傾倒，吻渴不能止。", "正性固自存，遽莫測其際。", "徐覺和以諍，雖勁還可喜。", "酒固未易知，知酒亦非易。", "酩酊何適從，不夷而不惠。"]'),
('975e51ab-eeb9-4215-9cf4-e26f36cc02f4','德清孫氏和樂秀明堂','牟巘','宋','宋诗','song-poetry','','[]','人生致足樂，莫如令兄弟。',264,'全唐诗/poet.song.233000.json','["人生致足樂，莫如令兄弟。", "綽綽而有裕，其中自春意。", "龜溪有二孫，能篤友于義。", "同居五十載，闔門數百指。", "幾微無間言，輪囷有和氣。", "粵從鴻雁散，惟恐棠棣廢。", "欲挽古道回，茲事良非易。", "亦既成新居，始得遂初志。", "和樂揭高扁，秀明屹對峙。", "怡然兩白髮，塤箎伯仲氏。", "子孫皆雍睦，閭里亦順悌。", "復如無事時，難得真可貴。", "唐史傳孝義，頗記張劉李。", "跡其屢易世，往往干戈際。", "義風不少衰，大書乃無媿。", "嗟哉廣明后，旌命曾弗至。", "雖有篤行者，誰爲紀姓字。", "我聞二孫名，不覺爲之喜。", "兩記信實錄，聯名盡名士。", "先見衆論公，必得一行史。", "行看表門閭，鄉邦誇盛事。", "我詩甚鄙拙，願爾多壽祉。"]'),
('94131152-7f73-43f8-bd7e-ca3f7dddd0da','贈俞山月','牟巘','宋','宋诗','song-poetry','','[]','童奴從長耳，萬風聲蕭騷。',96,'全唐诗/poet.song.233000.json','["童奴從長耳，萬風聲蕭騷。", "歸從半山路，問字良亦勞。", "卧聞饑虎嘯，喚醒平生豪。", "前山忽湧月，始覺所見高。", "頎然有遠孫，載酒江湖敖。", "胸中湛水鏡，邂逅得所遭。", "古月還相照，了不隔秋毫。", "但憐露草濕，時復暮蟲號。"]'),
('98030777-60a4-4416-8708-91a247d23b1e','送唐同知','牟巘','宋','宋诗','song-poetry','','[]','平生一寸心，神遊夢華錄。',156,'全唐诗/poet.song.233000.json','["平生一寸心，神遊夢華錄。", "喜君晚相遇，風景宛在目。", "肯爲此邦來，大是渠儂福。", "我但飲若水，生意已俱復。", "軋軋寒女手，何事嗟空軸。", "欲去復停車，爲爾兩眉蹙。", "猶是前叔度，五袴回餘燠。", "千家萬家喜，吾意始云足。", "路穩驅車去，祖帳紛相屬。", "賀下不賀上，此語傳古俗。", "况携善頌歸，親舍喜可掬。", "炰羔傾家釀，歡聲動鄰曲。", "麾節願早還，春風棠樹綠。"]'),
('c6b5ab91-385e-4948-b71a-9cb58898dd7d','適安齋','牟巘','宋','宋诗','song-poetry','','[]','天圓如旋磨，萬古幾曾息。',240,'全唐诗/poet.song.233000.json','["天圓如旋磨，萬古幾曾息。", "日轂環之走，西墜俄東出。", "聖賢法天運，所以長汲汲。", "大禹生胼胝，孔弗遑煖席。", "客寢何太康，人或規不及。", "亦有功名者，齋內運甓百。", "不放身暫閒，苦欲勞筋骨。", "如何適安齋，燕處甘暇佚。", "此齋匪侈麗，易安取容膝。", "竹几對藜牀，左右置書冊。", "有時值佳友，從容遂竟日。", "體適任屈伸，意適任語默。", "惟其適之安，適且忘吾適。", "向來孤山老，保此踰耄耋。", "以安遺子孫，此計固已得。", "人生天地間，何事非吾職。", "夜思晝所爲，然後安可即。", "况君抱修能，當念踵前業。", "相期在萬里，無從守一室。", "精義以致用，龍蛇豈其蟄。"]'),
('0a4bf642-10f3-4c73-b0e1-cc32c7f41493','次韻程晉輔','牟巘','宋','宋诗','song-poetry','','[]','一宿蘧廬托，百事弁髦棄。',288,'全唐诗/poet.song.233000.json','["一宿蘧廬托，百事弁髦棄。", "平生意何如，猶動沾沾喜。", "我喜在丘壑，富貴非所睨。", "况子好山居，泉甘野芳媚。", "鹿門時上冢，了不慕城市。", "或嫌人村遠，知一未知二。", "試看近市者，事奪紛夢寐。", "正墮膠網中，輾轉悞身世。", "舉手謝逋客，士固各有志。", "結習奈已深，坐上漫同異。", "山空陰綠凈，長日惟宜睡。", "夜半呼僮奴，發火燃枯蒂。", "滿紙詩已成，文采一何麗。", "墨池漲玄雲，晴窗藹微霨。", "自子來此山，與山相昆弟。", "又將三昧手，於焉小游戲。", "向來蜀之日，往往召狺吠。", "逌爾付一噱，千載息攘袂。", "變滅今安在，但有山繞翠。", "可憐七十翁，嬉遨尚童稚。", "坐聞酒如川，留客爛漫醉。", "亦思翩然去，芒屩踏初霽。", "就林煨短茁，带泥落花蘂。", "清絕恐無分，得已吾欲已。"]'),
('1d217a62-a587-4f80-87ac-2997835fcf33','仲實示中秋詩甚恨不同此樂用韻一笑病中殊無思也','牟巘','宋','宋诗','song-poetry','','[]','誰其持冰炭，晨夕闖我庭。',192,'全唐诗/poet.song.233000.json','["誰其持冰炭，晨夕闖我庭。", "遥哉水帝后，乃有此寧馨。", "不受百藥鎸，奈何頑且冥。", "是時八月半，無雲天正清。", "居然作災怪，流汗如翻瓶。", "捕逐出八荒，弱步愁□□。", "而子方寘酒，賓主更醉醒。", "作詩調明月，顧兔下乞靈。", "飲量聞小減，猶能吸南溟。", "客疾掃已空，蕩蕩白雲扃。", "何必傚淵明，苦問神影形。", "吾生七望八，朏朒知幾經。", "不樂復奚爲，羨子鬢未星。", "何時定一來，眼中見鸞停。", "軟語到夜闌，發火烹中泠。", "誦子新詩篇，我亦能靜聽。"]'),
('8fccc785-b8b6-4013-8467-ed26ee3f73c3','同賦開元宮避暑詩','牟巘','宋','宋诗','song-poetry','','[]','避暑如避虎，山林每逢旃。',168,'全唐诗/poet.song.233000.json','["避暑如避虎，山林每逢旃。", "誰知浩穰內，自有清靜緣。", "同來戴牟張，作計良亦賢。", "是時正流汗，赤日行中天。", "勞坐苦役役，何異烹炰煎。", "居然得勝地，神觀爲爽然。", "凉飆起珍簟，妙香汎瓊篇。", "坐客易生感，泉隠獨談玄。", "靜者躁之君，方寸湛其淵。", "勿謂火勝月，此意諒默傳。", "我戶隔珠庭，遥企玉真仙。", "仙遊雖云邈，肯逐大化遷。", "曲池况未平，中多蒲與蓮。", "更有離離者，使我增愁涓。"]'),
('bf9a675c-c973-480d-a816-33e866f19450','次韻仲實秋夜','牟巘','宋','宋诗','song-poetry','','[]','空庭兩犀株，吹香滿前軒。',132,'全唐诗/poet.song.233000.json','["空庭兩犀株，吹香滿前軒。", "頗疑顧虎頭，幻此金粟繁。", "或是乘鸞女，月窟分天根。", "更與瀉浩露，盡洗蜂蝶喧。", "苦無好事者，爲我載一尊。", "而我子張子，古誼夙所敦。", "肯將新詩句，到我羅雀門。", "何殊小山賦，欲招楚客魂。", "犀首纍佩印，陋矣不足論。", "老我罕出戶，東牆甘曝暄。", "應同花下醉，式副我願言。"]'),
('c41aea8f-8d01-4148-9b08-a7939ad2fbed','送家自昭長慈湖','牟巘','宋','宋诗','song-poetry','','[]','眉山鍾神秀，翁季天下偉。',276,'全唐诗/poet.song.233000.json','["眉山鍾神秀，翁季天下偉。", "直到仲虎輩，奕奕殊未已。", "家爲文章家，百年兼兩侍。", "存翁名侍從，頤山古膚使。", "秘書性具存，文脈益演迤。", "前除羅玉樹，乃復有令子。", "超趨夐不群，老氣壓紈綺。", "早歲瑟僴篇，短檠午夜几。", "要渠紹編剗，教示正勤止。", "家寶未輕出，吾儕方側耳。", "一朝著斑衣，束書事行李。", "堂上白髮翁，爲爾顔色喜。", "濤江日日靜，酒酣可以起。", "慈湖在何許，精廬屹其沚。", "我欲鼓枻游，浩渺曷涯涘。", "長風駕高浪，瞥忽可千里。", "如此寧不超，踔厲前無比。", "須知歸宿處，其道元甚邇。", "鯉庭尊所聞，固自有源委。", "願毋厭凡近，讀書愈窮理。", "修程與遠業，亦從今日始。", "合沓來衆譽，烜赫繼世美。", "持以貽家尊，良足當甘旨。"]'),
('3955224b-0887-44e9-a99d-f3d65473f737','贈陳一齋','牟巘','宋','宋诗','song-poetry','','[]','謝公文物郡，山川如錯綉。',288,'全唐诗/poet.song.233000.json','["謝公文物郡，山川如錯綉。", "轉眼成蕭瑟，富覽寧復有。", "自我識君子，再挹中嶼秀。", "卓犖妙言語，經術更兼茂。", "早歲六典書，嘐嘐發孤咮。", "春官失分寸，苦不入吾彀。", "天意將有待，本郡煩客授。", "鄉人弟子行，月旦師友舊。", "朝隨貢篚入，莫處儒席右。", "固知致遠業，當時無近售。", "多士皆景附，三道共輻輳。", "而我初何心，高下隨所就。", "澹然守吾一，擁書坐清晝。", "交帚謝俗物，冰雪凜懷袖。", "獨於吾輩人，倒屐惟恐後。", "誰云一縫掖，不如雁門守。", "好賢篤緇衣，同心藹蘭臭。", "况乃諸老翁，夜艾耿殘宿。", "殷勤見尊禮，能使風俗厚。", "頗憐世議隘，或用儒爲詬。", "元氣須愛護，大體必爭捄。", "誦言百僚上，大作萬間覆。", "君當自此升，儒藴獲盡究。", "是爲斯文福，豈弟神明祐。"]'),
('43cc7d1b-c6a4-49ba-8c3c-88fd570a24c9','送王仲明長明道','牟巘','宋','宋诗','song-poetry','','[]','君本鄴中士，行向建業去。',48,'全唐诗/poet.song.233000.json','["君本鄴中士，行向建業去。", "故都多感慨，盡在登臨處。", "乃心所師仰，當年上元簿。", "閉門玩微言，春風會歸趣。"]'),
('1a1137e1-6acc-458a-8dfa-f88e30f39d21','和馬侯游何山','牟巘','宋','宋诗','song-poetry','','[]','自還吳興居，頭童而齒豁。',240,'全唐诗/poet.song.233000.json','["自還吳興居，頭童而齒豁。", "信意時出教，所覽深以廓。", "何山在何許，細路穿木末。", "躋攀不憚勞，歷歷見郛郭。", "晴嵐堆紫翠，正在吾屋角。", "世事苦坌並，我但專一壑。", "嗟彼競利者，爲計自各各。", "緬懷安定公，雅合居臺閣。", "平生惟自道，未有輕造脚。", "朅從海陵來，姑蘇亦暫泊。", "湖學得公重，學子有攸託。", "南園慶曆間，六老曾會酌。", "當年馬太守，高誼誰能若。", "直卿爲之記，文字誠磊落。", "厥今同姓侯，胸次有活著。", "長篇俄寫就，傳寫腕欲脫。", "昨聞上湖墳，寒色正錯莫。", "樵木不爲禁，宰樹歎濯濯。", "新祠已卜龜，華表佇立鶴。", "神游倘來下，曠達離塵縛。"]'),
('b1afa091-088e-4882-9506-2ca3dcfb1e27','送呂錫入閩省覲','牟巘','宋','宋诗','song-poetry','','[]','吾友鄧善之，從游多佳士。',168,'全唐诗/poet.song.233000.json','["吾友鄧善之，從游多佳士。", "其間最妙齡，英英有呂子。", "虛中風寒處，子獨鍾秀美。", "憶昨初過我，丰度如冰峙。", "不肯逐利名，惟耽玩文史。", "閉門肆探討，往往窮日晷。", "刻意逗幽深，飛辨摘譌記。", "我欲濬其源，融液會衆理。", "何事遽索去，明發事行李。", "八詠須恣游，三山亦甚邃。", "人生著綵衣，侍官真樂只。", "行當拜家慶，親顔爲渠喜。", "非復舊阿蒙，有子能如此。", "便可置膝下，家室勿輕視。"]'),
('8a80db6c-3c30-4f2e-8795-b91f32e8d1ee','聚星堂','牟巘','宋','宋诗','song-poetry','','[]','建武重名節，狂奴態猶故。',228,'全唐诗/poet.song.233000.json','["建武重名節，狂奴態猶故。", "客星復何事，一夕感乾度。", "風聲激末造，駢首死黨錮。", "而五百里內，乃有賢人聚。", "行行望德星，高陽里中去。", "德隆則星晷，時網不足與。", "元氣之所全，政在簪盍處。", "乃知忠賢類，天每下其顧。", "二老甘隠淪，四海起尊慕。", "有如子孫行，已是廊廟具。", "深期任世道，相期扶國步。", "皇路方險巖，傾輈當急赴。", "赤手徒捧塊，詎障奔流怒。", "濡迹本捄時，其忍諉諸數。", "事蓋有至難，竟乖天所付。", "汝南榜堂皇，考亭繪縑素。", "室有聚星事，四遠競傳布。", "老眼苦昏暗，見畫如隔霧。", "卷還坐太息，冰炭擾百慮。"]'),
('8707c548-93fb-4501-b560-3edbc27b4f56','史彥明致樂堂','牟巘','宋','宋诗','song-poetry','','[]','高堂有壽母，黄髮映兒齒。',192,'全唐诗/poet.song.233000.json','["高堂有壽母，黄髮映兒齒。", "天方畀修齡，康寧燕多祉。", "怡然人子心，何物堪倫比。", "和氣爲愉色，皆自深愛始。", "郁穆涵春風，融怡妙天理。", "此是謂至樂，樂則焉可已。", "再拜爲獻言，忠養極娛侍。", "隨時換輕煖，每侍進修瀡。", "初非假外內，至樂皆在此。", "况能以志養，先意而承旨。", "魽鮓故自珍，歡不如菽水。", "有時平反歸，兒喜親亦喜。", "吾以名吾堂，致樂義最美。", "試看紀孝行，昔曾今日史。", "會有邦人士，升堂奉醇醴。", "俾爾登期頤，俾爾宜孫子。"]'),
('62f2b351-15c7-4f7d-a373-03e2fbcc090c','次史德載韻示諸孫','牟巘','宋','宋诗','song-poetry','','[]','我家無絳帳，貧賤人所棄。',288,'全唐诗/poet.song.233000.json','["我家無絳帳，貧賤人所棄。", "忽聞唔咿聲，老懷倍歡喜。", "比鄰亦驚怪，捩眼不敢睨。", "先生史魚直，自謂骨不媚。", "珠玉在短褐，深藏未輕市。", "而况門閥高，指不屈第二。", "肯應童蒙求，爲爾覺昏昧。", "袖中一卷書，傳之自名世。", "爾幸近得師，盍勉從學志。", "人品分中下，教法初無異。", "采芑復采芑，我田自新美。", "那似斥鹵濱，彌望荒白葦。", "短園圍敗屋，不見花藥麗。", "頼此小窗明，晴光開霮䨴。", "日長書好讀，所講先孝悌。", "泥牛共土狗，勿復事嬉戲。", "後池蒲稗深，竟日群蛤吠。", "也勿向池邊，照影如孔翠。", "低頭勤筆硯，翻墨滿裾袂。", "男兒十四五，年紀非幼穉。", "不妨笑阿翁，憒憒長如醉。", "先生有雪霜，嚴威不汝霽。", "今朝發長吟，閉門苦覓句。", "老年謝丸藥，殆似陳無己。"]'),
('0a3f483b-1a21-4eb3-aa62-a9bfb1200134','侍輅院叔過山廬意行甚適夜過半乃知醉卧山中而親友或去或留因借淵明時運暮春篇一笑  其一','牟巘','宋','宋诗','song-poetry','','[]','宿戒親友，蓐食詰朝。',160,'全唐诗/poet.song.233000.json','["宿戒親友，蓐食詰朝。", "携幼偕往，歷覽江郊。", "鳴吭在谷，時雲在霄。", "灼灼桃華，青青麥苗。", "且行且扶，且憩且濯。", "橋有危躡，湖有遐矚。", "古人惜春，常苦不足。", "又一月多，何如其樂。", "狷者隠淪，狂者詠沂。", "千載彭澤，異致同歸。", "匪怨匪荒，天趣發揮。", "大阮靜淵，心慕以追。", "暑嬉我林，夕偃我廬。", "或醉或逃，聽客所如。", "林墮片月，室耿殘壺。", "一笑成詩，良非起予。"]'),
('8108f55b-496e-4ac6-9792-1d261d4747cc','侍輅院叔過山廬意行甚適夜過半乃知醉卧山中而親友或去或留因借淵明時運暮春篇一笑  其二','牟巘','宋','宋诗','song-poetry','','[]','摩肩趨利，市門之朝。',160,'全唐诗/poet.song.233000.json','["摩肩趨利，市門之朝。", "夷然抱關，市也亦郊。", "一念靜躁，懸隔壤霄。", "旱火禾焚，實焮我苗。", "飲冰內熱，其何能濯。", "大播瞇昧，近或弗矚。", "我有至境，反觀內足。", "寂寞寬閒，自得其樂。", "茫茫禹跡，海岱淮沂。", "遊子倦矣，故鄉如歸。", "牛羊在野，舉肱一揮。", "既入其苙，夫又何追。", "八荒我闥，天地我廬。", "六鑿何有，一席晏如。", "西風籬落，剝棗斷壺。", "靜以觀復，閉戶者予。"]'),
('0a7adf3e-6606-4782-9494-f12b164bf377','長江圖','牟巘','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','漢川影落鸚鵡洲，金山鐘到多景樓。',112,'全唐诗/poet.song.233000.json','["漢川影落鸚鵡洲，金山鐘到多景樓。", "老龍幾載卧寒碧，中間不斷萬古流。", "晚來雪浪大如屋，澎湃舞我一葉舟。", "舟移岸轉知何處，離離烟草令人愁。", "說與渠儂莫倚柁，轉帆別浦盍少休。", "此圖此景俱可惜，展玩不足空白頭。", "家在江水發源處，何時還我舊菟裘。"]'),
('eadece67-86ec-461d-b716-61480869e71a','山水圖','牟巘','宋','宋诗','song-poetry','','[]','凝塵不去鼠行几，劃見巨然與千里。',144,'全唐诗/poet.song.233000.json','["凝塵不去鼠行几，劃見巨然與千里。", "修眉拂略遠意開，碎點孤烟樹如薺。", "髯龍鬰鬰新翠摇，我覺鄭公殊嫵媚。", "懸知自是棟梁具，歲晚霜雪須飽試。", "舊聞北岳鍾沍寒，長松造天冰裂地。", "蒼皮玉骨不受凍，礧砢千丈世絕擬。", "誰能爲我試貌取，奇姿偉狀來眼底。", "張君平生飫所見，雅復愛此秀而美。", "雖然莫作差池觀，老壯險夷同一致。"]'),
('74a3373f-554f-493a-b8ea-e123a5663110','鳳凰山澗石圖','牟巘','宋','宋诗','song-poetry','','[]','南湖山人小戲劇，夜半鈞天聞拊擊。',192,'全唐诗/poet.song.233000.json','["南湖山人小戲劇，夜半鈞天聞拊擊。", "音節疏宕鳳起舞，至今筍簴遺樅業。", "君來訪古用此時，地老天荒何處覓。", "矻矻渡盡澗與岡，确犖徑微予趾棘。", "重華忽已三千載，鳳鳥一去無消息。", "石兮石兮奈爾何，搔首湖滣徒佇立。", "群仙拍手相勞苦，但知簸空吸寒碧。", "殷勤問翁今何如，方瞳炯炯映丹頰。", "頗記三生石上無，讀書雙趺雨苔澀。", "歸來舉似翁一笑，飛鴻踏雪那可憶。", "子其爲我謝群仙，不妨天遊復八極。", "袖中行記真畫圖，留向人間作奇特。"]'),
('0f563acd-ff5e-436f-928c-9930c5245e81','題洪崖先生出市圖','牟巘','宋','宋诗','song-poetry','','[]','洪崖先生住何許，支離擁腫之爲伍。',160,'全唐诗/poet.song.233000.json','["洪崖先生住何許，支離擁腫之爲伍。", "蕭然行李偶出市，束書瓢劍略可數。", "自謂生在三皇前，野鹿標枝何太古。", "當時但以結繩治，書中正復作何語。", "輿馬絡頭亦復來，雪精胡爲馽紲具。", "只呼張老無不可，面謾三郎直戲侮。", "承平無事相娛嬉，力追遐風來湛露。", "一朝恍惚思草昧，此意似已厭繁膴。", "千村萬落荆杞生，宛是洪荒一風土。", "袖中紙馿不吃草，拍手還向洪崖去。"]'),
('dbfffb5f-851f-4f02-b47c-9c504507a6d4','王維畫孟浩然騎馿圖','牟巘','宋','宋诗','song-poetry','','[]','窮浩然，老摩詰，平生交情兩莫逆。',192,'全唐诗/poet.song.233000.json','["窮浩然，老摩詰，平生交情兩莫逆。", "也曾携去宿禁中，堪笑詩人命奇薄。", "只應寂莫歸舊廬，此翁殷勤殊未足。", "作詩借問襄陽老，詩中猶苦憶孟六。", "悠悠江漢經幾秋，一夕神交如在目。", "分明寫出騎馿圖，丰度散朗貌清淑。", "更有個倜一片心，不是相知那得貌。", "行行復行向何許，酸風吹馿耳卓朔。", "向來十上困旅塵，馿饑拒地愁向洛。", "不如乘輿且田園，萬山亭前大隄曲。", "鯾魚正肥甘蔗美，雞黍可具楊梅熟。", "一樽相與壽先生，醉歸勿遣馿失脚。"]'),
('cec41cd4-0bc6-4c0a-94eb-380c00be078b','和王寅甫御史遊南山韻','牟巘','宋','宋诗','song-poetry','','[]','平生愛山苦趼足，况此對面美冠玉。',384,'全唐诗/poet.song.233000.json','["平生愛山苦趼足，况此對面美冠玉。", "也曾杖屨極躋攀，稍度灣碕轉虛曲。", "徑踏青螭脊上行，所歷漸高山漸束。", "紅亭白塔出湖外，下瞰諸峰等臣僕。", "祖禪晏坐服生獰，法席宏開儼清肅。", "何人梵唄呼僧定，劃然透戶如擊筑。", "浮嵐暖翠忽紛披，依依精舍傍修竹。", "至今猶作咿唔聲，飽食頗慚空洞腹。", "崎嶇竟日亦已勞，應接滿前端爲目。", "道人對境了無羨，折脚鐺中煨脫粟。", "小立爲爾起深悟，願事掃除甘播掬。", "崢嶸歲月苦難記，三寸穉杉俄立鵠。", "山中老宿亦向盡，訪舊無人空感觸。", "細評道人似豪家，臺殿耽耽枕岩谷。", "當時氣象雄一方，誰教劫火燒糜竺。", "十年舊觀未全還，金錢奔走傾緇俗。", "何山試問何所有，一溪清泠嗽寒綠。", "入門使我意也消，不省人間有華辱。", "殆是高人勝士徒，山靈笑許茲論篤。", "曠蕩幽深兩俱勝，胡不重游勇奔鹿。", "多病歡娛久去心，良辰美景寧相屬。", "昏昏午窗供坐凉，跳丸西走白日速。", "夜來可奈風雨盡，盡力催花亦良酷。", "痛殺新紅三萬片，園林慘澹餘老木。"]'),
('dcd62886-892f-403f-9c9f-9705e1111ebd','送陳正德教諭常熟','牟巘','宋','宋诗','song-poetry','','[]','此邦自是高陽里，陳太丘家好孫子。',208,'全唐诗/poet.song.233000.json','["此邦自是高陽里，陳太丘家好孫子。", "十年閉戶養雋聲，我先子後一時起。", "前時送兄今送弟，綵衣拜親親爲喜。", "人言昆令而季强，羨君清標如玉峙。", "善和尚有千卷書，一一窮探親夜几。", "新詩那更翻手成，便當拾芥取青紫。", "小營甘旨束書去，且煩私淑青衿士。", "天公應念友于情，任國相望纔尺咫。", "蘇州明白照兩縣，正好高吟清影裏。", "吳江定作對牀留，笑隔垂虹膾鮮鯉。", "托好我已三世深，待老敢當二生侍。", "蕭蕭風雨起送客，萬里飛鴻看雙眥。", "端明老子舊家聲，一舉先鞭從此始。"]'),
('b7f5d94c-8011-41ab-a996-6d48bdad941b','楊求仁路教遊何道山之明日余始自洞庭歸恨不與雋遊漫趁韻一笑','牟巘','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','君能匝臘過苕水，我正絕湖尋橘里。',224,'全唐诗/poet.song.233000.json','["君能匝臘過苕水，我正絕湖尋橘里。", "人生有數會不免，先後差池數日耳。", "天教新年暫相見，握手如獲丹與砥。", "略似德公上冢回，徑入就談傾底裏。", "如聞前月清興發，杖藜曉對南山起。", "蒼官掀髯自虹舉，清流照影時鵠峙。", "我歸已晚不得陪，脚中平生信有鬼。", "獨留詩卷使我和，思枯預怕搜脂髓。", "小溪深處是何山，藏機一句無多子。", "當時言下誰領會，只認泉石爲對履。", "至今遺跡記東坡，遂使此山同畏壘。", "擬議固已輸一籌，躋攀銳欲窮寸晷。", "真境不樂有無間，更使高人爲標指。", "先生醉歸方熟睡，凍蠅一任鑽故紙。"]'),
('8d2cc09f-7448-44f1-9536-5eed3bd5d2a0','和顧伯玉陳朝檜','牟巘','宋','宋诗','song-poetry','','[]','長城大雄古剎裏，一庭老枿質已死。',160,'全唐诗/poet.song.233000.json','["長城大雄古剎裏，一庭老枿質已死。", "依約僅見左紐紋，垂柯布葉乃如此。", "相傳云是陳朝檜，欲論往事皆死鬼。", "冰懸雪跨黄塵盡，何煩皂莢相料理。", "只應孤根鐵石堅，不怕如壺之赤螘。", "四旁那復有生意，生意却從中心起。", "陳氏機淺根枝弱，雖有子孫何足倚。", "崢嶸霸業隨手壞，五傳不堪重屈指。", "君語居然多硬語，千載興亡雜悲喜。", "隋唐而來尤可感，區區未數錢與李。"]'),
('729354f6-2ac2-4ee6-a186-3a4adad25ec7','寄閻靜齋徐容齋二學士','牟巘','宋','宋诗','song-poetry','','[]','斯人宗工國司命，容齋有容靜齋靜。',176,'全唐诗/poet.song.233000.json','["斯人宗工國司命，容齋有容靜齋靜。", "海涵岳峙俱偉人，心同道同不同姓。", "向來先後持玉節，共仰福星在吳分。", "一公歸領集仙班，一公繼登六鼇禁。", "大名本是宰相職，高搴書帷地步峻。", "導密亦是翰林長，快埽槐廳消息緊。", "天教兩翁轉鴻鈞，赤子到頭合蘇醒。", "東南秀士頗不乏，當年著意極搜引。", "而今造化况在手，想見姓名猶見省。", "石生已起有溫生，我愛莫助德怲怲。", "苦爲百草憂春雨，坐待風霜發苕穎。"]'),
('a30d729b-859f-455d-a716-9b163704f845','善之入霅蘭皋置酒小詩紀坐中事','牟巘','宋','宋诗','song-poetry','','[]','病翁禁酒仍禁脚，不省人間有行樂。',160,'全唐诗/poet.song.233000.json','["病翁禁酒仍禁脚，不省人間有行樂。", "主人善最客善之，邀我來同雞黍約。", "清樽快吸船落琭，頗悔從前謝杯酌。", "故人久別如此酒，一時傾倒慰離索。", "更擘新笋供春淘，狐泉槐葉未須學。", "殷勤入鼎煮過熟，老饕恣吞不勞嚼。", "人生難得是合併，開口一笑良不惡。", "呼車載我雨中歸，阿香推車散飛雹。", "分明戒我輕破戒，故把春衫都濕却。", "我亦投牀作雷吼，無數殘紅枕邊落。"]'),
('c8ffe22e-31af-413a-8bd3-2ef27414c00e','倒撐魚船上灘圖','牟巘','宋','宋诗','song-poetry','','[]','倒撐魚船逆上溪，六鷁過宋風退飛。',48,'全唐诗/poet.song.233000.json','["倒撐魚船逆上溪，六鷁過宋風退飛。", "呂梁懸瀑行越之，灧澦如象人西歸。", "一笑恬視險與夷，同波委順未必非。"]'),
('a2f9b019-8d0c-4b50-9b6b-2d1cc073b170','趙石心詩','牟巘','宋','宋诗','song-poetry','','[]','試問吳兒歌小海，何如廣平賦梅花。',82,'全唐诗/poet.song.233000.json','["試問吳兒歌小海，何如廣平賦梅花。", "一片石心元不死，平生不落徐庾家。", "趙子陳陳有胸府，雲根半夜生槎芽。", "有時盤空吐硬語，更覺世上浮且夸。", "誰能爲爇青藜杖，苔莓荒盡天祿與辟邪。"]'),
('ddc41efe-f3ad-4562-bd60-49a55a168236','贈劉心月','牟巘','宋','宋诗','song-poetry','','[]','心月還將眼爲月，秋空表裏俱澄澈。',64,'全唐诗/poet.song.233000.json','["心月還將眼爲月，秋空表裏俱澄澈。", "閲盡世間媸與妍，分明無處藏毫髮。", "我方回向心地初，含光自照非外諜。", "平生最喜阮嗣宗，臧否兩字何曾說。"]'),
('9ddbdbe2-83d4-4962-b85f-44e12c86ce1a','送陳正德長慈湖','牟巘','宋','宋诗','song-poetry','','[]','本齋之孫盛詞華，下視流輩十倍過。',208,'全唐诗/poet.song.233000.json','["本齋之孫盛詞華，下視流輩十倍過。", "家書雖散尚千卷，其奈儲無儋石何。", "二昆研席相與共，勘辨不遣毫髮訛。", "一朝束書慈湖去，慈湖之學自象梭。", "人之高明騖高遠，不由梯級陡上坡。", "而其下者保固陋，終歲無路登嵯峩。", "萬形惟實乃無弊，此道自古傳思軻。", "慈湖論心論無我，真意初不煩鎸磨。", "虛明一語更超絕，不肯與人同其波。", "却笑禪宗用心錯，我每讀此毋麾哦。", "微言日絕諸老盡，獨抱永感如宿疴。", "君家詩友講貫熟，持之以注豈在他。", "我耕我穫粒我腹，而彼徒夢笠與蓑。"]'),
('94d226c1-42aa-42a7-b217-7f77944930ed','題喊泉亭','牟巘','宋','宋诗','song-poetry','','[]','大龍小龍天下絕，水簾高掛三千尺。',256,'全唐诗/poet.song.233000.json','["大龍小龍天下絕，水簾高掛三千尺。", "呂梁懸水那復言，便應壓倒棲賢峽。", "我來覓水洗雙眵，怪底老崖枯欲裂。", "龍公何處抱寶眠，閟蓄精枯未渠泄。", "誰知水火本無根，重陰可以陽氣徹。", "倚空長嘯山爲開，以虛爲感感尤烈。", "千山屭贔方沍寒，鍾乳淙流忽飛發。", "珠璣噴薄雜霏霧，瓊瑶傾瀉濺白日。", "若非捲取銀河水，那得變幻在呼吸。", "看泉須看無泉時，自無而有乃奇特。", "龍公作事真狡獪，吾儕用意亦奇崛。", "經營小立看未了，洞門忽已雲霏濕。", "龍公龍公可以止，何如翻手作飛雪。", "便將豐年報明主，蒼生赤子俱函活。", "火雲六月汗如漿，更爲渠儂洗炎熱。", "一笑回首謝龍公，神用俱停天地寂。"]'),
('500c0d8a-ea1a-405f-8fc4-f4b58a560ee2','再和楊求仁何道二山韻','牟巘','宋','宋诗','song-poetry','','[]','雪堂西席雪江水，廣文先生是鄉里。',224,'全唐诗/poet.song.233000.json','["雪堂西席雪江水，廣文先生是鄉里。", "此翁平生事崛奇，欲上虛空鞭騄耳。", "邇來深藏老鋒鍔，未許容易試越砥。", "插天光氣尚歷歷，若爲著渠岩石裏。", "仲華本願郡文學，百年功名一日起。", "崢嶸今不少自貶，吾道毋乃太孤峙。", "苦將新句調山靈，不遣陳迹蹋死鬼。", "世俗貴耳不貴目，誰得其皮兼得髓。", "翰林主人墨客卿，會將此事全付子。", "吾衰正復何所用，兩錢之錐漫苴履。", "固知梅老難抵當，夜半偏師來研壘。", "襆硯囊筆俱堅坐，爾以不戰淹客晷。", "天地凍合萬木僵，軍中頗怪多墮指。", "春風呼酒爲解嚴，十部從事賢一紙。"]'),
('bc9f0ef5-fba1-42fa-b8b8-da24046bd085','和孟能靜總管西莊閒居九日見招','牟巘','宋','宋诗','song-poetry','','[]','風物居然好，亭池穩處安。',120,'全唐诗/poet.song.233000.json','["風物居然好，亭池穩處安。", "上饒初奏最，西墅且追歡。", "朗誦詩千首，高眠日幾竿。", "放懷聞孟浩，乘興過蘇端。", "近局人人喜，閒居事事寬。", "扶筇差可强，投社亦非難。", "歲月期鮐背，功名付鼠肝。", "相將斟壽斚，一笑拂塵冠。", "紅蕾春猶小，黄花晚更寒。", "摩挲話銅狄，惟許鶴來觀。"]'),
('acf16dd4-a49d-4323-a1e7-f77301806a07','張彥清學士以使事來杭訪問忠烈王子孫蓋其先皆自保定原系實同乃合二譜聚族謁廟敘拜厥誼甚古仲實賦詩以紀錄寄山中輒和之','牟巘','宋','宋诗','song-poetry','','[]','有偉秦咸望，厥初保定人。',240,'全唐诗/poet.song.233000.json','["有偉秦咸望，厥初保定人。", "風雲際興運，茅土褒勳臣。", "端自積餘慶，非徒榮一身。", "聞孫藹令譽，抗志矯秋旻。", "嗜學今該古，問安昏復晨。", "金方感義氣，內譜存宗親。", "膚使光華盛，輶軒采訪頻。", "乃知清廟器，俱是崑山珍。", "分派既同出，馳聲尤絕倫。", "仙班重典領，宥府久彌綸。", "揭節方宣化，揮毫看爽神。", "應嗟遠俗薄，欲挽古風淳。", "鉅族同三眷，高情隘八垠。", "焚香肅遺像，序拜欣嘉辰。", "頗屈彥清貴，寧嫌仲實貧。", "綿延百年緒，翕合一家春。", "樂只飲此酒，勤哉書爾紳。", "尋盟諒愈篤，踏道毋胥淪。", "暫別山河阻，終期事業新。", "相從萬里去，伐鼓起通津。"]'),
('563bcd0f-5d27-4e88-9cd3-9c55d9677717','和梅君遇退閒','牟巘','宋','宋诗','song-poetry','','[]','鞅掌徒勞耳，人皆羨子閒。',48,'全唐诗/poet.song.233000.json','["鞅掌徒勞耳，人皆羨子閒。", "惟甘寄市隠，勿苦憶家山。", "街鼓晨眠穩，丹田夜氣還。", "蕭然無一事，意已出區寰。"]'),
('aef242c8-e2c2-4371-9e10-18865cafd7d2','贈厲白雲上人','牟巘','宋','宋诗','song-poetry','','[]','雙徑聞鐘罷，而今夜熟眠。',48,'全唐诗/poet.song.233000.json','["雙徑聞鐘罷，而今夜熟眠。", "事須紅日上，身在白雲邊。", "古貌應違俗，高吟不礙禪。", "爐頭煨芋火，相對各欣然。"]'),
('333bf280-07fe-451e-b686-0773467afc3b','群羊踏菜畦戲作','牟巘','宋','宋诗','song-poetry','','[]','活計元堪笑，毛群尚見欺。',48,'全唐诗/poet.song.233000.json','["活計元堪笑，毛群尚見欺。", "蹴蔬元匪夢，樊柳竟何裨。", "正爾敗諸葛，從何捉左慈。", "若鞭其後者，猶得養生規。"]'),
('5ba7d1ea-eca8-4edc-9912-020730dbf95b','次韻八詠樓','牟巘','宋','宋诗','song-poetry','','[]','八詠樓中景，都從筆下收。',48,'全唐诗/poet.song.233000.json','["八詠樓中景，都從筆下收。", "使君容此客，詩卷重於舟。", "我頗曾三至，君應倍四愁。", "瀟湘與章貢，千古只同流。"]'),
('5891a0b4-5995-4310-b4ef-c4486c065907','贈葉一山','牟巘','宋','宋诗','song-poetry','','[]','氣岸有如許，當年乃鶡冠。',48,'全唐诗/poet.song.233000.json','["氣岸有如許，當年乃鶡冠。", "覓官談笑易，知己古今難。", "膊聳如山瘦，心堅可歲寒。", "郎潛有顔駟，博士却儒酸。"]'),
('0386ba9d-0120-434e-a5f4-687c73520303','題詩禪方丈','牟巘','宋','宋诗','song-poetry','','[]','切忌犯正位，須教截衆流。',48,'全唐诗/poet.song.233000.json','["切忌犯正位，須教截衆流。", "聞鐘應已悟，縛律未爲遒。", "室小纔容膝，詩成自點頭。", "出門忽大笑，明月一天秋。"]'),
('b7b7cbe8-fdf5-4f36-930c-0aee711dc294','仲實踐約來訪又得韶甫方君同行數日語蟬聯甚慰五詩寄意甚高次韻爲一笑  其一','牟巘','宋','宋诗','song-poetry','','[]','重膇嫌卑濕，那堪暑雨稠。',48,'全唐诗/poet.song.233000.json','["重膇嫌卑濕，那堪暑雨稠。", "拋書事藥裹，敧枕聽溪流。", "何用攄孤憤，惟宜號四休。", "誰能訪生死，天際有來舟。"]'),
('e33370d4-49c4-4857-a508-3f82bd6564e3','仲實踐約來訪又得韶甫方君同行數日語蟬聯甚慰五詩寄意甚高次韻爲一笑  其二','牟巘','宋','宋诗','song-poetry','','[]','江河去不息，金石仰而觀。',48,'全唐诗/poet.song.233000.json','["江河去不息，金石仰而觀。", "但未隨流轉，安能制汗漫。", "親情人所重，友誼古尤難。", "二士俱來意，遥知可歲寒。"]'),
('13403f7c-bf50-4457-9719-a54496315cb1','仲實踐約來訪又得韶甫方君同行數日語蟬聯甚慰五詩寄意甚高次韻爲一笑  其三','牟巘','宋','宋诗','song-poetry','','[]','紅带承顔色，青霄奮翮時。',48,'全唐诗/poet.song.233000.json','["紅带承顔色，青霄奮翮時。", "猶尋雲弁約，肯爲水亭嬉。", "快婿豈嬌客，老翁真小兒。", "五噫且勿作，舉案樂齊眉。"]'),
('2c832544-9462-43f5-b731-2f999edb98fb','仲實踐約來訪又得韶甫方君同行數日語蟬聯甚慰五詩寄意甚高次韻爲一笑  其四','牟巘','宋','宋诗','song-poetry','','[]','陽羨長腰米，儋州禿鬢翁。',48,'全唐诗/poet.song.233000.json','["陽羨長腰米，儋州禿鬢翁。", "相傳作佳話，好爲表遺忠。", "收檻溪山勝，從容詩酒中。", "南湖未歸客，歲晚倘來同。"]'),
('db208c99-5a94-41c6-bbf3-1f7bd7488379','仲實踐約來訪又得韶甫方君同行數日語蟬聯甚慰五詩寄意甚高次韻爲一笑  其五','牟巘','宋','宋诗','song-poetry','','[]','平湖好亭子，高出亂雲層。',48,'全唐诗/poet.song.233000.json','["平湖好亭子，高出亂雲層。", "一水作之字，衆山羅豆登。", "襟懷爲爾豁，杯勺尚能勝。", "却笑鑽故紙，窗中效凍蠅。"]'),
('b6932fae-8a4b-494c-88d9-24a555c25223','答術者','牟巘','宋','宋诗','song-poetry','','[]','賢關夙多士，子獨抱遺經。',48,'全唐诗/poet.song.233000.json','["賢關夙多士，子獨抱遺經。", "衣尚舊時褐，眼誰今日青。", "直須行萬里，未許赴三星。", "會友誦佳句，等閒生鶴翎。"]'),
('4d84572c-c664-4080-a027-80e22f53f387','送吳古村入越','牟巘','宋','宋诗','song-poetry','','[]','笑我甘苕隠，因君動越思。',48,'全唐诗/poet.song.233000.json','["笑我甘苕隠，因君動越思。", "綠波元可鑑，縞髮已成絲。", "共說修齋老，仍懷閲道時。", "匆匆還別去，江海入新詩。"]'),
('c59156f7-174f-4636-b7e5-cd83116d3a40','次韻寄衛山齋','牟巘','宋','宋诗','song-poetry','','[]','蜀客嗟留落，甘爲學圃遲。',48,'全唐诗/poet.song.233000.json','["蜀客嗟留落，甘爲學圃遲。", "年華空自老，心事復誰知。", "未有盍簪日，還須上冢時。", "緒餘何足論，相對但期期。"]'),
('a9012f3f-0e44-47f2-8b92-f72eeb544045','送周東甫教授餘干','牟巘','宋','宋诗','song-poetry','','[]','博士廣文館，遲君二十年。',48,'全唐诗/poet.song.233000.json','["博士廣文館，遲君二十年。", "新邦重于越，舊俗記諸賢。", "鷁首南風至，臯比右席專。", "暮年尤惜別，搔首意凄然。"]'),
('10aa5498-9da2-4901-a87e-60d255ba62de','和雨中  其一','牟巘','宋','宋诗','song-poetry','','[]','但聽四簷滴，真成萬事休。',48,'全唐诗/poet.song.233000.json','["但聽四簷滴，真成萬事休。", "空村就誰飯，高樹繫吾舟。", "那忍田翁笑，還憐木偶流。", "老人渾忘事，略記酉年秋。"]'),
('4847f445-e512-459f-b7f1-2d5fabfbc2c9','和雨中  其二','牟巘','宋','宋诗','song-poetry','','[]','薄宦亦良苦，救圬泥濺裘。',48,'全唐诗/poet.song.233000.json','["薄宦亦良苦，救圬泥濺裘。", "陳紅猶不足，太白幾曾浮。", "頼有兩詩好，聊寬一日憂。", "天公應念此，未用祝篝甌。"]'),
('c77de0c5-6d9e-4db1-9471-eb230867d557','水村圖','牟巘','宋','宋诗','song-poetry','','[]','山色濃還淡，孤村水繞之。',48,'全唐诗/poet.song.233000.json','["山色濃還淡，孤村水繞之。", "俗塵飛不到，野老住偏宜。", "碕岸疏疏柳，茅簷短短籬。", "小舟欹仄過，便是少陵詩。"]'),
('d334d33a-ee71-426e-b796-c2dd30091610','劭農日漫成','牟巘','宋','宋诗','song-poetry','','[]','白髮紅顔烏帽翁，年年從爾覓年豐。',64,'全唐诗/poet.song.233000.json','["白髮紅顔烏帽翁，年年從爾覓年豐。", "爭看漢詔來身畔，便覺豳詩在眼中。", "且喜畦秧三日雨，莫愁花信幾番風。", "我今亦是惰游者，不稼而禾愧食功。"]'),
('054bc2f0-46fa-4ad2-bf30-0f361e6aefa9','景定甲子理宗嘗以顔曾傳道配饗下問詞臣越咸淳丁卯昉以曾子子思升侑孔庭蓋推本先意也先臣所被宸筆藏之私室會軍學撤舊廟崇新閣願得摹刻其上而某固未敢也府教張君遂詩以成之後之觀者將有考於斯文謹用韻以謝  其一','牟巘','宋','宋诗','song-poetry','','[]','在昔前朝帝問頒，龍樓當日正承顔。',64,'全唐诗/poet.song.233000.json','["在昔前朝帝問頒，龍樓當日正承顔。", "曾思參侑褒崇后，堯舜相傳密勿間。", "遹駿先猷昭若日，於皇吾道重于山。", "老臣獨抱烏號痛，不及臨雍扈從班。"]'),
('08f1829b-dcdb-462d-b297-e29d10457f16','景定甲子理宗嘗以顔曾傳道配饗下問詞臣越咸淳丁卯昉以曾子子思升侑孔庭蓋推本先意也先臣所被宸筆藏之私室會軍學撤舊廟崇新閣願得摹刻其上而某固未敢也府教張君遂詩以成之後之觀者將有考於斯文謹用韻以謝  其二','牟巘','宋','宋诗','song-poetry','','[]','藻有嘉魚首自頒，師儒樂育士歡顔。',64,'全唐诗/poet.song.233000.json','["藻有嘉魚首自頒，師儒樂育士歡顔。", "宸奎恍若從天下，傑閣崇成不日間。", "要識道原觀泮水，坐令文物盛黔山。", "熙明殿下槐龍舞，便合歸陪講讀班。"]'),
('2c85e732-dd56-4a86-aa70-ecb2782661df','荷花辱於淫邪陷於老佛幾千載自托根濂溪而後始得以其中通外直者儕於道而近世魏鶴山又推本周子之意取澤陂之詩所謂碩大且儼者歸之君子焉明倫堂後新池驟著花教授遂見之詩且有取于周子香遠之句寄興遠矣因次韻','牟巘','宋','宋诗','song-poetry','','[]','道中何物不生焉，頃刻能開碧玉蓮。',64,'全唐诗/poet.song.233000.json','["道中何物不生焉，頃刻能開碧玉蓮。", "根脚好時花發越，源頭活處水漪漣。", "喚醒佛土從前夢，細繹陳詩最後篇。", "霽月光風真灑落，千年此意後誰傳。"]'),
('6f6b2f48-62c6-4288-b84b-aa69ae9d8266','和張教雨詩','牟巘','宋','宋诗','song-poetry','','[]','占雲日日問何如，物意焦卷重可吁。',64,'全唐诗/poet.song.233000.json','["占雲日日問何如，物意焦卷重可吁。", "微灑人皆憂未濟，積誠我自愧中孚。", "滂沱幸已符先兆，䆉稏行看穫上腴。", "此事相關情正切，吾儕初豈事誇諛。"]'),
('3ae9dc94-344e-4c3a-ba7e-881f3e930a39','試院和李提管韻','牟巘','宋','宋诗','song-poetry','','[]','聖世旁搜盛武宣，幾人捨耒歎胝胼。',64,'全唐诗/poet.song.233000.json','["聖世旁搜盛武宣，幾人捨耒歎胝胼。", "武成宜取二三策，稽古還誇數萬言。", "充棟此時唯恐後，著鞭他日竟誰先。", "空筌相對真堪笑，半夜魚龍已變遷。"]'),
('2eb423d4-33a3-4643-a626-0c1aabd3d945','無黨爲東岡賦遠遊余卧病空山聞而壯之和韻爲別','牟巘','宋','宋诗','song-poetry','','[]','鬢絲梅雪兩鬖鬖，底事征車又指南。',64,'全唐诗/poet.song.233000.json','["鬢絲梅雪兩鬖鬖，底事征車又指南。", "自是曾遊習蛙黽，不妨小住話魚蠶。", "摻袪中歲情良苦，秉耒平生分所甘。", "若有書來訪生死，白雲多處是吾庵。"]'),
('56e232a0-0e69-46b1-ad41-90710597f860','次韻無黨留別','牟巘','宋','宋诗','song-poetry','','[]','濤波萬木撼新秋，却笑茅廬似葉舟。',64,'全唐诗/poet.song.233000.json','["濤波萬木撼新秋，却笑茅廬似葉舟。", "我但蕭疏眠潁尾，君方矍鑠向壺頭。", "早凉已喜無殘暑，老別當須似壯遊。", "黄木扶胥最奇處，想留句子待浮洲。"]'),
('ed427ea5-c70d-4be5-b031-f073d50e786b','和劉朔齋海棠','牟巘','宋','宋诗','song-poetry','','[]','人物當今第一流，以花爲屋玉爲舟。',64,'全唐诗/poet.song.233000.json','["人物當今第一流，以花爲屋玉爲舟。", "曉妝未許褰幃看，夜醉何妨秉燭遊。", "錦里宣華思舊夢，黄州定惠起新愁。", "何如歸伴徐公飲，穩結一巢花上頭。"]'),
('863552dc-1637-4c53-891b-5cecefb775c3','和善之寄遊何道二山  其一','牟巘','宋','宋诗','song-poetry','','[]','行盡千峰日未晡，齋餘扣檻喚紅魚。',64,'全唐诗/poet.song.233000.json','["行盡千峰日未晡，齋餘扣檻喚紅魚。", "百梁扶棟神輸巧，一鐸鳴簷樂出虛。", "那得詩情陪島可，但誇山色勝衡廬。", "老禪趺坐渾無語，案上旁行幾葉書。"]'),
('22024cb2-a348-4763-b532-ccafc087389f','和善之寄遊何道二山  其二','牟巘','宋','宋诗','song-poetry','','[]','兩人相對說蠶叢，蒿穭堪嗟滿故宮。',64,'全唐诗/poet.song.233000.json','["兩人相對說蠶叢，蒿穭堪嗟滿故宮。", "忽見畫圖如雪外，不知身世此山中。", "餘生纔寓一稊米，獨往殊欣六尺篷。", "寄得詩來何處覓，南湖蒲稗沒鳬翁。"]'),
('f684cc94-09f0-4b22-bb7b-c1cc13bffd1a','送李仲賓同知','牟巘','宋','宋诗','song-poetry','','[]','一別丰儀十載間，新春再見爲開顔。',64,'全唐诗/poet.song.233000.json','["一別丰儀十載間，新春再見爲開顔。", "鷄林傳去詩如錦，龍節歸來鬢未斑。", "白日絲綸端可待，平分風月早須還。", "此行已滿英雄彀，同上烟霞紫禁班。"]'),
('b1fc01a6-60af-444b-ae2b-fb09fb2be0f8','七兒應復同客飲櫻桃園摘新歸以遺親用其詩韻識所感  其一','牟巘','宋','宋诗','song-poetry','','[]','聞汝相隨入翠微，歸時晚色已凄迷。',64,'全唐诗/poet.song.233000.json','["聞汝相隨入翠微，歸時晚色已凄迷。", "櫻桃爲喜筠籠重，燕子休嫌茅屋低。", "我老恐妨兒輩樂，新詩欲繼古人題。", "年高自覺摧頹甚，送客何嫌過虎溪。"]'),
('83287545-0860-4645-84d2-06445435d3ac','七兒應復同客飲櫻桃園摘新歸以遺親用其詩韻識所感  其二','牟巘','宋','宋诗','song-poetry','','[]','尚記當年薦寢園，百官分賜荷恩淵。',64,'全唐诗/poet.song.233000.json','["尚記當年薦寢園，百官分賜荷恩淵。", "带青絲籠空餘夢，搔白頭人苦不歡。", "詩老誇稱作崖蜜，野翁驚看瀉銀盤。", "南山見說紅千樹，鳥雀兒童任入闌。"]'),
('689b0e30-f7c9-44f9-905a-03c5a36d10e9','次韻王寅甫','牟巘','宋','宋诗','song-poetry','','[]','共惜餘春賦式微，莫教當飯失苗藜。',64,'全唐诗/poet.song.233000.json','["共惜餘春賦式微，莫教當飯失苗藜。", "行行直度南雲北，得得還尋東院西。", "白髮已應隨日長，黄鸝更與盡情啼。", "試哦小雨輕埃句，絕勝前村滑滑泥。"]'),
('597e966c-86c2-4f35-8588-e1d97df66db2','和陳無逸九日  其一','牟巘','宋','宋诗','song-poetry','','[]','揚鸞設醴奏絲桐，九日臺頭詠渚鴻。',64,'全唐诗/poet.song.233000.json','["揚鸞設醴奏絲桐，九日臺頭詠渚鴻。", "宣遠風情雖曠代，淵明霜氣直橫空。", "卧龍自命初非過，戲馬當時未足雄。", "莫笑東籬太岑寂，南山長在醉醒中。"]'),
('3b5da6d7-e32b-4f4b-84bd-c300dd77e32d','和陳無逸九日  其二','牟巘','宋','宋诗','song-poetry','','[]','萬事真成一繆悠，西風節物若爲酬。',64,'全唐诗/poet.song.233000.json','["萬事真成一繆悠，西風節物若爲酬。", "鴻饑未覺他鄉遠，菊老誰同此日愁。", "已洗眵昏看白眼，更扶衰病費丹頭。", "吟情笑我今何似，廢筧寒泉澀不流。"]'),
('09150659-3687-420e-b0e2-e926e2922f10','和張老山辭免運同','牟巘','宋','宋诗','song-poetry','','[]','曾驅海若傲波臣，底事年來苦乞身。',64,'全唐诗/poet.song.233000.json','["曾驅海若傲波臣，底事年來苦乞身。", "徑爲蓴鱸稱退掾，要將蓑笠伴玄真。", "流空素月光難掩，過雨青山老更新。", "祇恐未應閒袖手，鹽梅鼎飪正須人。"]'),
('5175c571-858b-4269-8a97-0133b86751fd','和李侯九日  其一','牟巘','宋','宋诗','song-poetry','','[]','自愧羸瓶在井湄，頗思時復一中之。',64,'全唐诗/poet.song.233000.json','["自愧羸瓶在井湄，頗思時復一中之。", "平生殊欠題餻字，今日堪憐對菊時。", "烏帽已忻新得酒，白衣誰似更携詩。", "吳興太守真三絕，爛醉輕教玉笛吹。"]'),
('b139772c-b7af-4d7c-935a-be681cdf3658','和李侯九日  其二','牟巘','宋','宋诗','song-poetry','','[]','幾回九日九江湄，杖屨從容信所之。',64,'全唐诗/poet.song.233000.json','["幾回九日九江湄，杖屨從容信所之。", "下潠遠尋觀穫處，東籬想見醉眠時。", "共陪今日吳興守，猶記當年己酉詩。", "我亦平生知所慕，飄飄衣裾任風吹。"]'),
('dac20f81-932c-4d54-8b47-14ba0576d66c','賀張老山得代','牟巘','宋','宋诗','song-poetry','','[]','富貴方來本不期，湖山徑去豈無辭。',64,'全唐诗/poet.song.233000.json','["富貴方來本不期，湖山徑去豈無辭。", "衆咻直欲齊爲語，一笑姑存鄶與譏。", "難辦求田還問舍，且教入務并尋醫。", "幡然强爲招延起，從此巖阿爛蕨薇。"]'),
('3385cf8c-fb81-4be6-9d07-2f9714f66fab','別趙子昂','牟巘','宋','宋诗','song-poetry','','[]','粉省星郎蹋曉班，暫隨使傳走日間。',64,'全唐诗/poet.song.233000.json','["粉省星郎蹋曉班，暫隨使傳走日間。", "荆州利得習鑿齒，江左今稱庾子山。", "君意頗爲蓴菜喜，人情爭羨錦衣還。", "但憐老病匆匆別，白髮如何更可刪。"]'),
('122991bc-6333-4671-a90a-77f1cec31d90','送蕭子中','牟巘','宋','宋诗','song-poetry','','[]','誠齋手摘千巖稿，詩律清森近代無。',64,'全唐诗/poet.song.233000.json','["誠齋手摘千巖稿，詩律清森近代無。", "仍世科名香未歇，諸孫文采蔚相扶。", "橫經爲喜臯比穩，覓句何妨鶴骨癯。", "會見蕭生起東海，幾年志抱一時攄。"]'),
('27cf7a25-b4c4-4390-b86d-1cf495fda05e','春雪','牟巘','宋','宋诗','song-poetry','','[]','一冬祇辨作嚴寒，剪水飛花事竟難。',64,'全唐诗/poet.song.233000.json','["一冬祇辨作嚴寒，剪水飛花事竟難。", "閉戶不知春意動，撲窗忽覺雨聲乾。", "頗聞萬事正雲集，何處一簑如畫看。", "但喜畦蔬得蘇醒，從今小摘有餘歡。"]'),
('37bab559-2a4d-404b-a4cf-2f0489d93a6d','送羅漢臣','牟巘','宋','宋诗','song-poetry','','[]','向曾平步上仙鼇，拂袖歸來氣尚豪。',64,'全唐诗/poet.song.233000.json','["向曾平步上仙鼇，拂袖歸來氣尚豪。", "自有西山堪拄笏，不妨右手且持螯。", "凌雲載酒渾如夢，泛雪回舟也自高。", "顧我餘生復何事，閉門三徑削蓬蒿。"]'),
('5eafe7b9-9c6e-4b1d-9736-4c1fc68adf64','過洞庭山書湖中所見','牟巘','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','欲談舊事恐悽然，誰遣奇觀墮我前。',64,'全唐诗/poet.song.233000.json','["欲談舊事恐悽然，誰遣奇觀墮我前。", "鶩陣萬屯湖爲黑，冰鬚千尺水皆懸。", "無多風色似天相，阿那人家疑地仙。", "更有一般堪羨處，嫩醅綠蟻醉無眠。"]'),
('ea002b1a-7890-43dc-aa92-8e56acda243d','送趙蘭皋教杭學','牟巘','宋','宋诗','song-poetry','','[]','一似彭城向潁時，重開講席整冠緌。',64,'全唐诗/poet.song.233000.json','["一似彭城向潁時，重開講席整冠緌。", "青衿喜得新師範，白髮能言舊尹釐。", "獨冷定應非熱屬，衆芳况復異凡姿。", "不妨且作回翔意，直上摶扶亦未遲。"]'),
('68977628-225b-4c3b-9990-803d9b5e94da','送种南仲主簿','牟巘','宋','宋诗','song-poetry','','[]','六客堂前翠竹屏，雙溪館下碧鱗生。',64,'全唐诗/poet.song.233000.json','["六客堂前翠竹屏，雙溪館下碧鱗生。", "遍經此老行吟處，可是常行簿領人。", "吏爲求蠶覓休假，官因祭竈請比鄰。", "也知矮屋難淹滯，且與空山作好春。"]'),
('b28dac74-1453-41d9-98c5-3e078633d8b2','題用拙齋','牟巘','宋','宋诗','song-poetry','','[]','柿林園裏伾文黨，金谷叢中石賈塵。',64,'全唐诗/poet.song.233000.json','["柿林園裏伾文黨，金谷叢中石賈塵。", "漫說愚溪誑當世，苦將巧宦目他人。", "何如杜老幽居處，一似無懷太古民。", "說道書齋名用拙，可存吾道樂吾真。"]'),
('4b9402ab-a059-4a28-8895-2ff04efaddc2','曩在長沙有遺以石山今舊物雲散此石以堅頑獨存漁莊爲賦九芙蓉之句遂以歸之目爲壺中九華致其悵望','牟巘','宋','宋诗','song-poetry','','[]','當年持餉自襄東，共載尤憐翠色濃。',64,'全唐诗/poet.song.233000.json','["當年持餉自襄東，共載尤憐翠色濃。", "莫向壺頭疑薏苡，要從華頂看芙蓉。", "諸郎自是階庭秀，此物聊堪筆硯供。", "却笑仇池無與伴，圖中悵望九奇峰。"]'),
('cf6a1a6d-38db-40c6-9591-432c9f54ad96','餞留忠齋丞相','牟巘','宋','宋诗','song-poetry','','[]','咫尺柯山路未賒，人生迎養最堪誇。',64,'全唐诗/poet.song.233000.json','["咫尺柯山路未賒，人生迎養最堪誇。", "續茶山集過吳下，看戲綵堂來永嘉。", "八袠高齡忻子舍，同鄉盛事屬公家。", "邦人莫笑門生老，日日花間望小車。"]'),
('d0b752ad-be2a-4078-82fb-3b1b3030b0c6','予與會孟同游古心先生之門死生契闊今見其十年前與仲實詩帥初記和予亦繼焉','牟巘','宋','宋诗','song-poetry','','[]','擾擾人間萬事塵，舊交無奈白頭新。',64,'全唐诗/poet.song.233000.json','["擾擾人間萬事塵，舊交無奈白頭新。", "此翁固是同門友，今日真成曠世人。", "千里賞音知絕識，九秋落木見橫陳。", "也休頻把遺篇看，說到銅人更愴神。"]'),
('d307134d-f66d-47bb-9eaf-44edc9dd2f57','和虛谷韻簡唐月心','牟巘','宋','宋诗','song-poetry','','[]','平生自分只虞毗，况是而今一槁枝。',64,'全唐诗/poet.song.233000.json','["平生自分只虞毗，况是而今一槁枝。", "江左何人譚太極，洛陽有客賦新詩。", "物情於我真疏矣，吾道非公誰與斯。", "未必梅邊柳索笑，微言好與共參之。"]'),
('27ba9250-1be4-48c7-ae0f-02d909880844','餞陳正則學錄長城','牟巘','宋','宋诗','song-poetry','','[]','本翁十載郡博士，司鐸官清亦未遲。',64,'全唐诗/poet.song.233000.json','["本翁十載郡博士，司鐸官清亦未遲。", "暫屈吳淞湖海氣，來看陳檜雪霜姿。", "近家聊喜片帆穩，遠業當爲萬里期。", "老我柴扉看岑寂，不妨時寄晝溪詩。"]'),
('d781c217-2b19-4d92-a02b-0766e87e409b','再和虛谷韻','牟巘','宋','宋诗','song-poetry','','[]','肯隨世事事夸毗，得得來尋霜雪枝。',64,'全唐诗/poet.song.233000.json','["肯隨世事事夸毗，得得來尋霜雪枝。", "苕曲新添漁隠話，陵陽別論派家詩。", "卜鄰已喜同王翰，到處猶能說項斯。", "不是晚來投社去，杖藜兀兀欲何之。"]'),
('c85be4af-5a42-42fc-b773-cfda530c7155','和梅遇二詩  其一','牟巘','宋','宋诗','song-poetry','','[]','除却壺中日月長，不知何處是真常。',64,'全唐诗/poet.song.233000.json','["除却壺中日月長，不知何處是真常。", "等閒鉛汞自生死，從古薰蕕更臭香。", "糞掃袍邊覓鍾呂，步虛曲裏換伊凉。", "何當月朗風清夜，喚出胎仙舞一場。"]'),
('99fb818d-a4c5-41dc-bd3b-51451edd6ce3','和梅遇二詩  其二','牟巘','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','行止非人所可爲，疏慵何事不違時。',64,'全唐诗/poet.song.233000.json','["行止非人所可爲，疏慵何事不違時。", "已驚夢裏雞鳴早，翻笑人間鶴到遲。", "剡曲船回空此興，洞庭飛過怕渠知。", "依然身世溪亭上，售用新添五首詩。"]'),
('51c97167-541e-4abe-ba1e-ff9e2f9d9b31','高賢孺厚齋使君之令子自番來霅訪明親舊此意甚古歲辛亥余識厚齋金陵通守之舍堂陪朔齋劉公飲海棠花下俯仰四十五年追念悽然','牟巘','宋','宋诗','song-poetry','','[]','厚德流光報必豐，當年齒穉已奇童。',64,'全唐诗/poet.song.233000.json','["厚德流光報必豐，當年齒穉已奇童。", "蘭芽秀擢孤根內，華表驚呼一夢中。", "肯向陳人論世好，絕知新句有家風。", "海棠花下看鍾蔣，說著令人念此翁。"]'),
('dd00633c-c757-4db4-9561-c7dc86e3abc4','和王梅泉黄靜齋載酒問花','牟巘','宋','宋诗','song-poetry','','[]','逃瘧形容兀似槎，誰尋獨樹老夫家。',64,'全唐诗/poet.song.233000.json','["逃瘧形容兀似槎，誰尋獨樹老夫家。", "高人早擅無雙譽，佳客爭看第一花。", "已爲義尊成酩酊，更誇信筆寫葩華。", "斑斕小草真兒戲，得借餘光亦所嘉。"]'),
('2c507c0a-268f-4432-ac2a-dbe96879d753','吾五十年間未嘗一杯自壽汝曹所知者今乃力營甘旨爲七袠慶事出創見欲深避去復不可使汝曹他日懊恨亦如吾者小詩答渠勤意丙申正月十五示諸兒','牟巘','宋','宋诗','song-poetry','','[]','七十新年未盡窮，香醪滿泛饌尤豐。',64,'全唐诗/poet.song.233000.json','["七十新年未盡窮，香醪滿泛饌尤豐。", "便同五鼎爲吾養，汝有雙親勝乃翁。", "一念自能通造物，諸孫更與振家風。", "華燈璧月今何夕，春在親情笑語中。"]'),
('0201b81d-010e-4355-8923-c0656afcf2d8','十六日謝郡官兩學及鄉里朋友','牟巘','宋','宋诗','song-poetry','','[]','七袠空餘永感情，南園養病閉柴荆。',64,'全唐诗/poet.song.233000.json','["七袠空餘永感情，南園養病閉柴荆。", "一朝破戒爲兒子，四坐合併表友情。", "地主每能容枯枿，天公特爲放新晴。", "餘年得此今多幸，白髮傾欹一醉成。"]'),
('71bdac1e-0b52-4d10-92f1-ae84f2e84615','十七日謝趙子昂孟能靜及諸親友','牟巘','宋','宋诗','song-poetry','','[]','兒將白髮共嬉娛，敢意高軒訪敝廬。',64,'全唐诗/poet.song.233000.json','["兒將白髮共嬉娛，敢意高軒訪敝廬。", "七袠年齡同絳縣，諸賢詩句過黄初。", "菌芝那解出枯朽，冠蓋便能傾里閭。", "爛醉休須問生理，貧家今有百車渠。"]'),
('1929fc30-b1fe-4856-96c5-1391e68c82ae','送楊興府','牟巘','宋','宋诗','song-poetry','','[]','細語當年別後春，驚心宇縣尚吹塵。',64,'全唐诗/poet.song.233000.json','["細語當年別後春，驚心宇縣尚吹塵。", "濁醪易貰新豐酒，衰俗難逢舊雨人。", "君似伏波當益壯，我幾南斗不能神。", "合并未幾匆匆去，魚鳥蒹葭誰與鄰。"]'),
('bef661f3-cab5-4ec8-b709-8eb6056992c4','大水後得雪  其一','牟巘','宋','宋诗','song-poetry','','[]','便涓飛灑又何佳，得得來尋貧士家。',64,'全唐诗/poet.song.233000.json','["便涓飛灑又何佳，得得來尋貧士家。", "破屋青燈纔一黍，荒園老樹忽千花。", "酒逢寒夜饒偏貴，詩出窮人矯轉誇。", "兩月兒書渾未到，定應行脚更天涯。"]'),
('c4414ade-7dbc-4102-bd28-e111d4809271','大水後得雪  其二','牟巘','宋','宋诗','song-poetry','','[]','蕭條籬落勝於村，還徑人稀早閉門。',64,'全唐诗/poet.song.233000.json','["蕭條籬落勝於村，還徑人稀早閉門。", "過眼風花纔一瞥，到頭石笋只雙蹲。", "何妨歲惡詩仍好，那笑爐空火自存。", "笑詠車斜徵雪事，諸君本本又元元。"]'),
('ead418cb-b425-4edc-991e-e06b02d67564','再和  其一','牟巘','宋','宋诗','song-poetry','','[]','饑年得雪意殊佳，天亦終憐田父家。',64,'全唐诗/poet.song.233000.json','["饑年得雪意殊佳，天亦終憐田父家。", "是處連雲畦宿麥，一時積水散空花。", "預占餠餌真堪喜，若比瓊瑶未足誇。", "我正坐須來歲麨，夜中踏甕喜無涯。"]'),
('3935a240-1c46-4917-a3a7-4f1a51c16a0f','再和  其二','牟巘','宋','宋诗','song-poetry','','[]','正思覓食繞諸村，咄咄今朝雪塞門。',64,'全唐诗/poet.song.233000.json','["正思覓食繞諸村，咄咄今朝雪塞門。", "屋角空囷饑雀噪，牀頭敗絮凍鴟蹲。", "分無醽醁能相熟，頼有符貲僅自存。", "堪笑少陵窮不死，區區苦欲問黎元。"]'),
('a6cc73dd-14ff-42b6-ab13-2b9497317c41','三用韻  其一','牟巘','宋','宋诗','song-poetry','','[]','雪中饒有百般佳，却似綢繆困約家。',64,'全唐诗/poet.song.233000.json','["雪中饒有百般佳，却似綢繆困約家。", "老病自應餘菜色，風騷猶未合梅花。", "背暄擬向田翁覓，面少時聞兒女誇。", "可是年來四不出，也隨笭箵傍南涯。"]'),
('fcfddabe-7e74-47e0-a7d7-6ea49d0eaa25','三用韻  其二','牟巘','宋','宋诗','song-poetry','','[]','慚愧長髯市入村，送詩踏凍到衡門。',64,'全唐诗/poet.song.233000.json','["慚愧長髯市入村，送詩踏凍到衡門。", "未愁顧兔千毫禿，持看陽烏三足蹲。", "我亦欲尋安道去，人應共怪阿先存。", "界天雪嶺依然白，更憶當年李仲元。"]'),
('6ec884b4-1bcb-497d-8aff-4a2025d37f67','四用韻  其一','牟巘','宋','宋诗','song-poetry','','[]','寄食於人苦未佳，從來逆旅便爲家。',64,'全唐诗/poet.song.233000.json','["寄食於人苦未佳，從來逆旅便爲家。", "四時長是瓶無粟，一夜偶然燈有花。", "雪夜又寒誰復料，物中惟老不堪誇。", "卷書危坐時相望，不覺西南各一涯。"]'),
('179e71f8-fc57-4eee-95fc-14eed3751029','四用韻  其二','牟巘','宋','宋诗','song-poetry','','[]','五十年前三尺雪，匆匆捩柁下荆門。',64,'全唐诗/poet.song.233000.json','["五十年前三尺雪，匆匆捩柁下荆門。", "坐驚荏苒吳楓換，長憶輪囷蜀芋蹲。", "覆局還如一日事，劫灰能有幾人存。", "新詩讀罷令人感，轉瞬看看又歲元。"]'),
('4c1c09b7-7e2e-4391-8f94-74842d1f1930','道士號庭梅爲賦此','牟巘','宋','宋诗','song-poetry','','[]','苦把庭梅劣野梅，庭梅元自野梅來。',64,'全唐诗/poet.song.233000.json','["苦把庭梅劣野梅，庭梅元自野梅來。", "肯辭台鼎當年貴，直向丹田內景開。", "山意濃時還耐看，道根孤處更深培。", "玄機參透何分別，猛拊闌干一笑回。"]'),
('54b161f7-fe28-4dbc-ae2e-587502da8820','送張剛甫廣德學正','牟巘','宋','宋诗','song-poetry','','[]','桐川咫尺路平寬，華檄春風白髮歡。',64,'全唐诗/poet.song.233000.json','["桐川咫尺路平寬，華檄春風白髮歡。", "教育兼全三者樂，起居頻報四時安。", "的傳何况自諸老，遠業豈徒榮一官。", "從此江東有新句，寄來應對暮雲看。"]'),
('b8b95397-579a-40e0-a971-f780ccc8d413','十一月朔冬至','牟巘','宋','宋诗','song-poetry','','[]','魯僖再閏孰爲偏，五載之終似遠然。',64,'全唐诗/poet.song.233000.json','["魯僖再閏孰爲偏，五載之終似遠然。", "辛亥徒爲章首歲，上元直在太初年。", "未從元凱叩長歷，且效少陵吟短篇。", "一線閒愁隨日長，形容空老此江邊。"]'),
('f5a428c1-9d9e-4d39-99fe-4681bd9cfb5b','餞余好問入燕','牟巘','宋','宋诗','song-poetry','','[]','炎歊漸已轉凉颸，想見湖亭送別時。',64,'全唐诗/poet.song.233000.json','["炎歊漸已轉凉颸，想見湖亭送別時。", "發仞功名初得意，聯鑣賓主總能詩。", "昔人猶自薦佳客，今日何憂乏已知。", "最是人生急三釜，高堂白髮數歸期。"]'),
('313534fa-aad2-43e8-bf7b-4dbcf8c05102','和徐容齋正旦','牟巘','宋','宋诗','song-poetry','','[]','想見新年試筆時，風流應不減丘遲。',64,'全唐诗/poet.song.233000.json','["想見新年試筆時，風流應不減丘遲。", "歸來燕子元相識，落盡桃花若未知。", "何事蘭亭修禊樂，便懷墨客感秋悲。", "湖山勝踐無由共，禪榻茶烟老鬢絲。"]'),
('7d241694-d2f9-453f-8b30-8d9e354e66fa','和趙景程提舉見招','牟巘','宋','宋诗','song-poetry','','[]','高標照我髮星星，百尺樓邊一寸莖。',64,'全唐诗/poet.song.233000.json','["高標照我髮星星，百尺樓邊一寸莖。", "樽自不空如北海，客非善飲類公榮。", "四筵驚起聞豪唱，五斗拚教解宿酲。", "何事詩筒來較晚，且容湯粥煮榆羹。"]'),
('1a5e4e49-4c96-402c-9223-3b3d2dd62b09','再用前韻蓋座上有九老繡幛','牟巘','宋','宋诗','song-poetry','','[]','耆英圖障爛如星，勝似屏風映紫莖。',64,'全唐诗/poet.song.233000.json','["耆英圖障爛如星，勝似屏風映紫莖。", "洛社便如同此樂，商顔未必采其榮。", "戴花劉九徒歌舞，當局溫公豈醉酲。", "試問諸賢閒得否，熙豐一鼎沸於羹。"]'),
('dbb1682d-f22b-483b-9a4e-2f14ae049daf','次本齋韻  其一','牟巘','宋','宋诗','song-poetry','','[]','七十八春華髮老，斡旋文鼎力猶堪。',64,'全唐诗/poet.song.233000.json','["七十八春華髮老，斡旋文鼎力猶堪。", "品題人物多成傳，管領溪山盡屬銜。", "了不安排方是適，本無全缺又何慚。", "誇傳析國睢陽冠，五字新詩落枕函。"]'),
('da5dc8b5-bca0-4a7d-80e4-f35cf0d559b3','次本齋韻  其二','牟巘','宋','宋诗','song-poetry','','[]','怪底膺門稚子歡，倒衣迎拜病猶堪。',64,'全唐诗/poet.song.233000.json','["怪底膺門稚子歡，倒衣迎拜病猶堪。", "喜看詩卷牛腰大，慚說踏車鴉尾銜。", "風誼薄雲誰得似，雲泥被徑我增慚。", "新年精力知强健，酬答端能日百函。"]'),
('d590c91e-e10a-4ee6-be15-e685584ed559','十月能靜飲于海棠花下唐同知適至因言昔在漢中十月海棠亦開用韻','牟巘','宋','宋诗','song-poetry','','[]','貳車曾上漢中臺，十月海棠無數開。',64,'全唐诗/poet.song.233000.json','["貳車曾上漢中臺，十月海棠無數開。", "萬里相逢曾識面，雙眵掃凈更傳杯。", "高情共惜燕支暈，歸夢還思灧澦堆。", "客去主人應卜夜，不妨喚取燭籠來。"]'),
('3773db86-6346-4465-b77a-2ee11197b585','和除日聞鵲','牟巘','宋','宋诗','song-poetry','','[]','門前車馬氣如雲，鵲噪驚猜意甚馴。',64,'全唐诗/poet.song.233000.json','["門前車馬氣如雲，鵲噪驚猜意甚馴。", "別歲風光從草草，報人消息喜頻頻。", "當家金印君先得，明日椒盤我自親。", "共樂高堂稱斚壽，安輿迎養趁垂齡。"]'),
('36f5107d-9160-4623-baa9-980548a92075','送鄧善之','牟巘','宋','宋诗','song-poetry','','[]','尺一俄聞有急徵，風雲奮迅在南溟。',64,'全唐诗/poet.song.233000.json','["尺一俄聞有急徵，風雲奮迅在南溟。", "正如蜀客懷鉛筆，未羨鴻都寫石經。", "此事惟須一艮卦，今朝頓見兩文星。", "幘溝婁畔藏書去，人在金坡白玉扃。"]'),
('f04edb08-6e2d-459e-a757-40909ce2f1d4','送人赴宜興教授','牟巘','宋','宋诗','song-poetry','','[]','催喚沙棠港口船，門前龍象聳初筵。',64,'全唐诗/poet.song.233000.json','["催喚沙棠港口船，門前龍象聳初筵。", "養親始願家良近，事道中年志愈堅。", "美俗一新吾禮樂，高賢多羨此山川。", "不妨且爲坡翁住，却上玉堂陪衆仙。"]'),
('1d708520-e4e6-4b34-bc27-098104a248c1','次韻李千秋中秋','牟巘','宋','宋诗','song-poetry','','[]','節物詩情總索然，漫將梨栗當盤筵。',64,'全唐诗/poet.song.233000.json','["節物詩情總索然，漫將梨栗當盤筵。", "堪憐永夜空樽月，記取衰翁斷酒年。", "十日尚留花影在，兩瓶便作竹根眠。", "分明破戒緣佳句，免使兒童誚禁烟。"]'),
('db8af3f3-61f9-4c25-af42-aebcfa37346c','癸卯人日送李千秋還杭','牟巘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','喜聞罨畫初回棹，便擬共公吟過春。',64,'全唐诗/poet.song.233000.json','["喜聞罨畫初回棹，便擬共公吟過春。", "何事客鄉還送客，今朝人日更愁人。", "風吹杯面梅花老，路轉裙腰草色新。", "只恐西湖留不住，重來好爲活疲民。"]'),
('d36a31bf-acc8-489b-86b9-a367d52730c5','失題','牟巘','宋','宋诗','song-poetry','','[]','篇章何事等嬉游，尚想揮毫剪燭秋。',64,'全唐诗/poet.song.233000.json','["篇章何事等嬉游，尚想揮毫剪燭秋。", "從古殺青徒自苦，只今醉墨可能求。", "忽傳鷺立沙頭句，又見鴻歸天外州。", "襆研去來須猛省，不由自己更誰由。"]'),
('a4afea47-8942-4e13-b2bd-56d5b9232617','歲在丙辰元日立春是時先人守當塗郡齋賓客雲集皆用元祐八年東坡和王仲至秦少游詩故事所謂省事天公厭雨回先人笑曰天公省事今乃多事耶今三十有九年矣追念感慨小詩聊記當時笑談之語','牟巘','宋','宋诗','song-poetry','','[]','憶昨姑溪歲丙辰，老仙元日去班春。',64,'全唐诗/poet.song.233000.json','["憶昨姑溪歲丙辰，老仙元日去班春。", "當家句子頻催客，省事天公却笑人。", "紫鳳天涯今已老，泥牛歲首又還新。", "笑談誰記當時選，獨立東風倍愴神。"]'),
('ea2ea79e-3478-4aa5-b1af-64cfcc4db4ea','和任東津山長','牟巘','宋','宋诗','song-poetry','','[]','吳興學法遍諸華，吾道元無邇與遐。',64,'全唐诗/poet.song.233000.json','["吳興學法遍諸華，吾道元無邇與遐。", "今日誰能留下馬，古人猶自酹先茶。", "肯開燕豆驚流俗，共喜臯比得當家。", "入手新詩惟重拜，頡頏那得並飛霞。"]'),
('50da54a4-1928-44e0-aa5e-7d875189c261','和汴教耶律伯明','牟巘','宋','宋诗','song-poetry','','[]','翩然來自舊京華，歷數山河不謂遐。',64,'全唐诗/poet.song.233000.json','["翩然來自舊京華，歷數山河不謂遐。", "往事已空惟重黍，玄談未了更澆茶。", "南遊句好俄驚座，東道情深未憶家。", "也欲衛州門外去，一聲長嘯入烟霞。"]'),
('7a9894d9-8212-47ec-aecb-30d3f8fd4567','新城羅氏棣華堂','牟巘','宋','宋诗','song-poetry','','[]','中和偶向此枝藂，友愛當知吾意同。',64,'全唐诗/poet.song.233000.json','["中和偶向此枝藂，友愛當知吾意同。", "十世共居尤盛事，一家三代共春風。", "試看華萼相扶處，正在閨門載翕中。", "昭諫而來名節偉，更添新記與無窮。"]'),
('39bc8857-42b8-4833-8383-df85058fd692','寄昌化孫梅泉','牟巘','宋','宋诗','song-poetry','','[]','揮手秦稽信宿然，未行俄已兩週天。',64,'全唐诗/poet.song.233000.json','["揮手秦稽信宿然，未行俄已兩週天。", "雲緘尺素惟開後，雪輥雙溪恐墮前。", "高誼誰能似孫宰，舊題應復記蘇仙。", "何時布韈青鞋去，摘野芎苗古寺邊。"]'),
('86d7bc6e-faf2-4f2d-ae26-ab8d6ce9a92d','文性之惠蛤蜊綠橘','牟巘','宋','宋诗','song-poetry','','[]','二珍胥會到柴關，詩爲高情趁早還。',64,'全唐诗/poet.song.233000.json','["二珍胥會到柴關，詩爲高情趁早還。", "海上便如逢若士，橘中應不減商山。", "可人風味知渠雋，老我形容有許頏。", "快擊黄包烹紫殻，爲君呼酒一開顔。"]'),
('ec3c0c1d-beed-42cd-ba9d-6bd77c70af9f','送季雲在學錄','牟巘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','橫經之暇即吟詩，三載如常匪激隨。',64,'全唐诗/poet.song.233000.json','["橫經之暇即吟詩，三載如常匪激隨。", "聽雨不知官獨冷，看雲自與意俱遲。", "翬飛黌宇生新敬，鵠立儒衣動去思。", "還恐西湖難久滯，此聲梁楚已先馳。"]'),
('78cdb765-647d-4df5-b27e-570687c8b640','次韻九日寄史推','牟巘','宋','宋诗','song-poetry','','[]','弁有山兮水有湄，登臨捨此復何之。',64,'全唐诗/poet.song.233000.json','["弁有山兮水有湄，登臨捨此復何之。", "髮疏帽脫狂嘲後，雁過江涵感慨時。", "盛府主賓俱好事，滿城風雨苦吟詩。", "人生自可行樂耳，劍首功名但一吹。"]'),
('de4956ab-0769-405b-bdd4-a20b54085fcf','次韻寄史彥明','牟巘','宋','宋诗','song-poetry','','[]','等閒看盡弁衡毗，旁郡聊從捧檄馳。',64,'全唐诗/poet.song.233000.json','["等閒看盡弁衡毗，旁郡聊從捧檄馳。", "候管乍披新定志，郵筒忽見故人詩。", "君方清絕行明鏡，我正摧頹據槁枝。", "爲喜綵衣還膝下，椒柈趁得頌花時。"]'),
('c1012937-92c5-4d16-a8ff-a3b3d57b8ffe','答朱薌林見寄','牟巘','宋','宋诗','song-poetry','','[]','天目群仙帝所毗，別來引領但神馳。',64,'全唐诗/poet.song.233000.json','["天目群仙帝所毗，別來引領但神馳。", "分明輸與薌山老，活脫吟成玉局詩。", "論舊驚心幾甲子，扶羸笑覓一筇枝。", "如公再合幡然起，勿戀春先笋蕨肥。"]'),
('ff5f59f6-6a0a-4403-a356-6767be68acd6','次韻李侯喜雨','牟巘','宋','宋诗','song-poetry','','[]','誰似當年召信臣，天教來此活疲民。',64,'全唐诗/poet.song.233000.json','["誰似當年召信臣，天教來此活疲民。", "水鄉怕旱相傳古，甘澍隨車總是春。", "坐看豐登成樂歲，只將愷悌對明神。", "已聞宣布形歌詠，賓主殷勤用意新。"]'),
('a1d7a30b-c7ca-41d8-9d2b-83b1223b9541','謝李侯枉過','牟巘','宋','宋诗','song-poetry','','[]','鳴騶窮巷忽相過，其奈將迎窘步何。',64,'全唐诗/poet.song.233000.json','["鳴騶窮巷忽相過，其奈將迎窘步何。", "每望故都身不羽，欲賡新句硯空磨。", "籃輿端復爲公出，泥飲唯應說尹多。", "却是旁觀工指點，若爲公錦雜漁蓑。"]'),
('8202fda1-23ab-444a-a2f4-a7cdf567067e','長兒授館於杭每休暇過仲實家相與譚經析理間則飲酒賦詩爲樂今閏秋十四日會於復軒相視而笑曰好天凉月即中秋况今歲兩中秋乎乃留飲劇論夜參半蟬聯不休情愈郁穆予聞之甚喜因爲詩寄之','牟巘','宋','宋诗','song-poetry','','[]','共飲方酣月滿樓，劇談無寐露侵裘。',64,'全唐诗/poet.song.233000.json','["共飲方酣月滿樓，劇談無寐露侵裘。", "此宵此景應難值，吾婿吾兒亦罕儔。", "情誼渾如同一姓，風流不負兩中秋。", "絕憐老子婆娑甚，破戒何當大白浮。"]'),
('90f77733-cac0-4cc9-ad2f-5587819d349d','和陳無逸木犀','牟巘','宋','宋诗','song-poetry','','[]','秋旻金氣正高張，併作西風一夜凉。',64,'全唐诗/poet.song.233000.json','["秋旻金氣正高張，併作西風一夜凉。", "何處杯中無白墮，如今扇底有黄香。", "自慚老枿如犀禿，却笑春花爲蝶狂。", "勝賞清吟兩奇絕，吳山橫過即仙鄉。"]'),
('22ed83a2-d82c-42f0-ad01-5954e2d01e9f','和仲實秋興','牟巘','宋','宋诗','song-poetry','','[]','金飆吹暑頓然清，聞早空庭一葉驚。',64,'全唐诗/poet.song.233000.json','["金飆吹暑頓然清，聞早空庭一葉驚。", "拄頰偏宜對朝爽，揮毫正好賦秋聲。", "鏡中髯短休煩鑷，壁上絃閒不受檠。", "志士由來多慷慨，何如百囀聽鶑鳴。"]'),
('0464d9f0-c759-46c9-bd9b-7d66ce911eec','黄元靜飲客蒲蓮海中殊勝絕','牟巘','宋','宋诗','song-poetry','','[]','扁舟徑入芙蕖國，一笑俱非褦襶人。',64,'全唐诗/poet.song.233000.json','["扁舟徑入芙蕖國，一笑俱非褦襶人。", "低拂柳陰偏障暑，活烹芡觜快嘗新。", "小巾脫去我先醉，大杓取來渠更真。", "啜釂數觥詩興發，羨君越漾老精神。"]'),
('faac30ae-c374-496d-87b4-dd707509a019','次姚子敬簡高司丞','牟巘','宋','宋诗','song-poetry','','[]','西風小立對晴川，冷笑人間目聖顛。',64,'全唐诗/poet.song.233000.json','["西風小立對晴川，冷笑人間目聖顛。", "使事端因荔枝出，歸期休在菊花前。", "平生漫說少陵老，終日誰陪上界仙。", "應是杜中鷗與鷺，詩情比舊更依然。"]'),
('59f48670-72af-4086-a948-399358510925','王梅泉生日惠詩次韻答之','牟巘','宋','宋诗','song-poetry','','[]','堪笑衰翁作計狂，又隨笭箵到魚梁。',64,'全唐诗/poet.song.233000.json','["堪笑衰翁作計狂，又隨笭箵到魚梁。", "未秋早覺凋蒲柳，已老安能種豫章。", "誰似讀騷仍飲酒，有時贊易自焚香。", "梅邊有約君應記，但愧年來久覆觴。"]'),
('72474e5a-2f8c-4fda-a3e9-dcc7cbee1c93','白賁','牟巘','宋','宋诗','song-poetry','','[]','致飾雖云賁則亨，含章內照乃爲真。',64,'全唐诗/poet.song.233000.json','["致飾雖云賁則亨，含章內照乃爲真。", "離明外附天光發，艮止中存道體純。", "玉質未雕虹貫日，素功後繪物生春。", "也應笑我元猶白，不比羔羊正直人。"]');
